window.WER_SEARCH_INDEX = [{"title": "Organizando Processos de Requisitos", "authors": ["Soeli T. Fiorini", "Julio Cesar Sampaio do Prado Leite", "Carlos José Pereira de Lucena"], "year": 1998, "keywords": "padrões de processo; processo; requisitos; padrões.", "abstract": "Considerando que a definição e a documentação de processos é um ponto importante para a gerência de requisitos o presente artigo propõe um esquema básico para organização de processos de requisitos, cuja ênfase está na descrição de padrões. Organizando os processos em três tipos (padrão de processo, processo padrão e processo solução) procuramos fornecer informações sob três pontos de vista, de modo a facilitar a aplicação e adaptação de processos. Como damos ênfase nas descrições de padrões de processo, os apresentamos em diferentes níveis de abstração (padrão indivíduo, padrão em família e padrão em comunidade). Nas descrições de processos utiliza-se a idéia do LAL; a idéia de hipertexto; e estrutura-se mais a linguagem natural que descreve os padrões.", "url": "artigos/artigos_WER98/wer199801.html"}, {"title": "Un modelo de hipertexto para la especificación de Requisitos", "authors": ["María Carmen Leonardi", "Gustavo Rossi", "Julio Cesar Sampaio do Prado Leite"], "year": 1998, "keywords": "especificación de requisitos; modelo de hipertexto; pre y post-seguimiento", "abstract": "En este trabajo se presenta un modelo de hipertexto para la Requirements Baseline [Leite'97a] y las tarjetas CRCs derivadas a partir de ella[Leonardi'97][Leite'97b]. Este modelo se basa principalmente en el diseño navegacional de OOHDM[Rossi'97][Schwabe'98], una metodología de diseño Orientada a Objetos para aplicaciones hipermedia. El objetivo de este trabajo es presentar al modelo de hipertexto como un soporte para la etapa de modelización de requisitos. Esta integración trae ventajas en la facilidad de acceso a la información proveyendo diferentes formas de recorrer y analizar los documentos. De esta forma, se facilita la tarea del ingeniero durante la etapa de adquisición de requisitos [Fiorini'97]", "url": "artigos/artigos_WER98/wer199802.html"}, {"title": "Especificação de Requisitos de Software com o Método SCR", "authors": ["Flávio Ricardo Carpena", "Tereza Gonçalves Kirner"], "year": 1998, "keywords": "Especificação de Requisitos; Métodos Formais; Método SCR.", "abstract": "Este artigo apresenta um método formal para a especificação de requisitos de software, o método SCR - Software Cost Reduction, detalhando seu processo de utilização através de um estudo de caso. É feita uma discussão dos pontos fortes e dificuldades inerentes ao uso do método.", "url": "artigos/artigos_WER98/wer199803.html"}, {"title": "Utilizando Requisitos Não Funcionais para Análise de Modelos Orientados a Dados", "authors": ["Luiz Marcio Cysneiros", "Julio Cesar Sampaio do Prado Leite"], "year": 1998, "keywords": "engenharia de requisitos; requisitos não funcionais; MER", "abstract": "Recentes pesquisas apontam para a necessidade de modelos conceituais serem capazes de lidar com metas, de forma a poderem retratar situações complexas que existem no mundo real. Este trabalho aborda o uso de requisitos não funcionais (RNF) na análise de modelos orientados a dados. Esta análise é baseada no uso do Léxico Ampliado da Linguagem (LAL) como âncora para a construção de um grafo de RNFs e para a construção do modelo de dados e de heurísticas para a validação do modelo de dados. Nós adotamos o largamente utilizado modelo entidade relacionamento como o modelo de representação de dados. Apesar de apresentarmos apenas o modelo ER, acreditamos que o método apresentado neste artigo possa ser estendido para outros modelos de dados.", "url": "artigos/artigos_WER98/wer199804.html"}, {"title": "Requisitos de Hiperdocumentos de suporte ao domínio de Engenharia Reversa de Software", "authors": ["Valéria Delisandra Feltrim", "Renata Pontin de M. Fortes"], "year": 1998, "keywords": "Requisitos do Processo de Engenharia Reversade Software; Modelagem de Hiperdocumentos; Projeto de Hiperdocumentos.", "abstract": "Este trabalho apresenta os requisitos funcionais identificados no processode Engenharia Reversa de Software que possam ser suportados por um SistemaHipertexto. Por meio da modelagem conceitual e navegacional do domíniode informações relativas ao método de engenharia reversaFusion-RE/I, foram estabelecidos os requisitos funcionais de um aplicativohipermídia de suporte ao método, de forma a nortear o engenheirode software responsável pelo processo de engenharia reversa e possibilitaro acompanhamento da evolução desse processo.", "url": "artigos/artigos_WER98/wer199805.html"}, {"title": "Towards Requirements Engineering of Active Database Systems", "authors": ["José H. Canós", "Javier Jaén", "Isidro Ramos"], "year": 1998, "keywords": "Active Databases; Requirements Engineering; Dynamic Logic", "abstract": "Active systems are emerging in many fields, being particularly interesting those like Active Database Management Systems which always provide some kind of reactive capabilities. In this paper, starting from the assumption that activity is an important notion not only for database systems, but also for capturing semantics in the Requirements Analysis and Specification field, we present a model of active behavior that is independent of a concrete database data model, in the sense that the set of events is not predefined (imposed by the database system used), rather it varies with each problem being modelled. We define both a syntax and semantics to formalize different dimensions of active behavior. This approach, first, extends an OO model supporting formal requirements specification and rapid prototyping (OASIS) with active capabilities and second, allows implementing information systems in different architectures by translating the active concepts of our model to those of particular active database systems (relational, object-relational or object-oriented). This is a first step towards a CARE tool for the specification and prototyping of active systems.", "url": "artigos/artigos_WER98/wer199806.html"}, {"title": "Uma ferramenta baseada em regras heurísticas para gerar especificações diagramáticas de requisitos orientadas a objeto", "authors": ["Júlio Hartmann", "Carolina Sturm Trindade", "Stanley Loh", "José Mauro V. de Castilho"], "year": 1998, "keywords": "Engenharia de Requisitos; ferramentas CASE; OMT; Engenharia de Software; Inteligência Artificial; Regras Heurísticas.", "abstract": "Este trabalho apresenta uma ferramenta para a geração automática de diagramas de especificação de requisitos orientados a objeto a partir de textos. São apresentadas as bases de conhecimento desenvolvidas, manualmente, na forma de regras heurísticas, as quais foram obtidas através de estudos de caso e análise de procedimentos junto a especialistas. A utilização de conhecimento humano diferencia a ferramenta apresentada da maior parte das ferramentas CASE existentes, que somente atuam nas etapas seguintes à Engenharia de Requisitos no processo de Engenharia de Software. As especificações geradas pela ferramenta são representações de diagramas conceituais orientados a objeto na metodologia OMT (Object Modelling Technique), e o texto analisado é obtido a partir de restrições sintáticas à linguagem natural.", "url": "artigos/artigos_WER98/wer199807.html"}, {"title": "Modelo para Qualificação da Fonte de Informação do Cliente e de Requisito Funcional", "authors": ["Edna Pacheco Zanlorenci", "Robert Carlisle Burnett"], "year": 1998, "keywords": "contexto; domínio aplicação; negócio; ponto de vista; problema; requisito", "abstract": "O modelo proposto visa incrementar ao conteúdo do requisito parâmetros para qualificação e validação das informações. O foco de observação é sobre dois elementos: fonte de informação e características do requisito. Quanto à fonte de informação, o modelo propõe, primeiro, identificar a pessoa responsável pela declaração do requisito sob o ponto de vista de produtor e/ou consumidor da informação; segundo, visualizar claramente o papel que esta pessoa ocupa na organização (operacional, tático, estratégico) como formadora de opinião e, terceiro, qualificar o nível de exigência (essencial, expectativa, excedente) para a satisfação do requisito. Quanto ao requisito, o modelo propõe, primeiro, identificar a área de aplicação (operacional, tático, estratégico); segundo, identificar a área de origem do requisito (interno, externo, ordem legal) e terceiro, identificar a relação de dependência do requisito no contexto em estudo (individual, secundário, grupo). O procedimento seguinte será a validação de requisitos pelo confronto das informações do requisito com as dos variados pontos de vista das pessoas, através da ponderação (valor) do grau de exigência e conformidade com a necessidade e/ou desejo do cliente expresso no processo de extração de requisito, em relação ao produto ou serviço. Como resultado, obtém-se um índice médio de qualificação do requisito, que permitirá avaliar o grau de risco (alto, médio e baixo) para a implementação do requisito.", "url": "artigos/artigos_WER98/wer199808.html"}, {"title": "Suporte Automatizado à Gerência da Evolução de Cenários", "authors": ["Karin Koogan Breitman", "Julio Cesar Sampaio do Prado Leite"], "year": 1998, "keywords": "", "abstract": "Neste artigo discutimos aspectos relacionados à evolução de especificações baseadas em cenários. Apresentamos resultados de estudos realizados nesta área, traduzidos em um conjunto de operações. A partir destes resultados tecemos comentários sobre o apoio automatizado a especificações baseadas em cenários.", "url": "artigos/artigos_WER98/wer199809.html"}, {"title": "Inspección de escenarios", "authors": ["Jorge Horacio Doorn", "Gladys Kaplan", "Graciela Hadad", "Julio Cesar Sampaio do Prado Leite"], "year": 1998, "keywords": "Escenarios; Léxico; Requisitos; Elicitación; Inspección.", "abstract": "La cercanía de los escenarios con situaciones concretas y vitales ayuda a los clientes/usuarios y a los ingenieros de software en el desarrollo de una comprensión compartida de las necesidades. Este fenómeno se incrementa significativamente al construir los escenarios utilizando lenguaje natural. La flexibilidad que ofrece el uso del lenguaje natural mejora la interacción de los participantes en el proceso de captura de los requisitos, pero agrega una importante dificultad a la hora de validar los mismos, ya que la presencia de errores, discrepancias u omisiones es más difícil de detectar. Por otra parte, el contar con un conjunto de requisitos lo más consistente y completo posible es una necesidad creciente en la ingeniería de software. En el presente artículo se propone un conjunto de heurísticas para facilitar la detección de errores. Estas heurísticas consisten básicamente en la realización de verificaciones cruzadas entre los escenarios y el Léxico Extendido del Lenguaje y entre los escenarios mismos.", "url": "artigos/artigos_WER98/wer199810.html"}, {"title": "Erace-Tool-Uma ferramenta baseada em cenários para à engenharia de requisitos.", "authors": ["João Caldas Júnior", "Paulo C. Masiero"], "year": 1998, "keywords": "Engineering Requirements; Scenarios; Use Cases and UML", "abstract": "A tool to support requirements trading is presented. The Tool supports the ERACE approach. This approach starts from the systems requirement document and proposes to specify interactions between the system and its agents (scenarios), and then the scenarios are specified in detail. Heuristics to evolve from the requirements model to the analysis are also presented. An example to illustrates the approach is also presented.", "url": "artigos/artigos_WER98/wer199811.html"}, {"title": "Una Estrategia de Análisis Orientada a Objetos basada en Escenarios: Aplicación en un Caso Real", "authors": ["Laura RIVERO", "Jorge DOORN", "Mariana del FRESNO", "Virginia MAUCO", "Marcela RIDAO", "Carmen LEONARDI"], "year": 1998, "keywords": "Análisis Orientado a Objetos; Escenarios; LEL; Rastreabilidad.", "abstract": "El desarrollo de productos informáticos seguros y confiables es crucial. La Ingeniería de Requisitos desempeña un rol fundamental en este proceso, ya que enfoca un área substancial: la definición de lo que se desea producir. Un enfoque novedoso [8] presenta una metodología basada en el uso de LEL (Language Extended Lexicon) para registrar el vocabulario de un macrosistema y escenarios para modelar el comportamiento, extendida con la incorporación de heurísticas para la derivación de un modelo conceptual de objetos a través de tarjetas CRC. En este trabajo se exponen las experiencias obtenidas a partir de la aplicación de la metodología a un caso de estudio. Fue seguida etapa por etapa, respetando las heurísticas establecidas en forma estricta, requiriendo en algunos casos de la guía de los autores del método. Durante el desarrollo del caso se detectaron algunas ambigüedades que no resultaban evidentes en un análisis teórico. En el presente artículo se resumen las etapas de la metodología, indicando en cada una de ellas los inconvenientes encontrados al desarrollar el caso de estudio. Se sugieren cambios en algunos casos y en otros se deja el espacio de discusión abierto.", "url": "artigos/artigos_WER98/wer199812.html"}, {"title": "Derivación de objetos utilizando LEL y Escenarios en un caso real", "authors": ["Mariana del FRESNO", "Virginia MAUCO", "Marcela RIDAO", "Jorge DOORN*", "Laura RIVERO"], "year": 1998, "keywords": "LEL; Escenarios; Tarjetas CRC; Análisis Orientado a Objetos", "abstract": "El área de Ingeniería de Requisitos se encuentra en permanente evolución, y muchos de sus métodos y herramientas han tenido poca ejercitación en casos reales, por lo que algunas de las opiniones y conclusiones que se pueden recoger en la bibliografía especializada se han generado a partir de consideraciones teóricas o expresiones de deseo de sus autores. En [5] se ha propuesto un método para realizar una derivación preliminar de los objetos de un sistema, mediante el uso del Léxico Extendido del Lenguaje y Escenarios. Existen reportes acerca de algunas aplicaciones de este método, pero pocas de ellas han sido realizadas en situaciones controladas, prestando atención a la importancia relativa de cada uno de los pasos de las heurísticas empleadas. En el presente artículo se relata el proceso de aplicación de la metodología a un caso concreto y se detallan los resultados de las principales métricas utilizadas.", "url": "artigos/artigos_WER98/wer199813.html"}, {"title": "Guidelines From Organizational Requirements to Formal Specification", "authors": ["Fernanda M. R. de Alencar", "Jaelson F. B. Castro"], "year": 1998, "keywords": "Organizational Learning; Requiremen ts Formalization; Formal Specification", "abstract": "In this work we present some guidelines for the integration of organizational requirements and functional requirements of sys tem. For the organization modeling we use the i* technique, it allows a better description of the organizational relationships among the various agents of a system as well as an understanding of the rationale of the decisions taken. For the formal functional specification of the requirements we use at present Structured Modal Action Logic (MAL). We demonstrate the approach by means of an example of a mineral water factory.", "url": "artigos/artigos_WER98/wer199814.html"}, {"title": "Introduzindo Engenharia de Requisitos no Currículo de Engenharia Elétrica/Eletrônica1: O Caso UFPE", "authors": ["Fernanda M. R. de Alencar", "Jaelson F. B. Castro"], "year": 1999, "keywords": "", "abstract": "Neste artigo descrevemos alguns dos problemas típicos de um egresso no curso superior em Engenharia Elétrica habilitação em Eletrônica e observamos como estão relacionados com a deficiência de formação na área de requisitos. Examinamos então as recentes diretrizes Curriculares para Cursos de Engenharia propostas pelo MEC, verificamos e propomos que a matéria Engenharia de Requisitos seja incluída na grade curricular dos cursos da área, para sanar estas deficiências. Ao final, apresentamos um relato de nossa experiência com a introdução do ensino de Engenharia de Requisitos no curso de Engenharia Elétrica/Eletrônica da Universidade Federal de Pernambuco.", "url": "artigos/artigos_WER99/wer199901.html"}, {"title": "Enfoque middle-out en la Construcción e Integración de Escenarios", "authors": ["Graciela D. S. Hadad", "Jorge H. Doorn", "Gladys N. Kaplan", "Julio Cesar Sampaio do Prado Leite"], "year": 1999, "keywords": "Escenarios; Ingeniería de Requisitos; Elicitación; Léxico; Top-down; Bottom-up; Middle-Out.", "abstract": "En la literatura referida a escenarios existen varios autores que proponen un proceso de construcción de escenarios basado en un enfoque topdown1, es decir partiendo de uno o más Escenarios Generales y construyendo los siguientes escenarios en una forma de refinamiento por pasos. Por otro lado, existen otros autores que consideran que los escenarios deberían construirse desde lo particular. Nuestra experiencia con escenarios señala que un enfoque middle-out es más conveniente. En este artículo detallamos dicha estrategia y describimos cómo esta estrategia es importante para integrar escenarios y subescenarios. Nuestras conclusiones están basadas en varios casos de estudio.", "url": "artigos/artigos_WER99/wer199902.html"}, {"title": "LogicOO – uma metodologia para modelagem e construção de sistemas multimídia distribuídos", "authors": ["Giancarlo Guizzardi", "José Gonçalves Pereira Filho"], "year": 1999, "keywords": "engenharia de requisitos; análise de domínio; engenharia de ontologias; vídeo sob demanda; modelagem multimídia; orientação a objetos; Java; JMF.", "abstract": "Este trabalho descreve a implementação de um sistema de vídeo sob demanda seguindo o framework para desenvolvimento de sistemas orientados a objetos LogicOO. Este framework utiliza o conceito de ontologias no seu nível mais alto de abstração, o que permite o reuso do conhecimento sobre o domínio analisado. O protótipo construído, denominado Hipervisão, disponibiliza aos seus usuários o acesso a vídeos digitalizados e atualmente está em testes de uso no Departamento de Informática da UFES.", "url": "artigos/artigos_WER99/wer199903.html"}, {"title": "A Requirements Elicitation Approach Based in Templates and Patterns", "authors": ["A. Durán Toro", "B. Bernárdez Jiménez", "A. Ruiz Cortés", "M. Toro Bonilla"], "year": 1999, "keywords": "requirements engineering; requirements elicitation", "abstract": "One of the main problems of requirements elicitation is expressing customer requirements in a form that can be understood not only by requirements engineers but also by noncomputer professional customers and users. The usual choice for expressing elicited requirements is natural language, since it is frequently the only common language to all participants. Problems of natural language are wellknown, but using more formal notations too early is a risky choice that can make requirements impossible to understand for customers and users. Moreover, requirements engineers do not usually have good writing skills, and sometimes semantically correct requirements, expressed in natural language, are not understood because of the way they are written. In this paper, we present requirements templates that can improve requirements elicitation and expression, and two kinds of patterns: linguistic patterns, which are very used sentences in natural language requirements descriptions that can be parameterized and integrated into templates, and requirements patterns, which are generic requirements templates that are found very often during the requirements elicitation process and that can be reused with some adaptation.", "url": "artigos/artigos_WER99/wer199904.html"}, {"title": "Activity Theory: a Framework to Software Requirements Elicitation", "authors": ["Luiz Eduardo Galvão Martins", "Beatriz Mascia Daltrini"], "year": 1999, "keywords": "Activity; Activity Theory; Context; Requirement; Requirements Elicitation.", "abstract": "In this article we defend the idea that social aspects have strong influence in the software requirements elicitation (Goguen 1993), which drive us to find help in the social sciences. The Activity Theory is a theory developed in the Psychology that focuses the human practices of development process, both the individual and social levels. This theory states that any human action must be understood within a minimal social context, established by an activity. So, we have proposed an approach of software requirements elicitation that have as framework several precepts from the Activity Theory. The case study is developed to show the possibility of using some principles of the Activity Theory in the software requirements elicitation.", "url": "artigos/artigos_WER99/wer199905.html"}, {"title": "Elicit@99 um Protótipo de Ferramenta para a Elicitação de Requisitos", "authors": ["Néstor Adolfo Mamani Macedo", "Julio Cesar Sampaio do Prado Leite"], "year": 1999, "keywords": "Engenharia de Requisitos; Ferramenta de Requisitos; Modelo de Negócio; Repositório de Requisitos; Heurísticas; Acesso Estruturado; Requisitos Funcionais e Requisitos Não Funcionais", "abstract": "No presente trabalho apresenta-se o editor de requisitos Elicit@99, um protótipo de ferramenta para a elicitação de requisitos. Este protótipo está baseado no modelo Serbac-m, o qual é parte do Requirements Baseline. Elicit@99 implementa duas estratégias para a elicitação de requisitos: o uso do acesso estruturado ou enlace hipertextual, que víncula o editor de requisitos ao modelo de negócio, para a captura tanto dos Requisitos Funcionais (RFs) como dos Requisitos Não Funcionais (RNFs), e do repositorio de requisitos para a captura exclusiva dos RNFs de Qualidade.", "url": "artigos/artigos_WER99/wer199906.html"}, {"title": "A Knowledge Acquisition Systematic within the Domain Analysis Context", "authors": ["Mônica Zopelari Roseti", "Cláudia Maria Lima Werner"], "year": 1999, "keywords": "Knowledge acquisition; Domain Analysis; Software Reuse; Knowledge acquisition systematic.", "abstract": "This work presents a systematic approach to knowledge acquisition within the domain analysis context, which grants a well defined process for eliciting and representing domain information that is sensitive to the kind of knowledge to be explored. Within the domain analysis context, knowledge acquisition encompasses aspects that are similar to the ones found in Requirements Engineering, although it is necessary to identify, elicit, and register requirements that belong to a family of systems instead of a unique system. Besides domain requirements, every kind of information that is related to the given domain must be identified, elicited and registered, supporting its comprehension and future generation of applications.", "url": "artigos/artigos_WER99/wer199907.html"}, {"title": "O Impacto dos COTS no Processo de Engenharia de Requisitos", "authors": ["Fabrízia M. de Sousa", "Fernanda M. R. de Alencar", "Jaelson F. B. Castro"], "year": 1999, "keywords": "Metodologia de Desenvolvimento; Requisitos; COTS", "abstract": "Surge uma nova forma de desenvolvimento de software baseada no uso de software prontos, já existentes no mercado, chamados componentes COTS (Commercial Off-The-Shelf). O sucesso dessa nova metodologia de desenvolvimento tem sido demonstrado pelo uso crescente em importantes organizações, incluindo governo, indústria e comércio. Redução de custos e de prazos são os principais benefícios prometidos por esta nova tecnologia de desenvolvimento de software. Por outro lado, existem riscos associados ao novo processo. Nesse trabalho é apresentado o processo de desenvolvimento de software baseado em COTS e suas implicações na engenharia de requisitos. É feita uma análise das fases tradicionais do processo de engenharia de requisitos para adaptar as novas características de desenvolvimento introduzidas pelos componentes COTS.", "url": "artigos/artigos_WER99/wer199908.html"}, {"title": "An Object Oriented Library for Tracing Requirements", "authors": ["Francisco A. C. Pinheiro"], "year": 1999, "keywords": "Requirements traceability object-orientation;object library tracing environments.", "abstract": "We present the overall design of an object-oriented library for use when developing tracing capable applications. The library is implemented as java classes and consists of definitions of the basic classes for registration of objects and relations as well as methods for diferent types of tracing procedures and components for manipulating tracing results and viewing them graphically.", "url": "artigos/artigos_WER99/wer199909.html"}, {"title": "Formal and Informal Aspects of Requirements Tracing", "authors": ["Francisco A. C. Pinheiro"], "year": 2000, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER00/wer200001.html"}, {"title": "Non-Functional Requirements for Object-Oriented Modeling", "authors": ["Jaime de Melo Sabát Neto", "Julio Cesar Sampaio do Prado Leite", "Luiz Márcio Cysneiros"], "year": 2000, "keywords": "Non-Functional Requirements; Language Extended Lexicon; Scenarios; Object-Oriented", "abstract": "Recently, it has been pointed out that the majority of the requirements engineering methods do not take into account non-functional requirements (NFRs) [10][11]. Consequently, we have been experiencing serious problems during the development of software systems, such as cost and schedule overruns. In order to diminish this negligence of NFRs and its consequences, this work proposes a strategy (OONFR) that brings NFRs to object-oriented modeling. The OONFR strategy uses as input a Language Extended Lexicon of the Universe of Discourse (LEL of UofD) and outputs a class diagram with indications of what classes, attributes, operations and relationships are responsible for satisficing1 NFRs. This strategy consists of the following activities: build the Language Extended Lexicon of Universe of Discourse-NFR (LEL of UofD-NFR), build the scenarios and build the class diagram.", "url": "artigos/artigos_WER00/wer200002.html"}, {"title": "Prototipado de interfaces de usuario a partir de escenarios y modelos UML1", "authors": ["Juan Sánchez Díaz", "Alberto Aparicio Vila", "Oscar Pastor López", "Juan Jose Fons"], "year": 2000, "keywords": "Prototipos de interface de usuario; elicitación de requerimientos; validación de escenarios.", "abstract": "En este artículo presentamos un proceso de ingeniería de requerimientos que genera de un modo automático prototipos de interfaces de usuario a partir de escenarios, obteniéndose una especificación formal del sistema en la forma de diagramas de transición entre estados. Esta especificación se incluye dentro de un entorno de ejecución, pudiéndose animar cada uno de los prototipos. Los escenarios se describen mediante message sequence charts (MSC), enriquecidos con información referente a la interface de usuario. El proceso utiliza un modelo de casos de uso. Para una familia de casos, se genera un conjunto de MSC. Los diversos MSC se transforman en diagramas de transición entre estados para los objetos de interface y de control. Apartir de estos, se genera un prototipo de interface de usuario formado por un modelo de vistas por actor, un formulario por caso de uso y un modelo de navegación entre formularios, esto último se obtiene a partir de las relaciones entre los casos. Basándonos en la ejecución del prototipo y en la realimentación de los usuarios del mismo, este puede ser modificado de forma iterativa desde un entorno visual de construcción de interfaces de usuario. La propuesta, soportada por una herramienta CASE, es apropiada para aplicaciones que trabajen con bases de datos.", "url": "artigos/artigos_WER00/wer200003.html"}, {"title": "Uso de Patrones en la Construcción de Escenarios", "authors": ["Marcela Ridao", "Jorge Doorn", "Julio César Sampaio do Prado Leite"], "year": 2000, "keywords": "Ingeniería de Software; Ingeniería de Requisitos; Escenarios; Patrones", "abstract": "Los patrones permiten y han permitido en diferentes áreas del conocimiento humano reusar la esencia de la solución de un problema al enfrentar nuevos problemas similares. Es así que los patrones constituyen una especie de mecanismo de registro y concentración de experticia. Uno de los problemas que trae aparejado el uso de patrones en la práctica, es la identificación del patrón más apropiado para el problema en cuestión. En el presente artículo se describe una heurística de selección de patrones de escenarios basada en el uso de árboles de decisión, organizados con preguntas precisas y fáciles de responder.", "url": "artigos/artigos_WER00/wer200004.html"}, {"title": "Desenvolvendo Use Cases a partir de Modelagem Organizacional", "authors": ["Victor F.A. Santander", "Jaelson F. B. Castro"], "year": 2000, "keywords": "Cenários; Modelagem Organizacional; Engenharia de Requisitos", "abstract": "O paradigma de desenvolvimento orientado a objetos tem conquistado fervorosos adeptos na comunidade de engenharia de software. Um dos mais importantes avanços foi o surgimento da UML, uma linguagem padronizada para modelagem visual. Tipicamente Diagramas de USE CASES tem sido usados para capturar requisitos funcionais do sistema a ser desenvolvido. Contudo, o desenvolvimento de sistemas computacionais ocorre dentro de um contexto onde processos organizacionais estão bem estabelecidos. Portanto, é preciso capturar os requisitos organizacionais para definir como o sistema pretendido irá satisfazer os objetivos da organização, por que ele é necessário, quais as alternativas existentes, quais as implicações das alternativas para as várias partes interessadas, etc. Lamentavelmente UML e técnicas baseadas em cenários em geral, não estão equipadas para modelar os requisitos organizacionais. Precisamos de outra técnica, tal como i*, para representar estes aspectos. Contudo, os requisitos organizacionais precisam ser relacionados aos requisitos funcionais, representados através de Diagramas de Use Case. Neste artigo apresentaremos algumas diretrizes que podem auxiliar o engenheiro de requisitos a desenvolver Diagramas de Use Case em UML a partir dos modelos organizacionais propostos na técnica i*.", "url": "artigos/artigos_WER00/wer200005.html"}, {"title": "Ferramenta de Apoio aos Processos da Engenharia de Requisitos, nas Fases de Projetos", "authors": ["Edna Pacheco Zanlorenci", "Robert Carlisle Burnett"], "year": 2000, "keywords": "descrição; documentação; gerência; projeto; requisito; validação.", "abstract": "O artigo trata os requisitos que compõem os aspectos funcionais de uma ferramenta de apoio aos processos da Engenharia de Requisitos. A ferramenta é tratada sob dois aspectos: a parte geral que deve conter um tutorial com noção básica de uso e de instalação e, a parte específica de projeto que deve abordar os processos de requisitos. Os dados do projeto são suportados por um roteiro didático para descrição do ciclo de vida do requisito. O roteiro tem a função de orientar o processo descritivo a partir da demanda contratada até a especificação da solução. A infra-estrutura, serviços e produtos assistidos pela ferramenta compõem a parte complementar com gestão de recursos do projeto, gerência de requisitos e documentação do projeto.", "url": "artigos/artigos_WER00/wer200006.html"}, {"title": "Requirements Engineering for COTS Selection", "authors": ["Carina Frota Alves", "Fernanda M. R. de Alencar", "Jaelson F. B. Castro"], "year": 2000, "keywords": "COTS development process; non-functional requirements; product evaluation and selection.", "abstract": "There is growing interest in the notion of software development through the planned integration of COTS (Commercial Off-The-Shelf) products. The potential advantages of this integrationcentric approach are shorter development time and reduced cost. Often a COTS based development process consists of an evaluation, selection, adaptation, integration, and evolution of components obtained from external vendors. However, most methods focus on system adaptation and integration but neglect the processes of evaluation and selection of COTS. This paper introduces a COTS-Based Requirements Engineering Model that focuses on nonfunctional requirements to assist the processes of evaluation and selection of COTS products.", "url": "artigos/artigos_WER00/wer200007.html"}, {"title": "O Uso do Framework NFR no Projeto de Banco de Dados", "authors": ["Márcia Santos", "Maria Lencastre", "Jaelson Brelaz de Castro", "Décio Fonseca"], "year": 2000, "keywords": "Engenharia de Requisitos; Framework NFR; projeto de banco de dados distribuídos", "abstract": "O projeto de banco de dados distribuído é um processo bastante complexo que envolve aspectos distintos para a realização de uma adequada distribuição dos dados (Buretta 1997). Muitos desses aspectos correspondem a requisitos não funcionais (propriedades de qualidade ou restrições dos sistemas), como por exemplo, disponibilidade, custos e desempenho. Esses requisitos normalmente são pouco explorados nas etapas do projeto, deixando assim de auxiliar no processo de distribuição. Este artigo tem como objetivo representar os requisitos não funcionais nas fases iniciais do projeto de banco de dados distribuído, através da integração de estratégias propostas pela área de Engenharia de Requisitos. O trabalho foca em especial o uso do Framework NFR (Chung et al. 2000) e faz uma extensão de seus catálogos de requisitos não funcionais, a fim de integrar os principais aspectos relacionados com a distribuição dos dados.", "url": "artigos/artigos_WER00/wer200008.html"}, {"title": "O Uso de Workflow para Apoiar a Elicitação de Requisitos", "authors": ["Lis Ângela De Bortoli", "Ana Maria de Alencar Price"], "year": 2000, "keywords": "Engenharia de Requisitos; Sistemas de Informação; Elicitação; Aquisição de Conhecimento; Workflow.", "abstract": "Este artigo apresenta uma investigação sobre a utilização da modelagem Workflow para apoiar a elicitação de requisitos. Para conduzir este trabalho foi utilizado o método proposto pela primeira autora (De Bortoli 1999, De Bortoli e Price 2000): inicialmente são identificados os objetos (atores, atividades, tarefas e documentos); a fim de compreender o sistema de informação, para cada um dos objetos identificados elabora-se um conjunto específico de questões; com base nas questões elaboradas realiza-se a aquisição de conhecimento sobre os objetos, utilizando técnicas de entrevistas, observações e uma abordagem baseada em etnografia; são elaboradas descrições textuais estruturadas que detalham a execução das atividades e tarefas; a partir das representações textuais são elaboradas representações gráficas das atividades e tarefas, utilizando um modelo de Workflow; por fim, as representações textuais e os Workflows são validados pelos atores do Sistema de Informação. Para verificar a viabilidade do uso, a sistemática proposta foi aplicada numa situação real.", "url": "artigos/artigos_WER00/wer200009.html"}, {"title": "Identificación de Patrones de Reutilización de Requisitos de Sistemas de Información", "authors": ["A. Durán Toro", "A. Ruiz Cortés", "R. Corchuelo Gil", "M. Toro Bonilla"], "year": 2000, "keywords": "reutilización de requisitos; patrones de requisitos", "abstract": "En este artículo se exponen algunos de los resultados de la aplicación de las plantillas y patrones de requisitos presentadas en la edición previa del WER [6]. Uno de los resultados más interesantes de la normalización del formato de los requisitos ha sido la posibilidad de compararlos e identificar patrones de reutilización, tanto a nivel de requisitos de cliente (requisitosC, normalmente expresados en lenguaje natural) como a nivel de requisitos de desarrollador (requisitosD, habitualmente modelos conceptuales), que facilitan el desarrollo y mejoran la calidad de las especificaciones de requisitos. La relaciones de rastreabilidad entre requisitosC, requisitosD, e incluso elementos de menor nivel de abstracción como componentes software, ha permitido también plantear la posibilidad de reutilizar estructuras complejas, desde requisitosC hasta código, obteniendo así una reutilización vertical que abarque distintos niveles de abstracción del desarrollo de software.", "url": "artigos/artigos_WER00/wer200010.html"}, {"title": "HeAR, Una herramienta de Adquisición de Requistos", "authors": ["Laura Petersen", "Stella Tornabene", "María Carmen Leonardi", "Jorge Doorn"], "year": 2000, "keywords": "Ingeniería de Requisitos; lenguaje natural; Léxico Extendido del Lenguaje; escenarios; Herramienta", "abstract": "La Ingeniería de Requisitos cumple un papel primordial en el proceso de producción de software, ya que enfoca un área fundamental: la definición de lo que se desea producir. Obtener documentación de los requisitos implica la sucesión de las actividades de elicitar, modelar y analizar los fenómenos propios del Universo del Discurso, involucrando una combinación de métodos, personas y herramientas. Requirements Baseline1 es una metodología basada en lenguaje natural para registrar el vocabulario del macrosistema y escenarios para modelar el comportamiento, aumentada con verificaciones y validaciones tendientes a producir documentación de mejor calidad. En este artículo se presenta una herramienta de soporte a esta metodología, que tiene como objetivos primordiales asistir durante el proceso de documentación de requisitos automatizando algunas verificaciones. El metamodelo en que se basa el diseño de la herramienta permite adaptarla con facilidad a los cambios producidos en la documentación y su proceso de producción, hecho frecuente en una metodología en estudio y evolución.", "url": "artigos/artigos_WER00/wer200011.html"}, {"title": "Producción del LEL en un Dominio Técnico. Informe de un caso.", "authors": ["Gustavo D. Gila", "Daniel Arias Figueroa", "Alejandro Oliveros"], "year": 2000, "keywords": "Léxico Extendido del Lenguaje; Requerimientos; Elicitación", "abstract": "El presente trabajo se centró en las actividades de la fase de elicitación de requerimientos, utilizándose para la misma una metodología basada en el uso del Léxico Extendido del Lenguaje (LEL) y Escenarios. Se utilizó como caso de estudio el Sistema de Registración y Producción del Instituto de Hemoterapia de la provincia de Buenos Aires. Las experiencias existentes de construcción se desarrollaron en Dominios de Aplicación en los que los ingenieros de requerimientos cuentan con cierto grado de conocimiento del dominio y por lo tanto, del lenguaje, ello necesariamente reduce las actividades para capturar ese lenguaje. En este informe se resume una experiencia en la que el Lenguaje del dominio contiene una gran cantidad de palabras con un contenido muy específico, que denominamos lenguaje técnico\", y que por esta característica resulta de difícil comprensión para los desarrolladores. Las contribuciones del caso de estudio se centran en el hecho de ser un trabajo en el que hubo una fuerte interacción con el personal del Instituto para la construcción del Léxico Extendido del Lenguaje, se verificó la posibilidad de construir un LEL en un ambiente con uso de Lenguaje Técnico, se estableció un enfoque del LEL para asumir esos aspectos técnicos y por último se trata de un caso en el que no fue necesario utilizar la clasificación Estado introducida en la clasificación general definida por [Leite90], en donde se dividen los símbolos en Sujeto, Verbo, Objeto y Estado, con el propósito de la generación automática de Escenarios a partir del LEL.", "url": "artigos/artigos_WER00/wer200012.html"}, {"title": "Inspección Del Lexico Extendido Del Lenguaje", "authors": ["Gladys N. Kaplan", "Graciela D.S. Hadad", "Jorge H. Doorn", "Julio C. S. P. Leite"], "year": 2000, "keywords": "Léxico; Glosarios; Escenarios; Requisitos; Elicitación; Inspección.", "abstract": "El uso de glosarios en el proceso de elicitación de requisitos se ha difundido tanto entre los desarrolladores como entre los investigadores en el campo de la Ingeniería de Requisitos. Por otro lado, se ha comprobado que las actividades posteriores, luego de construido el glosario, pueden apoyarse en el mismo para facilitar el logro de su cometido. El presente artículo propone una heurística de verificación de glosarios como parte de un proceso de construcción de escenarios para describir situaciones de un cierto Universo de Discurso. La preocupación acerca de la calidad del glosario es más que justificada, ya que la construcción de los escenarios se basa en el mismo. En este caso el glosario es un Léxico Extendido del Lenguaje como una representación hipertextual que contempla la descripción de la denotación y la connotación de cada término o entrada en el léxico.", "url": "artigos/artigos_WER00/wer200013.html"}, {"title": "From Early Requirements Modeled by the i* Technique to Later Requirements Modeled in Precise UML", "authors": ["Fernanda Alencar", "Jaelson Castro", "Gilberto Cysneiros", "John Mylopoulos"], "year": 2000, "keywords": "Requirements Engineering; Object Oriented Development; UML; Early and Later Requirements", "abstract": "Requirements capture has been acknowledged as a critical phase of software development, precisely because it is the phase which deals not only with technical knowledge, but also with organizational, managerial, economic and social issues. The emerging consensus is that a requirement specification should include not only software specifications but also business models and other kinds of information describing the context in which the intended system will function. Unfortunately, the current dominant object oriented modeling technique, i.e. Unified Modeling Technique, is ill equipped for capturing early requirements which are typically informal and often focus on organisational objectives. UML is more suitable for later phases of requirements capture, which usually focus on completeness, consistency, and automated verification of functional requirements for the new system. In this paper, we present some guidelines for the integration of early and late requirements specifications. For the organizational modeling we use the i* technique, which focuses on the description of organizational relationships among various organizational actors, as well as an understanding of the rationale for the alternatives chosen. For the functional requirements specification, we rely on the precise Unified Modeling Language (pUML), annotated with constraints described in OCL. A small CD store example is used to illustrate how the requirements process iterates between the early and late requirements specification.", "url": "artigos/artigos_WER00/wer200014.html"}, {"title": "Requirements Elicitation Using a Combination of Prototypes and Scenarios", "authors": ["Markus Mannio", "Uolevi Nikula"], "year": 2001, "keywords": "requirements engineering; requirements elicitation; prototyping; use cases; scenarios", "abstract": "A survey of different types of prototypes and current prototyping methods is presented. Especially the usage of prototypes with use cases and scenarios is investigated, and an approach to requirements engineering combining the systematic use of prototyping and use cases is described. The approach consists of repeated prototype demonstration sessions with stakeholders in which use cases represented by multimedia prototypes are demonstrated. The prototypes are presented in a context familiar to the stakeholders and the use cases and prototypes are refined based on stakeholder feedback for subsequent iterations of prototyping. The purpose of the method is to aid in eliciting requirements from a diverse group of stakeholders. A small case study demonstrating the approach is described where the method is used to elicit the initial requirements for a mobile payment system for car parking fees. The results of the study are discussed and recommendations for future work are presented.", "url": "artigos/artigos_WER01/wer200101.html"}, {"title": "Organizando o Processo de Elicitação de Requisitos Utilizando o Conceito de Atividade", "authors": ["Luiz Eduardo Galvão Martins", "Beatriz Mascia Daltrini"], "year": 2001, "keywords": "Atividade; Elicitação de Requisitos; Teoria da Atividade.", "abstract": "O objetivo deste trabalho é apresentar uma proposta de organização do processo de elicitação de requisitos através do conceito de atividade. Para isso, apresentamos uma metodologia de elicitação de requisitos centrada neste conceito. O conceito de atividade é extraído da Teoria da Atividade, uma teoria da área da Psicologia, que estuda a formação dos processos mentais a partir da atividade humana. Nesta teoria, a atividade é concebida como uma unidade que define um contexto de análise das ações realizadas por um sujeito. A metodologia proposta busca nos elementos constitutivos da atividade referenciais que auxiliem a organização do processo de elicitação de requisitos. O artigo apresenta um estudo de caso onde é aplicada a metodologia proposta, demonstrando como organizar o processo de elicitação de requisitos tendo a atividade como unidade básica de organização.", "url": "artigos/artigos_WER01/wer200102.html"}, {"title": "Um método para elicitação e Modelagem de Requisitos Baseado em Objetivos", "authors": ["Marcia C. F. Carvalho", "Zair Abdelouahab"], "year": 2001, "keywords": "Use Cases; Scenarios;Goals; Requirements; Elicitation; Modelling", "abstract": "Este trabalho propõe uma integração da abordagem CREWS L?ecritoire baseado em cenários com a abordagem de casos de usos descrita por Regnell et al e o Método GBRAM baseado em objetivos. Dessa forma são adicionados ao trabalho de Regnell et al a noção de pedaço de requerimento (RC), as estratégias de descoberta do objetivo através dos relacionamentos AND, OR e de refinamento entre RCs, além de extender o modelo com um nível físico onde são descritas as ações internas do sistema. Em contrapartida, é adicionado à abordagem CREWS- L' Ecritoire o acoplamento objetivo- caso de uso onde a obtenção dos cenários origina-se da aplicação de uma estratégia de refinamento sobre os casos de uso, a integração de cenários normais e excepcionais em um modelo de uso sintetizado, com uma visão única por ator. No que concerne ao Método GBRAM, foram extendidas as relações de dependência de contrato entre objetivos para dependência alternativa e dependência condicional exclusiva, assim como foi introduzida a técnica de caso de uso, conforme descreve Regnell et al em [15,16] e extendida a noção de cenários para caracterizar situações não só excepcionais, mas também as normais e variacionais. Com a integração desses métodos, o método resultante irá representar um adicionamento de cada um isoladamente. Esse método se propõe a acoplar objetivos e casos de uso numa decomposição top-down em diferentes níveis de abstração. Ele combina a utilização destes dois conceitos em um pedaço de requerimento (RC). Um RC é um par <objetivo, caso de uso>, relacionados através de relacionamentos AND, OR e de refinamento. Esses três tipos de relacionamentos entre RCs conduzem a uma organização hierárquica de RCs em três níveis de abstração: o funcional, o comportamental e o físico.", "url": "artigos/artigos_WER01/wer200103.html"}, {"title": "Metodología DoRCU para la Ingeniería de Requerimientos", "authors": ["M. Griselda Báez", "Silvia I. Barba Brunner"], "year": 2001, "keywords": "Requerimientos del usuario; Documento de Requerimientos; Metodología; Documentos Isomórficos.", "abstract": "DoRCU, Documentación de Requerimientos Centrada en el Usuario, es una metodología para la Ingeniería de Requerimientos caracterizada por su flexibilidad y orientación al usuario. Considera los mejores resultados de los enfoques examinados y se apoya en diversos métodos, técnicas y herramientas ya desarrollados por otros autores, pero sin comprometerse con los lineamientos de un paradigma en particular. Tiende, además, a que se unifique la terminología empleada en el campo de la IR, eliminando de esta manera aparentes discrepancias que sólo son la consecuencia de confusiones semánticas que dificultan aún más el proceso de definición de requerimientos.", "url": "artigos/artigos_WER01/wer200104.html"}, {"title": "Generación automática de un esquema conceptual OO a partir de un modelo de flujo de trabajo", "authors": ["Hugo Estrada", "Alicia Martínez", "Oscar Pastor", "Javier Ortiz", "Octavio A. Ríos"], "year": 2001, "keywords": "modelado de procesos de negocio; ingeniería de requisitos; especificación formal; modelos de flujo de trabajo.", "abstract": "Actualmente se reconoce la importancia de incorporar información sobre procesos de negocios en la especificación de requisitos, donde el software es parte activa de este modelo de negocios. Trabajos recientes han intentado utilizar las técnicas de modelado conceptual de sistemas de software, como es el caso de UML, para modelar procesos de negocio, lo cual constituye un enfoque desafortunado, debido a que estas técnicas no permiten especificar en forma clara relaciones organizacionales entre actores también organizacionales. En este artículo se presenta una aproximación para generar un modelo de flujo de trabajo (como punto de inicio para el desarrollo de los modelos estratégicos del framework i*), a partir de una plantilla de requisitos organizacionales, posteriormente este modelo de flujo de trabajo es traducido a un esquema conceptual del cual es posible obtener implementaciones del sistema software en forma automática utilizando la herramienta CASE OO-Method.", "url": "artigos/artigos_WER01/wer200105.html"}, {"title": "Developing Use Cases from Organizational Modeling", "authors": ["Victor F.A. Santander", "Jaelson F. B. Castro"], "year": 2001, "keywords": "Scenarios; Organizational Modeling; Requirement Engineering.", "abstract": "The object oriented development paradigm has attracted many supporters in the Software Engineering community. One of the most important advances was the Unified Language Modeling (UML), a standard for visual modeling. Use Cases Diagrams have been used for capturing system functional requirements. However, the system development occurs in a context where organization processes are well established. Therefore, we need to capture organizational requirements to define how the system fulfils the organization goals, why it is necessary, what are the possible alternatives, what are the implications to the involved parts, etc. Unfortunately, UML and other scenario-based techniques are ill equipped for modeling organizational requirements. We need other techniques, such as i*, to represent these aspects. Nevertheless, organizational requirements must be related to functional requirements represented as Use Cases. In this paper we present some guidelines to assist requirement engineers in the development of use cases from the organizational models represented by i* technique.", "url": "artigos/artigos_WER01/wer200106.html"}, {"title": "Un Proceso para XR basado en Reglas de Negocio", "authors": ["Maria Carmen Leonardi", "Julio Cesar Sampaio do Prado Leite"], "year": 2001, "keywords": "", "abstract": "Extreme Requirements (XR) es una propuesta que procura dar mayor calidad a la conducción de proyectos en Extreme Programming (XP), una de las metodologías más usadas dentro de las metodologías conocidas como ágiles cuyos elementos claves son: poca documentación, simplicidad, análisis como una actividad constante, diseño evolutivo, integraciones y testeo diarios. XR define una estrategia de requisitos que puede ser acoplada a XP, ya que ésta no define una etapa de requisitos, iniciando su proceso con las stories, cortas descripciones de lo que debe hacer el sistema y que son utilizadas en todo el desarrollo. En este artículo presentamos un proceso de la familia XR. Nuestro proceso es orientado al cliente, basado en lenguaje natural, de fácil construcción y validación, que ayuda en la comunicación con los clientes definiendo un proceso de requisitos que complementa XR, y que permite convertir al cliente en un miembro del grupo de desarrollo siendo este concepto uno de los pilares de este tipo de metodologías.", "url": "artigos/artigos_WER01/wer200107.html"}, {"title": "Traceability en la Etapa de Elicitación de Requerimientos", "authors": ["Leandro Antonelli", "Alejandro Oliveros"], "year": 2001, "keywords": "requerimientos; LEL; escenarios; tarjetas CRC; traceability", "abstract": "Este artículo presenta un conjunto de reglas que permiten asegurar que se lleve a cabo traceability en el modelo de elicitación de requerimientos Client-oriented baseline approach [1]. Estas reglas indican la forma de mantener la consistencia de la información a lo largo de los cambios. A partir de la modificación de un elemento del client-oriented baseline determinan los cambios que deben sufrir el resto de los elementos, para que la información sea consistente. Estas heurísticas están implementadas en una aplicación llamada Baseline Mentor Workbench [2], la cual implementa las herramientas del client-oriented baseline.", "url": "artigos/artigos_WER01/wer200108.html"}, {"title": "Analysing the Tradeoffs Among Requirements, Architectures and COTS Components", "authors": ["Carina Alves", "João Bosco Pinto Filho", "Jaelson Castro"], "year": 2001, "keywords": "COTS-Based Development; Requirements Engineering; Software Architecture", "abstract": "The development of software systems from already built COTS components has been motivated by the prospect of reduced cost and development time. However, developing COTS-based systems introduces new challenges and risks different from building systems from scratch. In particular, this new paradigm requires simultaneous tradeoffs among user requirements, COTS products and system architecture. In this paper, we describe a set of guidelines for handling risks and uncertainties associated with such tradeoffs.", "url": "artigos/artigos_WER01/wer200109.html"}, {"title": "Uma Estratégia para Implantação de uma Gerência de Requisitos visando a Melhoria dos Processos de Software", "authors": ["Ana Elizabete Souza de Carvalho", "Cristina Tavares", "Jaelson Brelaz Castro"], "year": 2001, "keywords": "requisitos; processos; gerenciamento.", "abstract": "A indústria de software vem demonstrando crescente interesse em engenharia de requisitos, isto é, entender o que se deseja construir antes de começar a fazê-lo. Estão percebendo que o tempo utilizado no entendimento do problema é um excelente investimento. Os requisitos de software são a base a partir da qual a qualidade é medida. Desta forma, a falta de conformidade aos requisitos significa falta de qualidade. O modelo de avaliação de maturidade do processo de desenvolvimento CMM (Capability Maturity Model) considera o gerenciamento de requisitos como sendo uma das primeiras etapas para alcançar a maturidade organizacional, e para haver o gerenciamento é preciso que o processo de desenvolvimento de requisitos esteja implantado na empresa. Desta forma, para se alcançar a gerência de requisitos é necessário que os requisitos tenham sido definidos, e é importante que a empresa também possua seus processos de desenvolvimento de requisitos definidos. Este artigo tem por objetivo definir uma estratégia para a implantação dos processos de desenvolvimento e gerenciamento de requisitos para os projetos de desenvolvimento e manutenção de software sob responsabilidade do SERPRO, estabelecendo um entendimento comum entre o cliente e a equipe de projeto quanto aos requisitos que serão atendidos no projeto de software.", "url": "artigos/artigos_WER01/wer200110.html"}, {"title": "O Tratamento da Informação (Requisitos no Ciclo de Vida do Produto) Caso Prático: Sistema de Informações de Previdência", "authors": ["Edna Pacheco Zanlorenci", "Robert Carlisle Burnett"], "year": 2001, "keywords": "ciclo de vida; gerência de projeto; projeto; requisito funcional; requisito não-funcional; software.", "abstract": "Atualmente, fala-se muito sobre requisitos; propagam-se necessidades de gestão de mudanças, de atendimento ao cliente; diz-se muito de métodos, técnicas e ferramentas para descrevê-los e representá-los, mas muito pouco da aplicação prática deste conhecimento. A idéia central do artigo é focar o tratamento da informação requisitos no ciclo de vida do produto das fases de um projeto de software. As fases são aqui definidas como: entendimento da demanda, estudos de viabilidade do projeto, detalhamento de modelos lógico e físico do projeto, construção da solução e implantação. A descrição de requisitos é uma atividade indutiva e continuada. Tem conteúdo mais genérico na fase de entendimento da demanda. À medida que se avança nas demais fases de projeto, exige-se detalhamento e mais formalismo. As descrições de funcionalidade tornam-se mais específicas e completas e as de não-funcionalidade (características de qualidade) requerem decomposição e refinamento para se constituirem em argumentos técnicos na construção do software com qualidade.", "url": "artigos/artigos_WER01/wer200111.html"}, {"title": "Requirements Processes: An Experience Report", "authors": ["Julio Cesar Sampaio do Prado Leite", "Soeli T. Fiorini", "Amador Durán", "Beatriz Bernárdez", "Juan Sánchez Diaz", "Emílio Insfrán Pelozo"], "year": 2001, "keywords": "requirements engineering; requirements process; process reuse; requirements management; interface", "abstract": "Abstract. Processes are certainly a key element in software management. Defining and using processes is believed to be an important factor towards quality. Our paper describes a general process language and the experience on its use by two different research teams with two different requirements processes. The process language is the basic representation for a process reuse repository implemented as a web application. The web application was used in order to describe a process for requirements management and a process for interface generation based on requirements information. We present both processes as well as an evaluation of the prototype. Our results are a confirmation of the importance of process reuse and of the possibility of sharing requirements information by publication, on the web, of requirements processes.", "url": "artigos/artigos_WER01/wer200112.html"}, {"title": "Um Modelo de Avaliação de Especificações Semi-Formais de Requisitos de Software Baseado na Teoria dos Conjuntos Nebulosos", "authors": ["Luiz Eduardo Galvão Martins", "Ana Estela Antunes da Silva"], "year": 2001, "keywords": "Atributos de Qualidade; Especificação Semi-Formal de Requisitos; Função de Pertinência; Teoria dos Conjuntos Nebulosos.", "abstract": "O objetivo deste trabalho é apresentar um modelo de avaliação de especificações semi-formais de requisitos de software baseado na Teoria dos Conjuntos Nebulosos. Especificações semi-formais normalmente são apresentadas como um conjunto de diagramas onde os requisitos do software são declarados. Especialistas do domínio do problema e engenheiros de requisitos devem conjuntamente avaliar se a documentação produzida reflete de forma adequada os requisitos do software a ser implementado. Vários atributos de qualidade têm sido propostos para avaliar se uma especificação de requisitos é de fácil entendimento, completa, não ambígua, consistente internamente, possível de ser implementada, entre outros. A avaliação destes atributos de qualidade carrega um alto grau de subjetividade e incerteza, para os quais uma avaliação mais flexível, utilizando valores lingüísticos como baixo, médio e alto, torna-se adequada. Apresentamos ao longo do artigo os passos para a realização de tal avaliação, utilizando como base para o processo a Teoria dos Conjuntos Nebulosos.", "url": "artigos/artigos_WER01/wer200113.html"}, {"title": "Automatic Derivation of Workflow Specifications from Organizational Structures and Use Cases", "authors": ["Maria Carmen Penadés", "José H. Canós", "Juan Sánchez"], "year": 2001, "keywords": "Workflow specification; use cases; business processes requirements.", "abstract": "Workflow technology has reached a reasonable degree of maturity, with a number of both research prototypes and commercial systems available. However, methodological issues have received little attention, and WF developers often have to face the WF development process with neither a methodological support nor a global view of the process. In this paper, we introduce a requirements engineering layer in the workflow development lifecycle. It is organization-based, and follows a bottom-up modeling strategy. In order to capture business processes requirements to obtain a workflow model, we describe the tasks in the process as use cases. The use case model is refined by applying specialization, use and extension relationships, as we go up in the organizational hierarchy. A preliminary workflow model implementing the business processes is obtained automatically from the use case model. The transformation is driven by a set of rules derived from the equivalencies between use case and workflow concepts plus a set of process patterns. A tool supporting our method has been implemented and is outlined in this work.", "url": "artigos/artigos_WER01/wer200114.html"}, {"title": "An XML-Based Approach for the Automatic Verification of Software Requirements Specifications", "authors": ["Amador Durán", "Beatriz Bernárdez", "Antonio Ruiz", "Miguel Toro"], "year": 2001, "keywords": "requirements engineering; requirements verification; XML; XSLT", "abstract": "In this paper, we present an approach for the automatic verification of software requirements specifications. This approach is based on the representation of software requirements in XML and the usage of the XSLT language not only to automatically generate requirements documents, but also to verify some desired quality properties and to automatically compute some metrics. These ideas have been implemented in REM, an experimental requirements management tool that is also described in this paper.", "url": "artigos/artigos_WER01/wer200115.html"}, {"title": "Comprobación Automática de Requisitos de Calidad en Sistemas Multiorganizacionales", "authors": ["Antonio Ruiz", "Amador Durán", "Rafael Corchuelo", "Beatriz Bernárdez", "Miguel Toro"], "year": 2001, "keywords": "ingeniería de requisitos; requisitos de calidad; aplicaciones WEB", "abstract": "El uso de servicios WEB y de servidores de aplicaciones durante el desarrollo y explotación de sistemas multiorganizacionales basados en la WEB (MOWS), ha puesto de relieve algunas limitaciones de los actuales lenguajes de especificación de requisitos de calidad para soportar el tratamiento automático que, sobre este tipo de requisitos, precisan el desarrollo y la explotación de MOWS. En este artículo se presenta un lenguaje formal de especificación de requisitos que facilita la comprobación automática de la conformidad y la economía, dos propiedades de gran interés para los MOWS.", "url": "artigos/artigos_WER01/wer200116.html"}, {"title": "A Non-Functional Approach for COTS Components Trading", "authors": ["Luis Iribarne", "Antonio Vallecillo", "Carina Alves", "Jaelson Castro"], "year": 2001, "keywords": "COTS components; Non-functional requirements; Trading; Component-Based Software Development (CBSD).", "abstract": "In CBSD, the possible benefits of COTS software development, such as low cost, low risk, and high quality, cannot be satisfactorily achieved due to inadequate and/or incomplete proposals for component specification. In particular, non-functional aspects play an important role for components description and selection, but are usually not taken into account when documenting components and searching for them. In this paper, non-functional features of commercial components are analyzed, and a template for collecting this kind of information in XML documents is proposed in order to allow effective COTS components trading.", "url": "artigos/artigos_WER01/wer200117.html"}, {"title": "Using the Language Extended Lexicon to Support Non-Functional Requirements Elicitation", "authors": ["Luiz Marcio Cysneiros", "Julio César Sampaio do Prado Leite"], "year": 2001, "keywords": "Non-Functional Requirements; Language Extended Lexicon", "abstract": "Although Non-Functional Requirements (NFR) have been present in many software development methods, they have been faced as a second or even third class type of requirement, frequently hided inside notes and therefore frequently neglected or forgotten. Surprisingly, despite the fact that nonfunctional requirements (NFR) are among the most expensive and difficult to deal with [5] [12] [3][10], even today there are only a few works that focus on NFR as first class requirements (e.g. [7][8] [10]. Not so surprisingly, stakeholders demand for NFR has been continuously increasing. During 2001 edition of ICSE Mantis Chen from ACD System presented the 3 most important aspects for a software in the stakeholders point of view and the 3 most important one in the developers point of view. All the 6 were non-functional requirements. This work intends to show how we used the Language Extended Lexicon as a way of supporting initial NFR elicitation.", "url": "artigos/artigos_WER01/wer200118.html"}, {"title": "Incorporación de Patrones al Proceso de Construcción de Escenarios", "authors": ["Marcela Ridao", "Jorge Doorn", "Julio Cesar Sampaio do Prado Leite"], "year": 2001, "keywords": "", "abstract": "La idea central del uso de patrones en la construcción de escenarios consiste en aportar la experiencia acerca de situaciones similares acumulada en los patrones a las técnicas existentes. Analizando desde un punto de vista estructural las situaciones, es posible asociar la situación, completa o parcialmente, con uno o más patrones de un catálogo. Una vez determinado el patrón que más se aproxime a la situación real, se reusa su estructura con el fin de derivar el escenario más fácil y directamente. En el presente artículo se propone una modificación a la heurística de construcción de escenarios y se analizan los resultados obtenidos al aplicarla a dos casos de estudio cuyos escenarios ya habían sido obtenidos sin patrones.", "url": "artigos/artigos_WER01/wer200119.html"}, {"title": "Reutilização de Objetivos na Engenharia de Requisitos", "authors": ["Karla Donato Fook", "Zair Abdelouahab"], "year": 2001, "keywords": "", "abstract": "Tratar Requisitos Não Funcionais (RNFs) na concepção de um soft-ware é uma tarefa não trivial. O tratamento de RNFs é complexo na medida em que, além dos impactos nos requisitos funcionais, os RNFs podem estar interdependentes em diferentes situações. Analisar essa interdependência é muito importante para evitar retralho na construção de software. Essa classe de requisitos, RNFs, compreende as características de qualidade de uma aplicação. Isto implica que, ao tratar de requisitos subjetivos, precisamos do conceito de satisfação a contento. Modelos que reflitam o conhecimento, de forma concisa e clara, dessa subjetividade dos RNFs são necessários. Esses modelos devem ajudar o engenheiro de requisitos no tratamento desses requisitos, tanto nos impac-tos como nas interdependências. Esse tratamento, quando feito de maneira adequada é base para a tomada de decisões arquiteturais. Este artigo aborda o início de uma pesquisa sobre estratégias de análise da propagação de rótulos e o consequente impacto desses requisitos não funcionais, considerando o uso de catálogos de conhecimento do tipo SIG (Softgoal Interdependency Graph). Em particular, pretendemos investigar como o uso de Redes de Petri, pode ajudar no refinamento do grau de granularidade dos rótulos de um SIG, de forma a que a propagação de operacionalizações de RNFs sejam mais informativas.", "url": "artigos/artigos_WER01/wer200120.html"}, {"title": "Modelo de Integração de Especificações: Transformação de Use Cases em Tipos Abstratos de Dados", "authors": ["L.A. Martins", "G.S. Rangel", "D.J. Nunes"], "year": 2002, "keywords": "", "abstract": "Durante o processo de desenvolvimento de software, o sistema é especificado em diversos formatos e linguagens. No contexto da engenharia de requisitos, o sistema é especificado através de representações meramente informais ou semi-formais, pois um dos objetivos nesta fase é a comunicação com o cliente da aplicação, por isso a necessidade de formatos de representação intuitivos e não formais. A medida que o processo avança, o ideal seria a transformação das especificação informais e/ou semi-formais em representações formais, baseadas em modelos matemáticos, com sintaxe e semântica bem definidas, o que possibilita a verificação automatizada das especificações e o projeto formal do software. Dessa forma, a tendência seria a redução de erros e inconsistências nas especificações, reduzindo o tempo e os custos do projeto. Para atingir tal meta, é necessário uma metodologia eficiente para garantir a passagem correta entre especificações de requisitos e especificações formais. Este artigo trata exatamente deste problema, propondo um modelo de integração composto por uma metodologia e um conjunto de heurísticas, que combina use cases (modelo de especificação semi-formal orientado ao cliente), com tipos abstratos de dados (modelo de especificação algébrica orientado ao sistema). Para validar a proposta, é apresentado um estudo de caso ao final do artigo.", "url": "artigos/artigos_WER02/wer200201.html"}, {"title": "Fuentes Utilizadas por desarrolladores de Software en Argentina para Elicitar Requerimientos", "authors": ["L. Antonelli", "A. Oliveros"], "year": 2002, "keywords": "", "abstract": "Este artículo analiza cuales son las fuentes de requerimientos utilizadas por los desarrolladores de software en la Argentina. Realizamos una encuesta a 38 personas con formación académica y experiencia en la industria. Estas personas tomaron un curso de ingeniería de requerimientos de la maestría en Ingeniería de Software de la Universidad Nacional de La Plata en el año 2001. Al final del curso les pedimos que completen un cuestionario. Los participantes, basándose en su experiencia y en los conocimientos adquiridos durante el curso, respondieron a preguntas sobre su educación académica, experiencia profesional y, técnicas y fuentes utilizadas para elicitar requerimientos. Los resultados muestran que las fuentes utilizadas son principalmente las personas y los formularios.", "url": "artigos/artigos_WER02/wer200202.html"}, {"title": "Comprendiendo el Universo de Discurso Futuro con Escenarios", "authors": ["J.H. Doorn", "G.D.S. Hadad", "G.N. Kaplan"], "year": 2002, "keywords": "", "abstract": "La definición de requisitos es meramente el producto final de la fase de requisitos, pero es el punto de partida basamental para el diseño del software y para la tarea de seguimiento de requisitos, y además en muchos casos es un documento contractual con los clientes. Para lograr una correcta definición, no sólo es necesario comprender el Universo de Discurso presente sino también comprender el Universo de Discurso futuro. Se plantean en este artículo alternativas para la construcción de Escenarios Futuros, utilizando los mismos como medio de representación parcial del Universo de Discurso futuro en el que se asume la presencia del sistema de software que se planifica desarrollar.", "url": "artigos/artigos_WER02/wer200203.html"}, {"title": "Modelado de Anomalías mediante Escenarios", "authors": ["M. Ridao", "J. Doorn"], "year": 2002, "keywords": "", "abstract": "La importancia del manejo de anomalías por parte de los artefactos de software y el impacto que aquéllas provocan en el desarrollo de los mismos es ampliamente reconocida. El ingeniero de software no sólo debe esforzarse por lograr la máxima confiabilidad del sistema en condiciones de uso normal, sino también tratar de proteger la aplicación de los inconvenientes que surgen del uso de la misma bajo condiciones adversas. Sin embargo, las circunstancias anómalas en las que se va a desempeñar el software son muy poco percibidas en la elicitación de requisitos del Universo de Discurso (UdeD). La Ingeniería de Requisitos se interesa en la elicitación, modelado y análisis de las características que el sistema a desarrollar debe presentar. La falta de anticipación de contextos excepcionales da por resultado requisitos no realistas, inalcanzables y/o incompletos. Como consecuencia, el software desarrollado a partir de esos requisitos no será lo suficientemente robusto, con consecuencias a menudo críticas. En el presente artículo, se analizan las diferentes formas de representación de anomalías utilizando Escenarios y los beneficios que se pueden obtener utilizando patrones.", "url": "artigos/artigos_WER02/wer200204.html"}, {"title": "Support for Structuring Mechanisms in the integration of Organizational Requirements and Object Oriented Modeling", "authors": ["F.M.R. Alencar", "G.A.A. Cysneiros Filho", "J.F.B. Castro"], "year": 2002, "keywords": "", "abstract": "The success of computer applications depends on a good understanding of the organizational environment. Requirement modeling techniques may be used to help to understand the organizational process. In recent years, we have observed a growing influence of the object-orientation paradigm. Unfortunately the dominant technique of object oriented modeling UML (Unified Modeling Language) is ill equipped to represent the organizational requirements. We advocate the use of the i* technique to model organizational requirements in terms of the organizational relationships among the several organizational actors, as well as a means for understanding the rationale for the decision-making. In this paper we discuss some improved guidelines for the integration of early and late requirements specifications. We also present a prototype tool (GOOD - Goal Object Oriented Development) which support the mapping of i* organizational models stored in a Telos repository by the OME tool into UML elements modeled by the Rational Rose tool.", "url": "artigos/artigos_WER02/wer200205.html"}, {"title": "Capturing Web Application Requirements through Goal-Oriented Analysis", "authors": ["D. Bolchini", "P. Paolini"], "year": 2002, "keywords": "", "abstract": "New conceptual tools for effectively supporting the activity of requirements analysis of web applications are needed. Current approaches and model in Requirements Engineering (RE) can be tailored and extended in order to cope with the following distinctive features of interactive and hypermediaintensive web applications: a) high-level communication and business goals have to be addressed and carefully analyzed as an integral part of requirements management; b) goals and needs of the stakeholders need to be tied up with design in a coherent fashion, bridging the current gap between requirements and hypermedia specifications; c) lightweight, usable and informal models are needed for web designers and analysts with no engineering background. Starting from key achievements in RE this paper introduces a light-weight methodology blending goal-directed RE and scenario-based techniques. The core elements of the methodology will be illustrated through a real project experience.", "url": "artigos/artigos_WER02/wer200206.html"}, {"title": "Modeling Organizational Architectural Styles in UML: The Tropos Case", "authors": ["C.T.L.L. Silva", "J.F.B. Castro"], "year": 2002, "keywords": "", "abstract": "Todays software operate in a dynamic, organizational context and hence, it needs flexible architectures based in social and intentional concepts to enable software to evolve consistently with its operational environment. The Tropos requirements oriented development methodology, has defined a number of organizational architectural styles which are suitable to cooperative, dynamic and distributed applications. In this paper, we use the UML to describe these novel architectural styles. In doing so we are able to provide a detailed representation of both the structure and behaviour of the styles.", "url": "artigos/artigos_WER02/wer200207.html"}, {"title": "Generación de Especificaciones de Requisitos de Software a Partir de Modelos de Negocios: Un Enfoque", "authors": ["H. Estrada", "A. Martinez", "O. Pastor", "J. Sanchez"], "year": 2002, "keywords": "", "abstract": "Los trabajos de investigación actuales en ingeniería de requisitos buscan mecanismos que permitan establecer la relación entre la funcionalidad esperada de un sistema de información y los procesos de negocios a los que éste dará soporte. Este enfoque permitirá asegurar que el sistema de información a desarrollar sea realmente útil en las tareas de los actores organizacionales. Los trabajos de investigación en esta área han determinado que las metas organizacionales son una buena base para establecer la relación entre los objetivos perseguidos por el negocio y los requisitos del sistema de información a desarrollar, ya que todos estos requisitos (funcionales y no funcionales) deben corresponderse con tareas que se desean desempeñar dentro de un proceso de negocios. Los procesos de negocio a su vez, permiten el cumplimiento o satisfacción de alguna o algunas de las metas del negocio. En este trabajo se presenta una propuesta para la obtención de requisitos de software a partir de modelos de negocios. El artículo se divide en dos secciones principales: (a) la construcción de modelos de negocios a partir de un análisis orientado a metas (b) la obtención de un modelo de requisitos de software a partir del modelo de negocios. Este trabajo permite tener un punto de partida sólido para la construcción del sistema de información, donde cada requisito tiene su origen en las metas del negocio.", "url": "artigos/artigos_WER02/wer200208.html"}, {"title": "Uma Proposta para Melhorar o Rastreamento de Requisitos", "authors": ["M. Toranzo", "J.F.B. Castro", "E. Mello"], "year": 2002, "keywords": "", "abstract": "Many contributions concerned with software quality (DoD-2167A, ISO 9000-3 and Capability Maturity Model) mandate that requirements traceability be practiced. However, they do not provide a model of what information should be captures and used as a part of requirements traceability model. This paper provides an framework to improve the requirements traceability.", "url": "artigos/artigos_WER02/wer200209.html"}, {"title": "SmartTrace: Una Herramienta para Trazabilidad de Requisitos en Proyectos basados en UML", "authors": ["V. Anaya", "P. Letelier"], "year": 2002, "keywords": "Gestión de requisitos; trazabilidad de requisitos; UML.", "abstract": "La trazabilidad de requisitos es un proceso clave para la exitosa gestión de los requisitos de un sistema de información. A pesar de ello, no existe un consenso acerca de los tipos de especificaciones y enlaces entre éstos que deben usarse en un proceso de trazabilidad. Además, a pesar de la existencia de herramientas específicas para la gestión de requisitos, éstas no proven mecanismos adecuados para la configuración de la trazabilidad de acuerdo con las necesidades específicas del proyecto. En este artículo se presenta SmarTTrace, una herramienta que aprovecha los mecanismos de extensión proporcionados por la CASE Rational Rose para incorporar a ésta las tareas de configuración, especificación y explotación de trazabilidad en un proceso de desarrollo. Para ilustrar la funcionalidad de SmarTTrace respecto a dichas tareas se ha propuesto un pequeño ejemplo basado en el proceso Rational Unified Process.", "url": "artigos/artigos_WER02/wer200210.html"}, {"title": "Specifying Cooperation Environment Requirements using Formal and Graphical Techniques", "authors": ["M. Sánchez-Alonso", "J.M. Murillo"], "year": 2002, "keywords": "", "abstract": "Using formal languages to specify system requirements guarantees the correctness of systems specifications. However, having correct specifications does not guarantee such specification matching user requirements. To guarantee such matching, users are required to validate formal specifications. This is a difficult task because, usually, users are unaware of notations. This work focus on this problem, in particular the validation of formal specifications of complex coordinated systems. To make the users validation easier, a new graphic technique to represent the dependencies in a coordinated environment is proposed. This graphic (and visual) technique increases users understanding whilst lack of precisions is avoided. In fact, the proposed graphics correspond with visual representations of formal Maude specifications. Besides, taking advantage of the features of Maude, the system simulation is supported by the execution of Maude specifications. Thus, users are allowed to check whether the system produces the expected results.", "url": "artigos/artigos_WER02/wer200211.html"}, {"title": "Supporting Cooperative Requirements Engineering with an Automated Tool", "authors": ["D.F. Togneri", "R. de A. Falbo", "C. S. de Menezes"], "year": 2002, "keywords": "Cooperative Requirements Engineering; Requirements Engineering; Groupware; CSCW (Computer-Supported Cooperative Work); Software Engineering.", "abstract": "Requirements Engineering  one of the macro -activities of Sofware Engineering  is a systematic process of capturing, modeling and documenting requirements through an iteractive and cooperative approach[13]. Its an activity which require s team work. Groups of people formulate requirements, design and implement a system and execute quality assurance activities during the software process[28]. The cooperative work becomes necessary since solutions require different knowledge and professionals become more specialized[3]. Viewing these aspects, its worthwhile to use computational resources to support the cooperative Requirements Engineering activities. The area of Computer-Supported Cooperative Work (CSCW) is interested in how groups of people working on a cooperative basis can be assisted by computational support[28]. This work investigates how solutions from the CSCW area can support Requirements Engineering activities and introduces CRETA  a Cooperative Requirements Engineering support tool, which intends to integrate groupware applications into applications supporting Requirements Engineering. This tool was developed for the Web, using the object-orientation paradigm.", "url": "artigos/artigos_WER02/wer200212.html"}, {"title": "Relato de Experiência de Ensino de Engenharia de Requisitos em um Curso de Mestrado em Sistemas de Informação", "authors": ["L.E.G. Martins"], "year": 2002, "keywords": "", "abstract": "Este artigo apresenta um relato de experiência de ensino de Engenharia de Requisitos em um curso de Mestrado em Sistemas de Informação. O objetivo deste relato é discutir alguns indicativos sobre a área de Engenharia de Requisitos que emergiram ao longo da disciplina ministrada, tais como: relevância e aplicabilidade da Engenharia de Requisitos nas atividades profissionais exercidas pelos mestrandos, preferências de interesse sobre as atividades da Engenharia de Requisitos, preferências sobre o uso de algumas técnicas de Engenharia de Requisitos, entre outros. Estes indicativos foram obtidos a partir de dados coletados nos seminários e estudos de caso realizados pelos alunos, e de um questionário aplicado aos alunos no final da disciplina.", "url": "artigos/artigos_WER02/wer200213.html"}, {"title": "Using Quality Models for Assessing COTS Selection", "authors": ["P. Botella", "X. Burgués", "J.P. Carvallo", "X. Franch", "C. Quer"], "year": 2002, "keywords": "", "abstract": "We present in this paper a framework embracing different aspects involved in COTS component selection that influence the success of this activity. Playing a crucial role in this framework appears the concept of quality model, aimed at structuring the description of the quality of COTS components. We propose a methodology for building quality models based on the ISO/IEC 9126-1 standard which allows to create hierarchies of models appropriate for categories and domains of COTS components, and also for particular contexts of COTS selection activities. Such quality models facilitate the expression and refinement of quality requirements during COTS selection. We present also a formal notation for expressing these quality models, the quality requirements and the product descriptions themselves; the notation supports model analysis and makes feasible tool support during COTS selection. Last, we enumerate at the conclusions some issues matter of current and future research.", "url": "artigos/artigos_WER02/wer200214.html"}, {"title": "Medição de Pontos por Função a Partir da Especificação de Requisitos", "authors": ["H.C.A.B. Tavares", "A.E.S. Carvalho", "J.F.B. Castro"], "year": 2002, "keywords": "", "abstract": "Neste trabalho apresentaremos uma proposta para medição de Pontos por Função a partir da especificação de requisitos expressa em casos de uso, notação UML (Unified Modeling Language). Com esta medição torna-se disponível uma métrica confiável na fase de especificação de requisitos do processo de desenvolvimento de software. Esta proposta visa enfatizar a importância da especificação de requisitos para o trabalho de medição de sistemas, minimizando o esforço dos líderes de projeto, obtendo uma compreensão intuitiva do porte do projeto em termos de Pontos por Função de maneira simples e dinâmica. Verifica-se que caso de uso e pontos por função podem ser usados juntos efetivamente para alcançar sucesso no gerenciamento dos requisitos e do projeto.", "url": "artigos/artigos_WER02/wer200215.html"}, {"title": "Writing Use Cases Modelled with Situation Theory", "authors": ["F.A.C. Pinheiro", "I.D. López"], "year": 2002, "keywords": "", "abstract": "This article extends a framework intended to simplify the generation of use cases. The framework allows a concrete and systematic way of describing actions by means of a use case pattern and simple natural language sentences. The framework is composed of a pattern for specifying a use case and a set of guidelines for writing the sentences describing it. These guidelines help the specifier to write natural language sentences that may be easy and uniformly understood. The extension presented in this article uses situation theory to formalise the use cases as situations and to translate the simple sentences into situation theoretic concepts. This article refers to PROSIT, a computational implementation of situation theory, to show how use cases can be described in terms of situation theory.", "url": "artigos/artigos_WER02/wer200216.html"}, {"title": "Using Constraint Programming for the Automatic Detection of Conflicts in Quality Requirements", "authors": ["A. Ruiz-Cortés", "A. Durán", "R. Corchuelo", "M. Toro"], "year": 2002, "keywords": "requirements negotiation; quality requirements.", "abstract": "Requirements negotiation is quite an interesting, ongoing research area. Current requirements engineering models usually propose a negotiation process with similar methods and goals. Unfortunately, only a few have partial automatic support. In this paper, we revisit one of the most mature models, Boehms WinWin model. WinWin is a qualitative, processoriented model so that it is specially suited to be used at the early stages of requirements engineering, when knowledge about requirements is still vague, but not for quantitative, productoriented contexts where a more precise, exact knowledge about the requirements is needed. In this paper, we present a proposal to extend and refine WinWin in order it can be used in productoriented contexts. The main benefit of our approach is that the same conceptual model for requirements negotiation can be used during all software development process, instead of using different models in different phases.", "url": "artigos/artigos_WER02/wer200217.html"}, {"title": "Enhancing Data Warehouse Design with the NFR Framework", "authors": ["F.R.S. Paim", "J.F.B. Castro"], "year": 2002, "keywords": "", "abstract": "In recent years, Data Warehouse has emerged as a powerful technology for integrating heterogeneous data into a multidimensional repository on behalf of decision-support analysis. The complex extraction, transformation and loading process involved, as well as the aggregational-intensive queries are governed by a multitude of quality factors such as integrity, accessibility, performance, and other domain-specific non-functional requirements (NFRs). This clearly advocates the use of an NFR approach in support of building a high-quality data warehouse specification. In this work we extend the NFR Framework [3] to define catalogues of major data warehouse NFR types and related operational methods, for latter reuse during the specification stage. We illustrate the contributions of our approach in a case study on a large data warehouse project.", "url": "artigos/artigos_WER02/wer200218.html"}, {"title": "VRU: Un Método para Validar Requisitos y Generar Interfaces de Usuario Multiplataforma", "authors": ["J. Sánchez", "J. Belenguer", "P. Belenguer", "D. Pascual"], "year": 2002, "keywords": "", "abstract": "En el artículo se presenta un método de desarrollo de software que permite por una parte validar requisitos de usuario mediante prototipación automática y por otra generar interfaces de usuario. La generación de las interfaces utiliza como lenguaje intermedio el lenguaje de marcado UIML. Una interfaz en UIML puede ser traducida a diversas plataformas, lenguajes y sistemas operativos. El método es consistente con cualquier método de producción de software que utilice una capa de casos de uso y alguna variante de los diagramas de secuencia para mostrar las interacciones internas en el sistema. La ventaja de la propuesta radica en la utilización de una única definición de interfaz de usuario, que luego puede ser traducida y animada en diversos entornos. Las interfaces, con pequeñas modificaciones, pueden formar parte del producto software final.", "url": "artigos/artigos_WER02/wer200219.html"}, {"title": "Metamodeling for Requirements Reuse", "authors": ["O. López", "M.A. Laguna", "F.J. Garcia"], "year": 2002, "keywords": "Requirements engineering; requirements reuse; metamodeling; use case; scenario; workflow.", "abstract": "Correct requirements determination is a critical factor in software development as it takes resources and it is an error prone activity which can bring tragic consequences to the rest of the software life cycle. Having stored reusable requirements elements, both qualified and classified, in a repository might contribute to taking advantage of software development resources and to reducing the error probability in requirements specifications. However, the diversity of notations and formats, as well as the existence of different levels of requirements description make requirements reuse difficult. In this paper we present a metamodel to integrate some different types of semiformal diagrams into a requirements reuse approach. The description of reusable elements constitutes the basis for benefiting from diverse representations of requirements in the development of specifications by reusing requirements.", "url": "artigos/artigos_WER02/wer200220.html"}, {"title": "Transformación de Especificación de Requisitos en Esquemas Conceptuales usando Diagramas de Interacción", "authors": ["E. Insfrán", "E. Tejadillos", "S. Martí", "M. Burbano"], "year": 2002, "keywords": "", "abstract": "En el ámbito de la Ingeniería del Software, diversos métodos han sido propuestos para la especificación y modelado de requisitos y el modelado conceptual. En este trabajo se presenta un Proceso de Análisis de Requisitos (PAR) que permite refinar una Especificación de Requisitos representada mediante Casos de Uso utilizando Diagramas de Secuencia extendidos con estereotipos de UML. Se define además, un conjunto de reglas que facilita la trazabilidad de los elementos de la Especificación de Requisitos a una representación equivalente en el Esquema Conceptual.", "url": "artigos/artigos_WER02/wer200221.html"}, {"title": "Eliciting Requirements for Identifying Workflow Categories", "authors": ["Luzardo P. Silva", "Francisco A. C. Pinheiro"], "year": 2003, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER03/wer200301.html"}, {"title": "Análisis de Puntos Función en la Elicitación de Requerimientos", "authors": ["Mabel Bertolami", "Alejandro Oliveros"], "year": 2003, "keywords": "", "abstract": "La aplicación del Análisis de Puntos Función a diferentes artefactos producidos en el proceso de desarrollo de software es una práctica establecida en la ingeniería de software, especialmente a los documentos de diseño. Se presenta una investigación desarrollada para medir la funcionalidad de un sistema de información en la etapa de Elicitación de Requerimientos, específicamente de los escenarios producidos en esa etapa. Se desarrolló un enfoque ad-hoc que permite aplicar el Análisis de Puntos Función (FPA) a Escenarios construidos a partir del Léxico Extendido del Lenguaje (LEL). Se analizaron alternativas aplicables de cálculo de los Puntos Función, se seleccionó un método de FPA y se establecieron un conjunto de reglas y procedimientos que soportan el proceso de medición. Se aplicaron en varios casos disponibles produciendo resultados alentadores respecto a la pertinencia de las métricas obtenidas. Se presentan las conclusiones y se indican futuras líneas de investigación.", "url": "artigos/artigos_WER03/wer200302.html"}, {"title": "Uma Proposta para Processo de Requisitos em Ambientes de Desenvolvimento Distribuído de Software", "authors": ["Leandro T. Lopes", "Azriel Majdenbaum", "Jorge Luis N. Audy"], "year": 2003, "keywords": "", "abstract": "A crescente tendência de distribuição do processo de desenvolvimento tem afetado diversas áreas da engenharia de software. A engenharia de requisitos, por ser um processo que exige grande volume de comunicação e compreensão, sofre influência direta de fatores como linguagem, contexto e cultura. Existe necessidade de um novo processo de requisitos que enderece essas dificuldades, de forma a reduzir o impacto causado pela distribuição das equipes de desenvolvimento. Nesse sentido, este estudo propõe, de forma preliminar, um processo de requisitos para ambientes de desenvolvimento distribuído de software.", "url": "artigos/artigos_WER03/wer200303.html"}, {"title": "Uma Taxonomia Facetada para Técnicas de Elicitação de Requisitos", "authors": ["Edinelson Aparecido Batista", "Ariadne M. B. R. Carvalho"], "year": 2003, "keywords": "", "abstract": "O objetivo deste trabalho é propor uma taxonomia para as técnicas utilizadas na fase de elicitação de requisitos, através de um esquema de classificação facetado. As técnicas são classificadas segundo uma lista de parâmetros, ou facetas, que podem auxiliar os desenvolvedores na escolha das que serão utilizadas na elicitação. Várias técnicas e seus respectivos processos são relacionados, bem como as situações em que seu uso é indicado. A escolha da técnica de elicitação adequada cria condições para que os requisitos sejam melhor especificados e para que os possíveis problemas no desenvolvimento de sistemas fiquem num patamar aceitável.", "url": "artigos/artigos_WER03/wer200304.html"}, {"title": "Aliando Teoria da Atividade e TROPOS na Elicitação de Requisitos de Ambientes Colaborativos de Aprendizagem", "authors": ["Genésio Gomes da Cruz Neto", "Alex Sandro Gomes e Patrícia Tedesco"], "year": 2003, "keywords": "", "abstract": "Este artigo descreve um processo de elicitação de requisitos para o desenvolvimento de aplicações colaborativas de ensino que alia especificações TROPOS à modelos sócio-culturais da Teoria da Atividade. Para obter adequadamente requisitos de um sistema colaborativo de aprendizagem é preciso entender, sobretudo, as atividades de grupo realizadas pelos atores envolvidos no contexto educacional no qual o futuro software será usado. Um adequado Framework para esta análise é oferecido pela Teoria da Atividade. O artigo demonstra como modelos sócio-culturais oriundos do Framework da Teoria da Atividade podem fornecer informações que complementam os modelos organizacionais da metodologia TROPOS. Como estudo de caso, apresenta-se a aplicação do processo elicitação de requisitos proposto no desenvolvimento de um ambiente virtual voltado ao ensino baseado em projeto.", "url": "artigos/artigos_WER03/wer200305.html"}, {"title": "New Mechanism for the Integration of Organizational Requirements and Object Oriented Modeling", "authors": ["Fernanda M. R. Alencar", "Flávio Pedroza", "Jaelson F. B. Castro", "Ricardo C. O. Amorim"], "year": 2003, "keywords": "Requirements Engineering; The Integration of Early and Late Requirements; Object Oriented Development; Tool Support.", "abstract": "Abstract. The success of computer applications depends on a good understanding of the organizational environment. Thus, requirement-modeling techniques may be used to help to understand a process in terms of goals, business rules, tasks, resources and the relationship between their actors. We have observed a growing influence of the object-orientation paradigm but the dominant technique of object oriented modeling UML (Unified Modeling Language) is still ill equipped to represent the organizational requirements. So, we have advocated the use of the i* technique to model requirements in terms of the relationships among the several organizational actors, as well as a means for understanding the rationale for the decision-making. In this paper we discuss some improved guidelines for the integration of early and late requirements specifications. We ext end the i * technique so that we establish an order in the execution of the i* task dependency. We are also proposing to extend the prototype tool (GOOD - Goal Object Oriented Development) to support the new guidelines.", "url": "artigos/artigos_WER03/wer200306.html"}, {"title": "Integration between Organizational Requirements and Architecture", "authors": ["Lucia R. D. Bastos", "Jaelson F.B. Castro"], "year": 2003, "keywords": "", "abstract": "Software systems of today are characterized by increasing size, complexity, distribution, heterogeneity, and lifespan. Understanding and supporting the interaction between software requirements and architectures remains one of the challenging problems in software engineering research. To address these challenges we are investigating the relationship between the requirements and software architecture.In this work we show an approach for this integration of systems requirements and software architectures within the context of the Tropos project.", "url": "artigos/artigos_WER03/wer200307.html"}, {"title": "Crafting Saliente WEB Scenarios using Priorities", "authors": ["Davide Bolchini"], "year": 2003, "keywords": "", "abstract": "Scenarios are effective conceptual tools for requirements elicitation, analysis, and evaluation. However, choosing salient scenarios is one of the major problems of scenario-based web design. On one hand, due to the partiality of scenarios, it is often difficult to envision up-front all the scenarios necessary to cover every interaction capability to be designed for the site. On the other hand, drastically limiting ex ante the number of scenarios may mislead the design because of the risk of missing the coverage of crucial website requirements. This paper introduces a simple technique that enables reasoning about salient scenarios on the basis of the importance of the user profiles, the main stakeholders and their goals. Users and site main stakeholders assign priorities to user profiles and user goals; scenarios are then elaborated on the basis of the profiles and goals with the highest priorities. Advantages and limits of the approach are discussed by means of examples excerpted from a case study.", "url": "artigos/artigos_WER03/wer200308.html"}, {"title": "Closing the Gap between Organizational Modeling and Information System Modeling", "authors": ["Alicia Martínez", "Oscar Pastor", "Hugo Estrada"], "year": 2003, "keywords": "", "abstract": "The creation of a conceptual schema is a critical feature of the software production process. The conceptual schema should represent the structure and behavior of the information system so that the users can perform their organizational tasks. For this reason, the organizational context needs to be the starting point for the generation of an initial conceptual schema. This approach allows us to assure that the functionality of the information system will be equivalent to the tasks that are executed in the business. However, only a few research studies offer a systematic approach for carrying out the equivalence between models. In this paper, a methodological approach for deriving conceptual schemas from TROPOS business models is presented. The resultant conceptual schema will be the input of the OO-Method Case Tool, which implements the automatic software production process. By doing this, we go a step further in the process of including business modeling as a key piece in the software production process.", "url": "artigos/artigos_WER03/wer200309.html"}, {"title": "Indicadores para a Gerência de Requisitos", "authors": ["Claudia Hazan", "Julio Cesar Sampaio do Prado Leite"], "year": 2003, "keywords": "", "abstract": "A implementação de boas práticas de gerência de requisitos de software constitui uma das prioridades na implantação de melhoria do processo de software. Os indicadores de desempenho são formas de representação quantificáveis de características de produtos e processos, sendo utilizados para acompanhar e melhorar os resultados ao longo do tempo. Este trabalho tem como propósito propor indicadores para apoiar um gerenciamento efetivo de requisitos funcionais por meio de indicadores gerenciais de estabilidade e rastreabilidade.", "url": "artigos/artigos_WER03/wer200310.html"}, {"title": "Processo de Engenharia de Requisitos Aplicado a Requisitos Não-Funcionais de Desempenho - Um Estudo", "authors": ["Denise Lazzeri Gastaldo", "Edson Toshimi Midorikawa"], "year": 2003, "keywords": "", "abstract": "Este artigo apresenta um processo de engenharia de requisitos aplicado a requisitos não-funcionais de desempenho, que são um fator importante para obter resultados de qualidade nos projetos de software. O processo inclui as fases de elicitação, análise, documentação e validação. Juntamente com o processo, métodos como a PLanguage (uma linguagem de especificação), grafos de requisitos não-funcionais (para representar o conhecimento) e uma abordagem utilizando diagramas de casos de uso UML (para unir visões funcional e não-funcional) serão incluídos neste trabalho.", "url": "artigos/artigos_WER03/wer200311.html"}, {"title": "Completitud de Glosarios: Un Estudio Experimental", "authors": ["Jorge Doorn", "Marcela Ridao"], "year": 2003, "keywords": "", "abstract": "La introducción de técnicas de predicción basadas en modelos estadísticos en el campo de la Ingeniería de Software lleva ya varios años, especialmente en la estimación de errores residuales luego de una actividad de prueba de un sistema o de defectos totales, detectados y no detectados, durante una actividad de inspección. Estas técnicas son muy valiosas en aquellas áreas en las que la estimación de la completitud resulta un problema prácticamente inabordable de otra manera. En el presente artículo se estudia experimentalmente el uso de los datos de captura y recaptura en el proceso de la Ingeniería de Requisitos, en particular en la construcción del Léxico Extendido del Lenguaje. Los resultados de esta experiencia inicial son muy promisorios e indican que ésta es un área en la que se debieran realizar nuevos estudios a los efectos de corroborar los datos disponibles y consolidar el conocimiento acerca de la capacidad predictiva de estas técnicas.", "url": "artigos/artigos_WER03/wer200312.html"}, {"title": "Em Busca de um Modelo de Referência para Engenharia de Requisitos em Ambientes de Desenvolvimento Distribuído de software", "authors": ["Leandro T. Lopes", "Jorge Luis N. Audy"], "year": 2003, "keywords": "", "abstract": "Existe um interesse crescente em pesquisas que enderecem o desenvolvimento distribuído de software. A engenharia de requisitos, nesse contexto, apresenta diversos desafios causados pela distribuição. A necessidade de um processo de requisitos que aborde essas dificuldades é reconhecida. Nesse sentido, esse artigo visa apresentar um modelo de referência para engenharia de requisitos em ambientes de desenvolvimento distribuído de software, reunindo resultados de pesquisa teórica e prática. Os resultados empíricos foram obtidos em empresas multinacionais que realizam desenvolvimento distribuído de software em nível global.", "url": "artigos/artigos_WER03/wer200313.html"}, {"title": "Semantic Interoperability by Aligning Ontologies", "authors": ["Karin Koogan Breitman", "Carolina Howard Felicíssimo", "Luiz Marcio Cysneiros"], "year": 2003, "keywords": "", "abstract": "A fundamental premise of the semantic web is that a level of interoperability is guaranteed among applications running in an open environment. By the use of ontologies applications are able to share information and exchange meaningful data. In this context ontology alignment is paramount to assure communication among applications. In this paper we propose an ontology alignment strategy based in the concepts of partial alignment and inconsistency tolerance.", "url": "artigos/artigos_WER03/wer200314.html"}, {"title": "Towards a Goal-Oriented Requirements Methodology Based on the Separation of Concerns Principle", "authors": ["Geórgia Maria C. de Sousa", "Jaelson F. B. Castro"], "year": 2003, "keywords": "", "abstract": "One of the most important principles in Software Engineering is the separation of concerns. When this principle is correctly applied, it helps to promote comprehensibility, maintainability and reusability of software system artifacts. However, often, crosscutting requirements are specified in a scattered and tangled fashion. Therefore, in order to produce better requirements specifications, this paper presents a Goal-oriented REquirements Methodology founded on the Separation of Concerns principle. We named this methodology GREMSoC. It intends to better manipulate with crosscutting requirements in Requirements Engineering process providing a way to represent crosscutting requirements apart from the requirements they affect and to specify the composition between them in a noninvasive way. A case study of an Internet Banking System illustrates the use of this methodology.", "url": "artigos/artigos_WER03/wer200315.html"}, {"title": "An Agile Reverse Engineering Process based on a Framework", "authors": ["Maria Istela Cagnin", "José Carlos Maldonado", "Fernão Stella R. Germano", "Paulo Cesar Masiero", "Alessandra Chan", "Rosângela De"], "year": 2003, "keywords": "", "abstract": "This paper presents an agile reverse engineering process, referred to as PARFAIT/RE, which has been abstracted from the use of a framework-based agile reengineering process, named PARFAIT3. The proposition of PARFAIT/RE has been evidenced from an analysis done in a reengineering case study of a medium size system. Several factors collaborate to make PARFAIT/RE agile: a) active participation of legacy system users to validate the artifacts created and to suggest new requirements or the removal of requirements that do not belong to the business context; b) incremental approach; c) prototyping paradigm feasible from the framework instantiation; and d) use of an analysis pattern language (GRN), which was the basis for building the GREN framework. GRN belongs to the business resource management domain and supports object oriented modeling of procedural legacy systems. The analysis models created are used to support the framework instantiation.", "url": "artigos/artigos_WER03/wer200316.html"}, {"title": "Geração de Ontologias Subsidiada pela Engenharia de Requisitos", "authors": ["Carolina Howard Felicissimo", "Lyrene Fernandes da Silva", "Karin Breitman", "Julio Cesar S. P. Leite"], "year": 2003, "keywords": "", "abstract": "Cresce a necessidade do uso de ontologias em aplicações Web devido ao fato da maioria das informações publicadas estar em linguagem natural e, portanto, serem processadas apenas por humanos. Tais informações compõem o universo de informação da aplicação (UdI) que no processo de desenvolvimento de software é elicitado, modelado e analisado pela comunidade de engenharia de requisitos. Acreditamos que com o apoio de técnicas e métodos desenvolvidos e em utilização por esta comunidade podemos apoiar o processo de geração de ontologias por não especialistas. Neste trabalho apresentamos uma ferramenta que fornece apoio semi-automático à geração de ontologias tendo como base o Léxico Ampliado da Linguagem ( LAL).", "url": "artigos/artigos_WER03/wer200317.html"}, {"title": "Abordagem da Engenharia de Requisitos para Software Legado", "authors": ["Edna Pacheco Zanlorenci", "Robert Carlisle Burnett"], "year": 2003, "keywords": "", "abstract": "O artigo propõe abordar um modelo de recuperação de informações de requisitos funcionais e não-funcionais (qualidade) de software em operação (legado), com o uso de métricas de qualidade aplicáveis ao contexto de uso do software. Inicialmente, avalia efetividade, produtividade, segurança e satisfação do usuário com o uso do software. Na seqüência, utiliza um guia de referência para verificação de produtos gerados nas fases de projeto, levando em consideração as métricas de qualidade aplicáveis ao produto, enquanto em fase de desenvolvimento, relacionadas às expectativas do negócio (métricas externas) e à solução de arquitetura da solução (métricas internas).", "url": "artigos/artigos_WER03/wer200318.html"}, {"title": "COSTUME: Un Método Para la Combinación de Modelos de Calidad", "authors": ["Juan P. Carvallo", "Xavier Franch", "Carme Quer", "Xavier Burgués", "Gemma Grau"], "year": 2003, "keywords": "", "abstract": "El uso de modelos de calidad durante la selección de componentes COTS (Comercial Off-The-Shelf) proporciona un entorno adecuado para la descripción de los dominios a los que éstos pertenecen. En este artículo tratamos la construcción de modelos de calidad para Sistemas Software basados en Componentes COTS (SSCC), que definiremos como sistemas compuestos por varios componentes COTS interconectados. Los procesos de selección llevados a cabo para obtener un SSCC requieren la selección de varios productos COTS. Proponemos un método para la construcción de modelos de calidad para SSCC basado en la aplicación de cuatro actividades. Nuestro objetivo es conseguir que los factores de calidad que aparecen en los SSCC estén definidos en términos de los factores de calidad de los componentes COTS y, de esta forma, obtener eficientemente modelos de calidad y sean fáciles de entender, analizar, mantener y reutilizar.", "url": "artigos/artigos_WER03/wer200319.html"}, {"title": "PERSI - Modelo para Avaliação do Pendor da Engenharia de Requisitos de Sistemas de Informação", "authors": ["Álvaro Rocha", "José Vasconcelos"], "year": 2003, "keywords": "", "abstract": "Actualmente parece consensual a ideia de que a Engenharia de Requisitos (ER) é frequentemente conduzida com uma abordagem de pendor tecnológico excessivo. Este pendor é muitas vezes apontado como um contributo negativo para os resultados da ER e consequentemente para o sucesso dos Sistemas de Informação. Neste artigo apresentamos um modelo para avaliação do pendor da condução da ER. O modelo, designado PERSI, estrutura-se em três partes. A primeira foca o domínio da intervenção. A segunda foca os utilizadores. E a terceira foca os métodos e as técnicas subjacentes. O modelo foi validado inicialmente em cinco organizações portuguesas. Como esperado, todas as organizações seguiam na prática uma abordagem à ER de pendor tecnológico, sendo mais ténue nas organizações que apresentavam uma maior maturidade da Função Sistemas Informação.", "url": "artigos/artigos_WER03/wer200320.html"}, {"title": "GVR Guia de Validação de Requisitos baseados nas técnicas PBR e ad-hoc resultante de um estudo de caso no CPqD1", "authors": ["Priscilla B. B. Pagliuso", "Priscilla B. B. Pagliuso", "Claudia de Andrade Tambascia", "André Villas-Boas", "Miriam Ellen de Freitas"], "year": 2003, "keywords": "", "abstract": "A validação de documento de requisitos é uma atividade de extrema importância, uma vez que é possível garantir a qualidade do processo de desenvolvimento do produto de software através de um documento de especificação claro, correto e sem problemas de ambiguidade. Conhecendo esses fatores e as necessidades da empresa CPqD em constante melhoria no processo de elaboração e validação de requisitos surge o trabalho apresentado neste artigo, que tem como objetivo elaborar um método de validação de documento de requisitos resultante de um estudo de caso no módulo Operação do CPqD Gerência da Planta. Este método é denominado GVR  Guia de Validação Requisitos e foi desenvolvido com base na técnica de leitura PBR  Perspective-Based Reading [3] e na experiência em validação de documentos utilizando a técnica ad-hoc.", "url": "artigos/artigos_WER03/wer200321.html"}, {"title": "Requirements for Multi-Agent Systems", "authors": ["Carla Silva", "Jaelson Castro e Patricia Tedesco"], "year": 2003, "keywords": "", "abstract": "Autonomous agents are beginning to be used as a software paradigm, because of their potential to build more powerful and flexible complex systems. To achieve such benefits a standard definition of is agenthood is necessary. In doing so, agent-oriented software engineering will not only be able to develop standardised processes for building agent-based systems but also be able to better as evaluate existing agent-oriented methodologies. This paper presents a set of requirements for agent-oriented systems and the relationships between them using the NFR framework. In order to exemplify the use of the defined criteria, we present a comparative study of two important agent-oriented methodologies.", "url": "artigos/artigos_WER03/wer200322.html"}, {"title": "Designing Communication-intensive Web Applications: a Case Study", "authors": ["Vito Perrone", "Davide Bolchini"], "year": 2004, "keywords": "web applications; goal-oriented requirements analysis; conceptual design.", "abstract": "Who uses requirements engineering and design methodologies besides the people who invented them? Are researchers - at least - actually trying to use them in real-world complex projects and not in \"paper project\"? In this paper, we dare to recount the experience and the lessons we gained in trying to use seriously and in-depth a requirements engineering method (called AWARE) combined with a conceptual user-centered design method (called W2000) for the development of a real-world web application. The project is recounted through the process followed and the artifacts produced, as well as by crystallizing our experience in using and transferring the method to industry in practical and methodological recommendations.", "url": "artigos/artigos_WER04/wer200401.html"}, {"title": "Constructing Use Case Model by Using a Systematic Approach: Description of a Study", "authors": ["Anderson Belgamo", "Sandra Fabbri"], "year": 2004, "keywords": "use case construction; empirical study; requirements modeling", "abstract": "This paper presents the results of a feasability study that was carried out to evaluate the construction of Use Case Models by comparing the models with groups that used the GUCCRA techniques and groups that did not use them, that is, they only used their experience (Ad-Hoc). GUCCRA  Guidelines for Use Case Construction and Requirements document Analysis  is a set of two reading techniques that helps the elaboration of Use Case Models and, simultaneously, provides an opportunity to identify defects in the Requirements Document. The results of the study showed that applying a systematic and procedural technique to construct Use Case Models, a larger standardization may be reached and the construction process becomes more independent from the designers subjectivity and experience.", "url": "artigos/artigos_WER04/wer200402.html"}, {"title": "Contribuição à Engenharia de Requisitos de Ambientes Virtuais", "authors": ["Tereza Gonçalves Kirner", "Valéria Farinazzo Martins Salvador"], "year": 2004, "keywords": "requirements engineering; virtual environments; virtual reality systems.", "abstract": "This paper aims to contribute to the elicitation, specification, and evaluation of requirements applied to the development of virtual environments. Requirements engineering is characterized, based on existing concepts and on experience obtained through the development of three virtual environments. The requirements engineering process is described and exemplified and the main conclusions are pointed out.", "url": "artigos/artigos_WER04/wer200403.html"}, {"title": "Structural Testing with Use Cases", "authors": ["Adriana Carniello", "Mario Jino", "Marcos Lordello Chaim"], "year": 2004, "keywords": "structural testing; use case; software testing; UML", "abstract": "Understanding how a user interacts with a system is important if the goal is to deliver a product that meets the user's needs. Use cases constitute a primary source of requirements in a user-centered perspective and are often utilized to derive acceptance tests. Given such a critical role in requirements engineering, we introduce a novel set of testing criteria based on the use case specification with a two-fold objective: to assess the quality of test cases derived from use cases and to test the use case specification itself. Differently from previous approaches, the novel set of testing criteria requires that structural elements of the use cases be exercised at least once. To support the application of the new set of testing criteria, a testing coverage tool, called UCT - Use Case Tester, was developed. A case study using UCT shows that the new testing criteria are able to evaluate the quality of a test data set as well as to detect faults in use case specifications.", "url": "artigos/artigos_WER04/wer200404.html"}, {"title": "Taxonomic Ontology Alignment - an Implementation", "authors": ["Carolina Howard Felicíssimo", "Karin Koogan Breitman"], "year": 2004, "keywords": "", "abstract": "With the evolution of the Web evolving towards the Semantic Web, where the information should be presented in a meaningful way for both humans and machines, arises the need for semantic interoperability. By interoperability we understand the use of meaningful representation mechanisms that allow for information exchange among agents. There is a consensus that ontologies will be this representation model. The information exchange process depends on our ability to engage two or more ontologies in conversation. In this paper the focus is on the compatibility of different ontologies. We propose a strategy for automatic alignment of ontologies, implemented by an ontology taxonomic alignment component - the CATO component.", "url": "artigos/artigos_WER04/wer200405.html"}, {"title": "Ferramentas para Suporte do Mapeamento da Modelagem i* para a UML: eXtended GOOD – XGOOD e GOOSE", "authors": ["Flávio Pereira Pedroza", "Fernanda M. R. Alencar", "Jaelson F. B. Castro", "Fernando R. C. Silva", "Victor F. A. Santander"], "year": 2004, "keywords": "Modelagem i*; Modelagem UML; XMI ; Plataforma OME", "abstract": "O bom entendimento dos requisitos organizacionais é vital para o sucesso do desenvolvimento de aplicações na área de engenharia de software. Com a popularização do paradigma da orientação à objeto, a linguagem de modelagem UML (Unified Modeling Language) se tornou padrão para este tipo de desenvolvimento. Porém, a UML ainda não está suficientemente estruturada para suportar a modelagem dos requisitos organizacionais. Faz-se necessário a utilização de outras ferramentas de modelagem. A técnica de modelagem i* (istar) supre esta deficiência, sendo uma técnica bem difundida e aceita. Neste trabalho, apresentamos ferramentas de apoio às regras de mapeamento entre as técnicas i* e UML, o eXtended GOOD (Goals into Object Oriented Development) e o GOOSE (Goal Into Object Oriented Standard Extension) que possibilitam a geração de diagramas UML a partir de modelos i* de forma automática.", "url": "artigos/artigos_WER04/wer200406.html"}, {"title": "Satisficing the Conflicting Software Qualities of Maintainability and Performance at the Source Code Level", "authors": ["Bill Andreopoulos"], "year": 2004, "keywords": "Maintainability; Performance; NonFunctional Requirement; Software Quality; Optimization.", "abstract": "The major contributions of our work include adopting the NFR framework to represent and analyze two software qualities that often conflict with each other: maintainability and performance. We identified and described many heuristics that can be implemented in a system's source code to achieve either quality. We implemented some of the heuristics in two medium-sized software systems and then collected measurements to determine the effect of the heuristics on maintainability and performance. A general methodology is described for evaluating and selecting the heuristics that will improve a systems software quality the most. The results of our research were also encoded in XML files, and made available on the World Wide Web for use by software developers.", "url": "artigos/artigos_WER04/wer200407.html"}, {"title": "Estimación del Tamaño Funcional en la Elicitación de Requerimientos", "authors": ["Mabel Bertolami", "Alejandro Oliveros"], "year": 2004, "keywords": "Escenarios; tamaño funcional; regresión lineal", "abstract": "Disponer de la medición temprana del tamaño del software permite estimar costos y esfuerzo así como planificar la agenda de desarrollo. En trabajos previos se presentó un enfoque que aplica el Análisis de Puntos Función a los Escenarios derivados del Léxico Extendido del Lenguaje. En el proceso de validación de esa propuesta se aplicaron técnicas estadísticas sobre un subconjunto de los datos obtenidos de la medición de varios casos de estudio. En este artículo se presentan el análisis de regresión lineal que permitió establecer un modelo de estimación del tamaño funcional de un conjunto de escenarios y la comprobación de la validez del modelo. Los resultados son alentadores en cuanto a la factibilidad del modelo y sus posibles refinamientos posteriores.", "url": "artigos/artigos_WER04/wer200408.html"}, {"title": "Factores que Influencian el Análisis de Requerimientos para Sistemas de Información Interorganizacionales", "authors": ["Luciana C. Ballejos", "Jorge M. Montagna"], "year": 2004, "keywords": "redes interorganizacionales; sistemas de información interorganizacionales; análisis de requerimientos.", "abstract": "El trabajo presenta una metodología básica con los pasos a efectuar previamente al desarrollo de Sistemas de Información Interorganizacionales (SIOs). Ellos conforman el soporte para la ejecución de procesos en las Redes Interorganizacionales (RIOs), nuevas estructuras conformadas por varias organizaciones. Uno de los pasos críticos para el éxito de este tipo de proyectos es el Análisis de Requerimientos. Para hacer frente a ello, se analiza la influencia de un conjunto de factores que caracterizan a las RIOs sobre esta etapa particular para los SIOs. Esto es particularmente importante en ambientes donde la cooperación y coordinación entre varias organizaciones son los objetivos principales.", "url": "artigos/artigos_WER04/wer200409.html"}, {"title": "Medida de Tamaño en la Etapa de Elicitación de Requerimientos", "authors": ["M. Elena Centeno", "Alejandro Oliveros"], "year": 2004, "keywords": "", "abstract": "Establecer mediciones en etapas tempranas del desarrollo del software permite determinar la bondad del proceso elegido. En este trabajo se proponen mediciones de tamaño aplicadas al Léxico Extendido del Lenguaje, un producto de la elicitación de requerimientos. Las definiciones del LEL están expresadas en Lenguaje Natural, entonces al tratar de establecer mediciones se presenta una dificultad adicional inherente a una de las características del Lenguaje Natural: su diversidad de formas de expresión. Las mediciones que surgen en forma inmediata presentan grandes variaciones al aplicarlas a diferentes LEL. Nace así como solución a este problema el concepto de Palabra Normalizada. Efectuar mediciones teniendo en cuenta sólo las palabras normalizadas permite una evaluación más objetiva al conseguir abstraerse de las peculiaridades de cada LEL.", "url": "artigos/artigos_WER04/wer200410.html"}, {"title": "Evaluating Methodologies: A Requirements Engineering Approach Through the Use of an Exemplar", "authors": ["Luiz Marcio Cysneiros", "Vera Werneck", "Eric Yu"], "year": 2004, "keywords": "Agent-Oriented; Systems Development Methodology; Requirements Engineering; Evaluation", "abstract": "Systems development methodologies continue to be a central area of research in software engineering. As the nature of applications and systems usage move increasingly towards open networked environments, not only are new methodologies required, but new ways for evaluating methodologies for these new environments are also required. The agent-oriented approach to software engineering introduces concepts such as pro-activeness and autonomy to achieve more flexible and robust systems for complex applications environments. A number of AOSE methodologies have been proposed. In order to evaluate and compare these methods in depth, we proposed the use of a common exemplar  a detailed application setting within which each of the methodologies will be worked out. The evaluation method emphasizes a requirements engineering perspective. In this paper we show how to apply this exemplar to evaluate three agent-oriented methodologies.", "url": "artigos/artigos_WER04/wer200411.html"}, {"title": "Enhancing Requirements to derive Multi-Agent Architectures", "authors": ["Lúcia R. D. Bastos", "Jaelson F. B. Castro"], "year": 2004, "keywords": "", "abstract": "Software systems of today are characterized by the increasing size, complexity, distribution and heterogeneity. Understanding and supporting the interaction between software requirements and architectures remains one of the challenging problems in software engineering research. In this paper we present an approach for integration of system requirements and software architectures within the context of the Tropos project, an information system development framework that is requirement-driven in the sense that it adopts concepts used during early requirements analysis. Our framework advocates that a multi agent system corresponds to the organizational structure, in which actors are members of a group in order to perform specific tasks.", "url": "artigos/artigos_WER04/wer200412.html"}, {"title": "Towards Requirement Traceability in TROPOS", "authors": ["A. Castor", "R. Pinto", "C. Silva", "J. Castro"], "year": 2004, "keywords": "requirements traceability; agent-oriented development.", "abstract": "If we are to be successful in the development of the next generation of agent oriented systems we must deal with the critical issue of requirements traceability. Failure to do so will imply in higher costs and longer corrective and adaptable maintenance. Unfortunately most agent-oriented methodologies are not addressing this issue. Requirement traceability is intended to ensure continued alignment between stakeholders requirements and various outputs of the system development process. In this paper we show how traceability could be applied to agent oriented development paradigm. In fact, software developers have used agents as a way to understand, model, and develop more naturally an important class of complex system. The growth of interest in software agents has recently led to the development of new methodologies based on agent concepts. However, few agent-oriented methodologies are requirement driven, or recognize traceability as an important issue to be supported. In this paper we argue that requirement traceability must be considered in agent-oriented methodologies. In particular we show how a general-purpose traceability approach can be used in the context of the Tropos framework. An e-commerce case study is used to demonstrate the applicability of the approach.", "url": "artigos/artigos_WER04/wer200413.html"}, {"title": "Uma Proposta de Evolução em Sistemas Legados", "authors": ["Luciana de Paiva Silva", "Victor F.A. Santander"], "year": 2004, "keywords": "Análise; Engenharia Reversa; Modelagem; Engenharia de Requisitos.", "abstract": "O processo de evolução de sistemas legados é um tópico de recentes pesquisas na área de engenharia de requisitos. Organizações vêm se defrontando continuamente com a necessidade de mudar e/ou melhorar seus sistemas computacionais. Neste processo de evolução, as maiores mudanças envolvem a transição do uso de metodologias tradicionais tais como Análise Estruturada e Essencial para metodologias Orientadas a Objetos tais como Catalysis e Processo Unificado (UP). É consensual que um processo de evolução de sistemas legados não deve se basear unicamente na avaliação do código fonte, mas também nos demais artefatos que possam facilitar o processo de elicitação, análise e documentação de requisitos. Neste contexto, uma das principais dificuldades reside na falta de diretrizes que permitam mapear informações de sistemas legados representadas em modelos tais como Diagramas de Fluxos de Dados (DFDs) para novos artefatos utilizados em metodologias orientadas a objetos, como Casos de Uso em UML. Neste artigo, apresentamos um breve estudo das principais metodologias de desenvolvimento de software utilizadas atualmente tanto no âmbito acadêmico quanto industrial, bem como propomos um conjunto de diretrizes para apoiar desenvolvedores no processo de evolução de sistemas legados mapeando informações contidas em DFDs e código fonte para Casos de Uso em UML.", "url": "artigos/artigos_WER04/wer200414.html"}, {"title": "Construccion de una Taxonomía de Componentes COTS Orientados a la Gestión de Requisitos", "authors": ["Claudia P. Ayala", "Pere Botella", "Xavier Franch"], "year": 2004, "keywords": "COTS; Taxonomia; Meta; GBTCM; Ingenieria de Requisitos", "abstract": "Este artículo presenta un procedimiento detallado para la construcción de una taxonomía de componentes COTS en el área de Ingeniería de Requisitos (IR). La taxonomía e información resultante aporta beneficios trascendentales para la selección de herramientas y sistemas que asistan a los actores involucrados en el proceso de IR a simplificar sus diversas labores. La taxonomía es construida mediante un enfoque orientado a metas inspirado en GBRAN (Goal-Based Requirements Análisis Method), llamado GBTCM (Goal-Based Taxonomy Construction Method), que nos proporciona una guía general para el análisis de las fuentes de información y modelado de requisitos y dominios, así como la recopilación y organización del conocimiento relativo a cualquier dominio del mercado de COTS. GBTCM pretende impulsar la reutilización de requisitos y estándares de Ingeniería de Software, con la finalidad de dar soporte en diferentes procesos de selección e integración de componentes.", "url": "artigos/artigos_WER04/wer200415.html"}, {"title": "Uma Análise Crítica dos Desafios para Engenharia de Requisitos em Manutenção de Software", "authors": ["Rodrigo Santos de Espindola", "Azriel Majdenbaum", "Jorge Luiz Nicolas Audy"], "year": 2004, "keywords": "Engenharia de Requisitos; Manutenção de Software; Sistemas Legados", "abstract": "Diversos são os desafios encontrados na manutenção de sistemas legados. Dentre estes desafios, a realização da Engenharia de Requisitos destaca-se como sendo uma área particularmente afetada pelas dificuldades envolvidas em projetos de manutenção. O objetivo deste artigo é apresentar uma análise crítica da influência das principais dificuldades encontradas na manutenção de sistemas legados sobre os processos da Engenharia de Requisitos. Como resultado demonstra-se a criticidade de algumas das atividades da Engenharia de Requisitos, quando realizadas no contexto da manutenção de software. Identificou-se também uma certa dificuldade no uso dos modelos e processos de ER quando analisados sob a ótica do mantenedor de software e de suas necessidades, principalmente no que se refere aos aspectos de rastreamento de requisitos.", "url": "artigos/artigos_WER04/wer200416.html"}, {"title": "Mapeando Diagramas da Teoria da Atividade em Modelos Organizacionais Baseados em i*", "authors": ["Genésio Cruz Neto", "Alex Sandro Gomes e Jaelson Brelaz de Castro"], "year": 2004, "keywords": "Etnografia; Análise de Contexto; Modelagem Organizacional e Teoria da Atividade", "abstract": "Abordagens modernas de engenharia de requisitos dividem o processo de elicitação em dois estágios: um voltado para análise do contexto onde o futuro software será usado e outro focado em projetar alternativas de software adequados a este contexto. Um adequado Framework teórico para apoiar a realização de análises de contexto é oferecido pela Teoria da Atividade. A Teoria da Atividade é uma estrutura filosófica e interdisciplinar usada para estudar diferentes formas de práticas humanas através do uso da atividade como unidade básica de análise. No entanto, constata-se na atualidade uma carência por abordagens que integrem análises de contexto baseadas na Teoria da Atividade com técnicas de especificação de requisitos. Em publicação anterior os autores apresentaram um processo de engenharia de requisitos que integra análises etnográficas baseadas na Teoria da Atividade com modelagens organizacionais baseados em i*. Neste artigo apresentamos uma evolução do processo de engenharia de requisitos proposto através da inclusão de um conjunto de diretrizes de mapeamento que transformam, de forma sistemática, modelos de atividades da Teoria da Atividade em Modelos Organizacionais baseados em i*. As aplicações das diretrizes são demonstradas através da construção de um estudo de caso para um sistema de ensino baseado em projeto", "url": "artigos/artigos_WER04/wer200417.html"}, {"title": "A pattern language to join early and late requirements", "authors": ["Alicia Martínez", "Oscar Pastor", "Hugo Estrada"], "year": 2004, "keywords": "Organizational Model; Early Requirements; Late Requirements; pattern design.", "abstract": "At present, the early phase of Requirements Engineering is a new research area in the Software Engineering field. This phase is concerned with the analysis of the organizational context in which a software system will be used. The models used in this phase allow us to describe an organizational environment using actors, goals, business processes and relationships. The late phase of Requirements Engineering, which is focused on representing the expected functionality of the software system, is more developed, so there are multiple techniques and tools to describe the software system that will be developed inside its operational environment. However, although there are methodologies which give separate support to each phase of requirements engineering, the development of methods to derive late requirements from the early requirements in a methodological way has been neglected in recent research works. This is due, in great measure, to the large difference between the abstraction levels of these two specification models. The objective of this paper is to propose a pattern language which allows us to reduce the abstraction level between early requirements and late requirements in a systematic way. This is done in an MDA-based approach.", "url": "artigos/artigos_WER04/wer200418.html"}, {"title": "Integrating Natural Language Oriented Requirements Models into MDA", "authors": ["María Carmen Leonardi", "María Virginia Mauco"], "year": 2004, "keywords": "Natural language oriented requirements models; MDA Computer Independent Model; UML object diagram; OCL specifications", "abstract": "MDA is a software development framework where the core is a set of automatic transformation of models. One of these models, the CIM, is used to define the business process model. Though a complete automatic construction of the CIM is not possible, we think we could use some requirements models and strategies adapting them to be used in the MDA framework. We present an OCL based transformation to obtain a structural object-oriented CIM from natural language oriented models.", "url": "artigos/artigos_WER04/wer200419.html"}, {"title": "Análisis de Variabilidad con Modelos de Objetivos", "authors": ["Bruno González-Baixauli", "Miguel A. Laguna", "Julio Cesar Sampaio do Prado Leite"], "year": 2004, "keywords": "", "abstract": "Dentro del campo de la variabilidad, o la habilidad de cambio o personalización de un sistema, no es común que dicha variabilidad se tenga en cuenta en la definición de requisitos. En las propuestas donde si se contemplan se utilizan directamente features, aunque no son una técnica de elicitación de requisitos, sino que más bien están a medio camino entre los requisitos y la definición de la arquitectura. También existen propuestas que usan casos de usos, más cercanos a la elicitación de requisitos, pero que tienen problemas para modelar la variabilidad. En este artículo se propone aplicar técnicas de la Ingeniería de Requisitos (IR) al estudio de variabilidad utilizando un enfoque basado en modelos de objetivos, escenarios (incluyendo casos de uso) y features, para la especificación y análisis de requisitos de sistemas con variabilidad. De esta manera, se espera mejorar la fase de requisitos en este tipo de sistemas. Además, los modelos de objetivos proporcionan un mecanismo de decisión de alto nivel (los objetivos del usuario) y permiten incorporar los requisitos no funcionales (RNF).", "url": "artigos/artigos_WER04/wer200420.html"}, {"title": "Uso de los Diagramas de Actividades UML Y el Lenguaje i* en el Modelado del Proceso de Implantacion del Balanced Scorecard", "authors": ["Mariela Haya", "Xavier Franch", "Enric Mayol"], "year": 2004, "keywords": "", "abstract": "La complejidad en la gestión de las organizaciones ha motivado la formulación de diferentes modelos y metodologías que pretenden alinear la estrategia de la organización y el funcionamiento diario de la misma. Uno de estos modelos es el Balanced Scorecard (BSC). En este artículo, presentamos una propuesta para modelar el proceso de implantación del BSC en una organización, basada en la combinación de los diagramas de actividades de UML y los modelos de dependencias estratégicas del lenguaje i*. Los diagramas de actividades permiten establecer la secuencialización de las actividades involucradas en el proceso de implantación del BSC e identificar sus responsables. Para aquellas actividades con mayor contenido estratégico, los modelos de dependencias estratégicas permiten mostrar los aspectos intencionales de los actores que participan en el proceso. Finalmente, se modelizan los diferentes actores y responsables que han aparecido en ambos modelos utilizando el lenguaje i*. Si bien el artículo se limita al caso de estudio del BSC, creemos que la propuesta presentada se puede generalizar a otros procesos similares desde el punto de vista del impacto estratégico en las organizaciones, como puede ser la implantación de sistemas ERP o CRM.", "url": "artigos/artigos_WER04/wer200421.html"}, {"title": "GUCCRA: Contribuindo para a Identificação de Defeitos em Documentos de Requisitos Durante a Construção de Modelos de Casos de Uso", "authors": ["Anderson Belgamo", "Sandra Fabbri"], "year": 2004, "keywords": "requirements inspection; reading techniques; use case model", "abstract": "This paper presents the results of case studies that were carried out aiming at evaluating the defects identified by GUCCRA application and PBRUser application. GUCCRA  Guidelines for Use Case Construction and Requirements document Analysis  is a set of two reading techniques that helps the elaboration of Use Case Model and, simultaneously, identifies defects in the Requirements Document. The results of the case studies shown that the most part of defects identified by PBR-User also were identified by GUCCRA techniques. Besides, GUCCRA techniques identified defects that PBR-User did not. This characteristic must be due the GUCCRA techniques application, allowing the identification of defects during a systematic and procedural approach to construct Use Case Model.", "url": "artigos/artigos_WER04/wer200422.html"}, {"title": "Agent/goal Orientation versus Object Orientation for Requirements Engineering: A Practical Evaluation Using an Exemplar", "authors": ["Luiz Marcio Cysneiros", "Vera Werneck", "Juliana Amaral", "Eric Yu"], "year": 2005, "keywords": "Agent-Oriented; Object-Oriented; Systems Development Methodology; Requirements Engineering; Evaluation.", "abstract": "There are many different approaches to understand and model system requirements. However, systems today tend to be increasingly complex. Agent- and goal-oriented paradigms have been proposed as an alternative to object orientation to cope with these demands. Although it may be intuitive that object-oriented methods could not readily deal with issues such as autonomy, proactiviness and sociality, it is not yet clear to what extent this may be true. Thus, it is necessary to show not only where object orientation might fail, but also where agent/goal orientation still needs improvement. A practical approach that uses a well defined and complex problem producing specifications using agent/goal orientation and object orientation could guide us to understand better the strengths and weaknesses of each approach. That is the main goal of this paper. We use an exemplar proposed in 2001 by Yu and Cysneiros [1] to evaluate both agent/goal orientation and object orientation. For the agent/goal approach we use i*/Tropos, while for object orientation we use UML/RUP. Three teams applied both approaches to the exemplar, producing all the necessary models and answering the evaluation questions provided in the exemplar. We comment in detail on the key findings.", "url": "artigos/artigos_WER05/wer200501.html"}, {"title": "Uso de Agentes no Processo de Requisitos em Ambientes Distribuídos de Desenvolvimento", "authors": ["Miriam Sayão", "Julio Cesar S. P. Leite"], "year": 2005, "keywords": "gerenciamento de requisitos; desenvolvimento distribuído de software; agentes", "abstract": "Dentre as atividades de Engenharia de Software desenvolvidas no decorrer do desenvolvimento de um sistema de software, as mais intensivas em comunicação são aquelas ocorridas na fase do Processo de Requisitos. Nesta fase interagem diferentes atores ou interessados1: usuário, cliente, desenvolvedor, engenheiro de requisitos, coordenador do projeto, inspetores de qualidade. Cada um desses atores desempenha um papel no processo, visando atingir seus próprios objetivos; todos colaboram visando atingir um objetivo comum, que é a obtenção, ao final do processo de desenvolvimento, de um produto de qualidade que atenda às necessidades dos clientes e usuários. Defendemos a idéia que o paradigma de agentes é adequado para apoiar a solução de problemas encontrados no desenvolvimento distribuído de software, no qual fatores como distância, dificuldades de comunicação e diferenças em fusos horários colocam dificuldades adicionais aos atores. Nossa argumentação é validada pela modelagem das atividades de verificação e validação de requisitos, com o uso da modelagem i* para mostrar a intencionalidade de diferentes atores nesse processo.", "url": "artigos/artigos_WER05/wer200502.html"}, {"title": "A Survey of Good Practices and Misuses for Modelling with i* Framework", "authors": ["Ilca Webster", "Juliana Amaral", "Luiz Marcio Cysneiros"], "year": 2005, "keywords": "", "abstract": "The i* framework has been increasingly used by the requirements engineering community. However, good practices are not always followed. Many papers have presented the use of i* constructs in such ways that results are not coherent with their original specifications. Some cases attempt to adapt the framework to specific needs by misusing its elements. In other situations, misuses are due to wrong interpretations of i* syntax and semantic. Unfortunately, many of these misuses may lead to wrong interpretations of the models by other people using i*. This work carried out a survey on several published papers to collect both good practices and misuses of the framework. It aims to help requirements engineers to use the i* framework in its full capacity.", "url": "artigos/artigos_WER05/wer200503.html"}, {"title": "Metamorfosis: Un Marco para el Análisis de Requisitos Funcionales", "authors": ["Isabel Díaz", "Juan Sánchez", "Oscar Pastor"], "year": 2005, "keywords": "", "abstract": "Este artículo describe el Modelo de Realización de Metamorfosis. El propósito principal de este marco es proporcionar la base conceptual necesaria para el establecimiento de vínculos persistentes y controlables entre la especificación de los requisitos funcionales del sistema (expresado como un Modelo de Casos de Uso) y el producto de su análisis (representado a través de un Modelo de Objetos y un Modelo de Interacción). Metamorfosis permite la deducción automática de los modelos del análisis a partir del texto de los casos de uso. Con este objetivo, el Modelo de Casos de Uso ha sido enriquecido para hacer posible la representación de la información sintáctica y semántica de las acciones de los casos de uso. La utilización de roles para facilitar la comprensión de las representaciones y potenciar la genericidad, es otra característica de Metamorfosis.", "url": "artigos/artigos_WER05/wer200504.html"}, {"title": "A Content Analysis Technique for Inconsistency Detection in Software Requirements Documents", "authors": ["Alessandro Fantechi", "Emilio Spinicci"], "year": 2005, "keywords": "", "abstract": "This paper presents J-RAn (Java Requirement Analyzer), a tool that implements a novel Content Analysis technique to support the verification of consistency and completeness of a Software Requirement Specification. This technique exploits the extraction, from a requirement document, of the interactions between the entities described in the document as Subject-Action-Object (SAO) triples (obtainable using a suitable syntactic parser). SAO triples represent a concept in its most synthesizing form. Analyzing the distribution of such concepts in the requirement document helps to locate possible sources of inconsistency and incompleteness.", "url": "artigos/artigos_WER05/wer200505.html"}, {"title": "Using Task Descriptions for the Specification of Web Application Requirements", "authors": ["Pedro Valderas", "Joan Fons", "Vicente Pelechano"], "year": 2005, "keywords": "", "abstract": "There are a significant number of proposals for modelling and developing Web Applications, but very few of them state rigorously how to elicit and represent requirements, and how to go from the requirements specification to the conceptual schema with a sound methodological basis. This work presents an approach to capture Web application requirements by means of: (1) the identification of the tasks that users must be able to achieve and (2) the description of these tasks from the point of view of the interaction that the user requires of the web application. In addition, we show how the navigational structure of a Web application can be systematically derived from the task-based requirement specification.", "url": "artigos/artigos_WER05/wer200506.html"}, {"title": "Modelagem Informacional de Requisitos", "authors": ["Michel Heluey Fortuna", "Marcos R. S. Borges"], "year": 2005, "keywords": "objetivos informacionais; objetivos organizacionais; modelagem informacional.", "abstract": "Vários autores têm apontado problemas na modelagem de requisitos com casos de uso, relacionados com o detalhamento excessivo do comportamento, incompatibilidade com o enfoque de orientação a objetos, e o alcance da análise do domínio do problema. Parte desses problemas podem ser solucionados evitando-se excesso no detalhamento do comportamento através de regras mais objetivas capazes de orientar efetivamente o modelador na escolha dos níveis de abstração a considerar, e dando-se maior atenção ao detalhamento dos fluxos de informações trocados entre o sistema e seus atores. O artigo apresenta uma proposta para a modelagem de requisitos funcionais de sistemas de informação, que se baseia nestas premissas para produzir modelos concisos e abstratos, mais de acordo com o que se espera de uma primeira especificação de requisitos de um sistema.", "url": "artigos/artigos_WER05/wer200507.html"}, {"title": "Comparing Requirements Engineering Approaches for Handling Crosscutting Concerns", "authors": ["Ruzanna Chitchyan", "Awais Rashid", "Peter Sawyer"], "year": 2005, "keywords": "", "abstract": "A number of requirements engineering (RE) approaches have focused on addressing broadly scoped (non-functional) properties such as security, availability, etc. More recently, several aspect-oriented requirements engineering (AORE) approaches have been proposed to tackle both functional and non-functional requirements of a crosscutting nature. In this paper, we analyse how some well-known RE approaches address crosscutting concerns. We compare these approaches with AORE approaches in order to identify the additional contributions the latter have to offer while at the same time investigating what AORE can learn from traditional RE techniques. We use our comparison to derive a set of challenges to be addressed by AORE techniques. This paper is our position statement, rather then an attempt to precisely evaluate the discussed approaches, for which several large case studies are necessary.", "url": "artigos/artigos_WER05/wer200508.html"}, {"title": "Uma Linguagem de Modelagem de Requisitos Orientada a Aspectos", "authors": ["Lyrene Fernandes da Silva", "Julio Cesar Sampaio do Prado Leite"], "year": 2005, "keywords": "Requirement modeling; crosscutting concerns; early aspects; goal models", "abstract": "Durante a modelagem de requisitos percebemos que muitos dos requisitos estão fortemente relacionados, entrelaçados ou sobrepostos, influenciando ou restringindo uns aos outros. Todos estes relacionamentos tornam a rastreabilidade entre requisitos fator crucial para modelagem e para evolução de software. Neste trabalho, para abordar os problemas de entrelaçamento e espalhamento de requisitos, apresentamos uma linguagem de modelagem que utiliza conceitos da programação orientada a aspectos, de maneira a registrar o impacto que os requisitos exercem uns sobre os outros. Esta linguagem é parte de um método para separação e composição de características transversais, que visa facilitar a modelagem, entendimento, reuso e evolução de requisitos.", "url": "artigos/artigos_WER05/wer200509.html"}, {"title": "Multi-Perspective Requirements Engineering for Networked Business Systems: A Framework for Pattern Composition", "authors": ["Zlatko Zlatev", "Maya Daneva", "Roel Wieringa"], "year": 2005, "keywords": "", "abstract": "How business and software analysts explore, document, and negotiate requirements for enterprise systems is critical to the benefits their organizations will eventually derive. In this paper, we present a framework for analysis and redesign of networked business systems. It is based on libraries of patterns which are derived from existing Internet businesses. The framework includes three perspectives: Economic value, Business processes, and Application communication, each of which applies a goal-oriented method to compose patterns. By means of consistency relationships between perspectives, we demonstrate the usefulness of the patterns as a light-weight approach to exploration of business ideas.", "url": "artigos/artigos_WER05/wer200510.html"}, {"title": "Aplicación de un Enfoque Intencional al Análisis de Variabilidad", "authors": ["Bruno González-Baixauli", "Miguel A. Laguna", "Julio Cesar Sampaio do Prado Leite"], "year": 2005, "keywords": "", "abstract": "El interés por el estudio de la variabilidad, es decir la habilidad de cambio o adaptación de un sistema, ha aumentado significativamente durante los últimos años. Esto se debe a su utilidad en diversos campos, desde la personalización del software a las líneas de producto o la adaptación automática de sistemas. Dicho estudio ha estado centrado principalmente en cuestiones de diseño, y solo recientemente se ha empezado a abordar desde los requisitos del sistema. Las primeras propuestas, basadas en features, están claramente enfocadas a facilitar la obtención de la arquitectura del sistema. Debido a la necesidad de contemplar la elicitación de los requisitos del usuario han aparecido nuevas técnicas basadas en casos de uso, que facilitan la elicitación, pero fallan en la representación global de la variabilidad, dificultando la obtención de la arquitectura. También existen enfoques que unen ambas técnicas, compaginándose entre si. El problema común de estas técnicas es que ignoran el tratamiento de los Requisitos No Funcionales (RNF). Si bien los RNF son fundamentales para todo tipo de sistemas, en el caso de la variabilidad lo son aún más, puesto que explican la existencia de distintas variantes para una misma funcionalidad. En este artículo se presenta un ejemplo de aplicación de técnicas de la ingeniería de requisitos orientada a objetivos en el campo de la variabilidad, aplicada a la obtención de los requisitos y a la selección óptima de variantes, teniendo en cuenta los objetivos del usuario tanto funcionales como no funcionales.", "url": "artigos/artigos_WER05/wer200511.html"}, {"title": "Towards a Cognitive-Based Approach to Distributed Requirement Elicitation Processes", "authors": ["Gabriela N. Aranda", "Aurora Vizcaíno", "Alejandra Cechich", "Mario Piattini"], "year": 2005, "keywords": "", "abstract": "This paper describes a method for requirements elicitation based on goals for electronic commerce systems in agreement with security and privacy polices of the site. The method integrates the UWA approach [18] with the GBRAM method [3] for developing requirements policies for secure electronic commerce systems. The resulting method has the objective to guarantee that existing security and privacy policies do not become obsolete with the adoption of new functionalities to a site. For this purpose, the method provides means so that requirements elicitation is in conformity with other ones. In case organizations have not established its policies, the proposed approach suggests models through which it is possible the creation of such policies. The method still presents a model for requirements specification document in agreement with the approach described in this work. It seeks to establish a standard to specify software requirements to be useful for the development teams, in an attempt to facilitate the construction of systems, analyses, and for future maintenances or increment of functionalities to the site.", "url": "artigos/artigos_WER05/wer200512.html"}, {"title": "Uma Abordagem Baseada em Gestão do Conhecimento para Gerência de Requisitos em Desenvolvimento Distribuído de Software", "authors": ["Rodrigo Espindola", "Leandro Lopes", "Rafael Prikladnicki", "Jorge Luiz Nicolas Audy"], "year": 2005, "keywords": "Engenharia de Requisitos; Manutenção de Software; Gestão de Conhecimento", "abstract": "A distribuição das equipes de desenvolvimento tem provocado diversos desafios ao processo de software. Dentre os desafios, a engenharia de requisitos destaca-se, sofrendo impacto de fatores como distância, diferença de cultura e fuso-horário, bem como dos meios de comunicação disponíveis. Nesse contexto, o gerenciamento das informações relacionadas a requisitos torna-se crítico para garantir que as informações necessárias sobre um determinado domínio ou aplicação estão disponíveis para as equipes de desenvolvimento, bem como que estas informações sejam organizadas de forma a permitir futuro acesso por projetos de manutenção no mesmo escopo. Nesse sentido, este artigo propõe-se a analisar a engenharia de requisitos em projetos de desenvolvimento distribuído de software sob a ótica da gestão de conhecimento. A principal contribuição apresentada é a identificação das informações pertencentes às categorias de conhecimento envolvidas, bem como a forma com que devem ser disponibilizadas.", "url": "artigos/artigos_WER05/wer200513.html"}, {"title": "Reusable Knowledge for Achieving Privacy: A Canadian Health Information Technologies Perspective", "authors": ["Ilca Webster", "Vera Ivanova", "Luiz Marcio Cysneiros"], "year": 2005, "keywords": "", "abstract": "Privacy is a fundamental aspect when dealing with Personal Information. Privacy requirements are those that capture privacy goals and its associated measures for a system under development. In order to ensure privacy we must identify these elements. However, there are many challenges in their identification. For example, privacy requirements may be difficult to quantify and precisely specify. There is a need for systematic approaches for reasoning, modeling and analyzing privacy from the early stages of the software development. Furthermore, it is necessary to develop a usable ontology or classification of measurable aspects of privacy that can be used to aid in the specification of privacy requirements. These ontologies should be represented in a way that facilitates their use as guidelines for the requirements elicitation process. This work builds on a review of privacy legislation to develop a catalog of aspects of privacy that can be considered during requirements gathering. This catalogue is used to guide the requirements engineer through alternatives for achieving privacy. The approach uses the i* framework to model privacy as a special type of goal. We show how privacy can be modelled through different viewpoints with different alternatives for its operationalization. An example in the health care domain is used to illustrate our work.", "url": "artigos/artigos_WER05/wer200514.html"}, {"title": "É possível substituir processos de Engenharia de Requisitos por Contagem de Pontos de Função?", "authors": ["Claudia Hazan", "Daniel M. Berry", "Julio Cesar Sampaio do Prado Leite"], "year": 2005, "keywords": "Contagem de pontos de função; Engenharia de Requisitos; Análise de requisitos; Estimativa de tamanho de projetos de software", "abstract": "O principal problema que afeta os projetos de desenvolvimento de software é o de especificações de requisitos com baixa qualidade. As especificações de requisitos com baixa qualidade dificultam o desenvolvimento de software de alta qualidade. Propomos a utilização do método de Contagem Estimativa de Pontos de Função (CEPF), para estimar o tamanho de software, como um processo substituto de Engenharia de Requisitos (ER), especialmente para as organizações que não aplicam um processo de ER. Durante a contagem de Pontos de Função, o profissional que realiza contagem pode descobrir requisitos omissos, requisitos incompletos e inconsistências na especificação de requisitos. Assim, estas organizações podem aplicar a CEPF como um processo substituto de ER. Este artigo apresenta uma aplicação do método a uma parte do processo de construção de requisitos, mais especificamente à verificação de requisitos.", "url": "artigos/artigos_WER05/wer200515.html"}, {"title": "Uma análise do método ágil Scrum conforme abordagem nas áreas de processo Gerenciamento e Desenvolvimento de Requisitos do CMMI", "authors": ["Alexandre Lazaretti Zanatta", "Patrícia Vilain"], "year": 2005, "keywords": "", "abstract": "In this article we analize the agile method Scrum in relation to the process areas Requirements Management and Requirements Development of the CMMI model. The results obtained from this analysis indicate that Scrum does not meet all the required practices present in such process areas. We point out what is missing in Scrum to fully comply with these areas and propose solutions for it.", "url": "artigos/artigos_WER05/wer200516.html"}, {"title": "A Process for Requirement Traceability in Agent Oriented Development", "authors": ["Rosa Candida Pinto", "Carla Silva", "Jaelson Castro"], "year": 2005, "keywords": "", "abstract": "Requirement traceability is intended to ensure continued alignment between stakeholders requirements and various outputs of the system development process. Therefore a process for requirement traceability is a significant factor on efficient software project management. Failure to do so will imply in higher costs for maintaining software systems. Methodologies supporting requirement traceability can develop higher quality software with fewer costs. This paper presents an innovative research that aims to support traceability through requirements specifications, system architecture models, static and dynamic software design models and implementation artifacts of agent-oriented software systems. In this work we outline a process that can be used to extend Tropos to support traceability. An e-commerce example is used to demonstrate the applicability of the proposed approach.", "url": "artigos/artigos_WER05/wer200517.html"}, {"title": "Avaliação de uma Metodologia de Medição da Qualidade em um Documento de Requisitos Orientado a Aspectos", "authors": ["Ricardo Argenton Ramos", "Jaelson F. B. Castro"], "year": 2005, "keywords": "", "abstract": "A área de desenvolvimento orientado a aspectos esta cada vez mais ampla, abrangendo todas as fases no processo de desenvolvimento de software. Pesquisas promissoras estão sendo feitas na fase de requisitos cujo o propósito é separar no documento de requisitos os aspectos (requisitos não funcionais) que estão espalhados e entrelaçados aos requisitos funcionais. Contudo, não se tem conhecimento de proposta para avaliar a qualidade da definição dos aspectos que são elicitados na fase de requisitos. Este artigo apresenta uma avaliação realizada através de um estudo de caso, da aplicação de uma metodologia de medição da qualidade de documentos de requisitos em um documento de requisitos orientado a aspectos.", "url": "artigos/artigos_WER05/wer200518.html"}, {"title": "Avaliando a Qualidade da Técnica GUCCRA com Técnica de Inspeção", "authors": ["Anderson Belgamo", "Sandra Fabbri e José Carlos Maldonado"], "year": 2005, "keywords": "", "abstract": "This paper presents an evaluation of GUCCRA technique realized with an inspection technique whose objective is to identify defects in Use Case Models. GUCCRA is a reading technique that helps the construction of these models and two studies were already carried out to evaluate it. In these studies GUCCRA was compared with Ad-Hoc and the results shown that the models generated by GUCCRA were more standardized than the others and that the technique helped during the construction. The results of the current evaluation confirm the previous data and few defects were identified in the models generated by GUCCRA.", "url": "artigos/artigos_WER05/wer200519.html"}, {"title": "Un Marco para la Definición de Métricas sobre Modelos de Dependencias entre Actores", "authors": ["Xavier Franch", "Gemma Grau", "Carme Quer"], "year": 2005, "keywords": "", "abstract": "Los modelos de dependencias entre actores son un formalismo que describe los procesos como una red de relaciones de dependencias entre actores. En la actualidad, este tipo de modelos se usa, entre otros, en las fases preliminares del análisis de requisitos, en el análisis organizacional y en la reingeniería de procesos. En este artículo, proponemos un marco para la definición de métricas sobre este tipo de modelos, con el objetivo de facilitar el análisis de ciertas propiedades de los procesos tales como la seguridad, la eficiencia o la precisión. Las métricas se definen en términos de los actores y las dependencias del modelo, distinguiendo tres tipos de métricas diferentes que se definen formalmente y se aplican sobre el caso de estudio de un sistema organizador de reuniones.", "url": "artigos/artigos_WER05/wer200520.html"}, {"title": "Elicitación de requisitos en sistemas de gestión orientados a procesos", "authors": ["Isabel Villanueva", "Juan Sánchez", "Óscar Pastor"], "year": 2005, "keywords": "", "abstract": "La etapa de elicitación de requisitos abarca la primera y quizás más importante fase dentro del desarrollo de un sistema informático. Uno de los retos más importantes de la elicitación de requisitos es garantizar que los requisitos del sistema sean consistentes con las necesidades de la organización donde se utilizará el mismo y con las futuras necesidades de los usuarios. Por otra parte los modelos actuales de gestión (EFQM, ISO 2000) de las organizaciones incluyen como condición que la gestión esté basada en procesos frente a la gestión basada en la definición y evaluación de los puestos de trabajo, enmarcados en un organigrama jerárquico. En el artículo se propone utilizar modelos de gestión basada en procesos como guía para elicitar requisitos del futuro sistema. La aproximación permite relacionar aspectos de alto nivel de la organización (metas estratégicas) con requisitos del sistema.", "url": "artigos/artigos_WER05/wer200521.html"}, {"title": "Elicitación de Objetivos a partir de Escenarios", "authors": ["Pablo Thomas", "Alejandro Oliveros"], "year": 2005, "keywords": "", "abstract": "La Ingeniería de Requerimientos se ocupa de los aspectos de la Ingeniería de Software, relacionados con la comprensión y producción de descripciones de problemas para resolverlos a través de la construcción de Sistemas de Software. Los fundamentos del sistema (el por qué) están abarcados por los objetivos de la organización, y se definen usualmente como las metas a ser cumplidas por el sistema y su entorno. Como todo producto de la fase de requerimientos, los objetivos del sistema deben recorrer un proceso de elicitación, modelización y validación. Sin embargo, los enfoques orientados por objetivos, si bien poseen, aunque en diferente medida, procesos mediante los que modelizan y validan los objetivos, no sucede lo mismo en cuanto a las indicaciones para la elicitación de los objetivos.Este trabajo presenta la utilización de Escenarios como fuente para la elicitación de Objetivos, para lo que se propone una estrategia de identificación de Objetivos del modelo GBRAM de Antón a partir del esquema de Escenarios de Leite.", "url": "artigos/artigos_WER05/wer200522.html"}, {"title": "Requirement Elicitation Based on Goals with Security and Privacy Policies in Electronic Commerce", "authors": ["Simara Rocha", "Zair Abdelouahab", "Eduardo Freire"], "year": 2005, "keywords": "", "abstract": "This paper describes a method for requirements elicitation based on goals for electronic commerce systems in agreement with security and privacy polices of the site. The method integrates the UWA approach [18] with the GBRAM method [3] for developing requirements policies for secure electronic commerce systems. The resulting method has the objective to guarantee that existing security and privacy policies do not become obsolete with the adoption of new functionalities to a site. For this purpose, the method provides means so that requirements elicitation is in conformity with other ones. In case organizations have not established its policies, the proposed approach suggests models through which it is possible the creation of such policies. The method still presents a model for requirements specification document in agreement with the approach described in this work. It seeks to establish a standard to specify software requirements to be useful for the development teams, in an attempt to facilitate the construction of systems, analyses, and for future maintenances or increment of functionalities to the site.", "url": "artigos/artigos_WER05/wer200523.html"}, {"title": "Introdução", "authors": ["Fernanda Alencar", "Juan Sánchez", "Vera Werneck"], "year": 2006, "keywords": "introduction; índice; index", "abstract": "Primeiras páginas, incluíndo a palestra convidada: Social Modeling in Requirements Engineering de Eric Yu", "url": "artigos/artigos_WER06/wer200600.html"}, {"title": "SFP: Un Procedimiento de Estimación de Puntos Función de Escenarios", "authors": ["Mabel Bertolami", "Alejandro Oliveros"], "year": 2006, "keywords": "puntos función; escenarios; estimación", "abstract": "La medición del tamaño del software es una actividad esencial para estimar y planificar un proyecto de desarrollo. En las etapas tempranas del ciclo de vida, cuando los requerimientos funcionales no están completamente documentados o se requiere una estimación rápida, las técnicas de estimación de tamaño funcional representan una solución al problema. SFP permite estimar el tamaño funcional de los escenarios generados en la Elicitación de Requerimientos. Su diseño está basado en el FPA tradicional y en la estructura propuesta por el estándar ISO/IEC 14143-1 para los métodos de medición del tamaño funcional. En este artículo se describe el diseño del procedimiento de estimación y ejemplos de la aplicación a un caso de estudio. La estimación sobre un conjunto de casos produjo resultados compatibles con los obtenidos aplicando una propuesta previa de los autores. Por último, se presentan las conclusiones y la futura dirección de la investigación.", "url": "artigos/artigos_WER06/wer200601.html"}, {"title": "Aplicabilidade de metricas por pontos de função em sistemas baseados em web", "authors": ["Ariadne Carvalho", "Thelma Chiossi", "Marcos Drach"], "year": 2006, "keywords": "pontos de função; métricas; sistemas web", "abstract": "Este trabalho faz uma análise das características computacionais específicas da plataforma Web, com o intuito de avaliar o grau de adequação e aplicabilidade do método de Análise por Pontos de Função (FPA) a este tipo de ambiente, assim como sua contribuição para a estimativa de esforço. Para tal, são aplicadas duas outras métricas, específicas para Web, a um caso real e o resultado é comparado à aplicação do FPA ao mesmo problema.", "url": "artigos/artigos_WER06/wer200602.html"}, {"title": "Um Estudo sobre a Atividade de Elicitação de Requisitos em Projetos de Software da Área Espacial", "authors": ["Carlos Lahoz", "João Batista Camargo", "Jr."], "year": 2006, "keywords": "elicitação de requisitos; processo de software; sistemas aeroespaciais", "abstract": "Dentro do enfoque de que o software começa a atender cada vez mais um número crescente de funcionalidades de sistemas, é fundamental que a atividade de elicitação de requisitos assuma um papel decisivo no esforço de se alcançar um resultado satisfatório e seguro no projeto de um sistema. No que diz respeito a sistemas aeroespaciais críticos, onde a ambigüidade, a não completeza e a falta de requisitos podem provocar acidentes graves, envolvendo prejuízos econômicos, materiais e humanos, obriga a um tratamento mais cuidadoso sobre este assunto. Este artigo apresenta os resultados preliminares de um estudo sobre quais são os principais problemas que a atividade de elicitação de requisitos enfrenta atualmente em projetos espaciais no Brasil, segundo a visão dos autores. O foco principal do trabalho está na identificação dos requisitos de segurança em projetos de desenvolvimento de software.", "url": "artigos/artigos_WER06/wer200603.html"}, {"title": "Defining Strategic Dependency Situations in Requirements Elicitation", "authors": ["Antonio de Padua", "Luiz Marcio Cysneiros"], "year": 2006, "keywords": "i*; scenarios; mas", "abstract": "Recently, there has been a growing interest in the Agent-oriented paradigm to cope with the needs imposed by nowadays complex and networked systems. Developing Multi-Agent Systems (MAS) calls for addressing aspects such as interaction, autonomy, collaboration and pro-activeness. One way to cope with these needs is to have agency properties as well as intentionality in the center of the software development process. In this work a proposal is presented to bring intentionality and agency properties to the early stages of software development. The proposal is based on Strategic Dependency Situations (SDsituations) as a simple technique for helping requirements elicitation. Strategic Dependency Situations applies the Agent-Oriented approach based on intentionality to face the complexity of MAS developing.", "url": "artigos/artigos_WER06/wer200604.html"}, {"title": "Avaliação de Ferramentas para Controle Automatizado de Versões de Artefatos e Requisitos de Software", "authors": ["Susana Brunoro C. Oliveira", "Astério K. Tanaka", "Dalessandro S. Vianna"], "year": 2006, "keywords": "controle de versões; gerenciamento de requisitos; ferramentas; avaliação", "abstract": "The control of all the artifacts generated by a development team tends to be a great challenge in software development process. Such a need starts in the moment that the project begins, that is, in the preliminary requirements elicitation phase. From this moment on, any change not duly registered can reflect in failure at the end of the project. Having tools that allow the control of the artifacts generated during the development process is, thus, very important for the development teams. This presents an evaluation of the usage of tools for the development of requirements artifacts and for control of changes in the project, from the preliminary requirements elicitation phase.", "url": "artigos/artigos_WER06/wer200605.html"}, {"title": "Integrando Padrões de Usabilidade na Especificação de Requisitos para Apoiar o Re-Projeto Participativo de Interface", "authors": ["Felipe Távora Pereira", "Elizabeth Furtado"], "year": 2006, "keywords": "rup; re-projeto; usabilidade", "abstract": "Este artigo propõe uma metodologia para dar maior suporte ao re-projeto de interfaces dos sistemas de software, contendo atividades integradas à disciplina de Requisitos do Processo Unificado (RUP). Estas atividades são baseadas nos princípios de projeto participativo, através dos quais os usuários podem participar ativamente do processo de tomada de decisão sobre alterações de interface, tendo maior consciência dos impactos que essas alterações irão causar no sistema a partir da relação entre os requisitos especificados. A utilização de padrões de usabilidade facilitará a comunicação entre usuários e projetistas, por apresentar exemplos ilustrativos referentes a soluções de usabilidade para certos problemas, ainda, uma maior segurança ao usuário sobre o que ele espera das modificações.", "url": "artigos/artigos_WER06/wer200606.html"}, {"title": "Verifying the Construction of a Software Model from a Requirements Model", "authors": ["Nelly Condori-Fernández", "Oscar Pastor"], "year": 2006, "keywords": "software model; verification; measurement model; OO-Method", "abstract": "A software model is the outcome of abstracting a set of relevant elements that contribute to the functional size according to measurement model. The purpose of this paper is to verify the construction of the software model when applying the RmFFP measurement procedure with computer science students. The RmFFP procedure was designed according to the COSMIC-FFP standard method for estimating the functional size of object-oriented systems from requirements specifications obtained in the context of the OO-Method approach.", "url": "artigos/artigos_WER06/wer200607.html"}, {"title": "Estimación de Completitud en Modelos de Requisitos Basados en Lenguaje Natural", "authors": ["Marcela Ridao", "Jorge H Doorn"], "year": 2006, "keywords": "lel; completitud; lenguaje natural", "abstract": "La Ingeniería de Requisitos provee mecanismos para elicitar y especificar requisitos, procurando maximizar calidad y completitud. Sin embargo, obtener un modelo de requisitos completo es una meta inalcanzable, y meramente estimar el grado de completitud alcanzado es muy difícil. El mismo problema se presenta en diversas áreas del proceso de desarrollo de software, como las verificaciones de documentos de diseño y la prueba de programas, entre otras. La introducción de técnicas de predicción basadas en modelos estadísticos en el campo de la Ingeniería de Software lleva ya varios años, con muy buenos resultados. En el presente artículo se estudia experimentalmente el uso de los datos de captura y recaptura en el proceso de la Ingeniería de Requisitos, en particular en la construcción de Escenarios a partir del Léxico Extendido del Lenguaje. Se analiza también el impacto que la completitud del LEL tiene sobre la completitud del modelo de escenarios correspondiente.", "url": "artigos/artigos_WER06/wer200608.html"}, {"title": "Experimenting a Requirements Engineering Process Based on Rational Unified Process (RUP) Reaching Capability Maturity Model Integration (CMMI) Maturity Level 3 and Considering the Use of Agile Methods Practices", "authors": ["Caroline Carbonell Cintra", "Roberto Tom Price"], "year": 2006, "keywords": "rup; cmmi; requirements management", "abstract": "This work has the purpose of describing a software development process with the following characteristics: its scope lies within the requirements engineering activities; it fulfills CMMI requisites for Requirements Management and Requirements Development process areas (maturity level 2 and 3, respectively); it is based on RUP practices and activities where possible practices of agile methods are employed. Related work is considered and similarities as well as differences to the process proposed here are pointed out. Such process is presented in terms of each of its activity flows, including mention to the artifacts and roles involved on the activities. CMMI fulfillment is also described, followed by the description of the main contributions achieved by this work and comments on future development.", "url": "artigos/artigos_WER06/wer200609.html"}, {"title": "Using a Problem Domain Language to Specify Navigational Concerns in Web Applications", "authors": ["Leandro Antonelli", "Silvia Gordillo", "Gustavo Rossi", "João Araujo", "Ana Moreira"], "year": 2006, "keywords": "lel; domain language; navigational concerns", "abstract": "By nature, web applications involve a myriad of different concerns, which many times crosscut each other. The result is that these crosscutting concerns are scattered throughout different software artifacts provoking information tangling in those concerns. This paper presents an approach for using the problem domain language captured by LEL (Language Extended Lexicon) to improve the modeling of those concerns which affect navigation, i.e. the navigational concerns. It shows how to build partial navigation scenarios with user interaction diagrams, to analyze how they crosscut and, from there, how to obtain information for improving design models. Finally, it discusses how the interleaving of requirements elicitation with language specification allows improving the description of scenarios and the discovering of crosscutting relationships.", "url": "artigos/artigos_WER06/wer200610.html"}, {"title": "Analyzing Basic Problem Frames in i* Context", "authors": ["Maria Lencastre", "Keldjan Alves", "Renata Melo", "Fernanda Alencar"], "year": 2006, "keywords": "i*; problem frames", "abstract": "Problem Frames and i* are two broadly used approaches that require a good background from the requirements engineering. Both approaches have typical traits that fit in equivalent. On the other hand, there are features that do not fit. Thereby, there are some points which need improvements on both of them. This work analyzes the five basic problem frames, defined by Michael Jackson, in the i* context. Our aim is to identify how can they be represented in i* and what gains are achieved if problem frames concept can be applied in i* modeling (like for example simplicity, completeness and flexibility of the built models).", "url": "artigos/artigos_WER06/wer200611.html"}, {"title": "The SRAMO Technique for Analysis and Reuse of Requirements in Multi-agent Application Engineering", "authors": ["Alisson Neres Lindoso", "Rosario Girardi"], "year": 2006, "keywords": "reuse; ontology; mas", "abstract": "The increasing interest on the multi-agent software development paradigm turns necessary the elaboration of appropriate techniques and methodologies. A Multiagent Application Engineering process is characterized by the construction of applications based on agent-oriented reusable software artifacts. This paper presents SRAMO, an ontology-driven technique for requirement analysis of multi-agent applications by reusing domain models representing common and variable requirements of a family of multi-agent applications in a domain. The requirements of a particular application are represented in models obtained through the instantiation of the ONTORMAS ontology that expresses the knowledge of the MAAEM methodology for Multi-agent Application Engineering, MAAEM integrates SRAMO and techniques for design and implementation of a specific application in a domain family. Part of a case study employing SRAMO for modeling RecomTour, a multi-agent application for recommendation of touristic packages through Web usage mining and collaborative filtering is also described.", "url": "artigos/artigos_WER06/wer200612.html"}, {"title": "Uma Abordagem para a Transformação Automática do Modelo de Negócio em Modelo de Requisitos", "authors": ["Felipe Dias", "Gisele Morgado", "Pedro Oscar", "Denis Silveira", "Antonio Juarez", "Priscila Lima", "Eber Schmitz"], "year": 2006, "keywords": "modelo de negócio; casos de uso; transformação", "abstract": "Este artigo apresenta uma abordagem que visa facilitar a especificação de requisitos, melhorando e acelerando o desenvolvimento de sistemas de informação. Tal abordagem apresenta uma técnica para o mapeamento de processos em casos de uso e para o mapeamento de termos em classes de domínio. Esta técnica é acompanhada de uma ferramenta que implementa este mapeamento. Assim, é possível a transformação do Modelo de Negócio em Modelo de Requisitos de forma automática, diminuindo o tempo gasto na especificação do sistema de informação e diminuindo também os erros cometidos na fase especificação de requisitos.", "url": "artigos/artigos_WER06/wer200613.html"}, {"title": "A Study in Market-Driven Requirements Engineering", "authors": ["Carina Alves", "Silvia Pereira", "Jaelson Castro"], "year": 2006, "keywords": "market-driven requirements; cots", "abstract": "Packaged software is recognised as an important segment of software market. Market-driven software development consists of developing packaged software to a market rather than to a specific client. It has been argued that the requirements engineering process for market-driven software differs from customer specific software. This paper presents a study on market-driven requirements engineering. We present ten hypotheses we have collected from the literature in this field. We discuss the implications of these hypotheses and identify areas to conduct further research.", "url": "artigos/artigos_WER06/wer200614.html"}, {"title": "Técnicas de Inspeção de Documentos de Requisitos de Software: um Estudo Comparativo", "authors": ["Lilian A. Bertini", "Tereza G. Kirner", "Maria I. Montebelo", "Idemauro A. R. Lara"], "year": 2006, "keywords": "SRS; inspeção", "abstract": "This paper presents an empirical study on inspection of Software Requirements Specification (SRS) Documents, aiming at evaluate the efficiency of reading techniques applied to these documents. The techniques of Checklist, Scenario, and Perspective were comparatively evaluated, through the inspection of the SRS of a software application, performed by software engineers. The definition and execution of the empirical study were presented and the results were discussed.", "url": "artigos/artigos_WER06/wer200615.html"}, {"title": "SIGERAR: Uma Ferramenta para Gerenciamento de Requisitos", "authors": ["José Inácio De Grande", "Luiz Eduardo G. Martins"], "year": 2006, "keywords": "gerenciamento de requisitos; ferramenta; rastreabilidade", "abstract": "Atualmente, a utilização da Engenharia de Requisitos é um dos caminhos mais seguros para se obter qualidade no desenvolvimento e manutenção de sistemas de software, pois esta prática diminui sensivelmente os erros, falhas e ambigüidades do produto final a ser entregue. Com o passar do tempo, mudanças ocorrem nos requisitos devido a diversos fatores como erros, inconsistências, problemas organizacionais, evolução do conhecimento dos stakeholders1, alterações legais, etc., exigindo um grande esforço das empresas para o controle e gerenciamento dos mesmos. A proposta deste trabalho é apresentar uma ferramenta automatizada para gerenciamento de requisitos, chamada SIGERAR. A ferramenta coleta, armazena e mantêm os requisitos, gerenciando as mudanças e promovendo rastreabilidade entre os requisitos e entre os documentos de requisitos. A contribuição deste trabalho é oferecer aos desenvolvedores de Software uma ferramenta de gerenciamento de requisitos, de uso livre e fácil instalação, configuração e operação, aderente a todo o ciclo de vida do software, proporcionando controle e análise de riscos, impactos e custos de mudanças nos requisitos.", "url": "artigos/artigos_WER06/wer200616.html"}, {"title": "Integrando Groupware e Gerenciamento de Requisitos no Suporte à Engenharia de Requisitos Distribuída", "authors": ["Regina Andrade Brito", "Alexandre Marcos Lins de Vasconcelos"], "year": 2006, "keywords": "groupware; gerenciamento de requisitos; desenvolvimento distribuído de software", "abstract": "Esse artigo propõe a integração de groupware e gerenciamento de requisitos para permitir o registro e manutenção de rationale sobre requisitos e dessa forma, aumentar a compreensão destes em Desenvolvimento Distribuído de Software (DDS), além de ampliar a coordenação e comunicação entre os participantes. Para isso, uma análise de ferramentas de gerenciamento de requisitos existentes foi realizada para verificar a viabilidade da proposta e um protótipo foi desenvolvido e integrado a um groupware open source existente. Um estudo de caso é apresentado para validar a proposta.", "url": "artigos/artigos_WER06/wer200617.html"}, {"title": "Un Catálogo de Factores de Calidad para la Definición de Requisitos No-Técnicos en la Selección de Componentes COTS", "authors": ["Juan Pablo Carvallo", "Xavier Franch", "Carme Quer"], "year": 2006, "keywords": "cots; análisis de calidad; ISO/IEC 9126-1", "abstract": "La selección de componentes COTS (Commercial Off-The-Shelf) se realiza no sólo mediante el análisis de su calidad técnica sino también (y algunas veces principalmente) considerando cómo dichos componentes cumplen con los requisitos no-técnicos considerados relevantes. En este artículo proponemos un catálogo de factores no-técnicos que tiene como objetivo ayudar en la definición de este tipo de requisitos. El catálogo se presenta como una estructura jerárquica de características, subcaracterísticas y atributos análoga a la establecida en el estándar ISO/IEC 9126-1. También mostramos la utilización del catálogo en la especificación de requisitos, justificamos el contenido del catálogo y lo comparamos con otras propuestas existentes en la bibliografía.", "url": "artigos/artigos_WER06/wer200618.html"}, {"title": "Introduction", "authors": ["Carina Alves Frota", "Vera Werneck", "Luiz Marcio Cysneiros"], "year": 2007, "keywords": "introdução", "abstract": "We welcome you to the 10th Workshop on Requirements Engineering. This year, WER takes place in Toronto, Canada. This is the first time of the WER workshop series to be held in North America. The workshop started ten years ago as a meeting of the Ibero American requirements engineering community, but over the years has attracted attention of researchers from other parts of the world as well.", "url": "artigos/artigos_WER07/wer200700_1.html"}, {"title": "Keynote Talk: Requirements Engineering Lessons from House Building", "authors": ["Daniel M. Berry"], "year": 2007, "keywords": "requirements lessons", "abstract": "Anyone who has built or remodeled a house and has developed or enhanced SW must have noticed the similarity of these activities. This talk describes some lessons about requirements engineering I learned while being a customer in a house building and two house remodeling. The biggest problem is to avoid very expensive requirements creep. The main lesson is the importance of the customer insisting on following a full requirements engineering process, including goal identification, requirements elicitation, analysis, and specification, and validation of the specification. A secondary lesson is that a customer has an important role in requirements engineering and he or she sometimes needs to learn that role.", "url": "artigos/artigos_WER07/wer200700_2.html"}, {"title": "Understanding the Strategic Actor Diagram: an Exercise of Meta Modeling", "authors": ["Julio Cesar Sampaio do Prado Leite", "Vera Maria B. Werneck", "Antonio de Padua Albuquerque Oliveira", "Claudia Cappelli", "Ana Luiza A. Cerqueira", "Herbet de Souza Cunha", "Bruno Gonzalez-Baixauli"], "year": 2007, "keywords": "Actor diagram; meta-modeling", "abstract": "i-star (i*) modeling uses the actor concept to ground the intentions of a given Universe of Discourse. Our work contributes to the understanding of the actor concept as used in i*. We have used a collaborative approach to better understand the actor concept. The authors met 9 times to discuss the topic. The goal was to discuss i* meta-models, which was later specialized to discuss actor modeling. After the meetings and after one week of collaborative work using a collaboration based editor, Writely, we have agreed on presenting our model from two different perspectives, but both using UML as the meta language. We understand that these models, designed by consensus, represent what we have labeled the SA Diagram or the Strategic Actor Diagram. The article presents the models we have arrived as well as the process we have used. We believe that making this process transparent will help to shed light not only on the concept of actor, but on the process of meta-modeling as well.", "url": "artigos/artigos_WER07/wer200701.html"}, {"title": "Evaluating the Effectiveness of Using Catalogues to Elicit Non-Functional Requirements", "authors": ["Luiz Marcio Cysneiros"], "year": 2007, "keywords": "Non-Functional Requirements", "abstract": "Non-Functional Requirements (NFR) are subjective, interactive and relative, thus realizing the need for particular NFR is by itself a challenge. Furthermore understanding what the software must implement in order to cope with these needs may prove to be an even more challenging task. One way of addressing the need for help on NFR elicitation is the use of catalogues. However, it is not clear how effective it is to use them. This work investigates it through an empirical study where different teams will model the same problem. Two teams will use catalogues with a systematic method, another two teams will use catalogs in an ad hoc manner and yet another two teams will not use catalogues. We show at the end of this work that teams using catalogues performed significantly better.", "url": "artigos/artigos_WER07/wer200702.html"}, {"title": "Test-case Driven versus Checklist-based Inspections of Software Requirements–An Experimental Evaluation", "authors": ["Nina D. Fogelström", "Tony Gorschek"], "year": 2007, "keywords": "Inspections; Tests; Requirements", "abstract": "Software inspections have proved to be an effective means to find faults in different software artifacts, and the application of software inspections on requirements specifications is believed to give a high return on investment as problems are caught early. However, despite the existing evidence of positive effects requirements inspections are not a common practice in industry. The reason is believed to be the cost associated with inspections as a technology. This paper presents an evaluation of test-case driven inspections (TCD) - an emerging inspection technique that aims to cut costs associated with traditional requirements inspections. To formally test the efficiency and effectiveness of TCD inspections an experiment was conducted, in a controlled environment, where checklist based inspections was used as a point of reference. The experiment results indicate that TCD inspections perform better when it comes to effectiveness in finding major faults in a requirements specification.", "url": "artigos/artigos_WER07/wer200703.html"}, {"title": "Preliminary Results from an Empirical Study in Market-Driven Software Companies", "authors": ["Carina Alves", "Silvia Pereira", "George Valença", "João Pimentel", "Rodolfo V. C. L. de Andrade"], "year": 2007, "keywords": "empirical studies", "abstract": "In this paper we present initial findings from an empirical study that has been conducted with 13 marketdriven software companies based in Recife, Brazil. The objective of the study is to explore the state of the practice in requirements engineering (RE) for commercial off-theshelf software products. The study followed a qualitative research method using questionnaire and semi-structured interviews. The empirical study investigates key challenges faced by market-driven companies previously identified in a literature survey. Our goal was to gather empirical evidence from studied companies to evaluate specific facts concerning RE for software products identified in the literature.", "url": "artigos/artigos_WER07/wer200704.html"}, {"title": "Evaluating ADELFE Methodology in the Requirements Identification", "authors": ["V.M. B. Werneck", "A. Y. Kano", "L. M. Cysneiros"], "year": 2007, "keywords": "requirements evaluation", "abstract": "The increasing use of multi-agent systems brings challenges that have not been studied yet, such as how should we adapt requirements elicitation to cope with agent properties like autonomy, sociability and proactiveness. Many methodologies were proposed adopting this new paradigm. However, most of them are still in their early phases and therefore need to be adapted. In this work ADELFE, an agent-oriented methodology is evaluated. We use an exemplar proposed in 2001 by Yu and Cysneiros [1] to evaluate both agent/goal orientation and object orientation. This evaluation aims at analysing the strengths and weaknesses of ADELFE through the methodologies questions proposed in the exemplar.", "url": "artigos/artigos_WER07/wer200705.html"}, {"title": "Towards Variability Design as Decision Boundary Placement", "authors": ["Catalin Bidian", "Eric S.K. Yu"], "year": 2007, "keywords": "variability design", "abstract": "Complex information systems have numerous design variables that are systematically decided upon during the design process. In high-variability systems, some of these decisions are left open and deferred to later stages. For example, in product line architectures, some decision variables are used to generate families of products with variations in features. In user-adaptive systems, the behavior of the system is determined at runtime, based on user characteristics and preferences. In this paper, we propose to characterize variability in terms of boundaries in design decision graphs which depict the space of alternatives. A design decision about variability, such as what choices should be left to the user and which ones should be fixed at which stage in the design process, is then a question of where to place that decision boundary along some path in the relevant decision graph.", "url": "artigos/artigos_WER07/wer200706.html"}, {"title": "A Requirements Management Framework for Privacy Compliance", "authors": ["Sepideh Ghanavati", "Daniel Amyot", "Liam Peyton"], "year": 2007, "keywords": "requirements management", "abstract": "Compliance with privacy legislation is a primary concern for health care institutions that are building information systems support for their business processes. This paper describes a requirements management framework that enables health information custodians (HIC) to document and track compliance with privacy legislation. A metamodel is defined for our framework to define compliance tracking links between separate User Requirements Notation models of the HIC and privacy legislation. Using examples from a case study at a major teaching hospital, we show how this framework can be used to manage change and ensure compliance when privacy legislation is amended or the business processes evolved.", "url": "artigos/artigos_WER07/wer200707.html"}, {"title": "O Gerenciamento de Requisitos no Ambiente COCAR", "authors": ["André Di Thommazo", "Marcos Danilo Martins", "Sandra Fabbri"], "year": 2007, "keywords": "gerenciamento de requisitos", "abstract": "This research group has been working towards building an environment which helps software development, providing support to some activities mainly based on use case model. The reading technique TUCCA and a template to specify requirements were previously defined in another work of this group and are the basis of this environment. Aim. The aim of this paper is to give an overview of COCAR environment, emphasizing the requirement management activities supported by it. Method. Based on literature and several proposals of other authors, we introduced in the environment some functionalities that support requirement management and provide traceability between the requirements and the use case model. Results. The environment was used in a simple example of a real company and the results motivated the improvement of the environment and the continuity of this research. Conclusions. The information provided by the requirement functionalities give relevant support to maintain the requirement exchange controls, consistence and the development planning, supporting and facilitating some activities related to requirement management.", "url": "artigos/artigos_WER07/wer200708.html"}, {"title": "A Strategy for Information Source Identification", "authors": ["Julio Cesar Sampaio do Prado Leite", "Edson Andrade de Moraes", "Carlos Eduardo Portela Serra de Castro"], "year": 2007, "keywords": "information source; elicitation", "abstract": "Eliciting requirements is well known to be a difficult task. Several strategies exist that makes it possible to elicit information from different information sources. These strategies vary and should be selected in accordance with the situation at hand. For instance, selecting a strategy to a situation where there are available COTS solutions is different from a tailored and specialized software application. This article reports on a strategy to be used before the selection of an elicitation strategy. We are concerned in how to select the information sources that should be taken in consideration for the requirements elicitation. We consider this activity of fundamental importance to the elicitation process. Selecting the appropriate sources is fundamental as to deliver quality requirements. The article describes the proposed strategy and exemplifies it with a well known and published case, The London Ambulance Service.", "url": "artigos/artigos_WER07/wer200709.html"}, {"title": "Descomposición de árboles de metas a partir de modelos de procesos", "authors": ["Jose Luis De la Vara González", "David Anes Alcolea", "Juan Sánchez Díaz"], "year": 2007, "keywords": "modelos de procesos metas", "abstract": "Los Sistemas de Información (SI) utilizados dentro de una organización no son algo separado de la organización empresarial a la que le dan soporte, y por tanto la Ingeniería de Requisitos (IR) debe considerar las necesidades de negocio de una organización. Aunque se reconoce que la IR es el puente natural que conecta el mundo empresarial y el mundo de los SI, la mayor parte de la investigación en IR continúa estando orientada a la solución, evitando considerar los problemas reales del mundo empresarial. Las necesidades de negocio pueden ser descritas mediante el alineamiento de los SI con la estrategia del negocio, los procesos de negocio, las infraestructuras organizacionales y las metas organizacionales. Una de las consecuencias del alineamiento entre negocio y los SI es el mapeado de las metas organizacionales y los procesos a la especificación del sistema En este trabajo se presenta una aproximación que utiliza una especificación en la forma de modelo de metas, construida mediante heurísticas en base a modelos de procesos en la forma de BPMN. A partir del modelo de metas, mediante un proceso de refinamiento y de etiquetado, se obtiene un modelo de requisitos en la forma de casos de uso. La especificación así obtenida permite reflejar de manera más cercana las necesidades del negocio y asegura el alineamiento de las mismas con el futuro SI.", "url": "artigos/artigos_WER07/wer200710.html"}, {"title": "Guidelines for Business Modeling Elaboration based on Views from Domain Information", "authors": ["Silvia Angelica Zanco Ladeira", "Maria Istela Cagnin"], "year": 2007, "keywords": "business modeling", "abstract": "Business modeling is an activity of the Requirements Engineering that involves a knowledge process of the organization and provides a specific business domain view. On this process, models that can approach the context in which the system domain is inserted in different views (roles, business process and business rules) are built. In spite of the importance of these models, in general, they are not part of the software documentation due to the additional cost and time to build them. One solution for this is the business modeling reuse. In this context, this paper presents a set of guidelines for elaboration of business modeling based on views starting from the documentation of a certain domain, aiming to make available such modeling for reuse on the software development, maintenance and reengineering. A case study to evaluate the applicability of these guidelines was performed and it is also presented on this paper.", "url": "artigos/artigos_WER07/wer200711.html"}, {"title": "Evolving Use Case Maps as a Scenario and Workflow Description Language", "authors": ["Gunter Mussbacher"], "year": 2007, "keywords": "use case maps; scenario", "abstract": "Since 1996, the core Use Case Map (UCM) nota-tion has remained remarkably stable. As the structure and intent of workflow and scenario languages are very similar, UCMs have been applied to scenario, workflow, and business process modeling. The recent rise of workflow languages for the description of busi-ness processes and web services resulted in a more formal assessment method for such languages based on generic workflow and communication patterns. We present such an assessment for UCMs, thereby meas-uring the applicability of UCMs for workflow descrip-tion in particular and scenario descriptions in general and gathering evidence on how to evolve the UCM notation. The results are compared to similar assess-ments which were carried out for current standards for workflow, business process design, and business proc-ess execution languages such as the Business Process Modeling Notation (BPMN), the Business Process Execution Language for Web Services (BPEL4WS), and UML 2.0 Activity Diagrams.", "url": "artigos/artigos_WER07/wer200712.html"}, {"title": "Integración de un entorno de producción automática de software en un marco de alineamiento estratégico", "authors": ["José Luís De la Vara González", "Juan Sánchez Díaz", "Óscar Pastor López"], "year": 2007, "keywords": "producción automática de software", "abstract": "El alineamiento entre la estrategia de negocio y las tecnologías de información (TI) es reconocido como uno de los principales problemas a los que se enfrentan los responsables de una organización. Pese a que han sido presentadas numerosas propuestas para alcanzar este objetivo, sigue siendo frecuente que las inversiones que se realizan en TI no reporten todas las ventajas que se esperan de ellas porque no encajan con las necesidades reales de la organización. En este trabajo se presenta una aproximación para afrontar el alineamiento estratégico basada en la definición de un marco en el que se integre un entorno de producción automática de software. Para ello se usan el modelo de alineamiento estratégico SAM, el framework Zachman, el modelo de gestión empresarial Balanced Scorecard (BSC) y OO-Method, cuya unión tiene como fin la generación automática de infraestructuras TI a partir de infraestructuras organizacionales acordes a la estrategia de negocio, posibilitando así el alineamiento.", "url": "artigos/artigos_WER07/wer200713.html"}, {"title": "Business Process Monitoring and Alignment: An Approach Based on the User Requirements Notation and Business Intelligence Tools", "authors": ["Alireza Pourshahid", "Daniel Amyot", "Pengfei Chen Michael Weiss", "Alan J. Forster"], "year": 2007, "keywords": "business process monitoring; business intelligence", "abstract": "Monitoring business activities using Business Intel-ligence (BI) tools is a well-established concept. How-ever, online process monitoring is an emerging area which helps organizations not only plan for future im-provements but also change and alter their current ongoing processes before problems happen. In this paper, we explore how monitoring process perfor-mance can help evolve process goals and require-ments. We elaborate an approach that uses the User Requirements Notation (URN) to model the goals and processes of the organization, and to monitor and align processes against their goals. A BI tool exploit-ing an underlying data warehouse provides the Key Performance Indicators (KPI) used to measure the satisfaction of goals and process requirements. Feed-ing this information into the URN modeling tool, we can analyze the consequences of current business ac-tivities on desired business goals, which can be used for process and business activity alignment thereafter. We illustrate the approach with a case study from the healthcare sector: a hospital discharge process.", "url": "artigos/artigos_WER07/wer200714.html"}, {"title": "An Approach to Requirements Encapsulation with Clustering", "authors": ["Zude Li", "Quazi A. Rahman", "Nazim H. Madhavji"], "year": 2007, "keywords": "Requirements Encapsulation", "abstract": "Requirements encapsulation means organizing software requirements into a set of requirements clusters with tight cohesion along with external interfaces such that each cluster can be ultimately implemented by a functionality module. We propose an approach to encapsulating requirements which includes two steps: clustering requirements based on the similarity and associativity relations and then encapsulating each cluster by defining its external interface as stimulus-response pairs. The potential benefits of encapsulating requirements are reduced software development and maintenance costs.", "url": "artigos/artigos_WER07/wer200715.html"}, {"title": "Extended Disambiguation Rules for Requirements Specifications", "authors": ["Sri Fatimah Tjong", "Michael Hartley", "Daniel M. Berry"], "year": 2007, "keywords": "Disambiguation", "abstract": "This paper extends earlier work by the authors in identifying guiding rules for natural language (NL) requirements specifications (RSs) by analysing a few sets of requirements documents from different domains. It presents guiding rules that help reduce ambiguities and imprecision in NL RSs. It validates these rules by applying them to sentences in several industrial strength NL RSs.", "url": "artigos/artigos_WER07/wer200716.html"}, {"title": "i* with Aspects: Evaluating Understandability", "authors": ["Ricardo A. Ramos", "Fernanda Alencar", "João Araújo", "Ana Moreira", "Jaelson Castro", "Rosangela Penteado"], "year": 2007, "keywords": "i* aspects", "abstract": "The applicability of the i* approach for organizational modeling has been compromised by the complexity of the resulting models. To solve this problem an approach that use i* with Aspect Orientation is proposed. In this work we evaluate the understandability of five selected concerns of two requirements documents. The first requirements document was modeled by the i* approach and the other one by i* extended with aspects. To do this evaluation it was used abstract metrics that needed to be instantiated in both requirement documents.", "url": "artigos/artigos_WER07/wer200717.html"}, {"title": "Analyzing Problem Frames together with Solution Patterns", "authors": ["Ellen Souza", "Maria Lencastre", "Renata Melo", "Lilian Ramires", "Keldjan Alves"], "year": 2007, "keywords": "problem frames", "abstract": "The Problem Frames approach defines identifiable problem classes based on, among other things, their context and the characteristics of their domains, interfaces and requirements, without going deeply into the solution. Other software engineering approaches deal with the concept of patterns that present wellknown solutions, such as archetype, analysis and design patterns. We can say, for instance, that patterns are about solutions and problem frames are about problems. This paper attempts to make an analysis of the integration of problem classes, that is problem frames, and solutions, by analyzing a set of different kinds of patterns together within problem frames. The relationship, between these approaches, seems to have a good chance of improving software development.", "url": "artigos/artigos_WER07/wer200718.html"}, {"title": "Exploiting a Goal-Decomposition Technique to Prioritize Non-functional Requirements", "authors": ["M. Daneva", "M. Kassab", "M. L. Ponisio", "R. J. Wieringa", "O. Ormandjieva"], "year": 2007, "keywords": "Non-functional Requirements", "abstract": "Business stakeholders need to have clear and realistic goals if they want to meet commitments in application development. As a consequence, at early stages they prioritize requirements. However, requirements do change. The effect of change forces the stakeholders to balance alternatives and reprioritize requirements accordingly. In this paper we discuss the problem of priorities to non-functional requirements subjected to change. We, then, propose an approach to help smooth the impact of such changes. Our approach favors the translation of nonoperational specifications into operational definitions that can be evaluated once the system is developed. It uses the goal-question-metric method as the major support to decompose non-operational specifications into operational ones. We claim that the effort invested in operationalizing NFRs helps dealing with changing requirements during system development. Based on this transformation and in our experience, we provide guidelines to prioritize volatile non-functional requirements.", "url": "artigos/artigos_WER07/wer200719.html"}, {"title": "Requirements for Tools for Ambiguity Identification and Measurement in Natural Language Requirements Specifications", "authors": ["Nadzeya Kiyavitskaya", "Nicola Zeni", "Luisa Mich", "Daniel M. Berry"], "year": 2007, "keywords": "Natural Language Requirements Specifications", "abstract": "This paper proposes a two-step approach to identifying ambiguities in natural language (NL) requirements specifications (RSs). In the first step, a tool would apply a set of ambiguity measures to a RS in order to identify potentially ambiguous sentences in the RS. In the second step, another tool would show what specifically is potentially ambiguous about each potentially ambiguous sentence. The final decision of ambiguity remains with the human users of the tools. The paper describes two requirements-identification case studies with one small NL RS using a prototype of the first tool based on an existing NL processing system and a manual simulation of the second tool.", "url": "artigos/artigos_WER07/wer200720.html"}, {"title": "Role-Based Access Control Requirements Model with Purpose Extension", "authors": ["Faranak Farzad", "Eric Yu", "Patrick C. K. Hung"], "year": 2007, "keywords": "Role-Based Access Control", "abstract": "Role-Based Access Control (RBAC) is increasingly used for ensuring security and privacy in complex organizations such as healthcare institutions. In RBAC, access permissions are granted to an individual based on her defined roles. Much work has been done on the specification of RBAC models for enforcing access control; however, in order to arrive at appropriate choices of access control for particular roles and individuals in an organization, we need models at the requirements level to support elicitation and analysis. Crook et al. [3] have provided a requirements level model for RBAC, defining access to an information asset based on role, responsibility, operation, and context. We extend the Crook model to include a purpose hierarchy in order to meet the needs of privacy requirements. Access to health records is used as the example domain.", "url": "artigos/artigos_WER07/wer200721.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2008)", "authors": ["Juan Pablo Carvallo", "Lyrene Fernandes Silva"], "year": 2008, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER08/wer200800_1.html"}, {"title": "Organization", "authors": ["Juan Pablo Carvallo", "Lyrene Fernandes Silva"], "year": 2008, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER08/wer200800_2.html"}, {"title": "Table of Contents", "authors": ["Juan Pablo Carvallo", "Lyrene Fernandes Silva"], "year": 2008, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER08/wer200800_3.html"}, {"title": "Keynote Talk: Business-IT Alignment in Value Webs", "authors": ["Roel Wieringa"], "year": 2008, "keywords": "", "abstract": "Value webs are constellations of profit-and-loss responsible actors that have independent decision-making authority and that have decided to cooperate for a specific purpose. To the extent that the actors are independent, they each decide independently whether to participate in the network, and because they are profit-and loss responsible, this decision will be based on economic sustainability of the participation.", "url": "artigos/artigos_WER08/wer200800_4.html"}, {"title": "TRANSER: Ingeniería de Requisitos en un Desarrollo Orientado al Mercado.", "authors": ["Montse Ereño Incera", "Jokin Arizmendi", "Eusebi Calonge", "Joxeja Oiarbide"], "year": 2008, "keywords": "", "abstract": "La industrialización del software se configura, desde hace ya algún tiempo, como una de las nuevas vías de desarrollo en el sector de las Tecnologías de la Información. Sin embargo, el mercado todavía está dando sus primeros pasos. La brecha entre el mundo académico y el mundo industrial es considerable dentro de este contexto. Mientras la comunidad investigadora avanza en el estudio de este nuevo enfoque de desarrollo, y en la definición de técnicas y modelos que lo soportan, la aplicación industrial encuentra innumerables escollos en su aplicación. Una de las mayores dificultades se encuentra en las fases iniciales del desarrollo. Es comúnmente aceptado que el éxito de los productos software se mide en base al grado de cumplimiento de las expectativas de los usuarios; por lo tanto, resulta crucial capturar dichas expectativas lo más fielmente posible. Esto, no resulta nada sencillo cuando el producto no va dirigido a un cliente concreto, sino a todo un sector del mercado. Este artículo muestra las conclusiones obtenidas tras la aplicación de una serie de prácticas de Ingeniería de Requisitos Orientada a Perspectivas (IROP) en un caso real de desarrollo orientado al mercado.", "url": "artigos/artigos_WER08/wer200801.html"}, {"title": "Evaluación Empírica de la Estimación de Tamaño Funcional de Escenarios", "authors": ["Mabel Bertolami", "Alejandro Oliveros"], "year": 2008, "keywords": "", "abstract": "El uso creciente de las métricas de Puntos Función para la gestión de proyectos de software ha promovido el desarrollo de variantes del Análisis de Puntos Función para aproximar el tamaño funcional cuando la documentación, el tiempo o los recursos disponibles no permiten realizar el cálculo estándar. Scenario Function Points (SFP) es un procedimiento basado en el método IFPUG que permite estimar el tamaño funcional de los escenarios. En este artículo se presenta una validación empírica, sobre un sistema software ya implementado, y basada en la comparación entre el tamaño de los escenarios estimado por SFP y la medición del sistema con el método IFPUG. Esta última medición fue evaluada mediante el proceso de validación propuesto por Morris y Desharnais. Los resultados obtenidos son alentadores en cuanto a la capacidad de estimación de SFP y confirman la posibilidad y necesidad del plan de ampliar la experimentación sobre un mayor número de casos.", "url": "artigos/artigos_WER08/wer200802.html"}, {"title": "Uma Proposta para Avaliação de Equipes de Requisitos", "authors": ["Milene Serrano", "Fillipe Napolitano", "Maurício Serrano", "Eduardo Kinder", "Mark Douglas", "Danielle Loyola", "Bruno Rezende", "Julio Cesar Sampaio do Prado Leite"], "year": 2008, "keywords": "", "abstract": "Software Engineering has, as one of its main goals, the duty of helping software managers perform their jobs as better as possible. As such, technical management, which embodies software engineering expertise, is the central aspect in software management. Managing human resources is difficult for any production scheme, but is particular challenging for software, a knowledge intensive production process. This paper tackles the issue of evaluating requirements teams. An evaluation method is proposed to help managers better control their teams productivity. The proposed method stands on the shoulders of previous literature and on early feedback from its use in two laboratory projects conducted at PUC-Rio.", "url": "artigos/artigos_WER08/wer200803.html"}, {"title": "Aplicação de Técnicas de Leitura durante a Análise de Requisitos", "authors": ["Márcia Seabra Cabral", "Fernanda Alencar", "Jaelson Castro", "Oscar Pastor", "Juan Sánchez"], "year": 2008, "keywords": "", "abstract": "This paper describes the result work of the reading techniques application, Checklist and PBR, in the requirements analysis activity during the inspection process to help the inspectors to detect defects. The objective is to analyze the reading technique effectiveness. It presents the experiment result performed in the AMADeUs-MM requirements. será aceito ou não após a atividade de Validação de Requisitos.", "url": "artigos/artigos_WER08/wer200804.html"}, {"title": "Can Rules of Inferences Resolve Coordination Ambiguity in Natural Language Requirements Specification?", "authors": ["Sri Fatimah Tjong", "Daniel M. Berry"], "year": 2008, "keywords": "", "abstract": "Coordination ambiguity is the ambiguity that occurs from the use of coordinators such as and and or. The first authors previous work tried to resolve coordination ambiguity in natural language (NL) requirements specifications (RSs) by using language patterns derived from rules of logic (RLs). However, a reevaluation of the language patterns show that RLs cannot fully resolve coordination ambiguity in a RS because the coordinators are not always truth functional, due to incompatible interpretations that a human ascribes to the ambiguous RS. Furthermore, human perceptions in the interpretation of the coordinators in a RS vary incredibly widely. The implications of this observation on requirements elicitation are discussed.", "url": "artigos/artigos_WER08/wer200805.html"}, {"title": "Product Line Requirements: Multi-Paradigm Variability Models", "authors": ["Miguel A. Laguna", "Bruno González-Baixauli"], "year": 2008, "keywords": "", "abstract": "One of the most important issues in the development of software product lines is the elicitation, management, and representation of the variability. In this context, one of the most used instruments is the feature model. But a feature model (due to the open definition of feature) usually contains an amalgamation of various different variability aspects as structural, behavioral, non-functional, or platform variability. We propose to separate these variability aspects of the product line, using other models as goals or UML diagrams but keeping features as the core model. The second part of the article explores the possibilities of identifying mappings between the feature models and the correspondent architectural counterparts. With these mappings, the automated creation of traceability links between the product line models is possible and hence the productivity in the development process of the product line will be enhanced. This approach also simplifies the separation in several development stages, using the appropriate paradigms as goals, features, package models, platforms", "url": "artigos/artigos_WER08/wer200806.html"}, {"title": "Designing a Simulator for the Training of Software Engineers in Global Requirements Elicitation", "authors": ["Miguel Romero", "Aurora Vizcaíno", "Mario Piattini"], "year": 2008, "keywords": "", "abstract": "The requirements elicitation process is particularly difficult in Global Software Development (GSD) environments owing principally to cultural differences and communication problems derived from the geographical distance that separates stakeholders. For this reason it is necessary to train professionals in the skills needed to confront a requirements elicitation process in a GSD environment. In this paper we present the generic and specific competences derived from our review of literature that a software engineer must have if s/he is to carry out requirements elicitation. We have used these skills to design a tool to support the teaching of requirements elicitation in GSD. This tool is a simulator which, by using virtual agents, will enable students and professionals to acquire a subset of the skills necessary for requirements elicitation in GSD.", "url": "artigos/artigos_WER08/wer200807.html"}, {"title": "Study of Elicitation Techniques Adequacy", "authors": ["Dante Carrizo", "Oscar Dieste", "Natalia Juristo"], "year": 2008, "keywords": "", "abstract": "Requirements engineers can make use of a great many techniques to elicit user needs. However, there is no comprehensive practical guide on how to select the best techniques for a particular contextual situation within a software development project. We propose a framework to support developer decision making on which are the best elicitation techniques for the project at hand. Our framework identifies which elicitation technique responds better to certain project features.", "url": "artigos/artigos_WER08/wer200808.html"}, {"title": "Engenharia de requisitos em ambientes distribuídos de desenvolvimento de software: resultados preliminares de um estudo etnográfico", "authors": ["Alline de Melo Lemos", "Cleidson R. B. de Souza"], "year": 2008, "keywords": "", "abstract": "A indústria de software é uma das várias indústrias que tem sofrido alterações com o advento da globalização. A crescente demanda por software e a escassa mão-de-obra qualificada motivaram o surgimento do Desenvolvimento Distribuído de Software. Dentre os principais desafios a serem vencidos em projetos distribuídos de software, estão aqueles relacionados à Engenharia de Requisitos. O objetivo deste artigo é apresentar os resultados iniciais de um estudo empírico que está sendo realizado em uma organização de desenvolvimento de software que elicita, analisa e gerencia requisitos de clientes situados em locais diversos. Pretende-se com este artigo, sugerir recomendações para as dificuldades até então identificadas, na tentativa de melhorar o processo já adotado pela empresa em questão.", "url": "artigos/artigos_WER08/wer200809.html"}, {"title": "Updating a Systematic Review about Selection of Software Requirements Elicitation Techniques", "authors": ["Oscar Dieste", "Marta Lopez", "Felicidad Ramos"], "year": 2008, "keywords": "", "abstract": "Quality of software products is closely related to the elicitation requirement process. Several studies point out that elicitation techniques achieve different results when applied in different contexts. This paper presents some recommendations about the situations in which elicitation techniques are useful. Recommendations are based on a previous systematic review, which was updated and expanded with 13 new empirical studies and more than 60 new empirical results. The aggregation process generated 5 new evidences and modified 4 existing ones. In the previous review, it was found that interviews were one of the most adequate techniques in most situations. The new evidence supports the same conclusion.", "url": "artigos/artigos_WER08/wer200810.html"}, {"title": "A Methodology for Reducing Geographical Dispersion Problems during Global Requirements Elicitation", "authors": ["Gabriela N. Aranda", "Aurora Vizcaíno", "Alejandra Cechich", "Mario Piattini"], "year": 2008, "keywords": "", "abstract": "Global Software Development (GSD) challenges current practices for requirements elicitation because some difficulties to achieve effective communication are aggravated by cultural diversity and the impossibility of having face-to-face meetings. Considering that effective communication would help reduce misunderstandings among stakeholders, and therefore help achieve more committed requirements, we propose here a methodology for global requirements elicitation focused on minimizing the most frequent problems in GSD. We introduce the proposal as well as the results of a controlled experiment, which show preliminary but promissory tendencies.", "url": "artigos/artigos_WER08/wer200811.html"}, {"title": "Automated Assistance for Use Cases Elicitation from User Requirements Text", "authors": ["Shadi Moradi Seresht", "Olga Ormandjieva"], "year": 2008, "keywords": "", "abstract": "Software Requirements Engineering addresses specific challenges which exist in the effort to gain an understanding of the nature of the engineering problem arising from users real-world needs and desires. This research is aimed at helping software analysts meet these challenges. The proposed methodology forms the basis of the automated process designed to capture the high-level system services and actors from the textual user requirements. This model is intended to serve as a basis for software Use-Case Model development, and can be used by analysts in their in-depth study of requirements text. The approach is rooted in the syntactical analysis and formalization of text written in natural language, and it is enriched with domain-related information provided by the Expert Comparable Contextual (ECC) models that are extracted from reusable domain-specific data models. We illustrate the applicability of our methodology on an order invoicing case study and demonstrate it with a prototype tool. The results of the validation of our methodology prove that such a tool for assisting the elicitation of use-case models from textual requirements is feasible.", "url": "artigos/artigos_WER08/wer200812.html"}, {"title": "PARADIGMA: Uma Ferramenta de Apoio à Elicitação e Modelagem de Requisitos Baseada em Processamento de Linguagem Natural", "authors": ["Wilson Carlos da Silva", "Luiz Eduardo Galvão Martins"], "year": 2008, "keywords": "", "abstract": "The requirements engineers use several techniques to assist them on the elicitation, analysis, specification, validation and requirements management process, but the number of those tools in this segment is still reduced. The requirements are the base for the software development, which, most of time is described in natural language. In this paper a tool called PARADIGMA is presented, it was developed to assist the requirements engineers to identify in a easier way classes, attributes, operations and relationships from the described requirements in natural language, and using the Natural Language Processing (more specifically the morphosyntatics taggers), generating a conceptual classes model of UML (Unified Modeling Language). Besides the mentioned characteristics above, the tool uses the concept of linguistic standards that facilitate the creation of diagrams closer to those created by human. The experimentation of the tool was made by professionals and professors who act in the area of Requirements Engineering. On the basis of the results, we come to the conclusion of the relevance of the tool PARADIGMA in the context of the Requirements Engineering.", "url": "artigos/artigos_WER08/wer200813.html"}, {"title": "Método ERi*c - Engenharia de Requisitos Intencional", "authors": ["Antonio de Padua Albuquerque Oliveira", "Julio Cesar Sampaio do Prado Leite", "Luiz Marcio Cysneiros"], "year": 2008, "keywords": "", "abstract": "The aim of this paper is to present the Intentional Requirements Engineering Method - ERi*c, which is a contribution to Goal Oriented Requirements Engineering (GORE). ERi*c is based on the intentionality concept as applied by the i* Framework. Intentionality reflects organization actors motivations and interests and is represented in the models by goals and softgoals. The singularity of the proposal consists in how to do the intentionality elicitation and how to model it in a way of mitigating i* models complexity. The ERi*c Method has six steps, which cover elicitation, modeling and analysis. The ERi*c Method is shown through The Expert Committee System (EC System) exemplar, a system to support the organization of a conference program.", "url": "artigos/artigos_WER08/wer200814.html"}, {"title": "Um Processo Guiado para Levantamento e Modelagem de Requisitos de Aplicações Web Baseado em Objetivos e Casos de Uso", "authors": ["Dênis Zaniro", "Sandra Fabbri"], "year": 2008, "keywords": "", "abstract": "Web application development differs from the development of traditional software in several significant ways. Therefore, Requirements Engineering for Web (WebRE) needs to be fitted in a proper way to deal with some distinctive aspects that must be addressed in the development. Aiming to be a good communication channel between stakeholders and developers, WebRE methods should be lightweight, but to be useful to developers and to allow metric application, they should have expressive modeling constructions. Aim: Based on this context, this paper presents a part of the method Web-SEMP  Web System Elicitation, Modeling and Planning, proposed to help in these three activities of a Web application development process. Method: The most quoted WebRE methods in the literature were analyzed aiming to reuse and to extend them to compose the proposal here presented. Results: The method Web-SEMP was applied in the development of a real web application and the results showed that the method gives support for a more systematic WebRE process. Conclusion: The results provide insights that the method can help to improve the development process quality of Web Applications.", "url": "artigos/artigos_WER08/wer200815.html"}, {"title": "A Language-Based Approach to Variability Analysis", "authors": ["Bruno Santana da Silva", "Simone Diniz Junqueira Barbosa", "Julio Cesar Sampaio do Prado Leite"], "year": 2008, "keywords": "", "abstract": "Ways to deal with differences among users and hardware platforms have been investigated by several subareas in Computer Science. Despite these research efforts, even today we lack a systematic approach to deal with variations that reflect differences in user goals, needs, preferences, and strategies to achieve goals. In this paper, we explore the variability of the users domain language to promote the requirements engineers reflection on the need to deal with variations and what strategies are adequate to deal with them further in system design, as it will be reflected in the user interface language. In the proposed approach, we take into account concerns involved in different contexts of use to better understand the dynamic of user goals variability during system usage, before considering how to achieve the user goals on user interface language.", "url": "artigos/artigos_WER08/wer200816.html"}, {"title": "Uma abordagem semi-automática para a manutenção de links de rastreabilidade", "authors": ["Marcelio Leal", "Mayara Figueiredo", "Cleidson R. B. de Souza."], "year": 2008, "keywords": "", "abstract": "Atualmente, uma grande parte das falhas que acontecem em projetos de software está relacionada aos requisitos, tanto na sua elicitação quanto na sua evolução. Assim, a gerência de requisitos adquire um papel muito importante em um projeto, visto que através dela é possível ter maior controle sobre os requisitos. Nesse sentido, a importância da evolução, manutenção e da validade dos requisitos do projeto é um fator decisivo para este controle. É neste momento que a rastreabilidade se faz útil. Através dela é possível estabelecer ligações entre os requisitos e os diversos artefatos produzidos, acompanhando assim a evolução do projeto. A proposta deste trabalho é apresentar uma abordagem semi-automática para a implementação da rastreabilidade de requisitos, descrevendo uma maneira de efetuar esta rastreabilidade de forma mais prática e que possa ser utilizada em diversos tipos de projetos de software.", "url": "artigos/artigos_WER08/wer200817.html"}, {"title": "Quantifying Functional Reuse from Object Oriented Requirements Specifications", "authors": ["Nelly Condori-Fernández", "Oscar Pastor", "Maya Daneva", "Alain Abran", "Jaelson Castro"], "year": 2008, "keywords": "", "abstract": "Software reuse is essential in improving efficiency and productivity in the software development process. This paper analyses reuse within requirements engineering phase by taking and adapting a standard functional size measurement method, COSMIC FFP. Our proposal attempts to quantify reusability from Object Oriented requirements specifications by identifying potential primitives with a high level of reusability and applying a reuse indicator. These requirements are specified using OO-Method, an automatic software production method based on transformation models. We illustrate the application of our proposal in a Car Rental real system.", "url": "artigos/artigos_WER08/wer200818.html"}, {"title": "Using Mediation Theory to Build a Requirements Conflict Resolution Model", "authors": ["Nan Ma", "Tracy Hall", "Trevor Barker", "Ming Zhang"], "year": 2008, "keywords": "", "abstract": "Conflict is a common phenomenon in our daily life and as such conflict has an important impact on Requirements Engineering (RE). However, in the current RE literature, conflict is often addressed in terms of a technical issue leading to inconsistency in the requirements specification. Little attention is given to the socio-psychological aspects of the conflict. Furthermore, previous RE work typically views the resolution of conflicts in RE as a purely negotiationbased process, in which a requirements engineer acts as a representative of a developer site and negotiates with users. By drawing on the Information Systems and Conflict Resolution literature, we argue that conflict resolution in RE should be a mediated process, in which a requirements engineer acts as a mediator amongst different stakeholders. We introduce our narrative mediation theory and explain how it can be introduced into the field of RE.", "url": "artigos/artigos_WER08/wer200819.html"}, {"title": "Um Framework para Avaliação de Episódios de Gestão de Conhecimento", "authors": ["Francisco Milton Mendes Neto", "Pedro Fernandes Ribeiro Neto"], "year": 2008, "keywords": "", "abstract": "Support for organizational knowledge management (KM) requires mechanisms for creation, mapping and transference of knowledge. Many organizations use computer tools (KM systems) for achieving these goals. However, in many situations the whole potential of these systems to transfer knowledge and foment organizational learning is not adequately used. This happens mainly due to the lack of effective evaluation of essential properties and prerequisites of specific contexts of use of KM systems (KM episodes). This paper fills in this gap by proposing a framework for supporting formal evaluation of KM episodes, which facilitates the identification of the specific set of prerequisites of a KM episode and the formal verification of its properties. The verification of properties makes possible to check which business goals are probably reached with basis in the set of satisfied prerequisites.", "url": "artigos/artigos_WER08/wer200820.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2009)", "authors": ["Claudia Ayala", "Carla Silva"], "year": 2009, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER09/wer200900_1.html"}, {"title": "Keynote Talk: Tacit Knowledge in Requirements", "authors": ["Peter Sawyer"], "year": 2009, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER09/wer200900_2.html"}, {"title": "Comparing GORE Frameworks: i-star and KAOS", "authors": ["Vera Maria Bejamim Werneck", "Antonio de Padua Albuquerque Oliveira", "Julio Cesar Sampaio do Prado Leite"], "year": 2009, "keywords": "", "abstract": "Goal-Oriented Requirements Engineering (GORE) is an approach to requirements engineering dealing with intentionality in accordance with the relations among different actors. KAOS and i* (i-star) frameworks have been receiving many references as being important GORE proposals. This paper presents an conceptual analysis comparing characteristics of those methods giving examples related to actors relations definition, goal organizational model, tasks representation, risk analysis, and non-functional requirements. The aim of this work is to show both frameworks benefits and drawbacks. We believe that this analysis helps the understanding of the core concepts of GORE as well as it draws attention to key representation issues for both KAOS and i*.", "url": "artigos/artigos_WER09/wer200901.html"}, {"title": "An Initial Analysis on How Software Transparency and Trust Influence each other", "authors": ["Luiz Marcio Cysneiros", "Vera Maria Benjamim Werneck"], "year": 2009, "keywords": "", "abstract": "If we make a simple search on the internet for the definition of transparency there will be several different ones from optics to protocols. But most of the definitions will overlap among the notion that transparency is about how something is open enough to allow things to be deeply observed from different perspectives. Orthogonally, Transparency has been demanded in several different areas in our society. Governments are demanded to be more transparent, banks are being blamed for not being transparent and so on. In a world where software is already pervasive and where the internet is connecting individuals all over the world, software transparency seems to be not only a remote possibility but something we will have to deliver sooner than many have thought. This paper aims at showing that trust is one of the important features to achieve transparency although this trust can be sometimes misleading.", "url": "artigos/artigos_WER09/wer200902.html"}, {"title": "Towards a Framework for Improving Goal-Oriented Requirement Models Quality", "authors": ["Carlos Cares", "Xavier Franch"], "year": 2009, "keywords": "", "abstract": "Goal-orientation is a widespread and useful approach to Requirements Engineering. However, quality assessment frameworks focused on goaloriented processes are either limited or remain on the theoretical side. Requirements quality initiatives range from simple metrics applicable to requirements documents, to general-purpose quality frameworks that include syntactic, semantic and pragmatic concerns. In some recent works, we have proposed a metrics framework for goal-oriented models, but the approach did not cover the cycle of quality assessment. In this paper we present a semiotic-based quality assessment proposal built upon the i* framework and the SEQUAL proposal. We propose a simplification of SEQUAL which can be applied to i* models by defining semantic, pragmatic and social metrics. As a result, we obtain suites of metrics that can be applied to i* goaloriented requirements models. This theoretical work is put into practice by using iStarML, a XML representation of i* models, over which XQuery sentences compute the proposed metrics.", "url": "artigos/artigos_WER09/wer200903.html"}, {"title": "Modularizando Modelos i*: uma Abordagem baseada em Transformação de Modelos", "authors": ["Marcia Lucena", "Carla Silva", "Emanuel Santos", "Fernanda Alencar", "Jaelson Castro"], "year": 2009, "keywords": "", "abstract": "Este artigo apresenta uma estratégia para melhorar a modularidade dos modelos i* baseada na separação de interesses. São propostos um processo e um conjunto de regras de transformação para gerar modelos mais modulares.", "url": "artigos/artigos_WER09/wer200904.html"}, {"title": "Descubriendo la Arquitectura de Sistemas de Software Híbridos: Un Enfoque Basado en Modelos i*", "authors": ["Juan Pablo Carvallo", "Xavier Franch"], "year": 2009, "keywords": "", "abstract": "La mayoría de sistemas de software modernos se construyen integrando componentes de diversa naturaleza (comerciales, código libre, componentes legados, etc.), formando arquitecturas híbridas. La construcción de este tipo de sistemas se caracteriza por la adquisición de diversos componentes a proveedores externos a la organización que se integran con algún software hecho a medida. La correcta aplicación de este enfoque requiere la temprana identificación de los servicios que el sistema deberá brindar y su agrupación en dominios atómicos (los actores del sistema), que serán posteriormente remplazados de una manera oportunista, por los componentes más apropiados, independientemente de su naturaleza y origen. En este artículo abordamos este aspecto y proponemos un método basado en la utilización de modelos i*, que permite identificar los actores del sistema y su estructuración en una arquitectura de partida. El método es ilustrado con un caso práctico en una empresa de telecomunicaciones.", "url": "artigos/artigos_WER09/wer200905.html"}, {"title": "Um Processo de Validação de Requisitos Não-Funcionais Baseado no NFR-Framework", "authors": ["Anselmo de Araujo Couto", "Luiz Eduardo Galvão Martins"], "year": 2009, "keywords": "", "abstract": "This paper presents a proposal to validate non functional requirements based on the NFR-framework. Our aim is to offer a systematization to validate nonfunctional requirements, analyzing its evolution and the quality of the original document specification regarding the non-functional requirements. In order to achieve that we tested the systematization in 3 (three) documents of requirement specification for distinct systems, although in this paper only one is referred. The studies followed the proposed activities step-bystep. The case was applied in a requirement document specified for software of requirements management. The finding results allows us to verify that: a) the proposed process serves as instrument of quality improvement during the non-functional requirement validation; b) the process assists the requirements engineers to develop a refinement of non-functional requirements, identifying system properties that were previously obscure.", "url": "artigos/artigos_WER09/wer200906.html"}, {"title": "Explicitar Requisitos del Software usando Escenarios", "authors": ["Graciela Hadad", "Jorge Doorn", "Gladys Kaplan"], "year": 2009, "keywords": "", "abstract": "Los escenarios describen situaciones del proceso del negocio, tanto del proceso observable actual como del proceso proyectado o futuro. En este último caso los escenarios resultan ser contenedores de la mayoría de los requisitos del sistema de software, pero no son los requisitos propiamente dichos. Muchas de las buenas prácticas o prácticas recomendadas en el proceso de desarrollo de software se basan en la existencia de un documento de requisitos en el que éstos se individualizan en forma precisa. En el presente artículo se presenta una estrategia para confeccionar un documento de requisitos a partir de escenarios ya construidos. La particularidad que presenta la misma es que los requisitos individualizados tienden a ser libres de conflictos y de ambigüedad a consecuencia del propio proceso de producción.", "url": "artigos/artigos_WER09/wer200907.html"}, {"title": "Facilitando la Asignación de Prioridades a los Requisitos", "authors": ["Graciela Hadad", "Jorge Doorn", "Marcela Ridao", "Gladys Kaplan"], "year": 2009, "keywords": "", "abstract": "Existe una gran variedad de propuestas y estándares internacionales que ofrecen guías de contenido y estilo para la generación de un documento de especificación de requisitos (SRS). Adicionalmente, la literatura da cuenta de diversos métodos para asignar prioridades a los requisitos, que parten de un conjunto de requisitos perfectamente individualizados, frecuentemente plasmados en un SRS. En este artículo se presenta una estrategia alternativa para asignar prioridades a los requisitos, que se apoya en el proceso previo que les dio origen: su derivación desde escenarios y la descomposición de objetivos en subobjetivos.", "url": "artigos/artigos_WER09/wer200908.html"}, {"title": "Una Propuesta Metodológica para Modelar Procesos de Negocio de Decisión como Técnica de Elicitación de Requisitos para Sistemas de Business Intelligence", "authors": ["Aldo Quelopana Retamal", "Vianca Vega Zepeda", "José Gallardo Arancibia", "Claudio Meneses Villegas"], "year": 2009, "keywords": "", "abstract": "Entre las etapas de la Ingeniería de Requerimientos, una de las más complejas es la de Elicitación, por la dificultad propia que existe en el proceso de traspasar las necesidades y expectativas del futuro usuario de un sistema, al analista del sistema en desarrollo. Esta dificultad se incrementa cuando el sistema en desarrollo no es transaccional, sino un sistema de apoyo a la toma de decisiones. Como respuesta a esta problemática, en el presente trabajo se introduce y define el concepto de proceso de negocio decisional, el cual considera la toma de decisiones como un proceso más a ser modelado, y se propone una heurística basada en la Notación de Modelado de Procesos de Negocio (BPMN) para llevarla a cabo.", "url": "artigos/artigos_WER09/wer200909.html"}, {"title": "Research Findings on Empirical Evaluation of Requirements Specifications Approaches", "authors": ["Nelly Condori-Fernandez", "Maya Daneva", "Klaas Sikkel", "Roel Wieringa", "Oscar Dieste", "Oscar Pastor", ""], "year": 2009, "keywords": "", "abstract": "Numerous software requirements specification (SRS) approaches have been proposed in software engineering. However, there has been little empirical evaluation of the use of these approaches in specific contexts. This paper describes the results of a mapping study, a key instrument of the evidence-based paradigm, in an effort to understand what aspects of SRS are evaluated, in which context, and by using which research method. On the basis of 46 identified and categorized primary studies, we found that understandability is the most commonly evaluated aspect of SRS, experiments are the most commonly used research method, and the academic environment is where most empirical evaluation takes place.", "url": "artigos/artigos_WER09/wer200910.html"}, {"title": "OpenReq: uma Ferramenta para Auxílio à Gerência de Requisitos", "authors": ["Claiton Luís Grings", "Miriam Sayão"], "year": 2009, "keywords": "", "abstract": "The activity of requirements specification demands considerable efforts from professionals that execute it. To accomplish the activity, its not enough to obtain the requirements with customers. It is necessary to have a clear and complete understanding of customers necessities. Considering the issues associated to requirements registration and management, and the necessity of processs optimization during products conception, the OpenReq tool was developed. The objective of OpenReq is to offer the possibility of requirements managements through an automated tool that is different from the other tools because it is open source and consequently, doesnt have monetary costs for its utilization. The OpenReq was developed to Web platform, enabling the decentralized management of software requirements in just one base. The creation of this tool looks for the stimulation of the adoption of requirement management practices for small and medium companies and contribute with open source development community too, using open source technology.", "url": "artigos/artigos_WER09/wer200911.html"}, {"title": "A Systematic Process for Defining Meshing Tool Software Product Line Domain Model", "authors": ["Pedro O. Rossel", "María Cecilia Bastarrica", "Nancy Hitschfeld-Kahler"], "year": 2009, "keywords": "", "abstract": "Once an organization decides to develop a software product line (SPL), one of the first activities that needs to be done is to build a domain model. Here, commonalities and variabilities are identified, as well as the particular characteristics that products of the SPL will have. Although there exist some methods proposed for domain modeling, they are general and not specifically designed for scientific software, let alone for meshing tools. Meshing tools are highly complex software for generating and managing geometrical discretizations. Due to this complexity, they have generally been developed by end users with ad-hoc methodologies and not applying well established software engineering practices. Nevertheless, many meshing tools with varying degrees of variability have been developed over the years, making them a good application domain for SPL. This paper proposes a systematic process for building the domain model, specially suited for the case of a meshing tool SPL. We formally define the structure of the domain model, the process for building this model in a rigorous way, and we apply it to produce a meshing tool domain model. Both, the model and the process, are described and exemplified along the paper.", "url": "artigos/artigos_WER09/wer200912.html"}, {"title": "Uma Avaliação sobre Rastreabilidade de Software no Contexto do MPS.BR", "authors": ["Marcelio D’Oliveira Leal", "Sandro Ronaldo Bezerra Oliveira", "Cleidson Ronald Botelho de Souza"], "year": 2009, "keywords": "", "abstract": "The need to increase the productivity and competitiveness among software development organizations has demanded additional quality from these companies. Thus, the adoption of a processes quality model is a growing activity, mainly with the creation of the MPS.BR model, the Brazilian program for software process improvement. In this context, an activity that increases the quality and is basic is the software traceability. This paper presents an overview about the software traceability activity, one of the expected results of the requirements management in the MR-MPS.BR.", "url": "artigos/artigos_WER09/wer200913.html"}, {"title": "Towards a requirements reuse method using Product Line in distributed environments", "authors": ["Thais Ebling", "Jorge Luis Nicolas Audy", "Rafael Prikladnicki"], "year": 2009, "keywords": "", "abstract": "Distributed Software Development (DSD) is a recent approach where the teams are geographically distributed. Some characteristics of these environments have significant impact in activities that require constant communication, shared vision and stakeholders cooperation, as we have in Requirements Engineering (RE). The goal of this paper is to present a requirements reuse method that integrates software reuse in the context of Product Lines (PL), to improve the RE in a DSD environment.", "url": "artigos/artigos_WER09/wer200914.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2010)", "authors": ["Graciela Hadad", "Oscar Dieste"], "year": 2010, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER10/wer201000_1.html"}, {"title": "Organization", "authors": ["Graciela Hadad", "Oscar Dieste"], "year": 2010, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER10/wer201000_2.html"}, {"title": "Table of Contents", "authors": ["Graciela Hadad", "Oscar Dieste", "Juan Pablo Carvallo"], "year": 2010, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER10/wer201000_3.html"}, {"title": "Keynote Talk: Requirements Engineering. A market viewpoint", "authors": ["Alejandro Oliveros"], "year": 2010, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER10/wer201000_4.html"}, {"title": "Tutorial: Cómo crear piezas de conocimiento en ingeniería de requisitos: replicación y agregación experimentales", "authors": ["Oscar Dieste"], "year": 2010, "keywords": "", "abstract": "El interés en la ingeniería del software (IS) empírica ha propiciado la realización de múltiples experimentos y la acumulación de datos. No obstante, como ya ha ocurrido en el pasado en otras disciplinas más avanzadas (experimentalmente hablando) que la IS, los datos recabados son muchas veces difíciles de conseguir, parecen contradictorios y son difíciles de conciliar. Las técnicas de análisis de replicaciones (ya sea utilizando datos primarios o secundarios) permiten derivar piezas de conocimiento utilizando dichos datos imperfectos, las cuales pueden ser utilizadas tanto para guiar la práctica profesional como la investigación en IS.", "url": "artigos/artigos_WER10/wer201000_5.html"}, {"title": "A Goal-Oriented Approach for Variability in BPMN", "authors": ["Emanuel Santos", "Jaelson Castro", "Juan Sánchez", "Oscar Pastor"], "year": 2010, "keywords": "", "abstract": "Good business processes need to be up-to-date and automated to represent the organizational environment. To obtain models that reflect the changes it is necessary continuous checking between model and reality. Thus, business process model need to be modifiable and transformable in software. In order satisfy these needs we propose to apply variability analysis over Business Process Models, represented by Business Process Modeling Notation (BPMN), using a Goal-Oriented approach. In this paper we present a high-level process that links different methods in order to describe a systematic way to update BPMN models. Our proposal tries to achieve it by representing variability in goal trees.", "url": "artigos/artigos_WER10/wer201001.html"}, {"title": "Integração de Requisitos Não-Funcionais a Processos de Negócio: Integrando BPMN e NFR", "authors": ["Laís Xavier", "Fernanda Alencar", "Jaelson Castro", "João Pimentel"], "year": 2010, "keywords": "", "abstract": "A engenharia de requisitos é um fator crítico de sucesso em projetos de Software. Ou seja, uma elicitação de requisitos mal-realizada pode levar ao fracasso do projeto. Uma elicitação equivocada está relacionada a falta de compreensão do negócio pelo analista de sistemas, a falta de entendimento dos objetivos do sistema, a deficiência na comunicação entre analistas de negócio e analistas de sistema, entre outros. Esses fatores são, em parte, oriundos da dificuldade de ampla compreensão e validação dos modelos de requisitos , assimo como da ausência de um tratamento adequado dos requisitos nãofuncionais. Desta forma, neste trabalho propomos a extensão de uma notação para modelagem de processos de negócio (BPMN), que é de fácil compreensão pelos stakeholders, inserindo a noção de requisitos não-funcionais. Nesta abordagem, chamada BPMNFR, utilizamos catálogos de requisitos nãofuncionais, descritos no NFR Framework, para orientar a descoberta de suas operacionalizações no modelo de negócios. Neste artigo exemplificamos a aplicação da abordagem através de um estudo de caso real.", "url": "artigos/artigos_WER10/wer201002.html"}, {"title": "G2SPL: Um Processo de Engenharia de Requisitos Orientada a Objetivos para Linhas de Produtos de Software", "authors": ["Carla Silva", "Clarissa Borba", "Jaelson Castro"], "year": 2010, "keywords": "", "abstract": "Abordagens orientadas a objetivos podem ser usadas como uma forma de descobrir requisitos variáveis e comuns de uma Linha de Produtos de Software (LPS), bem como para reduzir os custos associados à configuração de um produto específico na família de produtos. Uma abordagem de requisitos orientada a objetivos que tem sido usada para o desenvolvimento de sistemas complexos é a framework i*. O i* fornece uma maneira de identificar e especificar tanto os objetivos dos stakeholders com relação ao sistema pretendido, como as características do próprio sistema. Este trabalho propõe uma extensão da linguagem de modelagem do i*, chamada i*-c (i* with cardinality), que permite a inserção de cardinalidade em alguns de seus elementos de modelagem. A abordagem G2SPL (Goals to Software Product Line) propõe um processo para identificar e modelar features comuns e variáveis de uma LPS em modelos i* com cardinalidade, como também para guiar a configuração de um produto específico na LPS.", "url": "artigos/artigos_WER10/wer201003.html"}, {"title": "Um Estudo de Campo sobre o Estado da Prática da Elicitação de Requisitos em Sistemas Embarcados", "authors": ["Jaime Cazuhiro Ossada", "Luiz Eduardo Galvão Martins"], "year": 2010, "keywords": "", "abstract": "Embedded Systems have a very important role in the modern life. We use them in our home, work, transportation, medical procedures, leisure time and so on. Despite of its great importance to our lives this kind of system steel lake a better process to improve the quality of its software. In this paper we present the results from a field research that focused the state of the practice of the embedded systems development, with special concern to the requirements elicitation aspects. The field research covered 53 embedded system practitioners that were predominantly placed in the state of São Paulo, Brazil. The results offer a picture of the embedded systems development practice in Brazil, and probably mirror the reality of this area in the Latin America.", "url": "artigos/artigos_WER10/wer201004.html"}, {"title": "From User Requirements to Tasks Descriptions in Real-Time Systems", "authors": ["Leo Ordinez", "David Donari", "Rodrigo Santos", "Javier Orozco"], "year": 2010, "keywords": "", "abstract": "Real-time scheduling theory has made a great progress in the last decades. From small devices to enormous satellites or industrial plants take advantage of this ongoing research. However, to the authors belief, there is still a gap to fully exploit the benefits of the theory. The cornerstone of real-time scheduling theory is the concept of task. Nevertheless, very little is mentioned about how to discover such tasks. Thus, the objective of this paper is to propose a systematic way of describing real-time tasks by jeans of requirements elicitation. The process begins with the gathering of user requirements through Use Case Diagrams. Then, tose use cases are refined to turn them into tasks descriptions. Lastly, tasks descriptions are further refined and brought to a detailed characterization of individual execution flows. This final tasks characterization is made with Activity Diagrams. Finally, a Line-Follower System is used to exemplify the proposed approach.", "url": "artigos/artigos_WER10/wer201005.html"}, {"title": "Evolución de un Juego Educacional de Ingeniería de Software a través de Técnicas de Elicitación de Requisitos", "authors": ["Elizabeth Suescun", "Vera Werneck", "Julio Sampaio do Prado Leite"], "year": 2010, "keywords": "", "abstract": "La ingeniería de requisitos tiene como tarea principal representar las necesidades de un contexto estudiado. El entendimiento y el uso de técnicas apropiadas para representar estas necesidades pueden asegurar la satisfacción de los interesados. Para ello la ingeniería de requisitos se vale de diferentes estrategias para la captura de esta información. Basados en estos conceptos queremos mostrar cómo la elección y la aplicación oportuna de estas estrategias pueden llevar a la evolución y mejora de los sistemas. Nuestro objetivo es mostrar como a través de la aplicación de técnicas de elicitación de requisitos fue concebida la evolución de un juego de cartas educacional. Este juego contaba con un modelo situacional como fuente de información y derivó para un modelo intencional, este último como parte de la representación evolucionada del juego.", "url": "artigos/artigos_WER10/wer201006.html"}, {"title": "Uma Análise Avaliativa de Ferramentas de Software Livre no Contexto da Implementação do Processo de Gerência de Requisitos do MPS.BR", "authors": ["Alexandre Brito Cardias Junior", "Luciana Neves Bentes", "Mauricio Ronny", "Sandro Ronaldo Bezerra Oliveira", "Ewelton Yoshidome"], "year": 2010, "keywords": "", "abstract": "The markets demands intensify the search for quality in software development and, as a result, it makes that even more companies adopt models in order to improve their software processes and, consequently, their final product. In addition to this, the time for product delivery can be significantly reduced when proper tools for a quicker evolution of the process are adopted. This paper presents free software tools, analyzing them from the point of view of the MPS.BR model.", "url": "artigos/artigos_WER10/wer201007.html"}, {"title": "Um Modelo de Rastreabilidade com suporte ao Gerenciamento de Mudanças e Análise de Impacto", "authors": ["Pablo Dall Oglio", "João Pablo Silva da Silva", "Sérgio Crespo Coelho da Silva Pinto"], "year": 2010, "keywords": "", "abstract": "É de senso comum que a gestão da mudança de requisitos exerce papel fundamental no processo de desenvolvimento de software, principalmente no que tange à qualidade. Para que se possa gerenciar a mudança de requisitos de forma efetiva e precisa, torna-se indispensável o uso de informações de rastreabilidade, que por sua vez, torna possível a realização da análise de impacto. Para que se possa efetivamente gerenciar as mudanças de software é necessário a existência de um modelo que permita representar com precisão a rastreabilidade de software, as mudanças ocorridas e os impactos gerados. Apesar destes assuntos serem de suma importância dentro da área da engenharia de requisitos, parece não haver um modelo que permita representar estes aspectos ao mesmo tempo de forma que supra os requisitos necessários identificados na literatura. Desta forma, a proposta deste trabalho é o desenvolvimento de um modelo de rastreabilidade que suporte o gerenciamento da mudança e análise de impacto, de forma que atenda aos requisitos identificados nos trabalhos já desenvolvidos na área.", "url": "artigos/artigos_WER10/wer201008.html"}, {"title": "A Tool for Formal Feature Modeling Based on BDDs and Product Families Algebra", "authors": ["Fadil Alturki", "Ridha Khedri"], "year": 2010, "keywords": "", "abstract": "Feature models are commonly used to capture the commonality and the variability of product families. There are several feature model notations that correspondingly depict the concepts of feature modeling techniques. Therefore, the tools based on them reflect this diversity in the notations used and the fuzziness of the concepts adopted. We propose a tool based on Product Families Algebra (PFA) and on Binary Decision Diagrams (BDD). The first brings the mathematical formalism to the specifications of product familias and the mathematical theory that enables calculations on featuremodels. The second brings efficient algorithms in time and in space. Hence, the tool allows several algebraic manipulations of feature models algebraically specified. The paper discusses the architecture of the tool, and the process through which a term in PFA is translated into a term formed by BDD symbols and operations. A case study is presented to illustrate the tools key functionalities.", "url": "artigos/artigos_WER10/wer201009.html"}, {"title": "Lenguaje de Especificación para el Framework Tropos", "authors": ["Alicia Martínez", "Carmen Velasco", "Eliel Morales", "Hugo Estrada", "Luis A. Gama"], "year": 2010, "keywords": "", "abstract": "El framework i* surgió como una propuesta para realizar reingeniería de procesos de negocios hace ya casi dos décadas. A partir de entonces han surgido numerosas propuestas y herramientas que han añadido nuevos conceptos y funcionalidades a esta propuesta original. Una de ellas es el framework Tropos, que es una metodología orientada a agentes enfocada al desarrollo de software. Sin embargo, uno de los grandes problemas que se presenta en el uso de esta metodología es que cada propuesta que usa o extiende Tropos o i* utiliza los conceptos dependiendo sus necesidades, y emplean diferentes formatos en el almacenamiento de sus modelos. En este artículo se presenta un lenguaje de especificación para el framework Tropos basado en XML, el cual define la estructura de sus diagramas e impone reglas para la utilización de sus primitivas de modelado. Se presenta un DTD (Document Type Definition) que representa la gramática de este lenguaje y que permite hacer la validación de la estructura de los modelos definidos en XML. El enfoque propuesto intenta homogeneizar el uso de los modelos organizacionales entre la comunidad que utiliza esta metodología.", "url": "artigos/artigos_WER10/wer201010.html"}, {"title": "TERASE: Template para Especificação de Requisitos de Ambiente em Sistemas Embarcados", "authors": ["Luiz Eduardo Galvão Martins", "Roberto de Souza Júnior", "Hermano Peixoto de Oliveira Jr.", "Cecilia Sosa Arias Peixoto"], "year": 2010, "keywords": "", "abstract": "This paper presents a template for environmental requirements specification in embedded systems, called TERASE. There is a lack of requirements specification templates that address the particularities of the embedded systems development. With TERASE embedded system engineers can improve their environmental requirements specification, as well as the communication process between hardware and software engineers. An empirical study was conducted to evaluate the template proposed. The goal of the empirical study was to apply and evaluate the results obtained with TERASE, from the point of view of the embedded system practitioner. The embedded system analyzed during the experiment was a datalogger used to capture and store temperature reading. It was adopted in-vitro modality for the experiment.", "url": "artigos/artigos_WER10/wer201011.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2011)", "authors": ["Maria Lencastre", "Hugo Estrada Esquivel", "Eduardo Figueiredo"], "year": 2011, "keywords": "", "abstract": "Welcome to XIV Edition of the Requirements Engineering Workshop (WER'11) held at Rio de Janeiro, Brazil; organized by the Pontifícia Universidade Católica do Rio de Janeiro (PUC-Rio), from the 28th to the 29th of April 2011. This year, WER'11 received 48 papers from 13 countries, written in the 3 official idioms: Portuguese, Spanish or English. All the submitted papers were revised by at least 3 reviewers from the WER'11 Program Committee. At the end of the process 15 papers where accepted to be published and presented at the Workshop. It's important to recognize and thank the hard work made by the reviewers and also its quality.", "url": "artigos/artigos_WER11/wer201100_1.html"}, {"title": "Keynote Talk - To be, or not to be (socially oriented ): that's the question", "authors": ["Jaelson Castro"], "year": 2011, "keywords": "", "abstract": "New technologies and systems are greatly impacting people's lives. However, innovation has the potential to bring benefits as well as threats. In this world of technical revolution we argue that in order to arrive at proper systems requirements, one should examine and understand the relationships among social actors. In this talk we review research that applies, adapts, extends, or evaluate the social modeling concepts and approaches. We also raise research challenges for our community.", "url": "artigos/artigos_WER11/wer201100_2.html"}, {"title": "Padrões de Escrita de Requisitos: um mapeamento sistemático da literatura", "authors": ["Rodrigo Cezario da Silva", "Fabiane Barreto Vavassori Benitti"], "year": 2011, "keywords": "Requirement Pattern; Systematic mapping study", "abstract": "The requirements elicitation is reported in the literature as essential to the success of software development projects. The existence of requirements patterns aimed at not only improving the quality of requirements specifications, but also the reuse of successful solutions of previous experience in new projects. In this paper, we present the results of a systematic literature mapping on requirements patterns. The results show that there is a diverse range of patterns for the process of requirements engineering, but there are still few studies addressing the requirements patterns that deal specifically with the documentation of software requirements.", "url": "artigos/artigos_WER11/wer201101.html"}, {"title": "Using Systematic Review to Elicit Requirements of Reference Architectures", "authors": ["Elisa Yumi Nakagawa", "Lucas Bueno Ruas Oliveira"], "year": 2011, "keywords": "", "abstract": "Software architectures have played a signi?cant role in determining the success of software systems. In this context, reference architectures have emerged as a special type of architecture that contains knowledge of a speci?c domain, aiming at improving reuse and productivity, facilitating the development of systems of that domain. Considering their relevance, the establishment of reference architectures is very interesting; however, it is not a trivial task, mainly due to the di?culty to identify their requirements, since a range of knowledge is required. Thus, the main objetive of this paper is to propose the use of Systematic Review as a technique to elicit requirements of reference architectures. In order to show the viability of our idea, we present a case study on the software testing domain. Results have pointed that Systematic Review could be considered an e?cient and additional technique to gather spread domain knowledge, essential task to the establishment of a more complete reference architecture.", "url": "artigos/artigos_WER11/wer201102.html"}, {"title": "Uma Proposta de Elicitação e Análise de Requisitos no Contexto de Médias e Pequenas Empresas de Desenvolvimento de Software", "authors": ["Cristiano Ferreira de Souza", "Victor F. A. Santander"], "year": 2011, "keywords": "Elicitação de Requisitos; Desenvolvimento de Software; Ferramenta Computacional", "abstract": "Na literatura da área de Engenharia de Requisitos apresentam-se diversas métricas de elicitação, análise, documentação e gerência de requisitos, sempre tendo como condutor o engenheiro de requisitos. Acredita-se que outra abordagem efetiva consiste em tornar o usuário/cliente como protagonista do processo de engenharia de requisitos. Mais especificamente, neste trabalho propõe-se uma abordagem alternativa a qual permite já nas primeiras fases do processo de engenharia de requisitos elicitar o maior número de requisitos sob a perspectiva e direta condução do usuário e/ou cliente. A proposta é apoiada por uma ferramenta computacional a qual é também brevemente apresentada e utilizada em um estudo de caso.", "url": "artigos/artigos_WER11/wer201103.html"}, {"title": "Estudio experimental de la efectividad de la entrevista abierta frente a la entrevista independiente de contexto", "authors": ["Dante Carrizo", "Oscar Dieste", "Natalia Juristo", "Marta López"], "year": 2011, "keywords": "Entrevista abierta; entrevista independiente de contexto; tipo de", "abstract": "OBJETIVO: Estudiar la efectividad relativa de las técnicas de entrevista abierta y entrevista independiente de contexto en la identificación de requisitos para sistemas software. MÉTODO: Experimento controlado ensayando dos factores: tipo de entrevista (abierta e independiente de contexto) y tipo de problema (identificación de requisitos para dos sistemas software distintos). Debido al reducido número de sujetos experimentales, se ha utilizado un diseño de medidas repetidas dentro de los sujetos. RESULTADOS: El poder estadístico del estudio es en general insuficiente, pero hemos podido constatar que el tipo de problema posee efectos significativos en la efectividad del proceso de relevamiento de requisitos. La experiencia del analista juega también un papel importante. El tipo de entrevista utilizada afecta en mucha menor medida. CONCLUSIONES: Es necesario comprender mejor qué es un problema de relevamiento de requisitos. Esto nos permitirá diseñar estrategias más eficaces para una identificación certera de los requisitos del software.", "url": "artigos/artigos_WER11/wer201104.html"}, {"title": "Modelagem da atividade de elicitação de requisitos utilizando a técnica de entrevista: uma abordagem utilizando dinâmica de sistemas", "authors": ["Victor O. Hermsdorf", "José Luis Braga", "Leonardo Carvalho", "Liziane S. Soares", "Bernardo G. Ambrósio"], "year": 2011, "keywords": "requisito de software; dinâmica de sistemas; elicitação de requisitos", "abstract": "O desenvolvimento de software é uma atividade que envolve riscos, parte deles relacionados a problemas de decisão, principalmente no nível gerencial. São muitas variáveis dinâmicas interconectadas a serem gerenciadas, sendo indispensável o uso de ferramentas que auxiliem os gerentes em suas tomadas de decisão, identificando os riscos antes de eles se materializarem. O objetivo deste trabalho é produzir um modelo de dinâmica de sistemas que aborde a atividade de elicitação de requisitos utilizando a técnica de entrevista, permitindo que gerentes possam utilizá-lo como uma ferramenta de apoio para auxiliá-los na análise e tomadas de decisão relativas à adoção desta técnica em projetos.", "url": "artigos/artigos_WER11/wer201105.html"}, {"title": "Transparência Aplicada a Modelos de Negócio", "authors": ["André Luiz de Castro Leal", "Henrique Prado Sousa", "Julio Cesar Sampaio do Prado Leite", "José Luis Braga"], "year": 2011, "keywords": "Transparência; paradigma de aspectos; transparência de processos de negócio", "abstract": "O presente artigo explora o uso do conceito de transparência em processos de negócio (BPM). Demonstra-se, através de um exemplo, como um processo de negócio pode tornar-se mais transparente e como a teoria de aspectos ajuda a modularizar o modelo do processo. Particularmente, ajudamos a comprovar a eficácia de aspectos na operacionalização de requisitos de clareza e simplicidade. O artigo utilza um exemplo baseado em um processo de solicitação de financiamento para aquisições num ambiente universitário.", "url": "artigos/artigos_WER11/wer201106.html"}, {"title": "O Método de Inspeção Semiótica Aplicado ao Requisito Usabilidade", "authors": ["Elizabeth Suescún Monsalve", "Vera Maria B. Werneck", "Julio Cesar Sampaio do Prado Leite"], "year": 2011, "keywords": "Inspeção semiótica; requisitos; requisitos não-funcionais; jogos educacionais", "abstract": "O requisito usabilidade é de suma importância para os artefatos de software principalmente na área de jogos computacionais, pois permite medir a capacidade de uso de um artefato de software. Classifica-se esse requisito como um requisito de qualidade ou Requisito Não-Funcional (RNFF). Nosso trabalho centra-se na operacionalização do requisito usabilidade no contexto de um jogo educacional usando o Método de Inspeção Semiótica (MIS), oriundo da área de Interação Humano--Computador (IHC). O SimulES-W é a primeira versão digital do jogo SimulES usado para o ensino da engenharia de software de forma lúdica e colaborativa entre os jogadores. Abstract. The usability requirement is extremely important to software artifacts especially in the area of computer games. This requirement can be classified as a quality or a nonfunctional requirement. Our work focuses on the operationalization of usability in the context of an educational game using the Semiotics Inspection method from the area of Human-Computer Interaction. SimulES-W is the first digital version of the game SimulES aiming at teaching software engineering in a fun and collaborative way.", "url": "artigos/artigos_WER11/wer201107.html"}, {"title": "Specification of Failure-Handling Requirements as Policy Rules on Self-Adaptive Systems", "authors": ["João Pimentel", "Jaelson Castro", "Xavier Franch"], "year": 2011, "keywords": "Self-adaptive systems; Autonomic systems; Failure requirements; Requirements engineering; Policy specification", "abstract": "Most adaptive systems have compensation mechanisms for recovering from or preventing failures. However, sometimes a compensation is not essential. Hence, diagnosing and compensating each and every one of their failures may be ineffective. Rather than polluting a requirements specification with fine grained definition of failure-handling conditions, this work aims to increase the flexibility of failure handling in self-adaptive systems using tolerance policies. We allow the expression of conditions in which certain failures may be ignored  i.e., conditions on which a failure will not be compensated. Such policies may lead to reduced costs and performance improvement. The FAST framework consists of the definition of a tolerance policy, the mechanisms to evaluate this policy and a tool to aid the creation of policies.", "url": "artigos/artigos_WER11/wer201108.html"}, {"title": "De Arquitecturas Organizacionais em i* a Arquitecturas Baseadas em Agentes: Uma abordagem orientada a modelos", "authors": ["Carla Silva", "Pedro Dias", "João Araújo", "Ana Moreira"], "year": 2011, "keywords": "Desenvolvimento Dirigido por Modelos; Transformações de Modelos; Framework i*; Modelos Arquiteturais; Sistemas multi-Agentes", "abstract": "O Tropos propõe uma abordagem para o desenvolvimento de sistemas multi-agentes; baseia-se nos conceitos sociais e intencionais oferecidos pelo framework de modelação organizacional i*, adotando-o para suportar as várias fases iniciais do desenvolvimento, em particular o desenho arquitectural. Reconhecendo no UML (Unified Modeling Language) a capacidade de actuar como uma Linguagem de Descrição Arquitectural, este trabalho especifica, através de uma abordagem orientada a modelos, as transformações necessárias para obter modelos arquitecturais, descritos no perfil de Agência UML, a partir de modelos arquitecturais organizacionais descritos em i* no contexto do Tropos.", "url": "artigos/artigos_WER11/wer201109.html"}, {"title": "Model Interchange and Tool Interoperability in the i* Framework: A Proof of Concept", "authors": ["Daniel Colomer", "Lidia López", "Carlos Cares", "Xavier Franch"], "year": 2011, "keywords": "i* framework; istar; i-star; model interchange; semantic interoperability; tool interoperability; iStarML; jUCMNav; HiME", "abstract": "Since the i* (i-star) framework was adopted by the requirements engineering community, different groups have formulated variations of the language proposed therein with the purpose of adapting the framework to the specific needs of its users. Whilst this flexibility is helpful from many perspectives, it poses some challenges, remarkably the difficulty of sharing a common model knowledge base, and tool incompatibility. In earlier works, we have formulated the iStarML interchange format as a mediator between these different variations. In this paper, we present a particular experience we have carried out, namely the interconnection of two existing tools, jUCMNav and HiME. We have provided the adequate mappings to transform models that correspond to the two metamodels adopted by these tools, we have identified the conflicting cases in the transformation, and we have implemented the mapping as import/export facilities in the tools. This case has not just an intrinsic value as proof of concept (i.e., the ability of these two tools to interchange models) but also sets the basis for a general solution to the i* tool interoperability problem.", "url": "artigos/artigos_WER11/wer201110.html"}, {"title": "Design Rationale Representation in Requirements Engineering using the KAOS meta-model", "authors": ["Ernani Gaspar Santos", "Adriana Pereira de Medeiros"], "year": 2011, "keywords": "Design Rationale; Requirements Engineering; Meta-model.", "abstract": "Requirements specifications made in a poor or incorrect manner have been recognized as a source of problems in software development. Recording design rationale in this activity may contribute to a better reasoning about requirements and how to model them, since the software engineers need to carefully evaluate the justifications for their decisions. This work investigates the design rationale representation for requirements models using the Kuaba approach and the KAOS meta-model. It shows that representing design rationale taking advantage of the design meta-models semantics can favor improvements in requirements models quality, working as design feedback. It also contributes to requirement changes management by giving semantics to requirements tracing and supporting impact analysis.", "url": "artigos/artigos_WER11/wer201111.html"}, {"title": "A Goal Oriented Approach to Identify and Configure Feature Models for Software Product Lines", "authors": ["Carla Silva", "Clarissa Borba", "Jaelson Castro"], "year": 2011, "keywords": "Goal Oriented Approaches; Software Product Line; i* framework.", "abstract": "A goal oriented approach can be used as a way to discover variable and common requirements of a software product line (SPL), as well as to reduce costs associated with the configuration of a specific product in a product family. A goal oriented requirements engineering approach which has been used to develop complex system is the i* framework. It provides a manner to identify and specify the stakeholders goals in relation to the intended system, as well as the characteristics of the system itself. This work proposes an extension of the i* modeling language, called i*-c (i* with cardinality), that allows inserting cardinality in some of its modeling elements. The G2SPL (Goals to Software Product Line) approach defines a process to identify and model common and variable features of a SPL using i* models with cardinality, as well as guides the configuration of a specific product in the SPL.", "url": "artigos/artigos_WER11/wer201112.html"}, {"title": "Message Structures: a modelling technique for information systems analysis and design", "authors": ["Arturo González", "Marcela Ruiz", "Sergio España", "Óscar Pastor"], "year": 2011, "keywords": "Message Structures; Communication Analysis; analysis; design; information systems; requirements engineering; model-driven development", "abstract": "Despite the increasing maturity of model-driven development (MDD), some research challenges remain open in the field of information systems (IS). For instance, there is a need to improve modelling techniques so that they cover several development stages and they facilitate the transition from analysis to design. This paper presents Message Structures, a technique for the specification of communicative interactions between the IS and its environment. This technique can be used both in analysis and in design. During analysis, it allows abstracting from the technology that will support the IS, and to complement business process modelling with the specification of communicational needs. During design, Message Structures serves two purposes: (i) it allows to systematically derive a model of the IS memory (e.g. a UML class diagram), (ii) and it allows to reason the user interface design using abstract patterns. The technique is part of Communication Analysis, a communication-oriented requirements engineering method, but it can also be used in combination with other modelling techniques (e.g. Business Process Modeling Notation, Use Cases). Two supporting tools are presented: one uses the Xtext technology, and the other uses the Eclipse Modelling Framework.", "url": "artigos/artigos_WER11/wer201113.html"}, {"title": "An Essential Textual Use Case Meta-model Based on an Analysis of Existing Proposals", "authors": ["Fábio Levy Siqueira", "Paulo Sérgio Muniz Silva"], "year": 2011, "keywords": "essential; meta-model; specification model; textual; use case.", "abstract": "Several studies have proposed meta-models for textual representations of use cases. Each of these meta-models has different goals and viewpoints, with either varying concepts and relationships or different semantics for the same concept. In Model-Driven Engineering approaches where there is no compatible proposal or a more appropriate viewpoint, or where there is no intention to limit the approach to a specific use case format, it might be difficult to choose between these proposals. Aiming at a generic textual representation, this paper presents a meta-model based on an analysis of 20 studies, chosen through a survey, that propose templates or meta-models. The more common elements of these studies are represented in a meta-model, together with their more frequent attributes. The goal is to create an essential and easily extendable meta-model that can be used directly in Model-Driven Engineering activities.", "url": "artigos/artigos_WER11/wer201114.html"}, {"title": "On the construction of specifications from requirements", "authors": ["Zhi Li", "Jon G. Hall", "Lucia Rapanotti"], "year": 2011, "keywords": "Problem Frames; Problem Progression; Requirements; Specifications; Communicating Sequential Processes", "abstract": "Transforming real-world requirements into specifications which are appropriate for subsequent software development is at the heart of Requirements Engineering. Doing it systematically remains an open challenge. In this paper we present a formal approach to systematise the move from requirements to specifications in the context of Jackson's Problem Frames.", "url": "artigos/artigos_WER11/wer201115.html"}, {"title": "Preface English - 15th Workshop on Requirements", "authors": ["Alejandro Oliveros", "Antonio de Padua Albuquerque Oliveira", "Gladys Noemí Kaplán"], "year": 2012, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER12/wer201200_1.html"}, {"title": "Prefácio em Português - Anais do 15o. Workshop em Engenharia de Requisitos", "authors": ["Alejandro Oliveros", "Antonio de Padua Albuquerque Oliveira", "Gladys Noemí Kaplán"], "year": 2012, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER12/wer201200_2.html"}, {"title": "Prefacio Español - 15° Workshop sobre Ingeniería de Requisitos", "authors": ["Alejandro Oliveros", "Antonio de Padua Albuquerque Oliveira", "Gladys Noemí Kaplán"], "year": 2012, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER12/wer201200_3.html"}, {"title": "A model-driven framework to integrate Communication Analysis and OO-Method: Supporting the model transformation", "authors": ["Marcela Ruiz", "Sergio España", "Óscar Pastor", "Arturo González"], "year": 2012, "keywords": "Model transformation; model-driven development; Communication Analysis; OO-Method; requirements engineering; Eclipse Modelling Framework; ATL.", "abstract": "Models are now part of an increasing number of engineering processes. However, in most cases, they are confined to a simple documentation role instead of being actively integrated into the engineering process. The model-driven development approach considers models as first-class entities and also considers tools, repositories, etc. as models. In order to take full advantage of these ideas, model transformation emerges as a main activity. Model transformation aims at supporting the production of target models from a number of source models. Following the model-driven development paradigm, we propose a model-driven framework to integrate Communication Analysis (a communication- oriented business process modelling and requirements method) and OO-Method (an object-oriented model-driven development method). This integration framework is composed of two stages: diagramming support and transformation support. This paper describes the second stage (the first stage was described in previous works). Phases, tasks, technological support and examples are presented. Finally, we conclude with an analysis and discussions about lessons learned and an evaluation proposal to assess the usability of the transformation module.", "url": "artigos/artigos_WER12/wer201201.html"}, {"title": "AIRDoc-i*: um processo para avaliação de modelos i*", "authors": ["Cleice Souza", "Fernanda Alencar", "Gabriela Guedes", "Monique Soares", "Cláudia Souza", "Ricardo Ramos", "Jaelson Castro"], "year": 2012, "keywords": "Linguagem i*; Elicitação de Requisitos; AIRDoc; Requisi-tos-não-funcionais (RFN’s).", "abstract": "A linguagem i* descreve ambientes organizacionais em termos de atores e suas depend&ecircncias. Ao descrever estes ambientes organizacionais, precisa-se conhecer e compreender a linguagem. Muitas vezes isso n&atildeo ocorre, acarretando erros por mau uso da linguagem relacionada com a sem&acircntica. Assim, faz-se necess&aacuterio avaliar documentos de requisitos descritos em i*, com o intu&iacuteto de identificar estes erros. Este trabalho realiza uma avalia&ccedil&atildeo atrav&eacutes de um processo chamado: AIRDoc-i*. Tem como objetivo identificar erros sem&acircnticos em documentos de requisitos i*. Ajudando o engenheiro de requisitos a usar a linguagem i*.", "url": "artigos/artigos_WER12/wer201202.html"}, {"title": "Bula de Software: Uma Estrutura Definida para Promover a Melhoria da Transparência em Software", "authors": ["André Luiz de Castro Leal", "Eduardo Almentero", "Herbet Cunha", "Henrique P. Sousa", "Julio Cesar S. do P. Leite"], "year": 2012, "keywords": "Transparency; documentation; software.", "abstract": "This article presents a novel proposal for software documentation that is founded on package insert (patient information leaflets) for drugs. The objective of our proposal, called Software Bula, is to provide for users and developers software information that are at the same time clean and well structured and organized.", "url": "artigos/artigos_WER12/wer201203.html"}, {"title": "Deriving requirements specifications from the application domain language captured by Language Extended Lexicon", "authors": ["Leandro Antonelli", "Gustavo Rossi", "Julio Cesar Sampaio do Prado Leite", "Alejandro Oliveros"], "year": 2012, "keywords": "Requirements specifications; Domain Analysis; Language; Extended Lexicon; Requirements statements; User Stories; Use Cases.", "abstract": "Understanding the context of a software system during requirements specification is a difficult task. Sometimes application domains are very complex, other times the limits of the application are fuzzy. Thus, it is difficult to elicit and write the initial set of requirements. This difficulty frustrates requirements engineers and restricts the process of analysis, which could lead to a final software requirement specification of low quality. In such situations technologically outstanding software systems can be built, but they may fail to suit the needs of the client. Hence, clients are unsatisfied and development projects fail. In this paper we propose a strategy to use the application domain language captured by the Language Extended Lexicon in order to obtain different products related to requirements specification. Products vary from classic requirements which state the system shallâ¦ to products such as Use Cases and User Stories. The strategy focuses on obtaining the initial set of functional requirements. We believe that by minimizing the gap between the problem and the initial set of requirements, we provide engineers with a preliminary product they can work on and refine to reach the quality needed.", "url": "artigos/artigos_WER12/wer201204.html"}, {"title": "Extending the 4-Variable Approach to Cyber-Physical Systems: A Practical Experience", "authors": ["Leo Ordinez", "Omar Alimenti", "Emilia Rinland", "Marisa Gomez", "Jorge Marchetti"], "year": 2012, "keywords": "", "abstract": "Cyber-physical systems are a new research discipline that involves many areas. The key concept behind this discipline has to do with a strong interaction between the physical world and a computing system, which should be transparent to an external observer. Thus, it cannot be determined whether the systemâs behavior is due to the influence of the environment or the actions of the computing system. In this paper, a requirement analysis approach for these systems is presented. It is called 3D Approach and it is based on the well-known 4-Variable Model. The 3D Approach came out as the result of systematizing practical experiences taken from the design of a biodigester.", "url": "artigos/artigos_WER12/wer201205.html"}, {"title": "GERSE: Guia de Elicitação de Requisitos para Sistemas Embarcados", "authors": ["Jaime Cazuhiro Ossada", "Luiz Eduardo G. Martins", "Bárbara Stefani Ranieri", "Anderson Belgamo"], "year": 2012, "keywords": "Embedded Systems; Requirements Elicitation; GERSE.", "abstract": "The projects with embedded systems are used for many different purposes, being a major challenge for the community of developers of such systems. As we benefit from technological advances the complexity of designing an embedded system increases significantly. This paper presents GERSE, a guideline to requirements elicitation for embedded systems. Despite of advances in the area of embedded systems, there is a shortage of requirements elicitation techniques that meet the particularities of this area. The contribution of GERSE is to improve the capture process and organization of the embedded systems requirements.", "url": "artigos/artigos_WER12/wer201206.html"}, {"title": "Improving the Quality of Software Requirements Specifications with Semantic Web Technologies", "authors": ["Verónica Castañeda", "Luciana Ballejos", "Ma. Laura Caliusco"], "year": 2012, "keywords": "Software Requirements Specification; Semantic Web Technologies; quality; consistency; correctness; traceability; organization; unambiguity.", "abstract": "A good software requirements specification (SRS) offers a number of benefits which include: being the contract between customers and suppliers, reducing the development effort, being a good basis for estimating costs and planning, a reference for verification and validation, and a basis for the identification of possible improvements in the analyzed processes. Mainly due to the lack of information and differences in interpretation between all those involved in the development of an information system, a good SRS is very difficult to define. In this paper, an approach based on Semantic Web technologies for defining a good SRS is presented. The main component of this approach is an ontology called OntoSRS that preserves the consistency, correctness, traceability, organization and unambiguity of a SRS. In addition, an application example is discussed.", "url": "artigos/artigos_WER12/wer201207.html"}, {"title": "Market-aware Requirements", "authors": ["Romina Torres", "Hernan Astudillo"], "year": 2012, "keywords": "Non-Functional Requirements; computing with words; fuzzy sets; fuzzy c-means", "abstract": "Traditionally, non-functional requirements (NFRs) are specified as measurable entities to permit evaluation satisfaction; however, NFR specifications quickly become obsolete because (1) NFRs are expressed in numbers, (2) architects specify them using the correct values at design time, and/or (3) providers are constantly improving their o er, in terms of functionality and quality of service (QoS). The computingwith- words approach has already been proposed to replace numerical NFR specifications, where natural language words denote fuzzy quality levels; unfortunately, current proposals provide only for design-time, stakeholder-de ned translation of words as numerical ranges. We propose a mechanism to automatically and dynamically determine current numerical ranges of the fuzzy quality levels from the available data, without human intervention, whenever changes to component QoS specifications. Our main contribution is allowing architects to specify their requirements using words only once (at design time), and whenever providers change components QoS characteristics, automatically update those requirements to the new market view, enabling market-aware requirements. The approach was validated by measuring the number of times that necessarily a requirement had to be rewritten at runtime in order to get new operationalizations which replace the now older ones. We use a set of ten complex requirements, a dataset of 1500 actual Web services with precise measurements for nine QoS aspects, and a simulated ering variability. A Web based prototype is also made available.", "url": "artigos/artigos_WER12/wer201208.html"}, {"title": "Melhorando a Ferramenta JGOOSE", "authors": ["Mauro Brischke", "Victor Francisco Araya Santander", "Ivonei Freitas da Silva"], "year": 2012, "keywords": "JGOOSE; Modelagem Organizacional; Framework i*; Casos de Uso; Engenharia de Software.", "abstract": "Um dos grandes desafios no desenvolvimento de software está em garantir que modelos funcionais tais como casos de uso em UML sejam desenvolvidos considerando intencionalidades expressas em modelos organizacionais. O uso de ferramentas computacionais pode facilitar este processo. Neste sentido, este trabalho apresenta uma nova versão da ferramenta JGOOSE (Java Goal Into Object Oriented Standard Extension), a qual permite gerar de forma automatizada casos de uso UML a partir de modelos organizacionais construí­dos via framework i*. Esta nova versão da ferramenta adiciona funcionalidades essenciais tais como, permitir alterar e salvar descrições textuais de casos de uso e gerar diagramas de casos de uso no formato XMI.", "url": "artigos/artigos_WER12/wer201209.html"}, {"title": "Modelo Intencional Genérico de Sistemas Biométricos", "authors": ["Jacqueline Abreu do N. T. Rodrigues", "Nathálea Salem", "Vera Maria B. Werneck"], "year": 2012, "keywords": "", "abstract": "Biometric systems have been presented in various environments. These systems are widely used in many situations, with emphasis to attend security non functional requirements. The study of essential processes executed by these systems could identify which are the functional and nonfunctional requirements for systems that handle biometrics. This work presents an intentional model using the i* framework that covers functional and non functional requirements and the relations between the actors involved in these processes. Therefore, we have proposed a generic intentional model that can be specialized for any biometric device, composing a reusable instrument that can be refined depending on the area in which the system must be applied.", "url": "artigos/artigos_WER12/wer201210.html"}, {"title": "Modelo matemático y procedimiento para evaluación por complejidad de los requisitos software", "authors": ["Karina Pérez Teruel", "Maikel Yelandi Leyva Vásquez", "Ing. Karel Fernandez Cedeño", "Sasha Valdes Jimenez", "Ing. Daimara Mustelier Sanchidrian"], "year": 2012, "keywords": "software requirements; estimation; complexity assessment.", "abstract": "Requirements Engineering provides an important basis for estimating time and effort in software development projects. Software requirements give a significant measure of product size to be developed. The University of Informatics Sciences (UCI) has an estimation method, which, in order to gain accuracy, incorporates a second estimate after the requirements phase to have more detailed technical input. This requirement shall be classified according to the complexity they bring to the software implementation. This article details a mathematical model for the classification of complexity in software requirements and a tool designed to facilitate the process of assessing the requirements on software development projects at UCI.", "url": "artigos/artigos_WER12/wer201211.html"}, {"title": "O Processo de Engenharia de Requisitos sob a Ótica da Gestão de Processos de Negócio", "authors": ["José Henrique de Melo Cardoso", "Adicinéia Aparecida de Oliveira", "Fernanda Alencar"], "year": 2012, "keywords": "Business Process Management; Process Requirements Engineering; Process Requirements Engineering Improvement.", "abstract": "This paper presents an approach where the process of RE is seen as a business process, and introduces principles of Business Process Management (BPM) in order to increase its performance. Initially, the traditional process of ER is considered, according the SWEBOK, as the initial model (As Is). Then a desirable process (To Be) is defined and modeled, with the introduction of strategic and performance management principles. The first provides an increased effectiveness for obtaining the requirements alignment with organizational goals and business process. The second allows a process quantitative control by measuring and monitoring of performance indicators parameters.", "url": "artigos/artigos_WER12/wer201212.html"}, {"title": "Uma Apoio Sistematizado à Implementação do Processo de Desenvolvimento de Requisitos do MPS.BR e CMMI a partir do Uso de Ferramentas de Software Livre", "authors": ["Ewelton Y. C. Yoshidome", "Maurício R. de A. Souza", "Wallace M. P. Lira", "Sandro R. B. Oliveira", "Alexandre M. L. de Vasconcelos"], "year": 2012, "keywords": "Software Quality; MPS.BR; CMMI; Requirements Development; Free Software Tools.", "abstract": "To meet the market demands and ensure competitiveness, the search for quality has become a strategic goal for many companies, so the search for quality models becomes necessity. In this context, this paper proposes a tool support for implementation of Requirements Development process included in MPS.BR and CMMI programs, exclusively using free software tools, analyzing adherence to the maturity programs and trying to reduce the time and cost of its implementation.", "url": "artigos/artigos_WER12/wer201213.html"}, {"title": "Verificação de Requisitos de Transparência em Modelos iStar", "authors": ["Joás Weslei Baía", "José Luis Braga", "Leonardo Fonseca de Carvalho"], "year": 2012, "keywords": "Framework iStar; transparência de software; verificação de modelos de requisitos.", "abstract": "A transpar&ecircncia de software &eacute um requisito n&atildeo funcional que os engenheiros de software precisar&atilde o demonstrar &agrave medida que a sociedade exigir transpar&ecircncia nas rela&ccedil&otildees com seus representantes, pois essas relaÃ§&ccedil&otildees s&atildeo automatizadas por software. Nesse sentido a verifica&ccedil&atildeo da presen&ccedila de transpar&ecircncia em modelos de requisitos de software &eacute a abordagem utilizada nesse trabalho. Esses modelos representados com o framework iStar s&atildeo verificados utilizando a linguagem CLIPS atrav&eacutes da aplica&ccedil&atildeo de regras de produ&ccedil&atildeo implementadas a partir das caracterÃ­sticas do iStar que possibilitam identificar os requisitos de transpar&ecircnncia. O modelo de requisito &eacute inicialmente representado no formato iStarML e transformado em fatos formando assim a base de dados do sistema de verifica&ccedil&atildeo. Essa base de dados Ã© submetida juntamente com a base de conhecimento ao motor de infer&ecircnncia CLIPS para extrair da especifica&ccedil&atildeo de requisitos o conhecimento impl&iacutecito sobre os requisitos de transpar&ecircnncia.", "url": "artigos/artigos_WER12/wer201214.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2013)", "authors": ["Nelly Condori Fernández", "Leandro Antonelli"], "year": 2013, "keywords": "", "abstract": "Welcome to the sixteenth edition of the Workshop on Requirements Engineering series (WER 13) collocated at the Ibero-American Conference on Software Engineering (CibSE 13) and to be held in Montevideo, Uruguay. WER 2013 continues with the tradition of previous editions, providing an active forum for researchers and practitioners. Although the workshop started as a meeting in order to consolidate the Ibero-American community of researchers on requirements engineering, over the last years, WER has also attracted attention of researchers from other parts of the world as well.", "url": "artigos/artigos_WER13/wer201300.html"}, {"title": "25 years of Requirements Engineering in Brazil: a systematic mapping", "authors": ["Karolyne Oliveira", "João Pimentel", "Emanuel Santos", "Diego Dermeval", "Gabriela Guedes", "Jaelson Castro", "Fernanda Alencar", "Carla Silva", "Cleice Souza", "Monique Soares"], "year": 2013, "keywords": "", "abstract": "The celebration of 25th anniversary of the Brazilian Symposium of Software Engineering (SBES) as well as the forthcoming Requirements Engineering Conference to be held in Brazil for the first time, has led us to have a closer look at the local Requirements Engineering (RE) Community. A systematic mapping was performed in order to find out the main Brazilian research groups, authors as well as their topics of interest and publications with greatest impact. This information may be useful for those that do not know well the local requirements engineering community, such as local newcomers or foreign researchers. It may also help to identify potential groups for collaboration. Similarly, it may provide valuable information to assist local agencies when granting research funds.", "url": "artigos/artigos_WER13/wer201301.html"}, {"title": "A Semi-Automatic Strategy to Identify Crosscutting Concerns in PL-AOVgraph Requirement Models", "authors": ["Maíra Medeiros", "Lyrene Silva", "Ana Luisa Medeiros"], "year": 2013, "keywords": "", "abstract": "The Requirements Engineering area faces problems because the requirements are often ambiguous, incomplete or confusing. These points are commonly obscured by the natural language, which abstracts the complexity of interactions among requirements. However, these interactions need to be an alyzed because they influence on how the software development life-cycle activities can be modularized from a well formulated and concise requirements description. In this context, PL-AOVgraph is an aspect-oriented requirement modeling language, which offers support to represent relationships among concerns and provides separation of crosscutting concerns. However, in order to identify these crosscutting concerns in PL-AOVgraph, there are only some heuristics, which help analysts to perform this activity manually. Therefore, this paper proposes a semi-automatic strategy to identify crosscutting concerns in PL-AOVgraph models. This strategy is based on analysis of an adjacency ma-trix composed of the relationships among requirements. In order to evaluate this strategy, a case study is applied.", "url": "artigos/artigos_WER13/wer201302.html"}, {"title": "Analyzing the Use of an Enterprise Model as a Stakeholder Requirements Model: An Experiment", "authors": ["Fábio Levy Siqueira", "Paulo Sergio Muniz Silva"], "year": 2013, "keywords": "", "abstract": "There are several possible representations for stakeholder requirements, such as goal models, scenarios, and natural language. This paper analyzes the use of an enterprise model as a stakeholder requirements model. We conducted a quasi-experiment with 29 graduate students who received either a textual problem statement or an enterprisemodel, representing the stakeholder requirements, and refined it into use cases, representing the software requirements. The subjects were evaluated considering the use case quality and the time spent, for two different scopes. The results indicate that the mean quality of the use cases created using an enterprise model was equal to or greater than the mean quality of the use cases created by the other groups. In addition, the mean time spent to create a use case using an enterprise model was equal to or less than the mean time needed for the other groups.", "url": "artigos/artigos_WER13/wer201303.html"}, {"title": "Buenas prácticas en la especificación del dominio de una aplicación", "authors": ["Leandro Antonelli", "Gustavo Rossi", "Julio Leite", "Alejandro Oliveros"], "year": 2013, "keywords": "", "abstract": "La ingenieria de requerimientos es un area critica en el desarrollo de software y particularmente lo es la especificacion de requerimientos. Se pueden construir productos tecnologicamente adecuados perosi ellos no cumplen con los requerimientos carecen de utilidad. Sin embargo, no es una tarea sencilla el construir una especificacion correcta que describa y logre transmitir el conocimiento, necesidades y deseos de los stakeholders. Por este motivo, es necesario contar con guias que faciliten la tarea de escribir especificaciones de requerimientos. En este artÃ­culo, se presentan una serie de guias que tienen por objetivo mejorar la descripcion del Lexico Extendido del Lenguaje (LEL). La identificacion de las guias se realizo durante un ejercicio de escritura del LEL en donde se recurrio a la literatura para identificar las guias a aplicar como buenas practicas, y finalmente se realizo un experimento para verificar la interpretacion de las especificaciones realizadas utilizando las buenas practicas propuestas.", "url": "artigos/artigos_WER13/wer201304.html"}, {"title": "Correcciones semánticas en métodos de estimación de completitud de modelos en lenguaje natural", "authors": ["Claudia Silvia Litvak", "Graciela Dora Susana Hadad", "Jorge Horacio Doorn"], "year": 2013, "keywords": "", "abstract": "La Ingenieria de Requisitos tiene como objetivo producir requisitos de alta calidad, poniendo especial interes en la completitud de los modelos elaborados. Establecer si la informacion elicitada y modelada es suficiente para construir un software que cubra las necesidades del cliente es una cuestion de dificil respuesta. Existen algunos intentos realizados en ese sentido, tal como una adaptacion del metodo decaptura-recaptura para estimar el tamano de modelos de requisitos escritos en lenguaje natural. Basados en dicho trabajo y considerando la naturaleza de estos modelos, proponemos introducir un analisis semantico previo a estimar el tamano, dado que el metodo predictivo solo contempla aspectos formales y cuantitativos. Dicho analisis semantico estudia la relevancia, pertenencia, sinonimia y homonimia del contenido textual del modelo. Comparando los resultados estadÃ­sticos detrabajos precedentes contra los obtenidos realizando correcciones semanticas, concluimos que estas son beneficio-sas para la estimacion dela completitud de modelos en lenguaje natural.", "url": "artigos/artigos_WER13/wer201305.html"}, {"title": "GT4CCI: An Approach Based on Grounded Theory for Crosscutting Concerns Identification in Requirements Documents", "authors": ["Larissa de Alencar Sobral", "Lyrene Fernandes da Silva"], "year": 2013, "keywords": "", "abstract": "When crosscutting concerns identification is performed on the activi-ties involved in requirements engineering there aremany gains in terms of qual-ity, cost and efficiency throughout the lifecycle of software development. However, despite these gains, this identification faces several difficulties such as the lack of systematization and tools that support it and the difficult to justify why some concerns are identified as crosscutting or not, since this identification is often made without any methodology that systematizes and bases it. In this context, this paper proposes and evaluates an approachbased on Grounded Theory, called GT4CCI, for systematizing the process of identifying crosscutting concerns in requirements document. Through the use of GT4CCI it is possible to better modularize the requirements document, make it more consistent, detect possible failures and improve traceability among requirements, adding significant gains in terms of quality and reliability to crosscutting concerns identification and to requirements engineering.", "url": "artigos/artigos_WER13/wer201306.html"}, {"title": "Introducing Use Cases in a small Organization: An Experience and Lessons Learned", "authors": ["Dolors Costal", "Xavier Franch", "Luis Delgado", "Carme Jiménez"], "year": 2013, "keywords": "", "abstract": "In this paper we report the adoption of use cases by a small organization in a university setting. Use cases were first introduced in the middle of a huge project and adopted thereafter for later projects. The paper mostly focuses in the first experience, whose most interesting characteristics were the large size of the resulting specification, the fact that it took place once the project had started (for documentation purposes instead of driving the development) and the limitation that resources allocated were not as much as required. We present the lessonslearned from this experience.", "url": "artigos/artigos_WER13/wer201307.html"}, {"title": "Quality Properties Evaluation for Software Requirements Specifications: An Exploratory Analysis.", "authors": ["Roxana Saavedra", "Luciana Ballejos", "Mariel Ale"], "year": 2013, "keywords": "", "abstract": "Most software problems arise from deficiencies in the manner in which software requirements are elicited and expressed. Ensuring that the Soft-ware Requirements Specification document (SRS) has the necessary quality is crucial to the success of any software development project, since its information is used across all project stages. However, assessing the quality of a SRS is not a simple process, mainly by the multitude of proposals, often contradictory, of the attributes to be evaluated and the methodologies used for that purpose. This work is intended to be a compendium of the most important tendencies and strategies in the field that serves as a starting point for developing comprehen-sive models and tools for quality attributes evaluation in a SRS.", "url": "artigos/artigos_WER13/wer201308.html"}, {"title": "Retrospective and Trends in Requirements Engineering through the WER", "authors": ["Joselaine Valaski", "Wilian Stancke", "Sheila Reinehr", "Andreia Malucelli"], "year": 2013, "keywords": "", "abstract": "This work refers to the review of 258 papers published in the WER throughout 15 editions. This reviewÂ´s goal was to identify the most active re-search groups within this workshop, the most debated topics and the trends in the Requirements Engineering area. The results showed that Brazil, Argentina and Spain hold the most active groups. Moreover, the results pointed out the re-quirements modeling as one of the most discussed topics in this event.", "url": "artigos/artigos_WER13/wer201309.html"}, {"title": "Uma Abordagem para Engenharia de Requisitos no Domínio de Software Embarcado", "authors": ["Milena Rota Sena Marques", "Eliane Siegert", "Lisane de Brisolara"], "year": 2013, "keywords": "", "abstract": "Este artigo apresenta uma abordagem para engenharia de requisitos orientada a modelos para o dominio de software embarcado. Para suportar a modelagem e a gerencia dos requisitos sÃ£o utilizadas as linguagens de modelagem UML, SysML e o perfil MARTE, todos padroes da OMG. Desta forma, a abordagem permite a completa modelagem de requisitos funcionais e nÃ£o funcionais frequentes no dominio de sistemas embarcados, alem da gerencia desses requisitos desde a especificacao ate a validacao. Um estudo de caso e usado para demonstrar a abordagem proposta.", "url": "artigos/artigos_WER13/wer201310.html"}, {"title": "Una estrategia de integración de  Modelos de Objetivos con Análisis Comunicacional", "authors": ["Maria Carmen Leonardi", "Roxana Giandini"], "year": 2013, "keywords": "", "abstract": "El Analisis Comunicacional (CA del ingles Comunicational Analysis) es un metodo basado en la comunicacion para elmodelado de proceso de negocio y requisitos que propone el analisis de lossistemas de informacion desde una perspectiva comunicacional. Este metodo se basa en analizar los flujos de informacion. En un contexto de desarrollo To-Be, donde no se cuenta con documentacion previa para analizar, este tipo de perspectiva puede ser complementada con un modelo motivacional, comenzado el proceso de analisis desde una perspectiva de objetivos de la organizacion, hasta llegar a modelar lo que se quiere hacer concretamente. Este trabajo propone una estrategia de integracion entre CA y un modelo de objetivos. Esta integracion permitira captar la intencionalidad y objetivos de la organizacion en sus diferentes niveles de abstraccion, dandole racionalidad al sistema y alineando los procesos con los objetivos.", "url": "artigos/artigos_WER13/wer201311.html"}, {"title": "Uso de sinônimos na identificação de atributos de transparência", "authors": ["Joas Baia", "José Luis Braga"], "year": 2013, "keywords": "", "abstract": "A transparencia e um principio democratico que permite aos cidadaos buscarem informacoes sobre fatos e processos. Nesse contexto, ocorre o aumento da demanda por transparencia nas relaÃ§Ãµes humanas. A transparencia de software e um requisito nao funcional que engenheiros de software precisarao demonstrar a medida que a sociedade exigir transparencia em suas relaÃ§oes, pois essas relacoes sao automatizadas pelos sistemas de software. Diante da importancia de demonstrar a transparencia nos processos de informacao, propoe-se nesse trabalho verificar a presenca de atributos de transparencia em modelos de requisitos de software representados com o Framework iStar, utilizando os termos que representam os requisitos e tambem seus sinonimos mais conhecidos. O modelo de requisitos e analisado utilizando uma base de dados contendo sinonimos dos atributos de transparencia, em adicao aos conceitos do iStar para identificar esses atributos.", "url": "artigos/artigos_WER13/wer201312.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2014)", "authors": ["Giovanni Giachetti", "Marcia Lucena"], "year": 2014, "keywords": "", "abstract": "Welcome to XVII Edition of the Requirements Engineering Workshop (WER 2014) held at Pucón, Chile; organized by the University of La Frontera, from 23th to 25th of April 2014.", "url": "artigos/artigos_WER14/wer201400_1.html"}, {"title": "Table of Contents", "authors": ["Giovanni Giachetti (UNAB - Chile)", "Márcia Lucena (UFRN - Brazil)"], "year": 2014, "keywords": "", "abstract": "Table of Contents.", "url": "artigos/artigos_WER14/wer201400_2.html"}, {"title": "Abstract security patterns for requirements specification and analysis of secure systems", "authors": ["Eduardo B. Fernandez", "Nobukazu Yoshioka", "Hironori Washizaki", "Joseph Yoder"], "year": 2014, "keywords": "", "abstract": "During the requirements and analysis stages of software development, the primary goal is to define precise requirements rather than being concerned with the details of software realizations. Security is a semantic aspect of applications and their constraints on the application should de described at this moment. From a security point of view we only want to indicate which specific security controls are needed, rather than getting involved with low-level design and implementation details. Therefore, at these stages, it is useful to have a set of patterns which define abstract security mechanisms. These patterns should specify only the fundamental characteristics of thesecurity mechanism or service, not specific software aspects. We present theconcept of Abstract Security Pattern (ASP), which describes a conceptual security mechanism that realizes one or more security policies able to handle a threat or comply with a securityrelated regulation or institutional policy. We present a detailed example of an ASP. We relate ASPs to each other using pattern diagrams as well as to Security Solution Frames and tactics. Finally, we discusstheir value for defining security requirements and for building secure systems.", "url": "artigos/artigos_WER14/wer201401.html"}, {"title": "Engenharia de Requisitos: Um Survey realizado no Porto Digital, Recife/Brasil.", "authors": ["Darlan Arruda", "Rafael Soares", "Dércio Vieira", "Rafael Ferreira", "Thiago Cabral", "Maria Lencastre"], "year": 2014, "keywords": "Engenharia de Requisitos; Porto Digital; Survey", "abstract": "Esse artigo teve como objetivo realizar uma pesquisa com empresas de tecnologia situadas no Porto Digital com o intuito de identificar como essas empresas lidam com a atividade de engenharia de requisitos. Para a realização da pesquisa de campo, usou-se como base um estudo já realizado na indústria nos Estados Unidos pela Jama Software em parceria com a RavenFlow. Após estudo, foram analisados os dados obtidos e, em seguida, uma análise comparativa entre os surveys foi realizada.", "url": "artigos/artigos_WER14/wer201402.html"}, {"title": "Extração de casos de teste a partir de modelos de processos de negócio", "authors": ["Henrique Prado Sousa", "André Luiz de Castro Leal", "Arndt von Staa", "Julio Cesar Sampaio do Prado Leite"], "year": 2014, "keywords": "casos de teste; suíte de teste; software; processosde negócio; BPM.", "abstract": "A modelagem de processos de negócio é um recurso que vem sendo empregado com diversas finalidades, entre as quais, planejamento e alinhamento estratégico. Na engenharia de requisitos, os modelos de processos de negócio também são utilizados como insumos na extração de requisitos de software, os quais deverão ser utilizados com base para testes posteriores. Neste sentido, propomos um método de extração de suítes de testes a partir de modelos de processo de negócio. A identificação dos casos de testes é baseada na junção de heurísticas de identificação de requisitos e novas heurísticas inspiradas em métodos de geração de casos de testes a partir de casos de uso e diagrama de estados. O produto é uma suíte de casos de teste definida ainda nas fases iniciais do desenvolvimento, com base em informações de contexto.", "url": "artigos/artigos_WER14/wer201403.html"}, {"title": "Managing requirements@run.time with a linguistic decision making approach?", "authors": ["Romina Torres", "Hernan Astudillo"], "year": 2014, "keywords": "correctness criteria; requirements@run.time; linguistic decision making models", "abstract": "In the seminal work about requirements, Zave and Jackson established that if specication models hold the correctness criteria then, they can be used instead of requirements to make decisions (e.g. select an architectural conguration to implement requirements). Unfortunately, during runtime for systems under changing environments, domain assumptions may change and if they are not properly maintained (synchronized) the correctness criteria may becomes not useful to detect when the specication model is not anymore a valid representation of requirements. Thus, requirements may be violated but not properly detected. In order to avoid specication models become obsolete during runtime, we already proposed reify requirements into abstract specication models. In this paper we extend the correctness criteria to requirements@run.time and we propose specically the linguistic decision making (LDM) models to represent these abstract models. We present an illustrative example of how our approach works. The main contribution of this approach is obtained during runtime, when the false negative rate error on determining when requirements are violated is reduced.", "url": "artigos/artigos_WER14/wer201404.html"}, {"title": "Modelo orientado à meta para estabelecer relações de contribuição mútua entre Proveniência, Transparência e Confiança", "authors": ["André Luiz de Castro Leal", "Henrique Prado Sousa", "Julio Cesar Sampaio do Prado Leite"], "year": 2014, "keywords": "Transparência; Proveniência; Confiança; modelo; requisito não funcional; softgoal; NFR framework", "abstract": "Estabelecer modelos de determinado domínio é um dos princípios básicos para uma construção de software com qualidade. Estes modelos facilitam a compreensão de realidades complexas, seus detalhes e interações de suas partes. Entre várias características, a Engenharia de Requisitos Orientada a Metas (GORE) sugere a modelagem de objetivos para expressar a razão das necessidades dos requisitos. O presente trabalho propõe um modelo baseado em GORE para estabelecer, além de detalhes sobre determinados requisitos não funcionais, elos de contribuição positiva entre eles. O estudo é feito com base na inter-relação entre as características de Proveniência, Transparência e Confiança.", "url": "artigos/artigos_WER14/wer201405.html"}, {"title": "NDR-Tool: Uma Ferramenta de Apoio ao Reuso de Conhecimento em Requisitos Não Funcionais", "authors": ["Alex Lins de Araújo", "Luiz Marcio Cysneiros", "Vera Maria B. Werneck"], "year": 2014, "keywords": "NFR-Framework; Ontology; NDR; NDR-Tool; NFR", "abstract": "Non-functional requirements (NFR) are fundamental for the software development. The NFR- Framework allows the elicitation to deeply cover necessary trade-offs involving synergetic and conflicting solutions. It also favor the capture of design decisions involving the reasons that lead one to choose between one alternative and another to implement a NFR. This work proposes and describes the NDR-Tool, a tool that supports the software engineer in the requirements elicitation and modelling process. This tool proposes the use of ontologies and web semantics techniques to facilitate storing and retrieving knowledge related to possible alternatives to implement NFR. The tool NDRTool was developed and integrated with a tool for modeling NFR diagrams. As proof of concept we used the tool in the medical field.", "url": "artigos/artigos_WER14/wer201406.html"}, {"title": "NòmosBPMN: Adaptando o Nòmos para a Modelagem de Processos de Negócio", "authors": ["Hidelberg Albuquerque", "Carla Silva", "Danielle Rousy"], "year": 2014, "keywords": "Requirements Engineering; Business Process Modeling; Nòmos; Law; Legal Compliance; Legal Requirements", "abstract": "O Framework Nòmos estende o framework i* para alcançar a conformidade legal dos requisitos de software. Um requisito legal é uma exigência expressa nas normas jurídicas e imposta por departamentos governamentais. O não-cumprimento de um requisito legal por parte de um software pode acarretar transtornos legais e financeiros às empresas e suas soluções. Para realizar a Engenharia de Requisitos efetivamente, é necessário conhecer e entender os processos de negócio. São eles que definem como as atividades da empresa são executadas para alinhar seus negócios aos objetivos estratégicos organizacionais. Assim, tanto os processos de negócio como os softwares que os apoiam devem estar em conformidade legal com as normas jurídicas existentes num determinado domínio de aplicação. Devido à ampla adoção do BPMN na indústria e na academia, este trabalho propõe uma adaptação do Nòmos para a modelagem de processos de negócio em BPMN (ao invés de usar exclusivamente o i*).", "url": "artigos/artigos_WER14/wer201407.html"}, {"title": "Prácticas de Ingeniería de Requerimientos en el desarrollo de aplicaciones Web", "authors": ["Alejandro Oliveros", "Fernando J. Danyans", "Matías L. Mastropietro"], "year": 2014, "keywords": "Requerimientos Aplicaciones Web; Procesos de la Ingeniería de Requerimientos; Investigación exploratoria", "abstract": "El rápido crecimiento del desarrollo de las aplicaciones Web no ha sido acompañado por estudios detallados de las particularidades de la Ingeniería de Requerimientos de aplicaciones Web. Las organizaciones de desarrollo han asumido algunas prácticas que no han sido suficientemente investigadas por la comunidad de Ingeniería de Requerimientos. En este artículo se presentan los resultados de una investigación exploratoria de las prácticas de ingeniería de requerimientos en el desarrollo de aplicaciones Web. Se ha logrado establecer un primer panorama del estado de la Ingeniería de Requerimientos en el desarrollo de aplicaciones Web. Basado en estos resultados se establecen recomendaciones para desarrollar una investigación de mayor validez.", "url": "artigos/artigos_WER14/wer201408.html"}, {"title": "Semantic Documentation in Requirements Engineering", "authors": ["Ricardo de Almeida Falbo", "Carlos Eduardo C. Braga", "Bruno Nandolpho Machado"], "year": 2014, "keywords": "Requirements engineering; requirements documentation; semantic documentation; semantic annotation; semantic document; ontologies", "abstract": "Currently, most requirements documents are prepared using desktop text editors. These documents are intended to be used by human readers. In this paper, we discuss the use of semantic annotations in requirements documents, in order to make information regarding links between requirements and other software artifacts, such as other requirements, use cases, classes and test cases, interpretable by computers. To do that, we extend a semantic document management platform to the requirements domain, and explore the conceptualization established by the Software Requirements Reference Ontology in order to provide features to support some activities of the Requirement Engineering Process, namely: prioritizing requirements, analyzing impacts from requirements changes, tracing requirements through traceability matrices, and verifying requirements using checklists.", "url": "artigos/artigos_WER14/wer201409.html"}, {"title": "Um modelo de features para jogos sérios voltados à saúde: uma abordagem baseada em linha de produtos de software", "authors": ["Danilo Tavares", "Carla Silva", "Danielle Rousy"], "year": 2014, "keywords": "Engenharia de Requisitos; Jogos Sérios; Linhas de Produtos de Software", "abstract": "Há uma crescente demanda por jogos sérios capazes de aprimorar ou treinar habilidades em profissionais ou estudantes em várias áreas do conhecimento. De fato, jogos sérios são capazes de representar situações reais em ambientes virtuais e permitem apresentar novas situações, discutir soluções e treinar atividades particulares. Diante do grande leque de aplicações de jogos sérios, esta pesquisa focou em jogos sérios voltados à reabilitação. Atualmente, há um grande interesse em usar este tipo de jogo em hospitais, clínicas e universidades. Aplicações que pertencem ao mesmo segmento de mercado e que possuem um grande número de características comuns, podem ser desenvolvidas como uma linha de produtos de software (LPS). Portanto, esta pesquisa visa definir jogos sérios voltados à reabilitação como uma LPS. Assim, foi realizada uma revisão sistemática sobre jogos desse tipo, a fim de capturar características comuns e específicas dos vários jogos encontrados na revisão. Como resultado, um modelo de features para jogos voltados à reabilitação foi definido para capturar as suas características, visando aumentar o reuso estratégico dos seus artefatos de software.", "url": "artigos/artigos_WER14/wer201410.html"}, {"title": "Uma Abordagem Colaborativa de Modelagem Conceitual de Informação utilizando Mind Maps", "authors": ["Rafael Duarte", "José Júnior", "Ruben Araújo", "Fernando Wanderley", "Maria Lencastre"], "year": 2014, "keywords": "Requirements Engineering; Collaborative Elicitation; Conceptual Modeling; Mind Maps.", "abstract": "Recent studies have shown that the existence of a poor requirements elicitation or the lack of this activity, during the information system development, have generated a series of system failures and resulted in unsatisfied customers. Among several reasons, the no user participation in the conceptual modelling process stands out. Another important issue is considering the need for creating a conceptual model with the integration of various viewpoints, from different stakeholders. In this context, this paper has two main goals: the first one is trying to make the modeling process more inclusive for the customers/stakeholders, during the conceptual modeling, through the adoption of cognitive models such as Mind Maps; the second one, is trying to consolidate the multiple perspectives of the resulting conceptual models (each from a different stakeholder) using merge techniques. The expected result is to obtain ubiquitous conceptual models with higher quality.", "url": "artigos/artigos_WER14/wer201411.html"}, {"title": "Uso Do Design Thinking Na Elicitação De Requisitos De Ambientes Virtuais De Aprendizagem Móvel", "authors": ["Cynara Lira de Carvalho Souza", "Carla Silva"], "year": 2014, "keywords": "mobile learning; ambiente virtual de aprendizagem móvel; desing thinking; engenharia de requisitos", "abstract": "Mobile Learning (m-learning) é o campo de pesquisa que busca analisar como os dispositivos móveis podem colaborar para a aprendizagem. O desenvolvimento de softwares para dispositivos móveis que atuem como recursos pedagógicos é essencial para a efetiva implantação do m-learning ou ambiente virtual de aprendizagem móvel (AVAM). Processos de engenharia de requisitos para AVAMs precisam de fato impactar o ambiente de ensino e aprendizagem. Para tanto, estes processos precisam incluir atividades que provoquem o uso de técnicas de criatividade, de forma a conceber a criação de AVAMs que de fato modifiquem e melhorem o processo de ensino e aprendizagem. Nesse contexto, o presente artigo apresenta um processo de elicitação e documentação de requisitos para ambientes virtuais de aprendizagem móvel. Este processo se baseia nos conceitos do processo do Design Thinking que fornece uma metodologia para provocar as necessidades dos clientes, produzindo protótipos rápidos e simples que eventualmente convergem para soluções inovadoras.", "url": "artigos/artigos_WER14/wer201412.html"}, {"title": "A Collaborative Approach to Capture the Domain Language", "authors": ["Leandro Antonelli", "Gustavo Rossi", "Alejandro Oliveros"], "year": 2015, "keywords": "Domain Analysis; Language Extended Lexicon; Collaboration", "abstract": "Software development is a succession of descriptions in different languages where a previous description is necessary for the next one. Thus, it is important to begin software development with requirements that are as correct and as complete as possible. Although some literature holds the belief that correctness and completeness are two attributes that requirements specifications must satisfy, we know that these attributes are very difficult to meet. However, we have to find ways to diminish the level of incompleteness and deal with the possible conflicts that do arise in the requirements context. Defining the domain language before specifying the requirements is a way of coping with this problem. Nevertheless, it is hard to produce a domain language specification when there are many stakeholders involved. We rely on collaboration in order to foster the cooperation of the stakeholders, thus they are able to explore the differences constructively and search for solutions that go beyond their own limited views. In this paper, we propose a strategy to capture the domain language in a collaborative way using Language Extended Lexicon and we show a preliminary validation of the proposed strategy", "url": "artigos/artigos_WER15/wer201501.html"}, {"title": "Extração de requisitos apoiada por técnicas de Inteligência Artificial embutidas em ferramentas de apoio", "authors": ["Cristiane Aparecida Lana", "Lucas Gonçalves Cunha", "José Luis Braga", "Antônio de Pádua Albuquerque Oliveira"], "year": 2015, "keywords": "Knowledge-based systems; iStar; softgoals and hardgoal; Léxico", "abstract": "A linguagem peculiar e a pluralidade de visões distintas exigem conhecimento e experiência do engenheiro de requisitos para o sucesso da atividade de extração de requisitos em domínios específicos. Neste trabalho, são apresentadas as ferramentas i*Get e TEKBS, que utilizam técnicas de inteligência artificial para auxiliarem o engenheiro de requisitos na extração de metas concretas e flexíveis, no contexto de iStar. A i*Get utiliza as ações concretas definidas no LAL enquanto a TEKBS as ações flexíveis combinadas com os sinônimos dos termos que representam essas ações, obtidos a partir do Wordnet. Os resultados são transformados em base de fatos da ferramenta CLIPS, e então processados usando uma base de regras de análise disparadas pela máquina de inferência do CLIPS. Resultados preliminares mostram que um número maior de requisitos são extraídos pelo engenheiro, melhorando o conhecimento sobre o domínio.", "url": "artigos/artigos_WER15/wer201502.html"}, {"title": "Improving Quality Model Construction Through Knowledge Reuse", "authors": ["Juan Pablo Carvallo", "Xavier Franch", "Carme Quer"], "year": 2015, "keywords": "Modelling; Knowledge Reuse", "abstract": "Software quality models provide a framework to measure and evaluate software quality of software systems. They are the basis upon which classify requirements and may be eventually used to guide the quantification of these requirements, especially non-functional requirements. Lots of approaches for building quality models have been proposed in the last decades, but still their reuse along different projects is a challenge. In this paper we present several types of knowledge repositories and reuse processes to bridge this gap. The approach implements the idea of software factory and uses some well-known standards and notations like ISO/IEC 25010 as quality standard and the i* framework to codify knowledge patterns. We will illustrate how this reusebased approach helps in obtaining composite quality models for systems that integrate several software components with an individual quality model each.", "url": "artigos/artigos_WER15/wer201503.html"}, {"title": "Criatividade Combinacional para Geração de Requisitos Inovadores: Um Relato de Experiência", "authors": ["Rafael Pinto", "Lyrene Silva", "Marcia Lucena", "Ilueny Santos"], "year": 2015, "keywords": "Elicitación de requerimientos; investigación experimental; evolución de la práctica", "abstract": "A Engenharia de Requisitos tem buscado, através de técnicas de criatividade, fornecer meios para elicitação de requisitos úteis e inovadores. Dentre as técnicas disponíveis, há a de Criatividade Combinacional, que visa produzir novas ideias através da associação de ideias antigas utilizando caminhos não familiares. O presente trabalho tem por objetivo propor uma estratégia baseada na técnica de criatividade combinacional para criar novos requisitos, utilizando como fonte de dados a documentação do próprio sistema. Nossa abordagem foi experimentada por alunos de um curso de Bacharelado em Engenharia de Software da Universidade Federal do Rio Grande do Norte (UFRN). Ao analisar as respostas, constatamos que 44 porcento das ideias propostas pelos participantes podem ser classificadas como originais e relevantes para o sistemaDessa forma, os resultados mostram que nossa estratégia pode enriquecer abordagens existentes de forma a complementar a extração de requisitos.", "url": "artigos/artigos_WER15/wer201504.html"}, {"title": "Fuentes y técnicas para elicitación de requerimientos. Un estudio de evolución de la práctica", "authors": ["Alejandro Oliveros", "Leandro Antonelli"], "year": 2015, "keywords": "Elicitación de requerimientos; investigación experimental; evolución de la práctica", "abstract": "La identificación las prácticas de Ingeniería de Requerimientos (RE) en la comunidad de desarrollo de software es un aspecto clave para la orientación de las investigaciones y el desarrollo de las actividades académicas en general. En particular la evolución de esas prácticas es una herramienta de orientación en proyectos nuevos de investigación. Si bien se dispone de ejemplos de estudio de las prácticas de RE en general, el proceso de elicitación de requerimientos a menudo se encuentra fuera del alcance de esas investigaciones. En parte la evolución de esas prácticas RE en el tiempo no dispone de un número relevante de estudios. En este artículo se informa una investigación de la evolución de las prácticas de elicitación de requerimientos de desarrolladores de software de la Argentina entre 2001 y 2014. La investigación se concentró en la utilización y/o conocimiento de técnicas de elicitación y de fuentes de requerimientos. Los resultados obtenidos permiten identificar algunos aspectos positivos de la evolución en la línea de desarrollo de RE y otros que sugieren una visión más pesimista que la que trasmite la literatura. La metodología utilizada consistió en un realizar un survey entre estudiantes de un curso de maestría en Ingeniería de Software del año 2014, que es una réplica del survey realizado en el mismo curso en el año 2001.", "url": "artigos/artigos_WER15/wer201505.html"}, {"title": "La Gestión del Conocimiento Aplicada en la Ingeniería de Requisitos: Un Caso de Estudio en Ecuador", "authors": ["Cecilia Hinojosa", "Geovanny Raura", "Efrain R. Fonseca C", "Oscar Dieste"], "year": 2015, "keywords": "Ingeniería de requisitos; Gestión del conocimiento; An´alisis de requisitos; Ingeniería de Software; Caso de Estudio", "abstract": "Antecedentes: La Ingeniería de requisitos (IR) es una de las fases más críticas dentro del proceso de desarrollo de software, ya que en ésta se definen las características del producto a ser construido. Sin embargo, las técnicas utilizadas en la IR no han sido lo suficientemente efectivas para asegurar la calidad de los requisitos. La Gestión del Conocimiento (GC) busca el mejoramiento de los procesos de negocio de una organización, a través de la incorporación de nuevas experiencias e información y su adecuado uso para la toma de decisiones. Las dos disciplinas (IR y GC) presentan un alto grado de concordancia entre sus atributos de calidad y las fases de su proceso. Por lo tanto, la GC podría perfectamente ayudar a la realización de la IR. Objetivo: Se propone REQ-KM, una técnica para el análisis de requisitos de software basada en gestión del conocimiento, en procura de la mejora de la calidad y efectividad de los requisitos. REQ-KM basa su procedimiento en la determinación de la validez y utilidad de la información recolectada en la elicitación de requisitos, de la mano con la gestión del conocimiento del dominio del problema. Metodología: El método utilizado para desarrollar REQ-KM partió de un estudio comparativo de los conceptos y procesos fundamentales de la IR y la GC, para determinar elementos coincidentes y divergentes. Dicho análisis permitió ampliar las técnicas de análisis de requisitos existentes, incorporando aspectos útiles de la GC que no han sido consideradas antes en la IR, como por ejemplo: análisis de la calidad de las fuentes de información, contraste de la lista de requisitos resultantes de la elicitación con mapas mentales o conceptuales del dominio del problema, etc. REQ-KM fue validada en una empresa ecuatoriana de desarrollo de software, siguiendo los lineamiento del método empírico de caso de estudio. Resultados: La aplicación de REQ-KM en el proceso de ingeniería de requisitos resultó beneficiosa de acuerdo al criterio de los practitioners, quienes evidenciaron una mejora en el proceso de análisis de requisitos y obtuvieron requisitos que cumplen con un mayor número de atributos de calidad. Conclusiones: La incorporación de conceptos de GC al proceso de IR permite mejorar la calidad de los requisitos frente a lo conseguido con aproximaciones tradicionales de la IR.", "url": "artigos/artigos_WER15/wer201506.html"}, {"title": "Elicitação e Especificação de Requisitos em Sistemas Embarcados: Uma Revisão Sistemática", "authors": ["Aêda Sousa", "Josenildo Melo", "Fernanda Alencar", "Celso Agra"], "year": 2015, "keywords": "Engenharia de Requisitos; Elicitação de Requisitos; Especificação de Requisitos; Sistemas Embarcados", "abstract": "A elicitação e especificação de requisitos são fundamentais para que o sistema pretendido funcione de acordo com as necessidades dos stakeholders e às restrições sob as quais se encontre submetido. Os sistemas embarcados têm sido usados em diferentes finalidades (automóveis, medicina, entre outros.). Apesar de avanços em desenvolvimento de sistemas embarcados, são poucas as iniciativas de engenharia de requisitos que atendam ás particularidades desses sistemas. Neste trabalho, foi conduzida uma revisão sistemática da literatura, com o intuito de realizar um diagnóstico mais aprofundado e sistemático sobre a elicitação e especificação de requisitos em sistemas embarcados. Na fase ini-cial da revisão sistemática as strings de busca aplicadas, retornaram 441 traba-lhos. Após aplicação dos critérios de seleção nas fases da condução da revisão e a inclusão de 2 trabalhos manualmente, apenas 15 trabalhos foram identificados e analisados.", "url": "artigos/artigos_WER15/wer201507.html"}, {"title": "Requisitos para Softwares Educacionais Gamificados: Uma Revisão Sistemática de Literatura", "authors": ["Mariana Maia Peixoto", "Carla Silva"], "year": 2015, "keywords": "Gamification techniques; education", "abstract": "Técnicas de gamificação estão sendo inseridas em ambientes educacionais com o objetivo de envolver os usuários dentro do contexto da aprendizagem. No entanto, apesar da sua relevância, não existe um completo e bem definido conjunto de requisitos para ambientes educacionais gamificados. Motivado por este cenário, o presente trabalho realizou uma revisão sistemática de literatura com intuito de investigar características de gamificação para ambientes educacionais e, assim, definir um conjunto de requisitos para serem reusados no desenvolvimento de softwares educacionais gamificados. Como resultado do estudo, reportamos os requisitos descobertos, os tipos das pesquisas realizadas, os anos de publicação e os países dessas pesquisas referentes a ambientes gamificados voltados à educação. Foi observado que ainda não há consenso sobre um conjunto fixo de características que devem existir em softwares educacionais gamificados.", "url": "artigos/artigos_WER15/wer201508.html"}, {"title": "Integrating the E4J editor to the JGOOSE tool", "authors": ["Leonardo Pereira Merlin", "Alexandre Luiz de Borba Silva", "Victor Francisco Araya Santander", "Ivonei Freitas Da Silva", "Jaelson Castro"], "year": 2015, "keywords": "E4J; JGOOSE; i* Framework; Requirements Engineering.", "abstract": "Requirements engineering is an important phase of software engineering. One of the main challenges of the requirements engineering process is the appropriate integration of various artefacts generated. In previous work we proposed a process to generate UML Use Cases from i* (istar) organizational models. It was a supported by the JGOOSE tool, which could transform i* models, generated by a third party tool, into Use Case models and descriptions. This dependence on an external tool, for the creation of the organizational models, was a major shortfall. Thereby, to solve this problem, in this work we present the E4J (Editor for JGOOSE) tool, an editor for i* organizational models integrated to the JGOOSE tool.", "url": "artigos/artigos_WER15/wer201509.html"}, {"title": "Modeling SOA from Organizational Models", "authors": ["Orlando Oliveira", "Carla Silva"], "year": 2015, "keywords": "Arquitetura Orientada a Serviços (SOA); Engenharia de Requisitos Orientada a Objetivos (GORE); Framework i*; SoaML.", "abstract": "Service Oriented Architecture (SOA) provides an architectural model that aims to enhance efficiency, agility, and productivity of companies. In this model, services are the main ways to meet organizational strategic objectives. However, the development of systems that use this style of architecture has required new strategies within the Software Engineering, mainly regarding the discipline of Requirements Engineering (RE). Moreover, GORE (Goal-Oriented Requirements Engineering) approaches obtained notoriety in the past few years. In fact, they introduce mechanisms that are not offered by traditional RE approaches, such as capturing the system stakeholders? goals and the system?s characteristics in the same model. By using this model, it is possible to analyze and identify if the system meets the stakeholders? goals. This is an important kind of analysis in the organizational context. However, there isn?t a systematic way to identify services in goal oriented requirements models. Furthermore, there is still a gap in the transition between the problem space (requirements) and the solution space (architecture) in the context of SOA. Thus, this work presents a systematic approach for identifying services into i* models and subsequently obtaining an architecture described in SoaML.", "url": "artigos/artigos_WER15/wer201510.html"}, {"title": "On the behaviour of context-sensitive systems", "authors": ["Jéssyka Vilela", "Jaelson Castro", "João Pimentel", "Paulo Lima"], "year": 2015, "keywords": "Behavior; Adaptation; Context-sensitive system; Goal Model; Monitoring", "abstract": "Software systems are being used in ever more diverse and dynamic environments where they have to routinely and efficiently adapt to changing environmental conditions. Therefore, they must detect variations in their operating context and adapt their behavior in response to such variations. However, specifying monitoring and adaptation can be difficult due to their dependence on the contextual elements, which need to be made explicit. The variable nature of these systems calls for new approaches to create systems that can adapt to context changes. This paper proposes the GOals to Statecharts (GO2S) process to systematically derive the behavior of context-sensitive systems from requirements models. This is an iterative process centered on the incremental re?nement of a goal model, obtaining different views of the system (design, contextual, behavioral). We illustrate our proposal with the meeting scheduler exemplar and we conducted a controlled experiment in order to evaluate our process. The experiment results show that the structural complexity of the group that used our GO2S approach was lower and the mean of behavioral similarity and the time spent was higher than control group. Besides, the subjects agreed that the GO2S process is easy to use indicating that it is possible to reproduce the process and it is understandable.", "url": "artigos/artigos_WER15/wer201511.html"}, {"title": "A Heuristic Approach for Supporting Innovation in Requirements Engineering", "authors": ["Ricardo André Cavalcante de Souza", "Gilberto Amado de Azevedo Cysneiros Filho", "Glauber Henrique Camelo Batista"], "year": 2015, "keywords": "design; innovative software", "abstract": "The first activity that most software development projects take is to elicit and document the project? requirements. Requirement elicitation is one of the most critical activities in the software development process. The ability to do it well is crucial to the project? success. The experience has shown that poor requirements frequently lead to rework, cost overruns and even project failure. Although several tools, processes, models, methods and frameworks have been developed to help with requirement elicitation, there is much less support for innovation through Requirement Engineering in software product development process. In this paper, we describe an approach to develop innovative software. Innovative software are products that differs of the existing products and that aggregate value. In particular, this work focus on software product that are produced by startups in a context of extreme uncertainty.", "url": "artigos/artigos_WER15/wer201512.html"}, {"title": "Apoio a Configuração de Processos de Negócio Dinâmicos", "authors": ["Tarcísio Pereira", "Fernanda Alencar", "Jaelson Castro", "Edson Alves", "Paulo Lima"], "year": 2015, "keywords": "Configuração de Processo de Negócio; Requisitos Nâo-Funcionais; Informação Contextual; Ferramenta; Metamodelo.", "abstract": "As organizações estão inseridas em ambientes dinâmicos, onde mudanças são constantes graças a fatores geógrafos, climáticos, financeiros e outros. Com isso, as empresas precisam manter seus processos atualizados e funcionando adequadamente, sem desprezar os requisitos de qualidade. Baseado neste cenário, foi proposto na literatura uma abordagem de configuração de processos chamada BVCCoN. Uma etapa desta abordagem e a modelagem dos requisitos não-funcionais, variabilidade e informação contextual. Contudo, modelar estas três perspectivas e uma atividade que consome tempo e propensa a erros. Assim, teste artigo propõe o desenvolvimento de um metamodelo para apoiar a modelagem das três visões citadas anteriormente. Alem disso, foi desenvolvida uma ferramenta baseada no metamodelo que foi criado. Para ilustrar o uso da ferramenta, uma avaliação de usabilidade foi realizada.", "url": "artigos/artigos_WER15/wer201513.html"}, {"title": "Um processo colaborativo para a construção de léxicos: o caso da divulgação de transparência", "authors": ["Priscila Engiel", "Joanna Pivatelli", "Pedro Nuno", "Roxana Portugal", "Julio Cesar Sampaio do Prado Leite"], "year": 2015, "keywords": "Tranparência; LAL; 3C; lexico ampliado da linguagem;", "abstract": "O léxico ampliado da linguagem é uma representação proposta para registrar o vocabulário de um contexto, estendendo o conceito de dicionário denotacional para um léxico circular com denotações e conotações. É uma linguagem utilizada por várias pesquisas para ancorar a modelagem de requisitos na linguagem corrente do contexto. Esse artigo descreve práticas colaborativas criadas para a evolução de um léxico sobre transparência baseada em dois livros clássicos sobre o tema. Diferentes técnicas de colaboração são explicitadas e mapeadas em modelos de colaboração. O uso da ferramenta de edição é analisado. Dessa análise surgiu a necessidade da criação de um software visualizador, justamente para auxiliar na divulgação de léxico para leitores em geral. O trabalho contribui tanto para um melhor compreensão do processo de evolução de léxicos, como para maneiras eficazes de práticas colaborativas durante esse processo.", "url": "artigos/artigos_WER15/wer201514.html"}, {"title": "Trends and Needs in Requirements Engineering Research in Ibero-America", "authors": ["Isabel Sofia Brito", "Jose Luis de la Vara"], "year": 2015, "keywords": "Needs; Trends; Requirements Engineering", "abstract": "Although Requirements Engineering (RE) is a global research area and people from all around the world have contributed to its development, some characteristics distinguish RE research from different regions. For example, North American universities are arguably the main contributors to requirements traceability [4], but not to safety assurance and certification [3]. When referring to research on i* [6], someone would probably associate it to the University of Toronto or the University of Trento, but not to the Université Paris 1 Panthéon-Sorbonne even though its researchers have also significantly contributed to goal-oriented RE (e.g., [5]). These characteristics are indicators of the trends in RE research in different regions. Certain aspects also constrain software development and requirements engineering in specific regions nowadays, such as outsourced software development to India [2] and the safety case regimes in the UK [3]. Other aspects are expected to impact RE research in the near future, such as the introduction of new system and software security regulations in Europe [1]. If these aspects are disregarded, then RE research results will very likely not fulfil the needs in these regions and RE technology transfer will be hindered. We have organised a panel at WER 2015 (18th Workshop on Requirements Engineering) for discussing trends and needs of RE research in Ibero-America. To this end, we aim to answer the following questions: 1. What characteristics in Ibero-America should RE research carefully take into account? 2. What RE topics have been successfully researched in Ibero-America? 3. What RE topics have not been sufficiently researched in Ibero-America? 4. What RE topics should be the main focus of Iberio-American RE research in the future? Three experts will present their opinion on these topics and we expect the panel attendees to also eagerly join the discussion. In addition to the whats, we are strongly interested in knowing why the experts and the attendees consider that certain phenomena have occurred or will occur.", "url": "artigos/artigos_WER15/wer201515.html"}, {"title": "Scalability of istar: a Systematic Mapping Study", "authors": ["Paulo Lima", "Jéssyka Vilela", "Enyo Gonçalves", "João Pimentel", "Ana Holanda", "Jaelson Castro", "Fernanda Alencar", "Maria Lencastre."], "year": 2016, "keywords": "Systematic Mapping study; Scalability; iStar; i*; Goal Models", "abstract": "Since its first proposal in the nineties, the i* framework has been used to requirements specification in many domains, such as healthcare, tele-communication, and air traffic control. After the modeling of different exam-ples and case studies, it has been observed that i* models become dramatically more difficult to understand and analyze as they grow larger. This issue has led us to investigate scalability in the context of the i* framework, by means of a systematic mapping study. A total of 119 papers were analyzed, in order to un-derstand how scalability is perceived by the i* research community, which pro-posals have considered this topic, and what open issues still need to be ad-dressed. We found that scalability issues are indeed perceived as relevant and that further work is still required, even though many potential solutions have al-ready been proposed. This study can be a starting point for researchers aiming to further advance the treatment of scalability in social goal models.", "url": "artigos/artigos_WER16/wer201601.html"}, {"title": "Transformação do modelo i* em user stories: uma abordagem para documentação ágil baseada nas razões, intenções e NFR", "authors": ["Celso Sá Filho", "Denise Assis", "Aêda Sousa", "Aline Jaqueira", "Marcia Lucena", "Teresa Maciel", "Fernanda Alencar."], "year": 2016, "keywords": "métodos ágeis; modelo de transformação; i*; user stories; razões; intenções; requisitos não funcionais; design rationales; engenharia de requisitos orientada a objetivos", "abstract": "Na documentação ágil, razões, intenções e requisitos não funcionais nem sempre são considerados a contento durante o ciclo de vida de desenvol-vimento de um produto. A não consideração desses aspectos pode prejudicar a qualidade do sistema, levando a dificuldades na manutenção e no gerenciamen-to dos requisitos. Para mitigar o problema, este trabalho propõe a transformação do modelo i* (iStar), que naturalmente considera razões, intenções e requisitos não funcionais desde as fases iniciais, através das user stories. A transformação é realizada através de um conjunto de diretrizes que inclui o design rationales na documentação ágil. Para análise da proposta, considerou-se os exemplos propostos por Eric Yu na concepção do i*. Como resultado, é apresentada uma documentação que considera razões, intenções e requisitos não funcionais, evitando assim a construção de requisitos desnecessários e minimizando o impacto das mudanças de requisitos.", "url": "artigos/artigos_WER16/wer201602.html"}, {"title": "An empirical study on the use of context annotations and flow expressions to specify the behavior of context- sensitive systems", "authors": ["Jéssyka Vilela", "Jaelson Castro", "João Pimentel", "Enyo Gonçalves."], "year": 2016, "keywords": "Context-sensitive systems; Context Annotations; Flow expressions; GO2S Process; Behavior; Empirical study.", "abstract": "Context-Sensitive Systems (CSS) must detect variations in their op-erating context and adapt their behavior in response to such variations. Accord-ingly, the specification of the required context and the behavior of the tasks of such systems is a complex and labor-intensive task, which calls for systematic methods. In previous work, we have presented the GO2S (GOals to Statecharts) process to derive the behavior of context-sensitive systems from requirements models. In this paper, we report the findings of an empirical study conducted with twenty-two professionals. We examine how they perceive the complexity of the notations for context and for behavior specification, as well as the com-plexity of the GO2S process. The study findings showed that approximately 81% of the subjects specified the behavior correctly, whereas 97% identified the contextual variation points correctly. Moreover, according to the subjectsâ feedback, the notations for behavior and context specification and the GO2S process have a moderate complexity. Finally, we conclude this work by show-ing promising research opportunities underexplored in current research.", "url": "artigos/artigos_WER16/wer201603.html"}, {"title": "Uma solução baseada em ontologia para o tratamento de erros em modelos construídos na linguagem i*", "authors": ["Heyde Francielle do Carmo França", "Renato de Freitas Bulcão Neto"], "year": 2016, "keywords": "Requirements Engineering; Goal; i* Language; OntoiStar; OWL.", "abstract": "The i* language faces problems regarding the quality of requirements models, which include typical mistakes of misuse of its constructs, the presence of ambiguities on the interpretation of those constructs and the complexity of the resulting i* models. This paper proposes the extension of an ontology-based representation for i* models aiming at preventing the most well-known errors while constructing such models. Results demonstrate an approximate coverage of 70% of those common errors in the context of a case study.", "url": "artigos/artigos_WER16/wer201604.html"}, {"title": "Avaliação do Processo de Engenharia de Requisitos em Empresas de Desenvolvimento de Software", "authors": ["Flavia Belintani Blum Haddad", "Elias Canhadas Genvigir", "Jose Augusto Fabri and Alexandre LErário."], "year": 2016, "keywords": "Melhoria de processo de requisitos; Avaliação; Maturidade", "abstract": "A demanda, em ascensão, pela produção de softwares sob medida e softwares destinados a um mercado geral gera uma preocupação com a forma como os softwares são desenvolvidos. Neste contexto, os processos de software contribuem com a definição de atividades a serem executadas pelas equipes, em cada uma das fases de desenvolvimento conduzindo a produção de softwares a fim de atender às necessidades dos clientes, dentro do prazo e custos pré-estabelecidos. Pesquisas apontam que entre 40 a 60 por cento dos defeitos e fa-lhas nos softwares são atribuídos a incorreta definição dos requisitos e que cor-rigir erros no sistema pronto pode ser até 100 vezes mais caro do que se a cor-reção ou a prevenção ocorrer durante a fase que envolve a engenharia de requi-sitos e a implementação do sistema. Portanto, esta pesquisa se destinou ao estu-do de processos de engenharia de requisitos em empresas de desenvolvimento de software, por meio de um estudo de caso único com múltiplas unidades de análise. Os processos de engenharia de requisitos atuais das empresas pesquisa-das foram modelados e avaliados com o auxílio de um quadro de avaliação de maturidade de processo, Uni-REPM (Unified Requirements Engineering Process Maturity Model). Na sequência, foram apresentadas, às empresas, normas e modelos de referências, tais como CMMI-DEV (Capability Maturity Model In-tegration for Development), ISO/IEC 12207, ISO/IEC 15288 e o Guia de boas práticas em engenharia de requisitos (REGPG), para que pudessem conhecer e propor a inclusão de práticas ao processo atual. A análise dos dados após o en-quadramento no Uni-REPM possibilitou verificar quantas ações são necessárias para que cada empresa alcance um nível de maturidade conforme dispõe o qua-dro de avaliação de maturidade de processos de requisitos utilizado. A relevân-cia da pesquisa se caracteriza pela aplicação do quadro Uni-REPM, disponível na literatura científica atual, em processos reais de engenharia de requisitos, ou seja, esta pesquisa contribui para a aproximação da ciência e da indústria por se tratar de uma pesquisa aplicada, além da busca constante pela melhoria de pro-cessos de software.", "url": "artigos/artigos_WER16/wer201605.html"}, {"title": "Melhoria de Documentos de Requisitos: um Mapeamento Sistemático da Literatura", "authors": ["Roberto Azevedo", "Aêda Sousa", "Ricardo Ramos", "Fernanda Alencar"], "year": 2016, "keywords": "mapeamento sistemático; documentos de requisitos; melhoria; qualidade", "abstract": "Diversas técnicas são utilizadas, tanto pela indústria quanto pela academia, para a especificação de requisitos de um sistema de software. Den-tre essas, destacamse casos de uso e descrição textual que, como outras, apre-sentam problemas com relação a requisitos que foram abandonados; estruturas demasiadamente longas ou muito pequenas, pouco significativas e até desne-cessárias; requisitos duplicados, fragmentados e espalhados. Tudo isso dimi-nui a facilidade de entendimento, a modularidade e a reusabilidade do docu-mento de requisitos, acarretando a inserção de erros nas fases posteriores do processo de desenvolvimento. Para esses casos, o quanto antes os problemas forem encontrados, menor será o custo para removê-los. Nesta pesquisa, utili-zou-se o mapeamento sistemático da literatura como procedimento metodológico, com o objetivo de verificar, com bases em evidências, o estado atual de estudos sobre a melhoria de documentos de requisitos. A ideia foi verificar como essas melhorias foram validados e se utilizam alguma ferramenta de a-poio. Diversos estudos propõem diferentes técnicas para avaliação e melhoria de documentos de requisitos por meio de refatorações e padrões, a fim de mi-nimizar ou remover deficiências. Após análise dos estudos identificados, me-lhorias serão propostas à abordagem AIRDoc (Approach to Improve Requi-rements Documents), bem como o desenvolvimento de uma ferramenta para apoiar a execução do processo de forma efetiva.", "url": "artigos/artigos_WER16/wer201606.html"}, {"title": "Trends and Needs in Requirements Engineering Research in Ibero-America: Insights from a Panel", "authors": ["Jose Luis de La Vara", "Isabel Sofia Brito", "Nelly Condori-Fernández", "João Araújo."], "year": 2016, "keywords": "Requirements Engineering; trends; needs; future research; panel", "abstract": "Some aspects characterise Requirements Engineering (RE) research from different regions, whereas others constrain RE and RE approaches should not disregard them. Within this context, this paper aims to provide new insights into the trends and needs in RE research in Ibero-America. We have analysed the results from a panel at WER 2015 on the characteristics in Ibero-America that RE research should consider, the topics successfully researched in the region, the topics not sufficiently researched, and the topics on which future research should focus. Among the conclusions, Ibero-America seems to have specific social and cultural characteristics that impact RE, research on goaloriented RE and RE for web-based systems can be regarded as successful, how to improve requirements quality should have been further studied, and RE education and knowledge transfer must be addressed in the future.", "url": "artigos/artigos_WER16/wer201607.html"}, {"title": "Calidad en la inspección de requerimientos de software: una propuesta de medición", "authors": ["Alex Armijos Roblero", "Carlos Monsalve", "Ruben H. Ullón", "Ricardo D. Maya", "José A. Romero."], "year": 2016, "keywords": "inspección; requerimientos de software.", "abstract": "La inspección de software, dentro del análisis de requerimientos, consiste en un conjunto de pasos ordenados y coordinados que intenta detectar tempranamente defectos para prevenir la construcción de un software que no responda a las necesidades del usuario final. Sin embargo, aunque se sigan estos pasos, su calidad podría verse afectada por el perfil de los inspectores. La calidad en la inspeccion de software no ha sido estudiada a profundidad; es decir, no se ha definido claramente que mediciones de calidad realizar y cómo realizar comparaciones entre inspectores. El presente estudio propone, con bases estadísticamente probadas, una forma concreta para medir la calidad en trabajos de inspección realizados por inspectores con diferentes perfiles. El experimento fue diseñado basado en la norma IEEE 1028-2008 y consistió en inspeccionar casos de uso para un software de un organismo del gobierno ecuatoriano donde los inspectores tenían dos perfiles: estudiantes universitarios y profesionales de computación. Los resultados obtenidos presentan mejores índices de calidad en los profesionales. La medición de calidad de inspección propuesta podría mejorarse con experimentos adicionales y trabajos a futuro.", "url": "artigos/artigos_WER16/wer201608.html"}, {"title": "Um modelo para tratamento de ambiguidades em requisitos de evolução de sistemas jurídicos baseado em mapeamento conceitual", "authors": ["Luiz Gustavo Ferreira Aguiar", "Rebeca Teodoro Da Silva", "Elias Canhadas Genvigir", "Jose Augusto Fabri", "Alexandre L´erario."], "year": 2016, "keywords": "Software Evolution; Engenharia de Requisitos; Mapas Conceituais.", "abstract": "O Domínio Judicial Brasileiro possui sistemas em processo de evolu-ção, principalmente os sistemas de processo judicial eletrônico. A participação de diferentes usuários, concomitante às complexidades do direito, geram requisi-tos de evolução de software contendo ambiguidades. Este trabalho apresenta um modelo para captação e tratamento desses requisitos, através de feedback dos usuários, utilizando mapeamento conceitual. O modelo proporciona a delimita-ção do escopo do requisito e sua conceituação, sendo importantes contribuições para a compreensão do requisito, reduzindo a incidência de ambiguidades. De-vido à complexidade do direito, a linguagem natural ainda é predominante para os requisitos, contudo, o mapeamento conceitual demonstrase eficiente para a representação dos conceitos da área, bem como de fácil aprendizado.", "url": "artigos/artigos_WER16/wer201609.html"}, {"title": "Uso de un Léxico y Escenarios para Mitigar Amenazas a Requisitos en el Desarrollo Global de Software", "authors": ["Juan Pablo Mighetti", "Graciela D. S. Hadad"], "year": 2016, "keywords": "Desarrollo Global de Software; Amenazas; Comunicación; Proceso de Requisitos; Léxico Extendido del Lenguaje; Escenarios.", "abstract": "El desarrollo global de software se estÃ¡ difundiendo cada vez mÃ¡s en las organizaciones. Si bien brinda ventajas competitivas al aumentar la velocidad en las entregas del software y reducir costos por aprovechar recursos calificados mÃ¡s baratos, es una forma de trabajo compleja, donde amenazas provenientes principalmente de distancias geogrÃ¡ficas y culturales pueden impactar negativamente en actividades y artefactos del proceso. La calidad de los requisitos suele deteriorarse debido a estas amenazas latentes no tratadas, propagando defectos en subsiguientes fases del desarrollo. Estas dificultades fueron estudiadas en un proyecto real de gran envergadura, desarrollado bajo esta modalidad de trabajo. Debido a ellas, se elaborÃ³ una propuesta utilizando un modelo LÃ©xico y Escenarios para mitigar amenazas que afectan a los requisitos en esta modalidad distribuida. La propuesta fue aplicada en un nuevo proyecto real de similares caracterÃ­sticas y, al compararlos en calidad y tiempos en requisitos, se obtuvieron resultados suficientemente promisorios.", "url": "artigos/artigos_WER16/wer201610.html"}, {"title": "Towards a Requirements Engineering Process for Innovative Software: Learning with the ConecteIdeias Case", "authors": ["Renata Guizzardi", "Marcos Accioly", "Letícia Fonseca", "Roberta Gomes", "Miriam Pinto"], "year": 2016, "keywords": "Innovative Software; Requirements Engineering; Learning.", "abstract": "For many years, Requirements Engineering has been regarded as a crucial phase of software development, because it is responsible to collect from the stakeholders and model the purposes of the system to be. Consequently, lots of research results have been accumulated over the years concerning approaches to elicit and model requirements. However, eliciting and modeling requirements for innovative software, for which no determined stakeholder is defined, are still open research issues. This is due to the very nature of innovation, which asks for new ways of thinking and generating software products. This paper aims at presenting the RE process which led to the development of a web-based social network named ConecteIdeias. This social network is aimed at supporting people on creating new ideas and solutions to change social reality in the place where they live. Besides briefly presenting the social network and thoroughly describing the process, this paper also presents some lessons learned and good practices gathered throughout the process execution. The long term goal of this research is to propose a general RE process for the development of innovative software.", "url": "artigos/artigos_WER16/wer201611.html"}, {"title": "A Especificação de Requisitos no Domínio de Sistemas de Informação com o Uso de Padrões", "authors": ["Leonardo Barcelos", "Rosângela Penteado."], "year": 2016, "keywords": "requirements document; requirements patterns; system information domain; computational support based on requirement patterns.", "abstract": "The requirement elicitation is the first step to obtain quality software, requiring constant interaction among stakeholders. The requirements in the information systems domain have similar characteristics, such as the CRUD operations. Reusing knowledge obtained in previous projects, requirement patterns can be elaborated to facilitate the complete and consistent specification of system requirements in that domain. This paper shows a set of functional requirement patterns and business rules elaborated to help the software engineer in the writing of the requirements document. The non-functional requirements were not considered in this project. A computational support was developed, based on that set of patterns, to facilitate the organized and complete writing of the requirements document. Case studies are presented with the use of the computational support.", "url": "artigos/artigos_WER16/wer201612.html"}, {"title": "A utilização da linguagem natural na especificação de requisitos: um estudo por meio das equações estruturais", "authors": ["Roberto Avila Paldes", "Angelica Toffano Seidel Calazans", "Ari Melo Mariano", "Eduardo José Ribeiro Castro and Bruno De Souza Silva."], "year": 2016, "keywords": "Requisitos de software. Especificação de requisitos. Linguagem natural. Equações estruturais.", "abstract": "O objetivo deste estudo é analisar fatores de influência para a escolha da linguagem natural (LN) na especificação de requisitos. A metodologia adotada é de estudo descritivo, de abordagem quantitativa por meio de equações estrutu-rais. O modelo teórico proposto baseia-se na Teoria Unificada de Aceitação e Uso da Tecnologia (UTAUT). Foi elaborado um questionário (a=0,817) com 17 perguntas para 50 analistas de requisitos. O instrumento de pesquisa foi validado e pode continuar a ser usado. Identificou-se que o motivo que leva os analistas a usar a LN na especificação é a expectativa de um rendimento elevado. A expec-tativa de esforço não pode ser confirmada com um fator de influência. Há um forte reconhecimento que o uso da LN leva a uma maior adesão às necessidades do cliente. Não se identificaram condições facilitadoras nas organizações que in-fluenciem o comportamento de uso, o que pode indicar uma direção de aprimo-ramento efetiva.", "url": "artigos/artigos_WER16/wer201613.html"}, {"title": "A Survey on Preferences of Quality Attributes in the Decision-making for Self-Adaptive Systems: the Bad, the Good and the Ugly", "authors": ["Luis H. Garcia Paucar", "Nelly Bencomo"], "year": 2017, "keywords": "Self-adaptation; decision making; preference trade-o; quality attributes", "abstract": "Diferent techniques have been used to specify preferences for quality attributes and decision-making strategies of self-adaptive systems (SAS). These preferences are defined during requirement specification and design time. Further, it is well known that correctly identifying the preferences associated with the quality attributes is a major dificulty. This is exacerbated in the case of SAS, as the preferences defined at design time may not apply to contexts found at runtime. This paper aims at making an exploration of the research landscape that have addressed decision-making and quality attribute preferences speciication for selfadaptation, in order to identify new techniques that can improve the current state-of-the-art of decision-making to support self-adaptation. In this paper we (1) review difierent techniques that support decisionmaking for self-adaptation and identify limitations with respect to the identi cation of preferences and weights (i.e. the research gap), (2) identify existing solutions that deal with current limitations", "url": "artigos/artigos_WER17/wer201701.html"}, {"title": "Rastreamento e Gerenciamento de Requisitos em Busca da Conformidade Legal", "authors": ["Ilueny Santos", "Erica Miranda", "Marcia Lucena"], "year": 2017, "keywords": "equisito legal; Rastreabilidade de requisitos; Conformidade legal", "abstract": "A crescente complexidade dos sistemas de software e a exigência de conformidade com a legislação vigente são condições sine qua non à era digital. Atender estas condições e gerenciar requisitos legais tornamse atividades custosas, quando feitas de forma não planejada. Requisitos legais referem-se ao conjunto de leis e regulamentos aplicáveis ao domínio do negócio do software, que se pretende desenvolver e por isso são altamente sensíveis às alterações que ocorrem na legislação. Neste trabalho, é apresentada uma proposta de gestão baseada na rastreabilidade de requisitos. Com isto, é possível realizar o acompanhamento e a descrição da vida de um requisito, visando o processo de manutenção e verificação da conformidade legal dos sistemas. Para melhor compreensão do problema foram realizadas pesquisas bibliográficas e entrevistas com especialistas em requisitos. Uma aplicação da abordagem no contexto de comércio eletrônico é apresentada.", "url": "artigos/artigos_WER17/wer201702.html"}, {"title": "Requirements Engineering for Robotic System: A Systematic Mapping Study", "authors": ["Danyllo Albuquerque", "Jaelson Castro", "Sarah Ribeiro", "Tiago Heineck"], "year": 2017, "keywords": "Robotic Systems; Requirements Engineering; Systematic Mapping Study.", "abstract": "Problem Statement: Several research efforts have been targeted to support Requirements Engineering (RE) in general software systems for the last two decades. However, to the extent of our knowledge, there is no framework to support RE in robotic systems domain. Goal: We aimed to systematically identify and analyze the existing research progress and directions that influence the elicitation, analysis and negotiation, specification, validation and management of requirements in robotic systems domain. Method: We used Systematic Mapping Study (SMS) method for identifying and analyzing 38 peer-reviewed studies. Our review has (i) taxonomically classified and (ii) systematically mapped the methods, modelling styles and process which support some RE phases. Results and Conclusions: According to the selected studies, we realize that all RE phases are addressed by one or more methods, modelling styles and process. In general, the elicitation and specification phases received greater attention from the academic community whereas validation, analysis/negotiation and management phases still require more attention. Furthermore, we note that only two studies mention all phases of the ER process but such studies do not describe in detail how RE phases should be performed.", "url": "artigos/artigos_WER17/wer201703.html"}, {"title": "A qualificação profissional do Engenheiro de Requisitos no Brasil", "authors": ["Vinícius Dias Paldês", "Janaína dos Reis Lopes", "André Luiz Coelho da Silva", "Roberto Avila Paldês", "Angélica Toffano Seidel Calazans"], "year": 2017, "keywords": "Educação e treinamento. Formação profissional. Engenharia de Requisitos. Mercado brasileiro. Aspectos Sociais.", "abstract": "Diante das demandas de um dos maiores mercados mundiais em TI, são necessários profissionais qualificados em engenharia de requisitos. O objetivo da pesquisa é investigar a qualificação atual dos profissionais de requisitos que atuam no Brasil. A amostra de 4000 currículos foi obtida em uma importante rede social de perfis profissionais, valendo-se de uma ferramenta desenvolvida para a extração dos dados. Nas cidades com mais currículos cadastrados, verificou-se apenas 45% dos profissionais são graduados em TI, o que concede uma formação generalista em requisitos. Menos de 5% recorreram à pós-graduação para cobrir essa lacuna, sendo que cerca de 1% realizou uma pós-graduação específica em Engenharia de Requisitos (ER). Somente 2% obteve uma certificação profissional específica. Como conclusão, constata-se os profissionais de requisitos atuam com reduzida formação acadêmica em ER, compensando em parte com competências em gestão. Cursos específicos são recentes em profissionais atuan-tes, embora isso possa melhorar a empregabilidade.", "url": "artigos/artigos_WER17/wer201704.html"}, {"title": "O perfil do analista de requisitos de software: uma comparação entre a academia e o mercado de trabalho brasileiro", "authors": ["Angélica Toffano Seidel Calazans", "Roberto Avila Paldês", "Emeli Braosi1", "Kiane Mabel Rezende", "Nathácia Indayara Pereira"], "year": 2017, "keywords": "Aspectos sociais. Aspectos culturais. Perfil profissional. Conformidade. Analista de requisitos", "abstract": "O trabalho do analista de requisitos é considerado crucial no ciclo de vida de um software. Neste artigo apresenta-se um estudo exploratório sobre o perfil desse analista, considerando o modelo de competência caracterizado por conhecimentos, habilidades e atitudes. Foi utilizada a análise de conteúdo e a ferramenta NVivo para categorizar 164 anúncios de vagas para analistas de requisitos entre os anos de 2015 e 2016. Grande parte dos resultados obtidos ratificam o perfil do analista de requisitos citados em trabalhos acadêmicos. Identificaram-se, entretanto, uma série de habilidades necessárias ao analista de requisitos que não são especificados na literatura, tais como: UML, programação e linguagens, bancos de dados e métodos ágeis. Identificou-se também a não exigência de domínio em uma segunda língua pela maioria das organizações que divulgaram ofertas de emprego no Brasil. Os resultados desta investigação ajudam na compreensão das reais necessidades do mercado brasileiro, apontando contradições com o perfil do analista descrito pela academia.", "url": "artigos/artigos_WER17/wer201705.html"}, {"title": "Requirements Engineering Practice and Problems in Agile Projects: Results from an International Survey", "authors": ["Stefan Wagner", "Daniel Méndez Fernández", "Michael Felderer", "Marcos Kalinowski"], "year": 2017, "keywords": "Survey; Requirements Engineering; Agile Projects; NaPiRE.", "abstract": "Requirements engineering (RE) is considerably different in agile development than in more traditional development processes. Yet, there is little empirical knowledge on the state of the practice and contemporary problems in agile RE. As part of a bigger survey initiative (Naming the Pain in Requirements Engineering), we build an empirical basis on such aspects of agile RE. Based on the responses of representatives from 92 different organisations, we found that agile RE concentrates on free-text documentation of requirements elicited with a variety of techniques. Often, traces between requirements and code are explicitly managed and also software testing and RE are aligned. Furthermore, continuous improvement of RE is performed due to intrinsic motivation. Important experienced problems include unclear requirements and communication flaws. Overall, we found that most organisations conduct RE in a way we would expect and that agile RE is in several aspects not so different from RE in other development processes", "url": "artigos/artigos_WER17/wer201706.html"}, {"title": "Retrospective and Trends in Requirements Engineering for Embedded Systems: A Systematic Literature Review", "authors": ["Tarcísio Pereira", "Deivson Albuquerque", "Aêda Sousa", "Fernanda Alencar", "Jaelson Castro"], "year": 2017, "keywords": "requirements engineering; embedded systems; trends.", "abstract": "In the embedded systems (ES) area, more than 50% of problems occur at system delivery and are related to misconceptions in capturing requirements. Also, requirements engineering (RE) is crucial to meet time, cost, and quality goals. An important step to improve the RE approaches for ES is to gain a detailed understanding of the retrospective and trends presented by the literature. We have conducted a systematic literature review to gain an in-depth understanding of trends and needs concerning RE research. We report on the main results of our study related to three research questions: what requirements should be considered during ES development? what are the RE contributions for ES? and what challenges/problems are identified in the research literature to RE for ES? Based on the results of the study, we draw conclusions for future RE research.", "url": "artigos/artigos_WER17/wer201707.html"}, {"title": "Jerarquías Naturales en el Contexto del Proceso de Requisitos", "authors": ["Gladys N. Kaplan", "Jorge H. Doorn"], "year": 2017, "keywords": "LEL; jerarquías naturales; vínculos semánticos; taxonomías; mereología", "abstract": "Los glosarios utilizados en los procesos de requisitos, cumplen fundamentalmente la función de reducir la ambigüedad de los modelos construidos en el proceso. Por lo tanto es mandatorio que se haga evidente todo tipo de complejidad presente en el léxico que describen. Estos glosarios contienen un conjunto de palabras y frases que son relevantes en el dominio particular que se está modelando. Este conjunto de palabras y frases contiene a su vez subconjuntos de términos con una vinculación semántica más estrecha aún, este es el caso de las jerarquías. En el presente artículo se propone una estrategia para analizar y resaltar las jerarquías naturales en el léxico del dominio. La indicación explícita de las jerarquías en estos glosarios mejora sustancialmente su contenido semántico, garantizando sus principales pilares que son optimizar la comunicación, mejorar la comprensión de los procesos del negocio y reducir la ambigüedad de los modelos construidos. Por otra parte, la presencia de jerarquías promueve una Especificación de Requisitos con mejor tratamiento de la granularidad de su contenido.", "url": "artigos/artigos_WER17/wer201708.html"}, {"title": "Limiting the Scope of the Domain Language to Describe the Application Language", "authors": ["Leandro Antonelli", "Gustavo Rossi", "Julio Cesar Sampaio do Prado Leite", "Alejandro Oliveros"], "year": 2017, "keywords": "Agile Development; Language Extended Lexicon; User Stories.", "abstract": "Agile methodologies arise as a way to cope with problems of estima-tion and planning that occur in traditional software development. Nevertheless, the transition to agile could be hard. The key challenge reported by literature re-fers to requirements, in particular with the identification and description of User Stories. It is stated that User Stories are often described vaguely by the wrong people at the wrong time. To cope with this problem, there is an already pro-posed strategy which consists in deriving User Stories from the domain lan-guage captured through the Language Extended Lexicon (LEL). This strategy produces an initial set of User Stories with small effort. Since the LEL aims to capture the language of the domain while the User Stories must be limited to a specific application we believe that it is necessary to adjust the LEL. In this pa-per, we propose a strategy to limit an LEL that describes the language of a do-main to describe the vocabulary of a specific application. Consequently, User Stories derived from the limited LEL using the already proposed approach will only describe the functionality of the application. Based on a preliminary evalu-ation, we state that teams with no experience in writing User Stories obtain bet-ter products. Although the results are preliminaries, we think that they are promising.", "url": "artigos/artigos_WER17/wer201709.html"}, {"title": "Towards an Ontology of Goal-Oriented Requirements", "authors": ["Pedro Pignaton Negri", "Vítor E. Silva Souza", "André Luiz de Castro Leal", "Ricardo de Almeida Falbo", "Giancarlo Guizzardi"], "year": 2017, "keywords": "requirements; ontology; goal-oriented; GORE; UFO; GORO", "abstract": "Goal-Oriented Requirements Engineering (GORE) has grown into an important area of research in the past decades. Still, some of its corners remain dark, since diferent GORE languages do not provide a well-founded conceptualization of the domain and are not consensual. This may lead to ambiguous or weak understanding of GORE concepts. In this paper, we introduce the Goal-Oriented Requirements Ontology (GORO), a domain ontology founded on the Uni ed Foundational Ontol- ogy (UFO) that intends to represent the nature and relations of concepts surrounding the GORE domain.We use GORO to explore and clarify the semantics used, sometimes implicitly, by well-known GORE languages.", "url": "artigos/artigos_WER17/wer201710.html"}, {"title": "Usando KIPO para Modelar Problemas e Socialização na Elicitação de Requisitos", "authors": ["Denize Pimenta", "Fernanda Baião", "Gleison Santos"], "year": 2017, "keywords": "Engenharia de Requisitos; Problemas na Elicitação de Requisitos; Ontologia.", "abstract": "A elicitação de requisitos essencialmente constitui uma atividade que envolve uma série de interações de comunicação entre os diversos stakeholders envolvidos no processo de desenvolvimento. Apesar disso, muitos engenheiros de requisitos não possuem ampla percepção sobre os problemas que acontecem durante a socialização, e não há entendimento preciso sobre como as técnicas específicas da engenharia de requisitos podem auxiliá-lo nessas atividades. A elicitação é um processo intensivo em conhecimento, pois a sua execução depende essencialmente do conhecimento dos envolvidos. Este artigo apresenta uma proposta para representar uma conceitualização mais precisa e explícita sobre alguns problemas e a dinâmica da socialização que ocorrem durante a elicitação de requisitos. A conceitualização é apresentada na forma de um modelo conceitual de domínio, que instancia o meta-modelo de processos intensivos em conhecimento representado pela KIPO (knowledge-intensive process ontology). Seu objetivo é compartilhar uma visão comum e tornar o domínio da engenharia de requisitos mais explícito e semanticamente preciso a seus stakeholders", "url": "artigos/artigos_WER17/wer201711.html"}, {"title": "Inspección centrada en Omisiones y Ambigüedades de un Modelo Léxico", "authors": ["Alberto Sebastián", "Graciela D. S. Hadad", "Ezequiel Robledo"], "year": 2017, "keywords": "Verificación de Requisitos; Inspecciones; Completitud de Modelos; Mapas Conceptuales; Léxico Extendido del Lenguaje.", "abstract": "El uso de modelos escritos en lenguaje natural en la producción de requisitos está ampliamente difundido tanto en la literatura como en el ámbito profesional. Si bien estos modelos favorecen la comunicación entre los involucrados y la validación, presentan ciertos obstáculos, como la ambigüedad del texto y la dificultad en realizar verificaciones automatizadas. La inspección es reconocida como una técnica de verificación de alta efectividad para detectar defectos en código fuente, modelos de diseño y modelos de requisitos. Se propone una variante de la técnica de inspección basada en la construcción de mapas conceptuales para verificar un modelo léxico. Estudios estadísticos han comprobado que este modelo léxico presenta un bajo nivel de completitud, y que puede arrastrarse a otros modelos pues suele construirse al inicio de un proceso de requisitos. Dado ello, la inspección propuesta se aboca a detectar principalmente omisiones y ambigüedades, habiéndose probado en siete casos con resultados promisorios.", "url": "artigos/artigos_WER17/wer201712.html"}, {"title": "Uma Notação Textual Modular e Escalável para Modelos de Requisitos iStar", "authors": ["Fabio Penha", "Marcia Lucena", "Leonardo Lucena", "Fernanda Alencar e Celso Agra"], "year": 2017, "keywords": "framework istar; modularidade; escalabilidade; notação textual", "abstract": "O framework iStar é uma notação gráfica utilizada para modelar dependências e raciocínios estratégicos em requisitos de sistemas computacionais. Um desafío recorrente desta notação está relacionado com a falta de modularidade e por consequência, escalabilidade. Uma das principais re exo destas fraquezas é a dificuldade em lidar com modelos mais complexos. Neste contexto, este artigo apresenta uma notação textual, modular e escalável, para modelos de requisitos iStar capaz de lidar com modelos complexos. A notação proposta também propõe uma orientação para leitura e entendimento dos modelos iStar por todos os envolvidos, facilitando a análise e verificação dos modelos.", "url": "artigos/artigos_WER17/wer201713.html"}, {"title": "Un Enfoque Inteligente para Derivar Use Case Maps a partir de Requerimientos de Software", "authors": ["Brian Caimmi", "Guillermo Rodriguez", "Álvaro Soria"], "year": 2017, "keywords": "Software Architecture; Use Case Maps; Machine Learning; Natural Language Processing", "abstract": "Los requerimientos de software descritos en lenguaje natural son la base para realizar la creativa pero exhaustiva tarea de diseñar una arquitectura de software. No obstante, suele existir una amplia brecha conceptual entre los requerimientos y la arquitectura de software que describe su funcionalidad; más aún, poco se ha explorado en este campo para reducir esta brecha. En este trabajo, proponemos un enfoque inteligente para derivar una descripción arquitectónica de un sistema, en particular utilizando la notación Use Case Maps (UCMs) a partir de requerimientos redactados en lenguaje natural con el objetivo de facilitar la transición entre la especificación de requerimientos y el diseño arquitectónico. El enfoque combina algoritmos de clasificación de texto, procesamiento de lenguaje natural y clusterización de texto para generar UCMs de la arquitectura de software prevista. La experimentación llevada a cabo con varios casos de estudio muestra resultados prometedores en cuanto al potencial del enfoque para asistir a los arquitectos de software durante las primeras etapas del proceso de desarrollo de software", "url": "artigos/artigos_WER17/wer201714.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2018)", "authors": ["Carla Silva", "Graciela Hadad", "João Pimentel"], "year": 2018, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER18/wer201800_1.html"}, {"title": "Industry Panel", "authors": ["Soeli Fiorini", "Maria Lencastre"], "year": 2018, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER18/wer201800_2.html"}, {"title": "Keynote Talk - A Refinement Calculus for Requirements Engineering", "authors": ["John Mylopoulos"], "year": 2018, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER18/wer201800_3.html"}, {"title": "Organization", "authors": ["Carla Silva", "Graciela Hadad", "João Pimentel"], "year": 2018, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER18/wer201800_4.html"}, {"title": "Modelando Requisitos de um Jogo Educacional Médico usando a Metodología INGENIAS SCRUM", "authors": ["Fernanda T. Novo", "Vanessa M. da Silva", "Bruno G. Ochotorena", "Lucas d’Amaral Pires", "Bruna Costa Cons", "Rosa Maria E. M. da Costa", "Vera M.B. Werneck"], "year": 2018, "keywords": "requirements engineering; embedded systems; process", "abstract": "Metodologias orientadas a agentes têm sido aplicadas no desenvolvimento de jogos educativos. No entanto, o uso dos métodos clássicos pode gerar excessivos custos, tempo e dificuldades na adaptação ao escopo dos produtos. Neste trabalho, são apresentados os resultados da aplicação de um método ágil orientado a agentes (INGENIAS SCRUM) no desenvolvimento de um jogo educativo para a área da saúde. Os modelos de requisitos, o processo de implementação e desenvolvimento são discutidos e apresentados neste trabalho. Evidências positivas do uso deste método foram observadas na qualidade do produto gerado e no tempo de desenvolvimento quando comparado a outro estudo, que usou o mesmo jogo como um modelo comparativo.", "url": "artigos/artigos_WER18/wer201801.html"}, {"title": "Um Estudo de Caso de Aplicação de um Método Ágil para Desenvolvimento de Requisitos de Software: O REACT", "authors": ["Kleoson B. C. Santos", "Sandro R. B. Oliveira"], "year": 2018, "keywords": "Robotic systems; Requirement Definition; Empirical Study.", "abstract": "This study presents the report about a case study on the application of REACT (Requirements Evolution in Agile ContexT), an agile method to support software requirements development, in a real software development environment. This case study assessed the strengths, weaknesses, opportunities, and threats related to the assets that make up REACT, namely: work products, life cycle, roles, and ceremonies. About the results, it was observed that REACT was effective, simple to use, strongly collaborative, suitable, user centered and goal oriented. Thus, achieved its main purpose to evolve the requirements of a software product in iteratively, efficiently and under of the agile mindset. The results contribute to the software industry by providing empirical data about the use of a agile method to software requirements development, which can serve as a reference for organizations seeking the adoption of agile methods related to the requirements area, as well as to provide the scientific community with a better empirical understanding of the relationship between requirements and agile methods.", "url": "artigos/artigos_WER18/wer201802.html"}, {"title": "Configuração de Processos de Negócio em Organizações Públicas Considerando Informações de Contexto e Requisitos Não-Funcionais", "authors": ["Amora Sukar", "Fernanda Alencar", "Higor Monteiro", "Tarcísio Pereira"], "year": 2018, "keywords": "Business Process Modeling; Business Process Configuration; Non-Functional Requirements; Context-Awareness; Public Organizations", "abstract": "Atualmente, o gerenciamento e a modelagem de processos de negócio são práticas bem estabelecidas no setor privado. No entanto, verifica-se que a orientação a processos nas organizações públicas ainda está em seus estágios iniciais. Devido à natureza dos processos de negócio desse setor, normalmente su-jeitos a diversas limitações, tais como leis, diretrizes políticas e orçamentos, é fundamental que seus modelos de processos de negócio sejam suficientemente flexíveis para apoiarem mudanças e restrições. Assim, essa pesquisa tem como objetivo apresentar um diagnóstico sobre como são consideradas informações de contexto e a influência dos Requisitos Não-Funcionais durante a configuração dos processos de negócio no setor público. Para isso, uma Revisão Sistemática da Literatura foi realizada com objetivo de identificar e avaliar abordagens existentes que tratem essas informações em conjunto na modelagem de processos. Também foram realizadas entrevistas em organizações públicas, para analisar como aqueles conceitos são ou podem ser considerados de fato na prática. Ao fim da pesquisa, buscou-se apontar evidências sobre a necessidade de adaptação da modelagem dos processos de negócio atuais para a construção de modelos que sejam sensíveis ao contexto, capazes de considerar Requisitos Não-Funcionais em sua configuração, bem como as vantagens e desvantagens envolvidas nesse processo.", "url": "artigos/artigos_WER18/wer201803.html"}, {"title": "Estimación de los Factores Situacionales del Proceso de Requisitos", "authors": ["Viviana A. Ledesma", "Graciela D. Hadad", "Jorge H. Doorn", "Nicolás A. Bedetti2"], "year": 2018, "keywords": "Proceso de Requisitos; Factores Situacionales; Variabilidad de Procesos; Ingeniería de Métodos Situacional.", "abstract": "Para obtener un producto software de buena calidad es vital aplicar un proceso apropiado de requisitos. En ese sentido, la literatura ofrece procesos de requisitos bien definidos de muy diverso alcance. Sin embargo, la experien-cia indica que gran parte de los proyectos reales tienen características que hacen conveniente efectuar cambios en los procesos. Para ello, es necesario disponer de un método claro que guíe cómo adaptar el proceso en cada situación. Estas situaciones se pueden caracterizar a través de un conjunto de factores observa-bles. Usualmente es difícil establecer con precisión el valor de estos factores al inicio del proceso de requisitos. También debe considerarse la posible evolu-ción de ciertos factores por cambios en el contexto. En otras palabras, a veces no alcanza con solo adaptar un proceso antes de su puesta en ejecución, sino que este puede requerir readaptaciones durante su desarrollo, ya sea por preci-sarse factores con valoraciones iniciales dudosas o incorrectas, o por ocurrir cambios en el contexto que implican cambios en algunos factores. Finalmente, es necesario estimar cuan viable resulta establecer los factores con una confiabi-lidad tal que su aplicación para adaptar el proceso resulte aceptable. Por tal mo-tivo, se ha estudiado la evolución de 21 factores durante la aplicación de un proceso de requisitos en 35 proyectos de la industria. Esto ha permitido corro-borar la evolución de las situaciones en las que está inmerso un proceso de re-quisitos y, asimismo, identificar factores a los cuales debe prestarse mayor atención para una adecuada adaptación dinámica del proceso.", "url": "artigos/artigos_WER18/wer201804.html"}, {"title": "Requisitos não Funcionais e Sustentabilidade para Computação em Nuvem: uma Revisão Sistemática da Literatura", "authors": ["Kádna Camboim", "Fernanda Alencar"], "year": 2018, "keywords": "Computação em Nuvem; Requisitos não funcionais; Sustentabilidade", "abstract": "A computação em nuvem continua a se disseminar no mundo web, possibilitando o uso de aplicações, plataformas e infraestruturas através de conexões remotas. Requisitos não funcionais de grande importância para computação em nuvem devem considerar desempenho e sustentabilidade, de modo a impactar diretamente nos custos e na qualidade dos serviços prestados, considerando ainda evitar (maiores) danos à saúde ambiental. Uma das grandes dificuldades enfrentadas é a falta de padrões na adoção desta tecnologia, o que implica na maneira de melhor configurar infraestruturas, levando em conta a diversidade de requisitos essenciais que devem ser atendidos para garantias de entrega e fornecimento dos serviços. Este trabalho apresenta quais requisitos não funcionais e parâmetros de sustentabilidade necessitam de especial atenção no processo de migração para computação em nuvem. Os dados são apresentados como resultados de uma revisão sistemática da literatura", "url": "artigos/artigos_WER18/wer201805.html"}, {"title": "A Requirements Definition Framework for the Robotic Systems Domain - An Exploratory Study", "authors": ["Danyllo Albuquerque", "Jaelson Castro", "Aeda Sousa"], "year": 2018, "keywords": "Robotic systems; Requirement Definition; Empirical Study.", "abstract": "A robotic system is a physical device composed by special-purpose hardware and software that must be integrated to enable a robotic system to function as expected. The first step towards the modeling robotic systems is to determine its requirements, which is a description of how the system should behave together with constraints on its operation. Much research effort in the last two decades has been invested to support requirements engineering (RE) for general systems. However, to our knowledge, there is no framework to properly support RE for robotic systems. Hence, we conducted an exploratory study aiming to answer the question \"What technical features affect the RE for the robotic systems domain?\" Based on what we learned in the study, we point out some challenges and issues in RE for the robotic systems domain. Additionally, we provide a framework to identify and manage several technical features which affect RE for this domain.", "url": "artigos/artigos_WER18/wer201806.html"}, {"title": "RASO: an Ontology on Requirements for the Development of Adaptive Systems", "authors": ["Cássio Capucho Peçanha", "Bruno Borlini Duarte", "Vítor E. Silva Souza"], "year": 2018, "keywords": "Adaptive Systems; Requirement; Models; Ontology", "abstract": "There is growing interest in software that can adapt their behavior to deal with deviations between their outcome and their requirements at runtime. A systematic mapping of the literature on selfadaptation approaches based on requirements models revealed over 200 papers on this subject. However, there is still a lack of a formal and explicit representation of the concepts in this domain, which can lead to problems in communication, learning, problem-solving, interoperability, etc. To make a clear and precise description of this domain, this paper proposes RASO: the Requirements for Adaptive Systems Ontology. RASO was built using a well-established Ontology Engineering method, is grounded on a foundational ontology and reuses concepts from other software-related ontologies. The ontology was evaluated by mapping constructs from the most referenced approaches from the literature to its concepts, thus creating a path for interoperability among them.", "url": "artigos/artigos_WER18/wer201807.html"}, {"title": "Requirements Engineering for Embedded Systems: The REPES Process", "authors": ["Tarcísio Pereira", "Fernanda Alencar", "Jaelson Castro"], "year": 2018, "keywords": "requirements engineering; embedded systems; process", "abstract": "[Context] Requirements Engineering (RE) for Embedded Systems (ES) is challenging since it has unique properties that make it complex, expensive and error-prone compared with other software categories, such as information systems. Due to their complexity, the risk of undetected requirements errors and deficiencies increases considerably. [Goal] Thus, this paper presents a specific process for requirements development and management named REPES which is tailored for embedded systems. [Method] In this proposal, we used the results of a Systematic Literature Review (SLR), metamodel and RE standards to guide the development of the process. [Results] REPES has four main process areas, 24 sub-processes, and 89 actions. [Conclusion] We argue that the proposed process can help organizations in improving their requirements practices to support completeness and correctness of RE for ES.", "url": "artigos/artigos_WER18/wer201808.html"}, {"title": "Experimentando o SPIDe aplicado à Elicitação de Requisitos", "authors": ["Jean C. S. Rosa", "Ecivaldo Matos", "Fiama S. Santos", "Gilton J. F. Silva"], "year": 2018, "keywords": "Engenharia de Requisitos; Fatores Humanos; Engenharia Semiótica.", "abstract": "A elicitação de requisitos é o momento que exige uma intensa comunicação entre os \"donos de problemas\" e os engenheiros de requisitos. Para elicitar requisitos é necessário que os engenheiros busquem técnicas adequadas, que favoreçam a comunicação. Uma das recomenda ções da literatura para facilitar a elicitação é o contato direto com os usuários, o que pode ser alcançado por meio do Design Participativo (DP), haja vista que suas técnicas podem proporcionar uma comunicação mais robusta. No Design de Interação, um processo metodológico compostou por técnicas participativas é o SPIDe. O SPIDe é um processo semioparticipativo, ou seja, associa o DP da Semiótica para estudar a comunica ção por meio da participação do usuário no processo de design. Sob essa perspectiva questiona-se: é possível elicitar requisitos por meio do SPIDe? Este artigo apresenta um estudo experimental para identificar se é possível elicitar requisitos por meio da aplicação do SPIDe. A partir dos resultados gerados foi concluir que por meio do SPIDe é elicitar requisitos, permitindo que os usuários tornem-se co-autores na elicitação de requisitos do software a ser desenvolvido.", "url": "artigos/artigos_WER18/wer201809.html"}, {"title": "O Uso de Design Thinking no Apoio ao Desenvolvimento de Software: Um Estudo de Caso no Contexto de Academias de Musculação", "authors": ["Lauriane Correa", "Daniel Maria", "Jean Carlos Bellio", "Sabrina Marczak", "Tayana Conte"], "year": 2018, "keywords": "Desenvolvimento de Software; Design Thinking; Double Diamond; Hasso Plattner; Estudo de Caso; Academias de Musculação", "abstract": "O Design Thinking (DT) aparece na Engenharia de Software como uma abordagem promissora para auxiliar no entendimento e consequente especificação das necessidades do usuário. Inspirado em práticas de design centradas no usuário, a abordagem ainda tem seus benefícios pouco conhecidos no contexto de desenvolvimento de software. Como parte de um projeto que visa identificar como a abordagem tem sido usada neste contexto, seus benefícios e recomendações de boas práticas, este artigo apresenta o relato de um estudo de caso sobre o uso de DT para explorar as necessidades de academias de musculação, visando verificar se o uso do DT e das suas técnicas nos permite identificar apropriadamente o entendimento da solução. Utilizou-se o modelo duplo diamante [7] e modelo Hasso Plattner [15] com um conjunto de 13 técnicas. Baseado na opinião dos stakeholders e demais participantes deste estudo de caso, o entendimento foi adequado e a solução proposta foi próxima do desejado pelos stakeholders, sugerindo que as técnicas são apropriadas para apoiar o desenvolvimento de um software.", "url": "artigos/artigos_WER18/wer201810.html"}, {"title": "Requirements Smells como indicadores de má qualidade na especificação de requisitos: Um Mapeamento Sistemático da Literatura", "authors": ["Rafael Nascimento", "Eduardo Aranha", "Uirá Kulesza", "e Marcia Lucena"], "year": 2018, "keywords": "Engenharia de Requisitos; Análise de Qualidade; Requirements Smells.", "abstract": "Artefatos de requisitos são primordiais para guiar as demais etapas do processo de desenvolvimento e garantir a qualidade do produto. Quando os artefatos são de má qualidade, estes sintomas tendem a ser propagados para as demais etapas, ocasionando mais problemas de qualidade. Diante disso, pesquisadores têm investigado a existência de indicadores de má qualidade na especificação de requisitos, prejudicando negativamente a compreensão, manutenção e qualidade dos artefatos. Estes indicadores são descritos como Requirements Smells e são utilizados para inspecionar a qualidade das especificações de requisitos em linguagem natural. Este trabalho apresenta um Mapeamento Sistemático da Literatura para compreender como o tema está sendo abordado, seu conceito, o nível dos suportes ferramentais e análise em projetos reais. Um total de 41 estudos foram selecionados e que desde 2013, trabalhos vêm sendo produzidos de forma crescente. Compreende-se que o conceito tem ganhado visibilidade, existência de suportes ferramentais, aplicação do conceito de Requirements Smells na inspeção de requisitos em projetos reais e o seu impacto em outras etapas do desenvolvimento de software", "url": "artigos/artigos_WER18/wer201811.html"}, {"title": "A Catalogue of iStar Extensions", "authors": ["Enyo Gonçalves", "Tiago Heineck", "João Araújo", "Jaelson Castro"], "year": 2018, "keywords": "Requirements; Catalogue; iStar extensions.", "abstract": "iStar has been extended since its initial proposal in the 90s. It is worth noting that since 2016 the language notation is under standardisation. However, new extensions continue to be proposed. The search for previous ex-tensions and its constructs can be a starting point in the proposal of new ones. So, to ease the identification of the previous extensions and its constructs is es-sential to next proposals. Motivated by this situation, the objective of this paper is to present a catalogue of iStar extensions. The extensions and their constructs were identified from a systematic literature review, which identified that 96 ex-tensions had been proposed until 2016. The results suggest that catalogue is im-portant during future iStar extensions proposal.", "url": "artigos/artigos_WER18/wer201812.html"}, {"title": "De KAOS para SysML na Modelagem de Sistemas Embarcados: Uma Revisão da Literatura", "authors": ["Timóteo Gomes", "Fernanda Alencar", "Aêda Sousa"], "year": 2018, "keywords": "SysML; KAOS; Rede de Petri; Sistemas Embarcados", "abstract": "Na modelagem de sistemas, de modo em geral, não se leva em con-sideração as razões e intenções que determinam as funcionalidades desses sis-temas. A Engenharia de Requisitos Orientada a Objetivos (do inglês, Goal Ori-ented Requirements Engineering GORE) visa resolver esse problema. Nesse contexto, está KAOS, que chega aos requisitos, pretendendo dar respostas às questões Por quê?, Quem? e Quando? sobre os objetivos/metas previa-mente declarados. Por outro lado, no desenvolvimento de sistemas complexos, nos quais os sistemas embarcados estão inseridos, utiliza-se a linguagem de modelagem SysML, mas que como UML, não dá muita atenção a dimensão das razões e intenções. Desta feita, pretende-se integrar KAOS a SysML através do mapeamento de seus quatro modelos para os diagramas da SysML. Alguns des-ses modelos são naturais à UML, no entanto SysML tem outras dimensões que precisam ser consideradas, sobretudo os novos diagramas: o de requisitos e o paramétrico. Como forma de verificar o grau de correção do pretendido mape-amento, pensa-se utilizar simulações através da modelagem em redes de Petri. Neste artigo são apresentados os primeiros resultados da revisão sistemática da literatura para a identificação de abordagens similares e de problemas ainda em aberto no contexto da modelagem de sistemas embarcados.", "url": "artigos/artigos_WER18/wer201813.html"}, {"title": "Tailoring the NFR Framework for Measuring Software Ecosystems Health", "authors": ["Simone da Silva Amorim", "Sandro Santos Andrade", "John D. McGregor", "Eduardo Santana de Almeida", "Christina von Flach G. Chavez"], "year": 2018, "keywords": "Software Ecosystems; Software Architecture; Non-Functional Requirements; NFR framework; Health Measures.", "abstract": "A healthy software ecosystem is capable of maintaining pro- ductivity and attractiveness, even in the face of problems and disrup- tions. Some studies have used software metrics to measure the health of a software ecosystem; however, there is little agreement on how to mea- sure those aspects related to software architecture nor how to weigh their in uence on the health state of the ecosystem. This paper introduces an approach to measuring and assessing the state of a software ecosystem's health that is aware of the architectural practices used. The approach uses a variation of the softgoal interdependence graph belonging to NFR (Non-Functional Requirements) framework on goal modeling. The key idea is to model and estimate in uences of architectural practices on the health indicators. This research carried out an exploratory case study in the KDE ecosystem. KDE architectural practices were identi ed and analyzed with the support of our proposed practice-aware approach. The ndings present the measurable in uences that can be used to support decision-making processes related to architectural practices.", "url": "artigos/artigos_WER18/wer201814.html"}, {"title": "Mechanisms to Support Requirements Prioritization: A Systematic Mapping Review", "authors": ["Cinthya Cavalcanti", "Maria Lencastre", "Roberta Fagundes", "Taina Santos", "Daniel Ferreira"], "year": 2018, "keywords": "Requirements engineering; requirements prioritization; supporting mechanisms; systematic mapping review.", "abstract": "Requirements prioritization is applied to identify which artifacts must be implemented first, in order to create a product that best satisfies the customers need by using the smallest number of resources. However, the task of prioritizing requirements is challenging and complex, and there is no well-defined set of mechanisms that help this activity. This article aims at identifying and analyzing the mechanisms to support the requirements prioritization. So, a systematic map-ping review was conducted. The result is a report that presents the different types of publications (journals, conference papers, thesis, book chapters), the published year, the supporting mechanisms, the phases of the requirements engineering pro-cess, and the prioritization techniques and tools used. It was observed that the prioritization requirements field is quite needy of mechanisms and tools that sup-port this activity, mainly that ones that provide visual resources.", "url": "artigos/artigos_WER18/wer201815.html"}, {"title": "Priorização de Requisitos em Startups no Armazém da Criatividade (Porto Digital): Resultados Preliminares", "authors": ["Gustavo Silva", "Wylliams Santos", "Maria Lencastre"], "year": 2018, "keywords": "Engenharia de Requisitos; priorização de requisitos; startups", "abstract": "As startups de software vêm ganhando destaque no mercado; na maioria das vezes, estão associadas ao conceito de desenvolvimento de produtos de software inovadores e que lidam com limitações de tempo e recursos. Pesquisas apontam que as startups não são versões menores de grandes empresas e que as práticas existentes de desenvolvimento de software não podem ser repassadas diretamente para as startups sem os devidos ajustes. Poucos estudos abordam e exploram como a priorização de requisitos é praticada em startups. Apesar de ser uma atividade essencial para garantir o sucesso dos projetos, isto é, para satisfazer às necessidades mais importantes e críticas dos stakeholders, assim como para o planejamento de releases. O objetivo deste artigo é explorar através de um estudo qualitativo as práticas de priorização de requisitos utilizadas em startups e os desafios associados a essas práticas. Com isso, será obtido conhecimento que poderá fortalecer novas pesquisas relacionadas à priorização de requisitos no contexto de startups, permitindo auxiliar também profissionais com a intenção de iniciar startups de software.", "url": "artigos/artigos_WER18/wer201816.html"}, {"title": "Requisitos de Qualidade de Usabilidade: análise da utilização em sistemas de uma instituição financeira", "authors": ["Angélica Toffano S. Calazans", "Eloisa Toffano S. Masson", "Roberto A. Paldês", "Fernando de A. Guimarães", "Kiane M. Rezende", "Ricardo Ajax. D. Kosloski"], "year": 2018, "keywords": "ISO/IEC 25000; Requisitos de qualidade; Requisitos Não funcionais; Usabilidade.", "abstract": "Os requisitos de qualidade com foco na usabilidade estão relacionados à facilidade de uso e de aprendizado de um sistema pelo cliente, contribuindo para o desempenho na sua utilização e para a satisfação do usuário. Essas carac-terísticas ganham relevância pelo alcance e aprovação amplos que devem apre-sentar nos sistemas da área financeira. Assim, a pesquisa tem como objetivo au-mentar a compreensão sobre a utilização dos requisitos de qualidade de usabili-dade. Foram analisadas especificações de 26 sistemas de uma organização finan-ceira pública de grande porte, incluindo sistemas de uso externo e interno à orga-nização. Foi utilizada a análise de conteúdo e o software Nvivo, sendo categori-zados e analisados 264 requisitos de qualidade de usabilidade. Considerando que os requisitos de qualidade de usabilidade selecionados diferiam em seu nível de abstração, detalhe e completude, foram definidos critérios para a classificação. Utilizaram-se as subcaracterísticas de Usabilidade da ISO/IEC 25010 para a clas-sificação. Como resultado obtido, constatou-se que grande parte dos requisitos definidos atendem à norma, apesar de terem sido classificados com nomenclatu-ras diferentes. A análise também identificou requisitos que seguem um padrão comum. Identificaram-se, ainda, as subcaracterísticas de Usabilidade com maior interesse: apreensibilidade (37%) e estética da interface do usuário (27%) dos requisitos elicitados. A subcaracterística de acessibilidade obteve menor percen-tual de atenção, com 1,89% dos requisitos identificados.", "url": "artigos/artigos_WER18/wer201817.html"}, {"title": "Apresentando o PRISE:um processo para conduzir as extensões do iStar", "authors": ["Enyo Gonçalves", "Jaelson Castro", "João Araújo"], "year": 2018, "keywords": "", "abstract": "iStar é uma linguagem de modelagem baseada em objetivos usada para modelar requisitos. Ela vem sendo utilizada em projetos acadêmicos e industriais. Frequentemente o iStar é estendido para incorporarnovos construtores de alguma área de aplicação específica. Atualmente, a linguagem está sobre padronização e diversos estudos tem focado em analisar as variações existentes da linguagem para identificar similaridades e definir um núcleo para iStar. Entretanto, nós acreditamos que ela continuará a ser estendida, assim é importante entender como iStar é extendido e propor mecanismos que ajudem nesta tarefa. Em trabalhos anteriores nós analisamos por meio de uma Revisão Sistemática de Literatura e de um estudo qualitativo como as extensões vem sendo feitas. Atualmente Este video contribui para este propósito apresentando um processo para conduzir as extensões de iStar. https://youtu.be/Ivon6EYElEg", "url": "artigos/artigos_WER18/wer201818.html"}, {"title": "Engenharia de Requisitos Aplicada na Prática em Empresa Júnior", "authors": ["Natalya Goelzer", "Herberth Reinstein", "Rafael Parizi"], "year": 2018, "keywords": "", "abstract": "A Missões Júnior é uma empresa júnior composta por acadêmicos, do curso de Sistemas de Informação, que buscam experiência profissional em projetos de softwares. O objetivo da equipe é gerar um produto que qualidade que satisfaça as necessidades do cliente. Porém, surgiram dificuldades que impediam de atingir este propósito, tal como questões relacionadas ao não cumprimento de prazos e ao retrabalho excessivo. Como alternativa para solucionar os problemas foi criado um CANVAS, na forma de quadro expositivo. O primeiro é intitulado Visão de Produto e é composto pelas colunas: visão, público, necessidade, produto e funcionalidades, onde são registrados os requisitos. Com o preenchimento destas informações é mostrado quais problemas serão solucionados. O segundo, Visão do Processo para o Produto, é composto por data, nome, funcionalidades e mêtricas da release. E serve para elucidar o que será entregue ao cliente a cada versão. Com os dois quadros completos a equipe verifíca o andamento do projeto e visualiza de maneira clara e rápida as alterações de requisitos. Prevendo, desta forma, atrasos de entrega antecipadamente. Enfim percebemos a importância da engenharia de requisitos para o sucesso do desenvolvimento, pois ela é a base do mesmo. https://vimeo.com/278698904", "url": "artigos/artigos_WER18/wer201819.html"}, {"title": "Possíveis Limites do Mapeamento Sistemático: Uma Visão de Pesquisadores em Engenharia de Requisitos", "authors": ["Roxana L. Q. Portugal", "Ana Maria da Mota Moura", "Romeu F. de Oliveira", "Julio Cesar Sampaio do Prado Leite"], "year": 2018, "keywords": "", "abstract": "No início de uma pesquisa, é preciso entender o estado da arte. Nesse sentido, diversas estratégias são utilizadas, uma delas é o mapeamento sistemático. No entanto, é possível que esta estratégia limite as possibilidades de busca, pois o mapeamento sistemático pode deixar de examinar: os principais periódicos, as principiais conferências, os principais pesquisadores, assim como teses ou dissertações. Além disso, pode deixar de explorar áreas afins. Esse vídeo mostra um caso onde, três pesquisadores escolhem diferentes maneira de explorar a literatura, tomando como base às 5 perguntas definidas no mapeamento sistemático de um dos autores. A pergunta principal desse mapeamento é: Como promover Acessibilidade Web em Tempo de Execução? Esse vídeo mostra a literatura selecionada por cada pesquisador, os métodos usados, assim como a discussão dos resultados. https://vimeo.com/288008086.", "url": "artigos/artigos_WER18/wer201820.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2019)", "authors": ["Fernanda Alencar", "Marcela Ridao", "Henrique Prado de Sá Sousa"], "year": 2019, "keywords": "wer; Requirements Engineering", "abstract": "The Workshop on Requirements Engineering 2020 is now in its twentieth-third edition. This series of workshops on the area started in 1998 as a meeting of the Ibero-American requirements engineering community, but along the years it has attracted attention from researchers and practitioners from other parts of the world", "url": "artigos/artigos_WER19/wer201900.html"}, {"title": "Aplicação da Etnografia no Contexto de Fábrica de Software na Perspectiva da Engenharia de Requisitos", "authors": ["Luana Souza", "Erica Miranda", "Márcia Lucena", "Apuena Gomes"], "year": 2019, "keywords": "Documentação; Compartilhamento de conhecimento; Etnografia; Scrum.", "abstract": "Observando o contexto de dificuldades na elaboração da documentação de requisitos e na atividade de transferir e compartilhar o conhecimento entre os engenheiros de requisitos, foi elaborada uma etnografia organizacional para entender de perto como uma fábrica de software lida com essa questão. O objetivo geral deste trabalho foi investigar desafios em duas equipes de engenheiros de requisitos, que impactem na produção e na manutenção de uma documentação efetiva para seus diferentes públicos alvo (desenvolvedores, analistas de teste, os próprios engenheiros de requisitos e clientes). Os desafios identificados foram agrupados em três grandes categorias: compartilhamento de conhecimento, consulta aos clientes, documentação e metodologias ágeis. Para realizar este trabalho foi desenvolvido uma adaptação de um processo etnográfico organizacional composta das etapas de: observação das equipes, entrevistas (com engenheiros de requisitos, líderes de equipes e direção de sistemas) e arqueologia dos sistemas. Ao final deste processo, os resultados coletados são interpretados na última etapa do processo etnográfico chamada de triangulação. Para então, ser aplicada metodologia Grounded Theory adaptada para categorizar os desafios, e indicar as práticas que permitirão, segundo a literatura, a fábrica de software obtenha: ganhos de produtividade, redução do custo de comunicação entre membros das equipes, redução do custo de planejamento das sprints, redução da dependência presencial do engenheiro de requisitos e uma documentação efetiva. Os desafios identificados, o benefício no uso das práticas sugeridas e o próprio processo etnográfico - constituído especificamente para esta pesquisa - são as contribuições deste trabalho", "url": "artigos/artigos_WER19/wer201901.html"}, {"title": "Críticas Cognitivas a Heurísticas Orientadas a Modelos", "authors": ["Jorge H. Doorn", "Graciela D.S. Hadad", "María Celia Elizalde", "Alan R.G. García", "y Lucas O. Carnero"], "year": 2019, "keywords": "Proceso de Requisitos; Ergonomía Cognitiva; Completitud; Calidad de Modelos; Lenguaje Natural", "abstract": "Los requisitos, como piedra basal del desarrollo de sistema de software, deben ser de la mejor calidad posible, cubriendo las necesidades reales de los clientes y las limitaciones del proyecto. Alcanzar un nivel aceptable de calidad no es fácil y, a veces, no suele cumplirse. En proyectos de investigación previos, se ha evaluado exhaustivamente estos niveles de calidad en modelos escritos en lenguaje natural, principalmente en glosarios con definiciones de los términos del lenguaje empleado en el contexto de aplicación, observándose en estos casos una baja calidad y escasa repetitividad de los mismos. Esta característica es prácticamente independiente del modelo y de las fuentes de información utilizadas. A pesar de reiterados esfuerzos consistentes en la incorporación de nuevas heurísticas, las mejoras logradas resultaron poco satisfactorias. Una revisión retrospectiva de estos trabajos permitió detectar que indudablemente es la habilidad cognitiva del propio ingeniero de requisitos el origen de estos defectos. Notablemente, las heurísticas utilizadas proveen guías rudimentarias acerca de cómo elaborar la información elicitada. Esta carencia es la base del proyecto de investigación de carácter exploratorio-descriptivo que se ha iniciado y que se presenta aquí", "url": "artigos/artigos_WER19/wer201902.html"}, {"title": "Evaluación de Variantes de Inspección en un Modelo Léxico", "authors": ["Alberto Sebastián", "Graciela D. S. Hadad", "Daniela Raffo"], "year": 2019, "keywords": "Verificación; Inspecciones; Modelos en Lenguaje Natural.", "abstract": "Elaborar modelos en lenguaje natural durante el proceso de requisitos es una práctica habitual que facilita la elicitación, validación y negociación con el cliente. Es frecuente construir inicialmente un glosario con los términos relevantes utilizados por los clientes. A pesar de construirse este glosario siguiendo heurísticas concretas, suele presentar un número significativo de defectos. Por consiguiente, es importante detectarlos y corregirlos tempranamente para evitar su propagación sobre posteriores modelos. En tal sentido, la inspección es una técnica de verificación que consigue una alta eficacia en identificar defectos. Existen distintas variantes de inspección sobre modelos de requisitos, centradas en el modo de lectura del modelo para capturar defectos. En el presente trabajo, se presenta un estudio comparativo, en términos de eficacia y eficiencia, de tres variantes de inspección: lectura con checklist, lectura basada en procedimientos y lectura constructiva, aplicadas sobre un modelo léxico. Con los resultados de 23 inspecciones, se observó que la lectura constructiva logró mayor tasa de detección de defectos, focalizada principalmente en omisiones y ambigüedades, aunque insumiendo más tiempo que la lectura con checklist, mientras que la lectura basada en procedimientos fue la que insumió los mayores tiempos, capturando en promedio una menor cantidad de defectos.", "url": "artigos/artigos_WER19/wer201903.html"}, {"title": "Identificando cenários de conflitos na Engenharia de Requisitos visando aplicação da Comunicação Não Violenta", "authors": ["Aline Ferreira Barbosa", "Maria Lencastre"], "year": 2019, "keywords": "Conflict; Communication Nonviolent; Engineering Requirements", "abstract": "[Contexto] A Engenharia de Requisitos envolve inúmeras interações sociais, que requerem do analista um alto nível de cooperação e empatia com pessoas de personalidades, valores e interesses diferentes. Nas equipes de desenvolvimento de software, independentemente do tamanho que seja o projeto, os conflitos fazem parte do seu ciclo de vida. Portanto, é importante o analista de requisitos monitorar continuamente os sinais que apontam a existência de conflitos, evitando o comprometimento do projeto. [Objetivo] Este artigo se concentra em identificar cenários de conflitos recorrentes nas equipes de desenvolvimento de software e utiliza uma estratégia para análise dos mesmos, a Comunicação Não Violenta (CNV). [Método] Foi realizado um estudo qualitativo utilizando como método de coleta uma entrevista semiestruturada com profissionais de 5 empresas distintas visando um aprofundamento nas situações de conflitos identificadas. [Resultados] Foram levantados um conjunto de cenários de conflito reais, assim como feita a análise dos mesmos, com base na CNV; isto ajudou os participantes (entrevistados) a observar o fato, independente de julgamentos, assim como identificar os sentimentos e necessidades presentes na situação; dessa forma, eles passaram a ter uma melhor compreensão do cenário onde ocorreu o conflito", "url": "artigos/artigos_WER19/wer201904.html"}, {"title": "iStar4Safety: Uma Extensão de iStar para Modelagem de Requisitos de Segurança em Sistemas Críticos", "authors": ["Moniky Ribeiro", "Jaelson Castro", "Jéssyka Vilela", "João Pimentel"], "year": 2019, "keywords": "Engenharia de Requisitos; Sistemas Críticos; Safety; iStar; Extensão", "abstract": "Sistemas Críticos de Segurança são caracterizados por serem sistemas que caso falhem ou não se comportem como esperado, podem levar à danos ou até perdas de vidas, destruição de propriedade, perdas de missões e/ou dano ambiental. A literatura reporta uma maior probabilidade de erros relacionados à segurança (do inglês safety) estarem associados às fases iniciais do processo de desenvolvimento (elicitação e especificação de requisitos) do que às fases finais (tais como a codificação). Objetivo: Este trabalho propõe uma extensão da linguagem iStar 2.0, a denominada iStar4safety, para possibilitar a modelagem de requisitos de segurança. Método: A definição dos novos construtores para modelar características relevantes a segurança foi realizada analisando os conceitos essenciais definidos pela literatura especializada. Além disso, propõe-se o metamodelo da linguagem juntamente com as regras de validação. Resultados: A linguagem iStar4Safety tem como foco a modelagem dos atributos de segurança no estágio inicial do desenvolvimento de sistemas, adotando uma abordagem orientada a objetivos. Um Sistema Crítico, que visa controlar o cruzamento de ferrovias, foi modelado usando a extensão proposta. Conclusões: Os resultados de uma avaliação preliminar indicam que iStar4Safety é conservativa, isto é, preserva os construtores da linguagem iStar 2.0, sendo adequada para descrever os requisitos iniciais de Segurança de Sistemas Críticos", "url": "artigos/artigos_WER19/wer201905.html"}, {"title": "Metricas de Tamanho de Software com Metodos Ageis no Setor Publico: uma Revisão Sistemática", "authors": ["Alexandre Mendonça", "Fernanda Alencar"], "year": 2019, "keywords": "métodos ágeis; métricas de tamanho de software; setor público; revisão sistemática da literatura", "abstract": "A administração pública tem utilizado cada vez mais metodos ageis, adequando-se à realidade do mercado. Muito embora continue obrigada a mensurar suas entregas através de alguma métrica de tamanho de software, a escolha adequada dessa métrica pode definir o nível de sucesso dos projetos públicos. Neste artigo, identi ca-se as configurações de métricas de tamanho de software em conjunto com métodos ágeis no setor público. Como instrumento metodológico para a identificação de evidências foi utilizada a revisão sistemática da literatura. A métrica Ponto de Função IFPUG e o método Manifesto Ágil e Scrum foram identificados como os mais utilizados no setor público. A definição de configurações de uso de métricas e métodos ágeis no setor público torna possivel direcionar a tomada de decisões para a conclusão com sucesso dos projetos, no menor tempo possível, com o menor custo aceitável e entregando valor agregado perceptível à sociedade.", "url": "artigos/artigos_WER19/wer201906.html"}, {"title": "O uso de modelos de processos de negócio e de modelagem organizacional em metodologias ágeis: uma revisão sistemática da literatura", "authors": ["Camila Tiemi Outa", "Victor F. A. Santander"], "year": 2019, "keywords": "Processos de Negócio; Ambientes Organizacionais; Metodologias ágeis", "abstract": "A necessidade de compreender o ambiente organizacional e processos de negócio é fundamental em qualquer processo de software. Neste sentido, é importante conhecer como práticas, técnicas e ferramentas de modelagem orga-nizacional e processos de negócio são utilizadas ou percebidas em contextos de desenvolvimento ágil na engenharia de software. Este é um aspecto importante e pouco explorado que deve ser estudado considerando a importância de metodologias ágeis nos últimos anos. Para realizar este estudo apresenta-se no pre-sente artigo uma Revisão Sistemática da Literatura", "url": "artigos/artigos_WER19/wer201907.html"}, {"title": "Privacy and Security in Requirements Engineering: Results from a Systematic Literature Mapping", "authors": ["Dorgival Netto", "Mariana Peixoto", "Carla Silva"], "year": 2019, "keywords": "Privacy; Security; Requirements Engineering; Systematic Literature Mapping", "abstract": "Computing has been revolutionizing the way people communicate, share, and access information. Consequently, concerns about privacy and security are increasing. In this scenario, the literature reports that it is necessary to address privacy and security from the Requirements Engineering (RE) phase. This paper presents the results of a Systematic Literature Mapping, covers the period from 2000 to 2016, whose goal is to understand the current state of approaches concerning privacy and security in RE domain. We divided the results into research topics, research methods, types of study, research problems, and indications of future works regarding the eld of privacy and security in RE.", "url": "artigos/artigos_WER19/wer201908.html"}, {"title": "Raciocinando sobre a propagação de impactos em modelos de metas através de Redes de Petri", "authors": ["Romeu Ferreira de Oliveira", "Julio Cesar Sampaio do Prado Leite"], "year": 2019, "keywords": "Requisitos não funcionais; propagação de impactos; Redes de Petri", "abstract": "Tratar Requisitos Não Funcionais (RNFs) na concepção de um software é uma tarefa não trivial. O tratamento de RNFs é complexo na medida em que, além dos impactos nos requisitos funcionais, os RNFs podem estar interdependentes em diferentes situações. Analisar essa interdependência é muito importante para evitar retralho na construção de software. Essa classe de requisitos, RNFs, compreende as características de qualidade de uma aplicação. Isto implica que, ao tratar de requisitos subjetivos, precisamos do conceito de satisfação a contento. Modelos que reflitam o conhecimento, de forma concisa e clara, dessa subjetividade dos RNFs são necessários. Esses modelos devem ajudar o engenheiro de requisitos no tratamento desses requisitos, tanto nos impactos como nas interdependências. Esse tratamento, quando feito de maneira adequada é base para a tomada de decisões arquiteturais. Este artigo aborda o início de uma pesquisa sobre estratégias de análise da propagação de rótulos e o consequente impacto desses requisitos não funcionais, considerando o uso de catálogos de conhecimento do tipo SIG (Softgoal Interdependency Graph). Em particular, pretendemos investigar como o uso de Redes de Petri, pode ajudar no refinamento do grau de granularidade dos rótulos de um SIG, de forma a que a propagação de operacionalizações de RNFs sejam mais informativas.", "url": "artigos/artigos_WER19/wer201909.html"}, {"title": "Relacionando requisitos de software e competências de recursos humanos através de modelos organizacionais", "authors": ["Henrique Prado Sousa", "Eduardo Kinder Almentero", "Julio Cesar Sampaio do Prado Leite"], "year": 2019, "keywords": "Requisitos de software; competências; Recursos Humanos; Modelagem organizacional; Processos de negócio", "abstract": "Os modelos de processos de negócio podem ser usados como insumo para elicitação de requisitos de software. Uma das motivações para o uso destes modelos é a busca por alinhamento entre a TI e a organização, considerando que eles representam com maior fidelidade o fluxo de tarefas e informações em uma organização. Entretanto, os modelos de processos de negócio são insuficientes na representação do complexo ambiente organizacional. Uma modelagem organizacional pode integrar elementos provenientes de diferentes áreas com o objetivo de possibilitar análises mais aprofundadas da interação dos conceitos modelados visando, por exemplo, favorecer o alinhamento organizacional. A linguagem GPI (Goal, Process, Indicators) vem sendo desenvolvida neste sentido, agregando conceitos específicos de domínio de Recursos Humanos para permitir a modelagem e avaliação do seu alinhamento. O objetivo deste trabalho é analisar o potencial dessas informações presentes nos modelos organizacionais como insumo para elicitação de requisitos. Para isso realizamos um mapeamento das informações de competências humanas com potenciais requisitos de software extraídos de modelos organizacionais. As relações entre competências humanas e requisitos de software demonstram ser relevantes e úteis para auxiliar na decisão organizacional envolvendo projetos de software.", "url": "artigos/artigos_WER19/wer201910.html"}, {"title": "Requirements Communication in Safety-Critical Systems", "authors": ["Jessyka Vilela", "Jaelson Castro", "Luiz Eduardo G. Martins", "Tony Gorschek", "Camilo Almendra"], "year": 2019, "keywords": "Safety-Critical Systems; Requirements Communication; Requirements Engineering; Safety Engineering; Systematic Literature Review", "abstract": "Safety-critical systems (SCS) are mainly controlled by software. Accordingly, the development of these systems must be carefully planned since inadequate or misunderstood requirements have been recognized as the major cause of a signifficant proportion of accidents and safety-related catastrophes. Objective: We investigate the integration and requirements communication in the requirements engineering (RE)process among different parties when developing SCS. Method:We used a Systematic Mapping Study as the basis for our work. Results: We analyze the challenges and needs involved, application context, research type, evaluation methods, type of contribution, domain, requirements activity as well as languages and tools used to specify safety requirements. Furthermore, we also analyze stakeholders involved, communication format, and for what safety standards have the approaches been proposed. Conclusions: We believe the results of such a study will benefit both researchers and practitioners. This information contributes to setting up possible collaborative networks and as a reference when developing new research projects.", "url": "artigos/artigos_WER19/wer201911.html"}, {"title": "The PRISE Tool to Support iStar Extensions", "authors": ["Enyo Gonçalves", "Tiago Heineck", "Luciana de Oliveira", "João Araújo", "Jaelson CastrO"], "year": 2019, "keywords": "Requirements; iStar extensions; Process; Tool.", "abstract": "iStar has been extended since its initial proposal in the 90s. It is worth noting that since 2016 the language notation is under standardisation. However, new extensions continue to be proposed. The search for previous extensions and its constructs can be a starting point in the proposal of new ones. PRISE (PRocess to conduct IStar Extensions) consists of a set of tasks, artefacts and templates which can be used when one needs to propose extensions which are more complete, consistent and without conflicts. The objective of this paper is to present a tool to support the proposal of iStar extensions based on PRISE. The tool helps to create projects of extensions and update the information about the performed tasks, as well as the information of the artefacts to be filled by the extender. The results suggest that PRISE Tool can be very useful to manage the iStar extensions.", "url": "artigos/artigos_WER19/wer201912.html"}, {"title": "Um processo para elicitar requisitos de software em projeto de implantação de ERP para empresas com unidades autônomas e diferentes culturas organizacionais", "authors": ["Hamilton G. P. Hitzschky", "Vagner L. Gava"], "year": 2019, "keywords": "Implantação de Sistema ERP; Elicitação de Requisitos; Cultura Organizacional; Subdivisões Autônomas", "abstract": "Os aspectos do processo para elicitação de requisitos na implantação de sistema ERP (Enterprise Resource Planning) são diferentes daqueles para desenvolvimento de um novo produto. Quando se trata da implantação deve-se ter atenção nas diferenças entre os processos de negócio e as funcionalidades oferecidas pelo sistema a ser implantado. Desalinhamentos em excesso pode tornar o projeto inviável. Diferentes culturas organizacionais e subdivisões em-presariais com alto nível de autonomia são algumas das principais causas de in-sucesso na implantação de sistemas corporativos. Esta pesquisa tem como obje-tivo propor um modelo de processo para adequar as solicitações do cliente, dife-rentes ou ausentes no sistema a ser implantado, às necessidades reais da organi-zação. Os resultados obtidos com a revisão sistemática possibilitaram a defini-ção do modelo proposto, formado por técnicas identificadas na literatura e adaptadas ao contexto apresentado. O processo teve sua eficácia comprovada por meio do método de pesquisa-ação e foi aplicado em ambiente real de im-plantação, no decorrer da fase de elicitação de requisitos", "url": "artigos/artigos_WER19/wer201913.html"}, {"title": "Uma Análise das Características de Especificação de Requisitos de Software em Normas de Ambientes Regulados", "authors": ["Johnny Cardoso Marques"], "year": 2019, "keywords": "software; certificação; requisitos; normas", "abstract": "Engenharia de Requisitos é o conjunto de atividades envolvidas no gerenciamento, levantamento, documentação e manutenção de um conjunto de requisitos para um produto. O termo Engenharia envolve o uso de técnicas sistemáticas de repetibilidade para garantir que os Requisitos de Software sejam completos, consistentes, válidos e verificáveis. A Especificação de Requisitos de Sof-tware é um processo organizado orientado para definir, documentar e manter os Requisitos de Software durante o ciclo de vida de desenvolvimento. Muitos autores sugerem que os requisitos devem sempre focar suas declarações no que o produto de software precisa abordar, sem especificar como implementá-las. No entanto, o detalhamento dos Requisitos de Software é influenciado por vários fatores, tais como: pensamentos organizacionais; padrões de especificação existentes; e necessidades regulatórias. Este trabalho se enquadra exatamente nas ne-cessidades regulatórias, onde são apresentadas e exploradas as características de Especificação de Requisitos de Software em Ambientes Regulados como aeronáutica, ferroviária e médica. Este artigo apresenta brevemente as três normas utilizadas nestes ambientes regulamentados (RTCA DO-178C, IEC 62279 e IEC 62304) e analisa suas similaridades do ponto de vista da Especificação de Requisitos.", "url": "artigos/artigos_WER19/wer201914.html"}, {"title": "Uso de Metodologias Criativas no Processo de Ensino da Disciplina Engenharia de Requisitos", "authors": ["Patrícia Mergulhão", "Maria Lencastre", "Melina Soares", "Ricardo Almeida", "Aline Barbosa"], "year": 2019, "keywords": "Creative Methodologies; Education; Requirements", "abstract": "Developing the ability to define the requirements of a system is one of the core competencies and objectives of the Requirements Engineering course. Several traditional teaching methods are used by the academy for this purpose, also trying to support experiences closer to reality and the generation of solutions more in line with the demands of stakeholders. However, they do not seem to meet the students' learning needs, who show a growing interest in more creative, interactive, engaging and participatory approaches. This paper evaluates the perception of graduate students in Software Engineering about creative teaching methodologies in the discipline of Requirements Engineering. For this purpose, an exploratory-descriptive study was carried out, where a questionnaire was applied to the students. The results show a favourable perception of the involved students in applying creative techniques", "url": "artigos/artigos_WER19/wer201915.html"}, {"title": "JGOOSE: Uma ferramenta para derivar casos de uso a partir de modelos em i* e BPMN", "authors": ["Victor Augusto Pozzan", "Victor F. A. Santander"], "year": 2019, "keywords": "", "abstract": "A ferramenta JGOOSE (Java Goal Into Object Oriented Standard Extension) tem como objetivo suportar a derivação de casos de uso na forma de diagrama e descrição textual a partir de modelos organizacionais desenvolvidos via framework i* (lê-se istar) como também a partir de modelos BPMN (Business Process Modeling Notation). A derivação é automática, pois a ferramenta automatiza as diretrizes para obter casos de uso já propostas em trabalhos pré-vios. Para melhorar este processo, também foram implementados editores para i*, BPMN e Casos de Uso o que permite que engenheiros de requisitos possam criar e editar os modelos envolvidos no processo. Todos os modelos podem ser salvos no formato .mxe o qual é nativo da ferramenta como também em formatos de imagem. Também é possível editar os cenários principal e secundário dos casos de uso gerados e salvá-los em documentos do tipo texto. A ferramenta está implementada na linguagem java e pode ser utilizada tanto no sistema opera-cional Windows quanto Linux. Atualmente esta ferramenta está sendo melhorada para incorporar estratégias de rastreamento de requisitos considerando os artefatos de requisitos suportados. https://youtu.be/FdDaQp_XqFQ", "url": "artigos/artigos_WER19/wer201916.html"}, {"title": "Laboratório da CNV: Um jogo digital para compreender a Comunicação Não Violenta", "authors": ["Camila Luísa F. de Lima", "Camila B. de Andrade", "Aline F. Barbosa", "Maria Lencastre"], "year": 2019, "keywords": "nonviolent communication; game; conflicts.", "abstract": "O Laboratório da CNV é um jogo digital desenvolvido com o objetivo de facilitar a compreensão da Comunicação Não Violenta, uma técnica de resolução de conflitos que nos guia no processo de reformular a maneira pela qual nos expressamos e escutamos os outros. Para isso, o jogo aborda um conflito e sua resolução usando as 4 etapas da CNV, são elas: observação, sentimentos, necessidades e pedidos. Esse jogo busca de maneira lúdica ajudar no desenvolvimento de competências socioemocionais que são essenciais para os profissionais da atualidade, em especial os engenheiros de requisitos, que lidam com pessoas de diferentes personalidades, experiências e valores. Portanto, nesse vídeo apresentamos o processo de desenvolvimento, incluindo desde a sua concepção ao resultado final do jogo. Vale ressaltar, que o jogo Laboratório da CNV é o primeiro jogo digital mobile a bordar a CNV, sendo assim, um grande potencial para disseminar uma nova forma, estruturada, de resolução de conflitos. youtu.be/i9JU80eiaGU e vimeo.com/325975234", "url": "artigos/artigos_WER19/wer201917.html"}, {"title": "Uso das Metodologias Ativas na Engenharia de Requisitos", "authors": ["Jose Vinicius Vieira Lima", "Andres Paul Moya Flores", "Fernanda M. R. Alencar"], "year": 2019, "keywords": "Metodologias Ativas. Engenharia de Requisitos. Ensino. Aprendizagem.", "abstract": "Com as mudanças ocasionadas através da inserção e do uso de sistemas e softwares nos mais diferentes contextos, faz-se necessário discutir sobre as necessidades provenientes destas quando relacionados ao âmbito educacional e as práticas de ensino em que estão sendo aplicadas. Nesse sentido, as metodologias ativas vêm sendo utilizadas como novos modelos de ensino e aprendizagem, onde estas têm como principais características, propiciar que os alunos busquem soluções para problemas do mundo real, sendo estes protagonistas do seu processo de aprendizado. Essas alternativas apontam os caminhos para a autonomia, autodeterminação pessoal, cultural e social, sendo indispensáveis para o desenvolvimento da consciência crítica quando relacionada a transformação da realidade. Assim sendo, este vídeo descreve um relato de ex-periência após as metodologias ativas serem inseridas em disciplinas da graduação e na pós-graduação. Para isso, entrevistas com os discentes foram realizadas a fim de identificar as vantagens e possíveis dificuldades encontradas por estes no momento da aplicação, do mesmo modo que foram apontadas as principais estratégias que estão sendo utilizadas, e como estas estimulam o ensino e aprendizagem através de experiências reais ou simuladas, visando condições de solucionar, com sucesso, desafios advindos das atividades essenciais da prática social e em diversos aspectos. http://y2u.be/XE-7QVzYI5Yfeature", "url": "artigos/artigos_WER19/wer201918.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2020)", "authors": ["Graciela Dora Susana Hadad", "João Henrique Pimentel", "Isabel Sofia Sousa Brito"], "year": 2020, "keywords": "", "abstract": "The Workshop on Requirements Engineering 2020 is now in its twentieth-third edition. This series of workshops on the area started in 1998 as a meeting of the Ibero-American requirements engineering community, but along the years it has attracted attention from researchers and practitioners from other parts of the world", "url": "artigos/artigos_WER20/wer202000_1.html"}, {"title": "Keynotes, Invited Talks, and Panel Session", "authors": ["Graciela Dora Susana Hadad", "João Henrique Pimentel", "Isabel Sofia Sousa Brito"], "year": 2020, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER20/wer202000_2.html"}, {"title": "Organization", "authors": ["Graciela Dora Susana Hadad", "João Henrique Pimentel", "Isabel Sofia Sousa Brito"], "year": 2020, "keywords": "", "abstract": "Keywords:", "url": "artigos/artigos_WER20/wer202000_3.html"}, {"title": "Avaliando a Relação entre o Catálogo de Transparência de Software e o Processo de Engenharia de Requisitos do MPS-SW?", "authors": ["Ana Clara Correa da Silva", "Henrique Prado de Sá Sousa", "Eduardo Kinder Almentero", "Julio Cesar Sampaio do Prado Leite"], "year": 2020, "keywords": "MPS.BR; Engenharia de Requisitos; Operacionalizações; Catálogo de Transparência de Software", "abstract": "MPS.BR is a program that aims to improve the quality of software development processes in the Brazilian context. MPS-SW, one of the components of MPS.BR, defines a set of expected results for the software process maturity in an organization, including results for Requirements Engineering (REQ) process. In previous works, it was observed that these results are related with the qualities present in the Software Transparency Catalog (CTS). The CTS details the qualities in issues that helps defining operationalizations which contribute positively to satisfice the quality. In this paper, we relate the results of REQ process to CTSs qualities towards proposing and evaluating operationalizations that are aligned to the REQ process. This alignment may help to take advantage of CTSs operationalizations to define a software development process adherent to level G of MPS-SW.", "url": "artigos/artigos_WER20/wer202001.html"}, {"title": "Comunicação de requisitos em quadros kanban virtuais", "authors": ["Jullia Saad", "Priscila Portela Costa", "Luciana A. M. Zaina"], "year": 2020, "keywords": "Requirements engineering; Virtual kanban board; Requirements communication", "abstract": "Quadros kanban virtuais permitem reunir informações sobre tarefas e requisitos do projeto, funcionando como uma das principais fontes de visualização sobre o desenvolvimento do projeto de software. Entretanto, muitas vezes alguns recursos não são bem compreendidos pelo time, o que pode acarretar problemas de comunicação entre o kanban virtual e o time. O objetivo deste artigo é apresentar uma proposta de funcionalidades que visam melhorar a comunicação sobre requisitos de software a partir do uso de um quadro kanban virtual. Para atingir o objetivo proposto, foram realizadas sessões de grupos de foco com 10 desenvolvedores de software para identificar as dificuldades que eles enfrentam diariamente utilizando quadros kanban virtuais. Em particular, observou-se dificuldades de acompanhamento das mudanças no quadro e o entendimento das tarefas de outros membros do time. A partir da análise dos dados coletados nos grupos de foco, foram propostas funcionalidades de visualização de atualizações e filtros de atividades. Essas funcionalidades são genéricas e podem ser aplicadas em diferentes ferramentas de quadro kanban virtual. Uma avaliaçãoo das funcionalidades propostas foi conduzida com 49 participantes. Os resultados da avaliação indicaram que houve uma melhora da comunica¸c~ao de requisitos a partir do uso de um quadro kanban com as funcionalidades propostas. Em particular, a visualização explícita do progresso e das atividades do projeto contribuiu para que os participantes entendessem corretamente os requisitos apenas pelo uso do quadro kanban.", "url": "artigos/artigos_WER20/wer202002.html"}, {"title": "Conflitos na ER: Proposta de uma Atividade de Narrativa com auxílio de Realidade Aumentada", "authors": ["Camila Andrade", "Maria Lencastre", "Aline Barbosa", "Patricia Mergulhão"], "year": 2020, "keywords": "Realidade Aumentada; Desenvolvimento de Software; Narrativa de Conflitos; Emoções; Ensino", "abstract": "Uma das principais causas de insucessos, nos projetos de Tecnologia da Informação (TI), reside na existência de conflitos; estes já fazem parte do ciclo de vida do desenvolvimento de um software. Observa-se, no entanto, a escassez de pesquisas que auxiliem nesse processo na área de TI. Esta pesquisa visa ajudar na expressão de relatos de conflitos reais na área, propondo para isso formas de estruturá-los e analisá-los de forma lúdica, visando a criação de um repositório que possa ser usado no ensino da Engenharia de Requisitos, através de Problem Based Learning (PBL). Quando uma pessoa expõe uma situação de conflito, geralmente, ela está emocionalmente envolvida e tem dificuldade em expressar o ocorrido, assim como os sentimentos despertados; entender esses fatores possibilita a sensibilização e empatia entre os envolvidos, potencializando a resolução do problema. Neste artigo, é proposta uma atividade de narrativa, com o suporte da Realidade Aumentada, que auxilia na descrição de cenários de conflito, em ambientes de desenvolvimento de software; são usadas emoções básicas e sentimentos relacionados em 3D, fornecendo imersão e visualização das diferentes perspectivas das partes conflitantes através de avatares. A atividade e a ferramenta proposta foram testadas no contexto de TI, e os resultados foram positivos quanto ao seu suporte.", "url": "artigos/artigos_WER20/wer202003.html"}, {"title": "Descrevendo requisitos de User eXperience em Critérios de Aceitação de User Stories", "authors": ["Jonathan H. J. Souza", "Leonardo C. Marques", "Tayana U. Conte", "Luciana A. M. Zaina"], "year": 2020, "keywords": "Engenharia de Requisito; User Stories; Critérios de Aceitação; User eXperience", "abstract": "User Stories (US) complementadas por critérios de aceitação (AC- Acceptance Criteria) são amplamente utilizadas no desenvolvimento ágil de software. Usualmente, USs e ACs descrevem requisitos funcionais, e poucas vezes são encontradas descrições de requisitos sobre a experiência do usuário (UX - User eXperience). Este artigo apresenta os resultados de uma investigação sobre quais elementos de UX (aqueles inerentes à interação do usuário) desenvolvedores descrevem nos ACs. Foi realizado um estudo junto a 30 desenvolvedores de software, no qual os participantes receberam um conjunto de artefatos de apoio à UX que deram subsídios para a elaboração das USs e ACs. Através de uma análise qualitativa em um total de 79 USs e 261 ACs gerados pelos participantes, examinou-se quais elementos de UX eram reportados nestes artefatos. Os resultados mostram que os elementos relacionados a design de interação e arquitetura da informação foram os mais reportados nos ACs analisados. Adicionalmente, constatou-se que as Heurísticas de Nielsen foi o artefato de UX mais utilizado durante a elaboração. Estes resultados contribuem para que equipes de desenvolvimento de software desenvolvam a consci- ência sobre quais artefatos podem influenciar na escrita de requisitos de UX e estimular desenvolvedores a descreverem requisitos de UX desde as etapas iniciais do desenvolvimento", "url": "artigos/artigos_WER20/wer202004.html"}, {"title": "Empathy and Criativity in Privacy Requirements Elicitation: Systematic Literature Review", "authors": ["Angelica Toffano Seidel Calazans", "Anderson Jefferson Cerqueira", "Edna Dias Canedo"], "year": 2020, "keywords": "Systematic Literature Review; Criativity; Empathy; Privacy; Requirements Elicitation", "abstract": "This paper presents a Systematic Literature Review (SLR) in order to find in the literature papers that use creativity and empathy techniques in privacy requirements elicitation. These techniques have been used in requirements elicitation in order to facilitate the understanding of the requirements and provide a collaborative interaction between the teams and the end user. Thus, we investigated whether the literature already has reports on the use of these techniques as facilitators in the process of privacy requirements elicitation. As a result of the SLR, we found few papers related to the use of Empathy in privacy requirements elicitation and no papers that relate Creativity to the elicitation of privacy requirements.", "url": "artigos/artigos_WER20/wer202005.html"}, {"title": "Hacia la Evaluación Automática de la Calidad de los Requerimientos de Software usando Redes Neuronales Long Short Term Memory", "authors": ["María Guadalupe Gramajo", "Luciana Ballejos", "Mariel Ale"], "year": 2020, "keywords": "Requirements Engineering; Deep Learning; Long Short Term Memory", "abstract": "El primer paso para obtener un producto de software de calidad es abordar la calidad de los requerimientos. Dado que los requerimientos estan escritos en lenguaje natural, la flexibilidad y las caracteristicas propias del lenguaje pueden conducir a errores durante su especificacion y, en consecuencia, esto puede influir negativamente en fases posteriores del ciclo de vida del software. Por esta razon, en este articulo se propone un enfoque innovador que combina tecnicas de procesamiento del lenguaje natural y redes neuronales, especificamente redes neuronales recurrentes LSTM, para predecir la calidad textual de los requerimientos. Inicialmente, se aborda el analisis de la propiedad de calidad singular definida en el estandar ISO/IEC/IEEE 29148: 2018. El modelo neuronal propuesto es entrenado con un conjunto de datos que incluye 1000 requerimientos. Cada requerimiento es sometido a un proceso de tokenizacion y etiquetado gramatical, con el fin de obtener una secuencia representativa que actue de entrada al modelo neuronal. La propuesta proporciona resultados prometedores con un alto nivel de precision, lo que motiva explorar su aplicacion en la evaluacion de otras propiedades de calidad.", "url": "artigos/artigos_WER20/wer202006.html"}, {"title": "Identificação de Requisitos de Segurança para Experimentos Científicos Embarcados", "authors": ["Heuller Aloys Carneiro Procópio", "Luiz Eduardo Galvão Martins", "Carlos Henrique Netto Lahoz"], "year": 2020, "keywords": "STPA; STAMP; Payload; Suborbital Rocket; Safety Requirements", "abstract": "Space flights are risky due to extreme environmental conditions, in addition to the high complexity of rockets, systems and subsystems. Additionally, there are personal and material risks that are due to the rocket launch operation. The cost for the execution of these projects and their respective tests, launching operation and eventual payload recovery, should also being taken in account. The Brazilian Space Agency (AEB) offers the national scientific community opportunities to access space to carry out experiments in a microgravity environment, by launching suborbital rockets. Given that the rate of launches of this type is low, the failures of the payload items cause significant delays in the project development and its constraints, like cost and schedule. This work proposes to apply the STPA technique (System-Theoretic Process Analysis), a method that is a systemic approach to safety analysis, based on the STAMP approach (SystemTheoretic Accident Model and Processes), a predictive risk assessment, to analyze scientific experiments onboard on payloads in suborbital rockets. As results, it is expected obtained safety constraints and recommendations that will contribute to the elaboration of safety requirements applicable to space scientific experiments. It is expected that the availability of systematized information to experimenters in the form of requirements, will contribute to the reduction of experiment failures, as well as simplify the validation process, reducing its subjectivity and interpretation problems.", "url": "artigos/artigos_WER20/wer202007.html"}, {"title": "Improving the Selection of Requirements Elicitation Techniques: A Faceted Guide", "authors": ["Rafael Crispim Ignácio", "Fabiane Barreto Vavassori Benitti"], "year": 2020, "keywords": "", "abstract": "In Requirements Engineering there are several techniques that can be used to elicit the requirements. In the current scenario, no sources were found in which these techniques are properly organized, facilitating their understanding in the identification of their characteristics, as well as assisting the search for techniques recommended for the context of a specific project. This paper describes the development of a organized and categorized requirements elicitation technique to support the identification of techniques appropriate to the scenario of a given project. Through a systematic mapping, 96 techniques of elicitation of requirements and 21 facets (characteristics) were identified to classify the techniques, which were organized to compose the guide presented in this paper. Through an evaluation with 30 participants, we can evidence the effectiveness of the guide to suggest techniques of elicitation, as well as its ease of use.", "url": "artigos/artigos_WER20/wer202008.html"}, {"title": "JiStar Rastreabilidade Entre Código Java e Modelos de Metas i*", "authors": ["Ana Maria da Mota Moura", "Julio Cesar Sampaio do Prado Leite"], "year": 2020, "keywords": "JiStar; Rastreabilidade; iStar; Java", "abstract": "Nos últimos anos, a engenharia de requisitos orientada a metas tem sido extensivamente pesquisada e os resultados indicam diversas vantagens sobre outras abordagens para a modelagem de requisitos. Uma vez que o software foi construído sob outras perspectivas e paradigmas, como compreender suas metas para fins de evolução? Na literatura, existem heurísticas de rastreabilidade que podem auxiliar no resgate das metas do software quando aplicadas no sentido código-requisitos. Entretanto, a rastreabilidade para trás, aplicada a sistemas construídos sob outros paradigmas pode gerar modelos extensos e com um nível de abstração muito baixo. Esta pesquisa visa definir um modelo de rastreabilidade para trás entre o código da aplicação e o modelo de metas através do uso de metadados de código. Em particular entre sistemas desenvolvidos em Java e modelos i*. Embora existam pesquisas sobre o mapeamento de modelos i* para representações OO, a rastreabilidade para trás é menos frequente na literatura. Desenvolvemos o framework JiStar que é composto por: (A) um conjunto de anotações de código Java para elementos do framework i* com vistas a viabilizar uma rastreabilidade entre os artefatos de código Java e modelos i*, e; (B) um exportador de modelos i* com vistas a permitir a geração automática de modelos de metas nos formatos HTML e PiStar. Avaliamos a viabilidade da nossa abordagem usando o código fonte de um sistema real chamado RioBus visando reconciliá-lo com suas metas. Nossos resultados indicam a adequação dessa rastreabilidade para fins de evolução do software", "url": "artigos/artigos_WER20/wer202009.html"}, {"title": "Negociação-Colaboração para Qualidade de Requisitos de Qualidade", "authors": ["Giovana Brandão Ribeiro Linhares", "Julio Cesar Sampaio do Prado Leite"], "year": 2020, "keywords": "Requisitos Não-Funcionais (RNFs) Colaboração; Negociação.", "abstract": "Em geral, os Requisitos Não-funcionais (RNFs) só são tratados nas atividades relacionadas à arquitetura do software, e, muitas vezes, apenas durante a implementação. Essa situação resulta em custos mais altos e menor qualidade do software. Este trabalho estuda mecanismos para promover os RNFs, a partir da compreensão dos relacionamentos humanos que ocorrem na dinâmica colaborativa permeada por negociações, durante as atividades de construção de requisitos. Uma estratégia colaborativa de construção de RNFs e seu suporte computacional são propostos. Um exemplo de uso da estratégia é elaborado a partir de um produto IoT: Cesta Automática de Medicamentos.", "url": "artigos/artigos_WER20/wer202010.html"}, {"title": "NFR4ES: Um Catálogo de Requisitos Não-Funcionais para Sistemas Embarcados", "authors": ["Reinaldo Silva", "Jaelson Castro", "João Pimentel"], "year": 2020, "keywords": "Requirements Engineering; Requirements Specification; Non-Functional Requirements; Embedded Systems; NFR Framework", "abstract": "Due to the complexity in the development of embedded systems, engineers look to the requirements engineering field for methods and techniques that support the construction of these systems, specially when it concerns the handling of Non-Functional Requirements (NFRs), such as cost and energy consumption. Indeed, many papers report challenges with the elicitation and specification of NFRs for embedded systems. Thus, this paper aims to address the difficulty of identifying, interrelating and documenting NFRs in embedded systems projects, by means of a catalog of Non-Functional Requirements for Embedded Systems (NFR4ES). With this catalog, knowledge was obtained from the literature and from experts on the subject, which was then organized in order to facilitate the elicitation and specification of requirements for embedded systems. NFRs were only included in the catalog if we could find written evidence of their applicability for such systems. It was evaluated by means of a proof of concept as well as through a survey with specialists, where it was considered useful and appropriate for the elicitation and specification of embedded systems", "url": "artigos/artigos_WER20/wer202011.html"}, {"title": "Os Benefícios do Uso de Ontologias em Sistemas Embarcados", "authors": ["Aêda Sousa", "Timóteo Gomes", "Letícia Lima", "Fernanda Alencar"], "year": 2020, "keywords": "Requisitos; Sistemas Embarcados; Ontologias", "abstract": "O desenvolvimento de sistemas embarcados vem crescendo rapidamente nos últimos anos. Eles são utilizados em diversos domínios (automotiva, aviônica, eletrônica de consumo, entre outras), cada uma com características específicas, e por isso, representam um grande desafio para engenharia de requisitos. A cada dia algumas abordagens para o desenvolvimento de sistemas embarcados são propostas, considerando várias áreas do conhecimento, tais como ontologia e linguagens diagramáticas (UML e SysML). Nos últimos anos, a engenharia de sistemas baseada em ontologias cresceu significativamente. Seu foco é usar ontologias para melhorar o corpo de conhecimento em projetos de sistemas. Elas atuam como facilitadoras de um bom gerenciamento de conhecimento, pois se concentram no estabelecimento de conceitos de domínio bem definidos em termos de terminologias, definições e relacionamentos. Além disso, o uso da semântica formal é essencial para representação explícita, compartilhável e reutilizável. No entanto, existem poucas pesquisas que avaliam os benefícios reais das ontologias para desenvolvimento de sistemas embarcados. Nesse contexto, este artigo apresenta uma revisão sistemática da literatura sobre o uso de ontologias no desenvolvimento de sistemas embarcados. O foco é identificar ontologias utilizadas no desenvolvimento desses sistemas, considerando os vários domínios, bem como os benefícios do uso de uma ontologia para esse fim. Após a aplicação dos critérios de inclusão e exclusão nas fases de condução da revisão, 27 artigos foram selecionados e analisados. As principais evidências positivas encontradas neste estudo estão relacionadas com a fase de requisitos (representação do conhecimento do domínio, facilitar a comunicação entre os Stakeholders e definição dos requisitos)", "url": "artigos/artigos_WER20/wer202012.html"}, {"title": "Problemas do Design Thinking para a Engenharia de Requisitos: uma Revisão Sistemática da Literatura", "authors": ["Fábio Avigo de Castro Pinto", "Fábio Levy Siqueira"], "year": 2020, "keywords": "Design Thinking; Engenharia de Requisitos; Revisão Sistemática da Literatura", "abstract": "Tido como uma estratégia de inovação no campo do Design e trazido como ferramenta à Engenharia de Software, o Design Thinking (DT) é uma abordagem promissora em crescente utilização nas etapas da Engenharia de Requisitos (ER), por focar no cliente final do software através de uma técnica iterativa estruturada em fases definidas. Este processo, entretanto, pode trazer um viés ao desenvolvimento de software por desconsiderar outros stakeholders que usualmente participam em processos tradicionais e direcionar todos os esforços de requisitos para o usuário. De forma a identificar a existência de problemas trazidos à ER com a aplicação do DT e de desafios ainda existentes na área não endereçados diretamente pela abordagem, este artigo apresenta uma revisão sistemática da literatura de relatos de uso ou de estudos de caso de aplicação do DT a projetos de software na etapa de requisitos. Além dos problemas de ER levantados pelos autores em estudos primários, a revisão também identificou as sugestões de aprimoramento do método. Os resultados apontam para a existência de problemas na área que ainda não são resolvidos pela aplicação do processo de DT", "url": "artigos/artigos_WER20/wer202013.html"}, {"title": "REACT-M: O Relato de um Estudo de Caso de Aplicação de um Método Ágil para Gerência de Requisitos de Software", "authors": ["Bleno W. F. V. da Silva", "Sandro R. B. Oliveira"], "year": 2020, "keywords": "Dynamic Software Product Lines; Dynamic Variability; Self-Adaptive Systems; Goal Models; iStar", "abstract": "In Dynamic Software Product Lines (DSPLs) product configuration occurs at runtime. Modelling variability and configuring the product in DSPLs should consider the context and non-functional requirements (NFRs) satisfaction. ConG4DaS (Contextual Goal models For Dynamic Software product lines) is a Requirements Engineering (RE) approach for DSPL which supports (i) modelling of variability with goals, NFRs, contexts and the relationship between them; and (ii) offers a product configuration based on contexts, NFRs and their priority and interactions. In this paper, we present a survey evaluation of ConG4DaS with RE and DSPL researchers in regard to the perceived usefulness. In the survey, both RE and DSPL researchers perceived ConG4DaS as useful for modelling and configuring DSPLs. However, the RE group gave more positive answers than the his study presents the report about a case study on the application of REACT-M (Requirements Evolution in Agile ContexT - Management), an agile method to support software requirements management, in a real software development environment. This case study assessed the strengths, weaknesses, opportunities, and threats related to the assets that make up REACT-M, namely: work products, life cycle, roles, and ceremonies. About the results, it was observed that REACT-M was effective, simple to use, strongly collaborative, suitable, user centered and goal oriented. Thus, achieved its main purpose to evolve the requirements of a software product in iteratively, efficiently and under of the agile mindset. The results contribute to the software industry by providing empirical data about the use of a agile method to software requirements management, which can serve as a reference for organizations seeking the adoption of agile methods related to the requirements area, as well as to provide the scientific community with a better empirical understanding of the relationship between requirements and agile methodDSPL group.", "url": "artigos/artigos_WER20/wer202014.html"}, {"title": "Requirements for a Software Audit Model in Safety-Critical Domains", "authors": ["Talita Marques Ruiz Slavov", "Johnny Cardoso Marques", "Luiz Eduardo Galvão Martins"], "year": 2020, "keywords": "Requirements elicitation; Software Audit Model; SafetyCritical Software", "abstract": "This paper presents the requirements for a more flexible and adaptable Software Audit Model and its associated adaptable checklist to conduct a software audit. This flexibility allows applying the SAM independently of the software development life cycle chosen. The initial proposed SAM will enable us to evaluate, integrate, and adapt the Stages of Involvement in different software development cycles based on the events necessary for aircraft certification with safety-critical software", "url": "artigos/artigos_WER20/wer202015.html"}, {"title": "Safety Requirements and Risk Analysis Related to Insulin Infusion Pumps: A Systematic Review", "authors": ["Felipe dos Santos Rocha", "Luiz Eduardo Galvão Martins"], "year": 2020, "keywords": "", "abstract": "Diabetes mellitus is a metabolic disease characterized by high levels of blood glucose; in severe cases of diabetes, insulin infusion pumps are prescribed as treatment. Infusion pumps are automated devices with the purpose to simulate the functioning of the organism of a healthy person regarding the production and delivery of insulin, as this is a medical device, its operation must be reliable enough to avoid any risk to the patientâs health and well-being. The aim of this article is to conduct a systematic literature review to investigate and perceive what are the risks implicated for the user of insulin infusion pumps also understand how safety and functional requirements for these devices have been treated, developed and studied", "url": "artigos/artigos_WER20/wer202016.html"}, {"title": "SPIDe para a Elicitação de Requisitos integrada ao Design de Interação: a percepção de especialistas em desenvolvimento de software", "authors": ["Jean C. S. Rosa", "Beatriz B. do Rêgo", "Filipe A. Garrido", "Pedro D. Valente", "Nuno J. Nunes", "Ecivaldo Matos"], "year": 2020, "keywords": "Engenharia de Requisitos; Interação Humano-Computador; Fatores Humanos; Engenharia Semiótica", "abstract": "A elicitação de requisitos é uma etapa que exige uma intensa comunicação entre engenheiros de requisitos e usuarios. Ressalta-se a necessidade dos engenheiros em utilizar tecnicas adequadas para favorecer esse momento de comunicação. Uma das recomendações na literatura é que o contato direto com os usuários pode ser beneficiado por meio do Design Participativo, haja vista que suas técnicas podem motivar uma comunicação mais efetiva entre os envolvidos. O SPIDe, por sua vez, é um processo de Design de Interação que associa o Design Participativo Ã Engenharia Semiótica para intermediar e estudar a comunicação, a colaboração, a cooperação e a participação do usuário. Sob essa perspectiva questiona-se: é possivel e útil elicitar de requisitos integradamente ao design de interação por meio do SPIDe? Este artigo apresenta resultados parciais de um estudo de caso para investigar a possibilidade e a utilidade da integração da elicitação de requisitos ao design de interação usando o SPIDe. Com a análise dos dados coletados, realizada por meio da Grounded Theory, identificou-se que o SPIDe tem potencial para realizar aquilo que é proposto e pode ser útil para elicitar requisitos e projetar a interação em projetos de pequeno e médio porte", "url": "artigos/artigos_WER20/wer202017.html"}, {"title": "Suporte ao rastreamento de requisitos na ferramenta JGOOSE", "authors": ["Victor Augusto Pozzan", "Gustavo Cesar Lopes Geraldino", "Victor Francisco Araya Santander", "Ivonei Freitas da Silva"], "year": 2020, "keywords": "Requirements; traceability; JGOOSE", "abstract": "Requirements engineering is an important phase of software engineering. The Requirements traceability is an essential activity for requirements management, by enabling a system development team to assess the impact of the changes in the requirements, ensuring the quality of the system. However, nowadays the computational tools that support the software process also need to contain some sort of traceability. This paper will be taken into consideration studies related to the requirements traceability techniques and the requirements traceability means which will be the basis for the implementation of features that allow tracking and managing artifacts generated by the JGOOSE tool. The JGOOSE tool allows, from the i* and BPMN organizational models, to generate UML use cases. Thus, this paper aims to show the implementation that provides support for traceability in the JGOOSE tool, from horizontal and vertical traceability metamodels, generating traceability matrices. This new support will help requirements engineers to assess and make changes appropriately and accurately, maintaining the systemâs consistency and their generated documentation", "url": "artigos/artigos_WER20/wer202018.html"}, {"title": "Survey Evaluation of an Approach for Dynamic Software Product Lines", "authors": ["Gabriela Guedes", "Carla Silva", "Monique Soares"], "year": 2020, "keywords": "Dynamic Software Product Lines; Dynamic Variability; Self-Adaptive Systems; Goal Models; iStar", "abstract": "In Dynamic Software Product Lines (DSPLs) product configuration occurs at runtime. Modelling variability and configuring the product in DSPLs should consider the context and non-functional requirements (NFRs) satisfaction. ConG4DaS (Contextual Goal models For Dynamic Software product lines) is a Requirements Engineering (RE) approach for DSPL which supports (i) modelling of variability with goals, NFRs, contexts and the relationship between them; and (ii) offers a product configuration based on contexts, NFRs and their priority and interactions. In this paper, we present a survey evaluation of ConG4DaS with RE and DSPL researchers in regard to the perceived usefulness. In the survey, both RE and DSPL researchers perceived ConG4DaS as useful for modelling and configuring DSPLs. However, the RE group gave more positive answers than the DSPL group.", "url": "artigos/artigos_WER20/wer202019.html"}, {"title": "Uma Ferramenta para Construção de Catálogos de Padrões de Requisitos com Comportamento", "authors": ["Taciana N. Kudo", "Renato F. Bulcão-Neto", "Auri M. R. Vincenzi"], "year": 2020, "keywords": "Padrão de requisito de software; BDD; Ferramenta; Catálogo", "abstract": "Um padrão de requisitos de software (PRS) reúne comportamentos e serviços de aplicativos com características semelhantes. Apesar dos benefícios obtidos com a adoção de PRS em projetos de software, há uma carência de pesquisas sobre PRS em outras fases do desenvolvimento, além da Engenharia de Requisitos. Com base em descobertas na literatura, o uso prático de PRS pode ser melhor experimentado pelo uso conjunto de metodologias de desenvolvimento bem estabelecidas, ferramentas de software orientadas a PRS e catálogos de PRS de modo sistematizado. Nesse sentido, o metamodelo Software Pattern MetaModel (SoPaMM) permite relacionar um PRS com outros tipos de padrão de software e incorpora comportamentos sob a influência da metodologia ágil Behavior-Driven Development (BDD). Neste artigo, propõe-se a ferramenta Terminal Model Editor (TMEd) para apoiar a construção de modelos terminais para domínios específicos, usando o metamodelo SoPaMM como modelo de referência. Um exemplo de uso da TMEd é apresentado com a elaboração de um catálogo de padrões de requisitos legais para a certificação de Sistemas de Registro Eletrônico de Saúde (S-RES) no Brasil. Espera-se que os esforços com a ferramenta TMEd e o catálogo de padrões de requisitos para S-RES baseados no metamodelo SoPaMM ajudem a comunidade a melhor compreender o impacto geral do uso de PRS no ciclo de vida de software, não limitando-se à Engenharia de Requisitos.", "url": "artigos/artigos_WER20/wer202020.html"}, {"title": "Would You Like Better Visualization for Requirements Prioritization and Release Planning?", "authors": ["João Pimentel", "Maria Lencastre"], "year": 2020, "keywords": "Requirements Engineering; Requirements Prioritization; Goal Modelling", "abstract": "On the one hand, requirements prioritization is a key requirements engineering activity that lacks proper visualization support. On the other hand, goal modelling is a visual approach for requirements engineering that enables expressing and reasoning about alternative solutions that best match the stakeholder needs, both for the early requirements and the late requirements phase. This paper proposes a set of strategies for visually representing prioritization and release planning information using goal-based models, aiming at minimizing the cognitive effort required in prioritization analysis. The proposal is supported by a tool that implements the visualization strategies here defined.", "url": "artigos/artigos_WER20/wer202021.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2021)", "authors": ["Maria Lencastre", "Graciela Hadad", "Johnny Marques"], "year": 2021, "keywords": "", "abstract": "The Workshop on Requirements Engineering 2021 is now in its twentieth-fourth edition. This year, the WER was organized by the Centro Universitário de Brasília from the Brasilia city in Brazil. This university also coordinated the online transmission due to the COVID-19 pandemic, through a videoconferencing platform. For the first time at the WER, this edition has introduced four technical tracks. The Regular Track, as the traditional modality. There was a Software Requirements Tool Track to promote a forum for the presentation and demonstration of tools to support the requirements development and management processes. A Master's and Doctoral Track. And the fourth new track was dedicated to presenting a 3-hour tutorial to students, researchers, as well as practitioners on some topics of interest to the Requirements Engineering community. We have received 59 abstracts, but finally 47 papers were submitted: 36 for the Regular Track, 3 for the Software Tool Track, 7 for the Master's and Doctoral Track, and 1 for the Tutorial Track. Each submitted paper was reviewed by three reviewers, resulting in a total of 141 reviews. The presentations of the accepted papers, tools and tutorial were organized in ten technical sessions. Four keynote speakers were invited: Didar Zowghi from the University of Technology Sydney (Australia), Alejandro Oliveros from Universidad Nacional de Tres de Febrero (Argentina), Luiz Eduardo Galvão Martins from the Universidade Federal de São Paulo (Brazil), and Gustavo Dias Henrique from the BIOTIC industry (Brazil).", "url": "artigos/artigos_WER21/wer202100_1.html"}, {"title": "Tutorial - Analysis of business processes compliance with LGPD", "authors": ["Mariana Peixoto", "Diogo Santos", "Jéssyka Vilela", "Carla Silva"], "year": 2021, "keywords": "", "abstract": "News about data leaks of private and confidential data are being reported with increasing frequency. To mitigate these issues, governments have taken actions to ensure that companies raise their investments and the actions related to user's data security and privacy. Laws were created, like the European General Data Protection Regulation (GDPR) and the Brazilian law called LGPD (Lei Geral de ProteÃ§Ã£o de Dados, in portuguese, or General Law of Data Protection), which define the privacy rights on user data and establishes penalties to the companies which do not comply with the law. Data privacy and security, which are fundamental non-functional requirements for many socio-technical systems, became a priority among the problems faced by many companies. These systems support business processes that are of fundamental importance in a compliance program with these laws and to balance transparency on the services provided. This tutorial will discuss the importance of developing privacy-aware systems and business processes and present a method to obtain LGPD compliance in business processes. In particular, LGPD4BP (LGPD for Business Process) - a method composed by an evaluation questionnaire and a modelling method supported by a modelling patterns catalog - will be presented to the audience.", "url": "artigos/artigos_WER21/wer202100_2.html"}, {"title": "A Method to Evaluating Consistency, Completeness and Correctness in Evolution Requirements", "authors": ["Edneuci Denise Audacio", "Katia Romero Felizardo", "Luiz Gustavo Ferreira Aguiar", "Rebeca Teodoro da Silva", "Elias Canhadas Genvigir"], "year": 2021, "keywords": "Requirements Engineering; Requirements Evolution; Requirements Domain; Requirements Assessment", "abstract": "Changes in the domain in which a specific software was developed can generate a demand for new requirements known as requirements evolution. However, it is expected that these will be specified in a consistent, complete and correct manner. This work defines a method that makes it possible to assess the consistency, completeness and correctness of requirements defined during the software evolution. The developed method is composed of two phases: (1) analysis of units of information, i.e., the analysis of each requirement and its domain; and (2) analysis of these items through indicators for consistency and completeness. For verification purposes, the method was applied through a case study in a software company and, the results presents positive indicators for the improvement of quality in requirements evolution. The project, object of this study, originally had a high rework load, that is, correction in the codification of the requirements of the case study. Through the application of the method, it was possible to identify that most of the evaluated requirements, which presented inconsistency or completeness problem, were associated with rework efforts.", "url": "artigos/artigos_WER21/wer202101.html"}, {"title": "Análise de Ontologias para Sistemas AAL (Ambient Assisted Living) e o suporte a Compliance", "authors": ["Timóteo Gomes", "Fernanda Alencar"], "year": 2021, "keywords": "Ambient Assisted Living; AAL; Ontologia; Compliance", "abstract": "O ambiente de vida assistida (do inglês, Ambient Assisted Living - AAL) se constitui em uma abordagem tecnológica, que tem por objetivo atender às emandas do público idoso e das pessoas com deficiências. Dentre os desafios de desenvolvimento de sistemas AAL estão o atendimento às restrições éticas, legais, sociais, médicas e técnicas. Com isso, surge a necessidade de tratar a compliance. Esse trabalho apresenta o resultado da análise de ontologias para sistemas AAL e a verificação da existência ou não do suporte ao atendimento aos aspectos de compliance por parte dessas ontologias. Para levantamento das ontologias existentes para AAL, foi realizado um mapeamento sistemático da literatura sobre o uso de ontologias no desenvolvimento de sistemas AAL e ontologias para suporte a compliance. Após a aplicação do protocolo da MSL, 63 artigos responderam a questão de pesquisa sobre ontologia para sistemas AAL. Nenhum dos trabalhos retornados abordou em suas ontologias o aspecto de compliance. Logo, a principal evidência encontrada está relacionada à falta de aplicação conjunta da ontologia e compliance em sistemas AAL. Diante disso, é apresentada uma proposta (ainda em fase inicial) de uma ontologia para sistemas AAL que aborde aspectos de compliance.", "url": "artigos/artigos_WER21/wer202102.html"}, {"title": "Aplicando técnicas de Design Thinking para a especificação de cenários na elicitação de requisitos", "authors": ["Jose Carlos Duarte", "Adriana Damian", "Rafael Parizi", "Sabrina Marczak", "Tayana Conte"], "year": 2021, "keywords": "Design Thinking; Cenários; Mapa da Jornada do Usuário; Blueprint de Serviços; Storyboard; Storytelling", "abstract": "Design Thinking (DT) é uma abordagem que busca a solução de problemas e promove o desenvolvimento de soluções criativas e inovadoras, em uma perspectiva empática e multidisciplinar. DT tem sido empregado no desenvolvimento de software para auxiliar no processo da Engenharia de Requisitos (ER) que exige cada vez mais uma perspectiva centrada no ser humano. A integração de DT com a ER pode acontecer em diferentes atividades, entre elas está a especificação de cenários. Os cenários são amplamente utilizados no processo de elicitação de requisitos, descrevendo as situações de uso do sistema pelos seus usuários. Portanto, é importante compreender o potencial das diferentes técnicas de DT para a elaboração de cenários, com o objetivo de entender como estas podem contribuir para a especificação de requisitos. Neste sentido, este artigo apresenta a aplicação das técnicas Mapa de Jornada do Usuário, Blueprint de Serviços, Storyboard e Storytelling para a elaboração de cenários visando representar a interação do usuário em um aplicativo de transporte particular. Com este trabalho, espera-se apoiar os engenheiros de requisitos na elaboração de cenários com técnicas DT para promover um melhor entendimento das necessidades dos usuários, contribuindo para a identificação de requisitos que proporcionem o desenvolvimento de produtos de software inovadores.", "url": "artigos/artigos_WER21/wer202103.html"}, {"title": "Casos de Garantia de Segurança aplicados a sistemas robóticos: revisão sistemática da literatura", "authors": ["Mozart de Melo Alves Júnior", "Maria Lencastre", "Lucas Florêncio de Brito", "Jaelson Castro", "Moniky Ribeiro"], "year": 2021, "keywords": "caso de garantia; caso de garantia de segurança; garantia de segurança; caso de segurança; certificação de segurança; robótica", "abstract": "Contexto: A segurança dos sistemas robóticos é de extrema importância, pois falhas ou acidentes relacionados a eles podem resultar em perdas irreparáveis. Estes sistemas precisam ser certificados por entidades reguladoras que exijam evidências de sua segurança em termos de Casos de Garantia de Segurança. Objetivo: Analisar abordagens, conceitos, ferramentas, normas e métodos relacionados à garantia da segurança em robôs e descobrir o estado da arte em relação ao uso e aplicação dos Casos de Garantia de Segurança em Sistemas Robóticos. Método: Condução de uma revisão sistemática da literatura (RSL) para identificar e analisar as abordagens aplicadas aos sistemas robóticos com base em Casos de Garantia de Segurança. Resultados: Foram identificados 21 estudos de um conjunto de 857 trabalhos publicados. Os resultados indicam que os Casos de Garantia de Segurança podem assumir um papel importante na gerência das especificações dos requisitos de segurança. Conclusão: A análise realizada pode auxiliar os profissionais a compreender melhor a área em trabalhos porvir. Foram relatadas as descobertas mais relevantes e suas implicações, também foi proposta uma agenda de pesquisa para a comunidade de engenharia de requisitos, especificamente para os sistemas robóticos, que será abordado em trabalhos futuros.", "url": "artigos/artigos_WER21/wer202104.html"}, {"title": "Diversidade de gênero - Elicitação de requisitos: Uso do GenderMag como Estratégia de Identificação de Requisitos de Usabilidade", "authors": ["Moises Barbosa", "Isabelle Brilhante", "Artur Andrade", "Júlia Luiza Conceição", "Genildo Gomes", "Tayana Conte", "Bruno Gadelha"], "year": 2021, "keywords": "Elicitação de requisitos; GenderMag; Techs4Events; requisitos não-funcionais", "abstract": "Criar softwares que atendam a uma grande diversidade de usuários não é uma tarefa trivial pois envolve identificar as diferentes dificuldades que eles poderão ter ao utilizá-los. Essa identificação deve ser realizada o quanto antes visando tornar o produto de software mais inclusivo, abrangendo uma maior diversidade de usuários. Considerando essa perspectiva da diversidade, neste artigo é discutida a possibilidade de identificar requisitos de um software a partir de uma análise sob o viés de gênero através do método GenderMag. Este método utiliza as técnicas de Percurso Cognitivo e Personas para identificar problemas do software a partir de uma perspectiva de gênero. Para avaliar o uso do GenderMag como uma ferramenta de identificação de requisitos, realizou-se um estudo com um protótipo de um sistema de recomendação. Inicialmente seis usuários avaliaram o protótipo, respondendo a entrevistas em seguida. Posteriormente, aplicou-se o método GenderMag. Como resultado, verificou-se a possibilidade de utilização deste método para avaliação de protótipos antes de uma interação com usuários reais, uma vez que este possibilitou a identificação de diversos requisitos que foram elicitados com os usuários no primeiro estudo.", "url": "artigos/artigos_WER21/wer202105.html"}, {"title": "Engenharia de Requisitos Ágil: Extensão de uma Revisão Sistemática da Literatura", "authors": ["Renato Menezes", "Suzana Sampaio", "Marcelo Marinho"], "year": 2021, "keywords": "Requirements Engineering; Software requirements; Agile requirements; Agile methods; Agile methodologies; Agile Practices", "abstract": "Nowadays, the daily routine of software engineers is determined by agile methods practices, motivating questions about how to adopt a more flexible and dynamic Requirements Engineering (RE), distinct from the traditional model. What makes suitable to exploring the advances of agile RE in diverse and challenging environments. Therefore, this paper aims on identifying and understanding the current scenario regarding practices and techniques within Agil RE, as well as its challenges and lessons learned. An extension of a systematic literature review study was conducted to carry out this analysis and the evidence is synthesized from sources published between 2017 and 2020. In addition, the work delivers a compiled of practices, observing the different contexts of projects and organizations.", "url": "artigos/artigos_WER21/wer202106.html"}, {"title": "Especificação de Requisitos de Privacidade em Conformidade com a LGPD: Resultados de um Estudo de Caso", "authors": ["Carina Alves", "Moisés Neves"], "year": 2021, "keywords": "Requisitos de privacidade; Lei Geral de Proteção de Dados (LGPD); Padrões de Privacidade; Estudo de Caso", "abstract": "A Lei Geral de Proteção de Dados (LGPD) visa proteger os dados pessoais, inclusive nos meios digitais, por pessoa natural ou por pessoa jurídica de direito público ou privado, e que pode impor sanções severas pelo seu não cumprimento. Grande parte das organizações ainda não está preparada e precisa implementar várias medidas para garantir que seus sistemas cumpram a conformidade imposta pela lei. No entanto, a legislação vigente é considerada de difícil entendimento para os profissionais de TI. Estes profissionais enfrentam dificuldades para extrair e operacionalizar requisitos legais e de privacidade. Este artigo apresenta um estudo de caso realizado em uma organização do poder judiciário para entender os principais desafios enfrentados por analistas de requisitos para especificar requisitos de privacidade em conformidade com a LGPD. Como contribuição empírica, discutimos o ponto de vista dos analistas em relação às seguintes categorias: conceitos de privacidade, processo de conformidade, obstáculos na conformidade, tradeoff entre privacidade e transparência, rotina de trabalho. A partir das percepções dos participantes do estudo de caso, elaboramos uma proposta baseada em padrões de privacidade. A abordagem proposta foi utilizada para especificar requisitos de privacidade de um sistema de software da organização estudada.", "url": "artigos/artigos_WER21/wer202107.html"}, {"title": "Identificação e Mensuração da Dívida Técnica de Requisitos: um survey na indústria de software", "authors": ["Ana Carolina Candido de Melo", "Roberta Andrade de A. Fagundes", "José Vinícius Vieira Lima", "Fernanda Alencar", "Wylliams Barbosa Santos"], "year": 2021, "keywords": "Technical Debt of Requirements; Measurement; Survey", "abstract": "Contexto: A Engenharia de Requisitos (ER) possui extrema importância no ciclo de vida de projetos de software. No entanto, quando tarefas são realizadas inadequadamente, ocasionam problemas que afetam a qualidade do software, os quais podem ser exemplos de Dívida Técnica (DT). Identifica¸cão e mensura¸cão são as duas primeiras etapas no processo de gerenciamento de uma DT. São etapas essenciais, no entanto, no contexto da ER ainda são pouco exploradas. Objetivo: Assim, este trabalho tem por objetivo diagnosticar como a identificacão e mensuracão da DT de requisitos estão sendo realizadas na prática em contextos reais do desenvolvimento de software. Método: Para isso, um survey foi aplicado com 30 profissionais da indústria de software de diferentes organizacões. Resultados: Dentre os resultados, tornou-se possível identificar: (i) causas atribuídas ao surgimento dessa DT; (ii) estratégias e métricas utilizadas para identificá-la e mensurá-la; e (iii) dificuldades encontradas ao realizar essas atividades. Conclusã: Ao final, percebe-se uma ausência de conhecimento por parte dos profissionais sobre ferramentas e informacões que auxiliem a automatizar essas atividades.", "url": "artigos/artigos_WER21/wer202108.html"}, {"title": "Modelando perfis de Recursos Humanos para alinhamento de grupos de trabalho", "authors": ["Henrique Prado de Sá Sousa", "Eduardo Kinder Almentero", "Juliana Cesar Sirena Machado", "Julio Cesar Sampaio do Prado Leite"], "year": 2021, "keywords": "Requisitos de recursos humanos; Alinhamento de equipes; Alinhamento de grupos de trabalho; Modelagem de recursos humanos; Modelagem organizacional", "abstract": "Os recursos humanos (RH) são parte fundamental das organizações e um dos principais responsáveis pela qualidade das tarefas que são realizadas no dia a dia. Essas tarefas, por sua vez, demandam como requisito uma ou mais competências para serem realizadas a contento. O perfil necessário para um ator organizacional define os requisitos que o indivíduo deve possuir para ser considerado adequado à posição do ator. No entanto, no ambiente organizacional, os indivíduos comumente atuam em grupo, de forma colaborativa. Isso envolve um conjunto maior de requisitos de RH de natureza social. Também surgem outras variáveis específicas provenientes da dinâmica de trabalho em grupo. Neste trabalho, propomos uma extensão da linguagem GPI-HR para permitir a modelagem de competências relacionadas ao trabalho em grupo e posterior análise de alinhamento. Adicionalmente, propusemos regras de propagação de impactos e mecanismos de pesos, visando representar de forma mais apropriada os resultados das contribuições individuais presentes no trabalho em grupo.", "url": "artigos/artigos_WER21/wer202109.html"}, {"title": "O papel do patrocinador para apoiar o processo da engenharia de requisitos na busca por ideias externas em projetos de inovação aberta", "authors": ["Fabrizio Farias", "Kiev Gama", "Hermano Moura"], "year": 2021, "keywords": "Requirements engineering; Open innovation project; qualitative study", "abstract": "Presently, globalization is causing companies to be more competitive, and one of the ways this can be achieved is through the use of Open Innovation Projects (OIPs). Although considerable research has been devoted to Open Innovation (OI), rather less attention has been paid to how the OIP sponsor deals with limited resources to implement the requirements of the OIP. The purpose of this paper is to investigate the concerns and challenges that the sponsor has in supporting the requirements engineering (RE) process to meet the OIP requirements. A qualitative study was conducted to investigate five companies in the automotive, steel, oil, health and electric power industries. The findings show that there are differences between activities of the sponsor and the OIP team that help to characterize the problems that must be addressed by participants in an OIP. There is an evolving role for the sponsor to carry out the RE which is different from the OIP when the OIP first started. This is because the analysis of the requirements in OIP is constantly evolving during the project, and thinking about the requirements in the management phase of the OIP also needs to evolve to reach an innovative solution. The experiences shared here can help future OIP participants to better set requirements for their OIPs as well as to proactively address problems of inadequate collaboration, motivation, and empathy of the participants in OIPs.", "url": "artigos/artigos_WER21/wer202110.html"}, {"title": "O uso da Lean Persona+ para auxiliar a elaboração de requisitos de UX", "authors": ["Gabriel Viana Teixeira", "Angelica Cunha dos Santos", "Tayana Conte", "Luciana Zaina"], "year": 2021, "keywords": "requisitos de UX; personas; experiência do usuário", "abstract": "Os requisitos de User eXperience(UX) têm se tornado essenciais para a aceitacão dos usuários ao software. Uma das técnicas que auxiliam na coleta destes requisitos é a persona, porém é conhecida por ser custosa em sua elaboracão. Como alternativa, a técnica de Lean persona mostra-se mais viável devido a sua característica enxuta. Este artigo apresenta os resultados de uma investigacão sobre como a técnica e a ferramenta Lean persona+ apoiam a elaboracão de personas enxutas para descricão de requisitos. A proposta e a ferramenta foram avaliadas por 34 indivíduos com conhecimentos em UX. Através de uma análise qualitativa de um total de 41 lean personas produzidas pelos participantes como auxílio da ferramenta, examinou-se quais eram os requisitos de UX reportados nestes artefatos. Os resultados da análise indicam que tanto a ferramenta quanto a técnica com o uso de perguntas-guia ajuda\u0002ram na descricão de requisitos de UX. Os resultados também mostraram que a técnica e a ferramenta tiveram uma ampla aceitacão por parte dos participantes, sendo considerada de fácil aprendizagem. Estes resultados mostram que a Lean Persona+ contribui na fase de elicitacão de requisitos UX em diferentes perspectivas, fornecendo informacões importantes sobre o público-alvo.", "url": "artigos/artigos_WER21/wer202111.html"}, {"title": "Requirements Engineering for Embedded Systems: A Systematic Literature Review", "authors": ["Tarcísio Pereira", "Quelita Ribeiro", "Mozart Melo", "Sthefanie Magro", "Fernanda Alencar", "Jaelson Castro"], "year": 2021, "keywords": "Embedded Systems; Requirements Engineering; Systematic Literature Review", "abstract": "Most problems that occur at system delivery of Embedded Systems (ES) are related to requirements misconceptions in capturing requirements. Hence, a Requirements Engineering (RE) process is crucial to meet time, cost, and quality goals. Objective: We investigate the studies to analyze and understand how the RE approaches are used for embedded systems development. Method: We conducted a Systematic Literature Review (SLR) as the basis for our work. Results: We uncovered 92 studies and found out the RE phases that are attracting more attention, the main requirements modeling styles used, the types of requirements modelled, and the existing challenges/problems. We also proposed a research agenda. Conclusions: This paper is a step towards developing a body of knowledge in RE for ES that is derived from a large-scale SLR. We believe the results will benefit both researchers and practitioners.", "url": "artigos/artigos_WER21/wer202112.html"}, {"title": "Requirements Smells como Indicador de Qualidade para Histórias de Usuários: Estudo Exploratório", "authors": ["Rafael Nascimento", "Eltoni Guimarães", "Marcia Lucena"], "year": 2021, "keywords": "Histórias de Usuário; Fatores de Qualidade; Requirements Smells", "abstract": "Os métodos ágeis transformaram a maneira como os softwares são desenvolvidos. Neste contexto, um dos artefatos mais utilizados para a escrita de requisitos são as Histórias de Usuários. No entanto, Histórias de Usuários mesmo sendo simples de escrever, podem ser acometidas de sintomas de má qualidade gerando, por exemplo, ambiguidade, problemas de estimativa e de negociação. Neste contexto, alguns trabalhos investigaram fatores de qualidade que devem estar presentes na escrita das Histórias. No entanto, nas pesquisas até o momento não encontramos trabalhos que investigam os tipos de sintomas de maus usos da escrita que impactam os Fatores de Qualidade. Este estudo, verifica se Requirements Smells, um conjunto de indicadores de qualidade na escrita, podem ser aplicados para detecção de sintomas de má qualidade na escrita de Histórias de Usuários. Os resultados obtidos no Estudo Exploratório, atestam que o uso de Requirements Smells é adequado para detecção de sintomas de má qualidade na escrita de Histórias de Usuário comprometendo assim os seus Fatores de Qualidade.", "url": "artigos/artigos_WER21/wer202113.html"}, {"title": "Rotule-me! Uma experiência de engenharia de requisitos para um sistema de rotulagem", "authors": ["Letícia Passos", "Lucas Viana", "Edson César Oliveira", "Tayana Conte"], "year": 2021, "keywords": "requirements engineering; visual analytics; machine learning; data labeling systems", "abstract": "Machine Learning (ML) tem sido cada vez mais aplicado em diversos domínios do conhecimento humano. Em projetos de ML supervisionado, é necessário que haja uma base de dados para treinamento do modelo de ML. Sistemas de rotulagem de dados são frequentemente utilizados para apoiar o desenvolvimento desse tipo de ML quando a gestão dessa base de dados é crítica para o sucesso do projeto. Contudo, a elicitação de requisitos desses sistemas apresenta desafios relacionados à interação dos usuários com grande volume de dados. Há a necessidade de entender os requisitos específicos desses sistemas para elaborar um software de qualidade. Este trabalho relata uma experiência de engenharia de requisitos em um sistema de rotulagem de dados para ML. Esse sistema tem como objetivo atuar na inspeção de rotulagem de milhões de produtos para fiscalização de impostos pelas Secretarias da Fazenda dos Estados Federativos do Brasil. A partir dos requisitos iniciais, foi realizado um processo evolutivo de prototipagem de interfaces. O processo incluiu três iterações, envolvendo o gerente de produto e a equipe de desenvolvimento. Os protótipos auxiliaram a refinar os requisitos a partir da análise de cada iteração, além de possibilitar a avaliação dos requisitos atendidos.", "url": "artigos/artigos_WER21/wer202114.html"}, {"title": "RST-IoT: Um Apoio Computacional para Especificação de Requisitos de Sistemas de Software IoT", "authors": ["Ednilson da S. A. Júnior", "Daniella de O. Costa", "Rebeca C. Motta", "Bruno P. de Souza"], "year": 2021, "keywords": "Engenharia de Requisitos; Especificação de requisitos; Internet das Coisas; Engenharia de Software Experimental", "abstract": "A Internet das Coisas (IoT) é resultante da evolução tecnológica constante, e pode ser compreendida como um novo paradigma tecnológico que combina os mundos real e virtual com o objetivo de fornecer sistemas de software em todos os lugares por meio de objetos do cotidiano. Porém, ao mesmo tempo que a tecnologia evolui, maior conhecimento e controle sobre ela devem ser considerados, principalmente nesta área em que o domínio da aplicação não é facilmente compreendido. Pesquisas sobre sistemas IoT e sua composição de dispositivos e aplicações continuam a avançar, todavia, há pouco esforço na evolução da área da Engenharia de Software, especificamente na Engenharia de Requisitos. Esta é uma etapa crítica na construção de sistemas tradicionais; e para sistemas baseados em IoT não é diferente, os quais requerem soluções de requisitos distintos devido a suas novas especificidades. Este trabalho propõe a RST-IoT, uma ferramenta de apoio à especificação de requisitos para sistemas IoT, que tem como objetivo auxiliar engenheiros de software em tal atividade. A RST-IoT foi desenvolvida para apoiar o processo de especificação de requisitos de sistemas IoT, implementada com um design simples visando sua fácil utilização. Foi adotada uma metodologia baseada em experimentação para avaliar a ferramenta. Este trabalho descreve um estudo de viabilidade realizado na indústria e um estudo de observação com estudantes. A RST-IoT se mostrou viável em relação ao tempo de aplicação e à facilidade de uso, bem como obteve evidências iniciais de sua aplicação.", "url": "artigos/artigos_WER21/wer202115.html"}, {"title": "Specification Cases: a lightweight approach based on Natural Language", "authors": ["Leandro Antonelli", "Julio Cesar Sampaio do Prado Leite", "Alejandro Oliveros", "Gustavo Rossi"], "year": 2021, "keywords": "Use Cases; LEL; Scenarios; Kernel Sentences; Requirements", "abstract": "Use Cases are one of the most used artifacts in software requirements specifications. Although there are a lot of templates that suggests how to de\u0002scribe Use Cases, as well as many quality inspection techniques, there are no many techniques to deal with the complexity and the effort to produce good quality Use Cases. On top of that, Use Cases are biased towards user interac\u0002tion, leaving out important domain information. Thus, it is necessary to provide techniques to incrementally describe specifications that goes beyond user inter\u0002action but which can be derived from simpler artifacts in order to make the pro\u0002cess organized and effective. This paper proposes an approach to begin with very simple sentences (kernel sentences), following with the LEL glossary and Scenarios, in order to describe Specification Cases. The approach relies on al\u0002ready defined kernel sentences and suggests three procedures to reorganize the knowledge captured in kernel sentences to describe the LEL, then Scenarios and finally Use Cases. This paper also reports a preliminary evaluation that supports the applicability and usability of the approach.", "url": "artigos/artigos_WER21/wer202116.html"}, {"title": "The Philosophy Behind IRES, an Intentional Requirements Engineering Strategy", "authors": ["Antonio de Padua Albuquerque Oliveira", "Vera Maria Benjamim Werneck", "Luiz Marcio Cysneiros", "Julio Cesar Sampaio do Prado Leite"], "year": 2021, "keywords": "Goals Elicitation; GORE; Goal-Oriented Requirements Engineering; Intentionality; iStar Framework; Model-driven Requirements", "abstract": "Intentionality is considered particularly important in several facets of social context. For example, police investigation usually starts based on the why, which is searching for a motive. The search for a motive is also frequent in the anamnesis process in medicine, as well as in investigative journalism. In a criminal investigation, early discovery of motive usually provides a track to identify a crimes perpetrators. When in the doctors office, the usual first question a patient has to answer is why he/she is there. In the same way, no one disagrees that software utility is the backbone of construction success. Since the task of discovering the why (goals) is abstract, subjective, and complicated, we delineate a thinking process frame, a philosophy, for guiding Requirements Engineers into focusing on intentions for the elicitation of goals. The philosophy, at the beginning of the IRES (Intentional Requirements Engineering Strategy), provides a backbone to the requirements process. It is composed of four topics (Necessity, Motivation, Goal, Action), and is linked by the intentionality and their interconnections in a given State of Affairs. The goal of this paper is to explain how this frame helps the construction of well-anchored models.", "url": "artigos/artigos_WER21/wer202117.html"}, {"title": "Thinking about gender: Combinando Design Thinking e GenderMag na elicitação de requisitos para um software de apoio a avaliação de UX.", "authors": ["Elizamara K. Almeida", "Vinícius Monteiro", "Franciane Alves", "Brenda Aguiar", "Leonardo Marques", "Bruno Gadelha", "Tayana Conte"], "year": 2021, "keywords": "Elicitação de Requisitos; Design Thinking; GenderMag; UX; Inclusão; Gênero", "abstract": "A elicitação de requisitos é a primeira etapa do processo de Engenharia de Requisitos. Essa etapa é fundamental para o desenvolvimento de software visto que, busca entender quais são as necessidades do usuário. Design Thinking (DT) é uma abordagem centrada no usuário, buscando identificar as suas necessidades e desejos, viabilizando o desenvolvimento de um software mais adequado. Nesse sentido, DT é uma boa alternativa para elicitar requisitos. Apesar de existirem várias abordagens de implementacao do DT, não há uma amplamente adotada com ênfase em inclusão de gênero, na fase de elicitação de requisitos. Todavia, existe um método que avalia essa questão de inclusão, chamado GenderMag (GM). Este artigo propõe investigar os benefícios do uso conjunto do DT e GM no processo de elicitação de requisitos. Para isso, foi feito o levantamento de requisitos utilizando técnicas de DT, para um software de apoio a avaliação UX. Em seguida foi aplicado o GM no protótipo gerado. Os resultados do uso conjunto dessas abordagens consistem numa lista de requisitos obtidos através do DT que apoiam o uso do software por quem possui algumas facetas cognitivas, comuns no gênero masculino. Por outro lado, o GM forneceu uma lista de correção que possibilitou a adequação do protótipo incluindo outras facetas cognitivas. A principal contribuição deste trabalho consiste em mostrar como o uso do GM permitiu a concepção de um software mais inclusivo, mostrando os benefícios do seu uso conjunto com DT, além de fomentar a importância de levantar requisitos voltados à inclusão de gênero.", "url": "artigos/artigos_WER21/wer202118.html"}, {"title": "Um Método para Modelagem de Requisitos não Funcionais em Ambient Assisted Living", "authors": ["Maurício Manoel Coelho Júnior", "Willy Silva Coutinho", "Robson Lima de Alencar", "Fernanda Alencar"], "year": 2021, "keywords": "Requisitos não Funcionais; Ambientes de Vida Assistida; AAL; Modelagem; NFR Framework", "abstract": "O aumento da expectativa de vida da população mundial é uma realidade, e quando combinado a quedas acentuadas e taxas de fertilidade, esses avanços na expectativa de vida podem levar a um rápido envelhecimento da população em todo o mundo. Tecnologias como Ambient Assisted Living (AAL) fornecem serviços que permitem às pessoas idosas viver uma vida independente, segura e saudável. De forma a atender às necessidades do idoso, faz-se necessário superar as percepções de riscos, incertezas relacionadas à tecnologia, usabilidade e contexto de uso, itens que exigem o cumprimento de diversos requisitos não funcionais (Non Functional Requirements - NFR). Nesse contexto, este artigo apresenta um método para auxiliar na modelagem de requisitos não funcionais no contexto de AAL.", "url": "artigos/artigos_WER21/wer202119.html"}, {"title": "User Requirements for Game Software Process: An Empirical Investigation", "authors": ["Saiqa Aleem", "Luiz Fernando Capretz", "Faheem Ahmed", "Shuib Basri"], "year": 2021, "keywords": "user requirements; game software; empirical investigation; user perspective; game user factors; quality of software games", "abstract": "This study attempts to provide a better understanding of the user dimension as a factor in software game success. It focuses mainly on an empirical investigation of the effect of user factors on the software game development process and finally on the quality of the resulting game. A quantitative survey was developed and conducted to identify key user dimensions. For this study, a survey was used to test the research model and hypotheses. The main contribution of this paper is to investigate empirically the influence of user key factors on software game development process that ultimately results in a higher quality final product. The results provide evidence that game development organizations must deal with multiple user key factors to remain competitive and handle high pressure in the software game industry.", "url": "artigos/artigos_WER21/wer202120.html"}, {"title": "CSC - Um Sistema de Controle de Cenários de Conflito", "authors": ["Marcos Paiva", "Maria Lencastre", "Aline Barbosa"], "year": 2021, "keywords": "Ferramenta; cenários de conflito; Engenharia de Requisitos", "abstract": "This paper presents the Conflict Scenario Control tool a web system that assists in the elicitation and management of interpersonal conflict scenarios, in the context of Requirements Engineering, considering conflicts categorization (based on a systematic literature review in the area) and promoting empathy with the involved stakeholders. The tool evaluation occurred as a classroom study; the students used the tool to record and manage real conflict scenarios, through interviews with RE professionals; at the end, students answered a questionnaire which shows that they consider the system comfortable, organized, easy to use, with a didactic layout, and capable of recording real scenarios, in a structured way, and with support to help in thinking about conflicts.", "url": "artigos/artigos_WER21/wer202121.html"}, {"title": "Helius: On a Recommendation System of Design Thinking Techniques for Software Development based on Professionals' Collaboration", "authors": ["Rafael Parizi", "Igor Couto", "Lucas Hanauer", "Sabrina Marczak", "Tayana Conte"], "year": 2021, "keywords": "Design Thinking; Techniques; Recommendation System; Requirements Engineering; Elicitation Support", "abstract": "This paper reports further on Helius, a collaborative recommendation system of Design Thinking techniques for software development. DT has been using as an approach for problem-solving, supporting software development activities such as Requirement Engineering (RE). DT integrated to RE fosters empathy, team collaboration, creativity, and an innovative mindset putting the user needs at the center of the development process. DT provides a large set of techniques, including Interviews, Brainstorming, Personas, User Journeys, Prototyping, etc. Therefore, selecting the DT techniques for RE activities becomes a challenge, mainly for novice professionals. This way, Helius uses professionalsâ experiences and techniques evaluations as collaborative resources to recommend DT techniques. Heliusâ proposes resulted from a DT session with software development professionals and researchers. Helius presents innovative fe\u0002atures when compared with similar tools. Therefore, we expect to sup\u0002port software development professionals in selecting DT techniques and collaborate with the DT adoption in software development.", "url": "artigos/artigos_WER21/wer202122.html"}, {"title": "Análise de Requisitos Não-Funcionais nos Processos de Migração para Microsserviços", "authors": ["Marcio Veronez", "Ivonei Freitas da Silva"], "year": 2021, "keywords": "microsserviço; monolítico; migração; requisitos não-funcionais; modelo de features", "abstract": "Requisitos não-funcionais como alta disponibilidade, redund?ancia e escalabilidade são descritos na literatura como motivação e benefícios quando se migra de uma arquitetura monol´?tica para microsserviços. No entanto, não está claro quais os principais requisitos não-funcionais e seus trade-offs que engenheiros de requisitos e arquitetos de software devem considerar antes do processo de migração. Este trabalho descreve os principais requisitos não-funcionais e seus trade-offs do processo de migração de sistemas monol´?ticos para microsserviços. Para isto, primeiramente, as motivações e forças norteadoras que justificam as migrações de sistemas monolíticos para microsserviços são mapeadas para requisitos não-funcionais através de um mapeamento sistemático da literatura. Então, uma análise de similaridade e variabilidade entre estes requisitos não-funcionais é realizada com um modelo de features. Essa análise pode guiar os arquitetos de software nas decisões arquiteturais durante o processo de migração.", "url": "artigos/artigos_WER21/wer202123.html"}, {"title": "Auxiliando Professores de Engenharia de Requisitos a Identificar Jogos como Recursos Pedagógicos", "authors": ["Caio Steglich", "Sabrina Marczak"], "year": 2021, "keywords": "Engenharia de Requisitos; Ensino de Requisitos; Engenharia de Software; Design Science Research; Jogos no Ensino de Requisitos", "abstract": "Os professores de requisitos são responsáveis por formar os futuros profissionais que lidarão com a especificação de software que serão desenvolvidos pela indústria. A literatura sobre o ensino de requisitos costuma apresentar estudos que vislumbram a perspectiva dos estudantes, mas raramente exploram as dificuldades do professor, como, por exemplo, localizar recursos para utilizarem em sala de aula. Esta pesquisa visa entender as dificuldades do professor quanto a localização de jogos didáticos e compor um ambiente que apoie os professores de requisitos a encontrarem jogos que possam ser utilizados no ensino da disciplina. Esta pesquisa utiliza-se da metodologia de Design Science na qual permite, em ciclos de pesquisa, a elaboração de um artefato que neste estudo será um ambiente a ser proposto. Nestes ciclos, ocorrerão os seguintes estudos: 1) Uma survey para identificar os professores de requisitos, 2) Uma revisão de literatura para popular inicialmente o ambiente proposto, 3) Um estudo de Campo para captação dos requisitos do ambiente, 4) Propostas de protótipos e avaliações destes e 5) Múltiplos estudos de Caso para testar o uso do ambiente na prática. A contribuição esperada ao fi- nal deste estudo é um ambiente que auxilie professores de Engenharia de Requisitos a identificarem jogos que podem ser utilizados como recursos pedagógicos em suas disciplinas.", "url": "artigos/artigos_WER21/wer202124.html"}, {"title": "Mantendo a consistência na coevolução de modelos iStar, BPMN e Casos de Uso na Engenharia de Requisitos", "authors": ["Diogo Do Nascimento Paza", "Victor Santander"], "year": 2021, "keywords": "iStar; framework i*; i-estrela; BPMN; Casos de Uso; Modelagem UML; Modelos de Negócio; Modelos Organizacionais", "abstract": "A Engenharia de Requisitos (ER) é uma etapa fundamental no desenvolvimento de um software. Tecnicas de modelagem organizacional como iStar (lê-se i-estrela), de processos de negócio como BPMN (Business Process Model and Notation) e de requisitos funcionais como Caso de uso UML são utilizadas para elicitar e documentar requisitos. Em trabalhos prévios, propõe-se derivar casos de uso a partir de modelos iStar e BPMN e gerar esses artefatos na ferramenta JGOOSE (Java Goal into Object Oriented Standard Extension). Contudo, as diretrizes de derivação propostas e a ferramenta de suporte não garantem a consistência desses artefatos quando os mesmos evoluem. Isto significa que altera¸cões em casos de uso não são refletidas nos modelos iStar ou BPMN usados como base. Esta deficiência pode levar à documentos inconsistentes ao longo do ciclo de vida de um software. Desta forma, propõe-se definir regras de mapeamento que garantam a consistência entre esses modelos bem como incluir esse suporte na ferramenta JGOOSE. Também neste trabalho pretende-se validar a solução proposta utilizando a engenharia de software experimental.", "url": "artigos/artigos_WER21/wer202125.html"}, {"title": "Padrões de Requisitos para Sistemas de Registro Eletrônico de Saúde", "authors": ["Mariana Martins", "Taciana Kudo", "Renato Bulcão-Neto"], "year": 2021, "keywords": "Reúso; Catálogo; Padrão de Requisito de Software; S-RES", "abstract": "Um catálogo de padrões de requisitos de software (CPRS) organiza requisitos comuns entre aplicações de um domínio para que sejam reusados e, assim, reduzir os esfor¸cos de elicitação, especificação e validação de requisitos de uma nova aplicação de mesmo domínio. O CPRS tem importante papel para a Engenharia de Requisitos e todo o ciclo de vida, pois mais de 50% dos defeitos identificados em projetos advêm de requisitos de baixa qualidade. Estudos recentes reforçam que o desenvolvimento de CPRS é uma das ações que promovem maior disseminação da adoção de padrões de requisitos na indústria. Além da baixa disponibilidade de CPRS, poucos estudos realizam a validação e a avaliação de CPRS. Assim, visa-se desenvolver um CPRS para Sistemas de Registro Eletrônico em Saúde (S-RES), validado e avaliado por especialistas desse domínio de aplicação. A construção do CPRS é apoiada pela ferramenta Terminal Model Editor (TMEd), e os conceitos e a estrutura do CPRS seguem as definições do metamodelo Software Pattern Metamodel (SoPaMM). A construção do CPRS apoia-se em requisitos usados na certificação de S-RES pela Sociedade Brasileira de Informática em Saúde (SBIS). O CPRS será então disponibilizado à SBIS para apoiar não somente a certificação, mas também o desenvolvimento de S-RES.", "url": "artigos/artigos_WER21/wer202126.html"}, {"title": "Processo de Especificação de Banco de Dados em Sistemas Críticos", "authors": ["Sarasuaty Yelisetty", "Johnny Marques", "Luiz Dias"], "year": 2021, "keywords": "banco de dados; sistemas críticos; requisito; processo; validação", "abstract": "O software de sistemas críticos em segurança, incluindo banco de dados, requer processos robustos de especificação, desenvolvimento, validação, verificação, gerenciamento de configuração e garantia de qualidade. A pesquisa reportada neste trabalho, em seu estágio atual, propõe a criação de um processo de especificação e validação de requisitos para bancos de dados em sistemas críticos. A metodologia utilizada envolve a condução de uma Revisão Sistemática da Literatura em processos de especificação de bancos de dados. Adicionalmente, inclui-se um diagrama do processo de especificação e validação de requisitos para bancos de dados em sistemas críticos que inclui a criação dos cenários de validação de requisitos. Espera-se que o processo possa ser utilizado por empresas desenvolvedoras de sistemas críticos e apresentará rastreabilidade para as necessidades regulatórias de alguns domínios selecionados como o aeronáutico, médico e ferroviário. Adicionalmente, o processo também permitirá uma construção organizada de bancos de dados orientados por requisitos, visando a mitigação de erros inseridos em sua construção e mecanismos de garantias desde a especificação até a integração com o software de aplicação.", "url": "artigos/artigos_WER21/wer202127.html"}, {"title": "Requisitos de Confiança para Robôs Socialmente Assistivos", "authors": ["Larissa Rodrigues da Costa", "Jaelson Castro"], "year": 2021, "keywords": "Engenharia de Requisitos; Interação Humano-Robô; Robótica Socialmente Assistiva; Confiança; STPA", "abstract": "No campo de pesquisa dos Robôs Socialmente Asistivos (SARs) o estudo da Interação Humano-Robô (HRI) tem o importante papel de indagar a forma como o aspecto humano e robótico colaboram entre si e qual o espaço do robô na vida humana. Alguns aspectos vêm sendo bastante estudados na literatura, dentre eles a confiança, que é crucial e bastante complexa, composta de diversos fatores que precisam de algumas condições necessárias para ser atingida, condições essas, que a Engenharia de Requisitos pode contribuir para compreender, moldar e analisar quais requisitos são fundamentais melhorando assim a aceitação da utilização desses robôs. Objetivo: Essa pesquisa propõe a construção de um catálogo de requisitos não funcionais chamado NFR4TRUST, que possa ajudar a aumentar a confiança humana na utilização de robôs no domínio de SARs. Método: Inicialmente, será realizado um levanta\u0002mento bibliográfico visando verificar o estado da arte em HRI no contexto de confiança, segurança e taxonomias existentes. A partir deste estudo, será construída uma proposta de taxonomia que auxiliará a descoberta de requisitos para SARs. A técnica STPA será utilizada como método para avaliar as ameaças a confiança, enquanto a validação do catálogo proposto será realizada por especialistas e elaboração de um estudo de caso. Resultados esperados: Com este trabalho criaremos o Catálogo NFR4TRUST que permitirá apoiar as etapas de elicitação e especificação de requisitos referentes a confiança no domínio proposto. Conclusão: Os resultados deste trabalho permitirão incrementar, avaliar e melhorar a confiança humana na utilização dos SARs.", "url": "artigos/artigos_WER21/wer202128.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2022)", "authors": ["Leandro Antonelli", "Maria Lencastre", "Victor Santander"], "year": 2022, "keywords": "wer; Requirements Engineering", "abstract": "The 25th Workshop on Requirements Engineering (WER 2022) was held at the Federal University of Rio Grande do Norte (UFRN) in Natal, Brazil, from August 23rd to 26th. The event marked a milestone in the WER series and brought together a diverse international community to discuss key challenges in Requirements Engineering. Featuring keynote talks from prominent researchers such as Daniel Amyot, Luis Olsina, Luiz Marcio Cysneiros, and Óscar Pastor, the program spanned multiple tracks including Research, Journal First, Tools, and Master's and Doctoral sessions. Highlights included industry talks on real-world requirements in public health systems, a tutorial on security requirements elicitation, and a retrospective panel celebrating 25 years of WER. The open-access proceedings showcased innovative work on privacy, design thinking, machine learning, and safety requirements, reflecting the event’s commitment to academic excellence and industry relevance.", "url": "artigos/artigos_WER22/wer202200.html"}, {"title": "A Catalogue of Concerns for Specifying Machine Learning-Enabled Systems", "authors": ["Hugo Villamizar", "Marcos Kalinowski", "Hélio Lopes"], "year": 2022, "keywords": "Requirements engineering; requirements specification; perspectives; concerns; machine learning; artificial intelligence", "abstract": "Requirements engineering (RE) activities for machine learning (ML) are not well-established and researched in the literature. Many issues and challenges exist when specifying, designing, and developing ML-enabled systems. Adding more focus on RE for ML can help to develop more reliable ML-enabled systems. Based on insights collected from previous work and industrial experiences, we propose a catalogue of 45 concerns to be considered when specifying ML-enabled systems, covering five different perspectives we identified as relevant for such systems: objectives, user experience, infrastructure, model, and data. Examples of such concerns include the execution engine and telemetry for the infrastructure perspective, and explainability and reproducibility for the model perspective. We conducted a focus group session with eight software professionals with experience developing ML-enabled systems to validate the importance, quality and feasibility of using our catalogue. The feedback allowed us to improve the catalogue and confirmed its practical relevance. The main research contribution of this work consists in providing a validated set of concerns grouped into perspectives that can be used by requirements engineers to support the specification of ML-enabled systems.", "url": "artigos/artigos_WER22/wer202201.html"}, {"title": "A Catalogue of KAOS Extensions", "authors": ["Pedro Rodrigues de Carvalho Junior", "Enyo José Tavares Gonçalves", "Rainara Maia Carvalho", "Marcos Antonio de Oliveira"], "year": 2022, "keywords": "Requirements Engineering; KAOS; Extensions; Catalogue", "abstract": "KAOS, a goal-based modeling language, has been extended since its creation. Searching for existing KAOS extensions and their constructs is a task that can be the start point for requirements modeling or for the creation of new KAOS extensions. This search can be performed by using strings searches in databases or through a catalogue that supports them. This exploratory task about extensions can take a great deal of time and be prone to failure when performed without specific and adequate support. catalogues have been used successfully to bring together a body of knowledge, including knowledge of modeling language extensions. Motivated by this scenario, this work proposes a catalogue of extensions to the KAOS modeling language. The results suggest that the proposed catalogue can be used to retrieve information about extensions and their constructs correctly and that it is easy to use.", "url": "artigos/artigos_WER22/wer202202.html"}, {"title": "A Collaborative Approach to specify Kernel Sentences using Natural Language", "authors": ["Leandro Antonelli", "Alejandro Fernandez", "Nicolas Ruffolo", "Emiliano Sansone", "Diego Torres"], "year": 2022, "keywords": "requirements; specifications; kernel sentences; collaboration; natural language", "abstract": "Requirements engineering is a critical part of software development. Errors in the requirements, if not found and corrected early in the engineering process, become costly problems later on. Analysts commonly rely on Use Cases or Users Stories to capture requirements. However, there is domain knowledge that these artifacts dont capture well (for example, business rules and given-then-when scenarios). Such domain knowledge is generally distributed among multiple stakeholders and domain experts with complementing perspectives. Therefore, it is important to use a collaborative technique with a simple artifact to acquire and validate their knowledge. Kernel sentences is a linguistic definition about small sentences (with only one verb) written in active voice. Some authors relate kernel sentences to business rules. We argue that kernel sentences are adequate to use in the collaborative acquisition and they can be used as the input to produce more complex artifacts. This paper proposes a collaborative approach to acquire and validate kernel sentences. The process has three main activities: acquisition of the kernel sentences, validation of them, and assessment of the activity of the experts who participate in the activity. This paper also describes a prototype to support the process. Finally, the paper shows the result of a preliminary evaluation with promising results about the applicability of the process.", "url": "artigos/artigos_WER22/wer202203.html"}, {"title": "An Iterative and Collaborative Approach to Specify Scenarios using Natural Language", "authors": ["Leandro Antonelli", "Juliana Delle Ville", "Felipe Dioguardi", "Alejandro Fernandez", "Luciana Tanevitch", "Diego Torres"], "year": 2022, "keywords": "requirements; specifications; kernel sentences; collaboration; natural language", "abstract": "Requirements engineering is one of the most important stages in software development. Errors committed at this stage require a lot of effort to fix in further stages. There are two main strategies to deal with software development: classic and agile. Classic software development relies on an extensive and very detailed specification, while agile development minimizes the effort on requirements specifications, relying on brief descriptions and a running prototype as a means of communication. Before the specification of requirements, there are some preliminary meetings held between the stakeholders and the IT team with the objective of discovering the goal and scope of the application to be developed. The knowledge transferred during these meetings is crucial to provide a context to requirements, no matters whether the approach is classic or agile. We argue that scenarios written in natural language are adequate artifacts to capture this knowledge. This paper proposes an iterative and collaborative approach to describe scenarios. The approach has two main activities: one of them is concerned with the description that stakeholders should perform, while the other provides guidelines to verify and possible improve the scenarios. This paper also presents a prototype tool that helps enforcing these guidelines automatically. This prototype relies on natural language processing. Finally, the paper shows the result of a preliminary evaluation of the proposed approach that indicates its results are promising", "url": "artigos/artigos_WER22/wer202204.html"}, {"title": "Design Thinking and Non-Functional Requirements Elicitation: A Survey", "authors": ["Fábio Avigo de Castro Pinto", "Anarosa Alves Franco Brandão", "Fábio Levy Siqueira"], "year": 2022, "keywords": "Design Thinking; DT; Non-functional Requirements; NFR", "abstract": "Design Thinking (DT) is a human-centered approach used in innovative problem-solving. In software development projects, it can be usually applied as a toolbox, mindset or process. Moreover, DT has seen a large rise in popularity over the past decade, especially in its upfront use for eliciting requirements. Despite its many benefits and successful use cases in this scenario, some of the shortcomings related to its uses in Requirements Engineering (RE) have started to show up. One of them lies in the difficulty with eliciting other non-functional requirements (NFR) besides usability, possibly jeopardizing the subsequent software development life-cycle if these requirements are not properly addressed. This article presents a qualitative survey conducted via LinkedIn with 53 software developers that have had previous experiences with the use of DT as an upfront process in software projects. The focus of the research has been on identifying the existence of problems, how they became manifest, and whether the software community has tools for mitigating them. The results suggest the neglect of DT for requirements other than those of a functional or usability nature in this situation. Since this use of DT is focused on improving the users experience, and identifying their needs, we argue that such needs are not limited only to the functions of a software or its usability. In fact, we also advocate that other aspects that are intrinsic to NFR, such as performance and reliability are part of such needs.", "url": "artigos/artigos_WER22/wer202205.html"}, {"title": "Engenharia de Requisitos de Sistemas IoT e Ciber-Físicos: Resultados Preliminares", "authors": ["Ernesto Fonseca Veiga", "Renato F. Bulcão-Neto"], "year": 2022, "keywords": "Engenharia de Requisitos; Internet das Coisas; IoT; Sistemas Ciber-Físicos; CPS; Mapeamento Sistemático; Estado da Arte", "abstract": "Internet of Things (IoT) e Cyber-Physical Systems (CPS) referem-se a um conjunto relacionado de tendências na integração de recursos digitais (conectividade de rede e capacidade computacional) com dispositivos físicos e sistemas, visando melhorar seu desempenho e funcionalidade. Esses paradigmas têm criado oportunidades de progresso e crescimento econômico em diversos setores, como indústria, energia e transportes. O desenvolvimento de IoT/CPS e as suas aplicações têm possibilitado a criação de sistemas cada vez mais complexos. Porém, os projetos destes sistemas, muitas vezes, se mostram desafiadores para o processo tradicional de Engenharia de Requisitos (ER), levando à adaptação de técnicas pré-existentes, ou mesmo à criação de novas abordagens de ER, no intuito de atender as características específicas desses sistemas. Neste contexto, o objetivo deste artigo é fornecer uma visão abrangente sobre o processo de ER para sistemas IoT/CPS. Para atingir esse objetivo, realizou-se um Mapeamento Sistemático em que foram encontrados, por meio de busca automática e critérios de seleção, 31 estudos primários de ER para IoT/CPS. Desses estudos, foram extraídos tipos e fontes de requisitos, atividades de ER, técnicas utilizadas e problemas tratados. Como resultado, a principal contribuição deste trabalho é um levantamento do estado da arte sobre ER para sistemas IoT/CPS.", "url": "artigos/artigos_WER22/wer202206.html"}, {"title": "Obtendo Casos de Uso a Partir de Modelos de Processos de Negócio: Uma Revisão Sistemática da Literatura", "authors": ["Victor F.A. Santander", "Sidgley C. de Andrade", "Ivonei F. da Silva", "Alexandre L. B. Silva", "Victor A. Pozzan", "Marco A. Toranzo Céspedes"], "year": 2022, "keywords": "Processos de Negócio; BPMN; Casos de Uso; Revisão Sistemática.", "abstract": "Os modelos de processos de negócio servem como fonte de requisitos para a modelagem de sistemas de informação que podem ser construídos para operacionalizar processos organizacionais. Embora os requisitos possam ser representados através dos Casos de Uso, a transformação de um modelo em nível de negócio para um modelo em nível de sistema é dificultada devido à notação ou linguagem utilizada para modelar o negócio ser diferente da utilizada para modelar o sistema. Essa diferença entre modelos é uma das barreiras na obtenção ou definição de requisitos de qualidade, pois o engenheiro de requisitos pode ter pouco conhecimento sobre os conceitos de processos de negócio e a falta de iniciativas (abordagens, métodos, técnicas, processos ou ferramentas) que apoiem esse processo pode induzir o profissional a projetar o sistema de forma equivocada. Este trabalho conduz uma revisão sistemática com o objetivo de apresentar o atual estado da arte sobre a derivação de Casos de Uso a partir de modelos de processos de negócio, bem como fornecer um guia aos engenheiros de requisitos, apresentando um leque de possibilidades dessas iniciativas e seus principais conceitos e fundamentos.", "url": "artigos/artigos_WER22/wer202207.html"}, {"title": "Organizing the TD Management Landscape for Requirements and Requirements Documentation Debt", "authors": ["Larissa Barbosa", "Sávio Freire", "Nicolli Rios", "Robert Ramac", "Nebojša Taušan", "Boris Pérez", "Camilo Castellanos", "Darío Correal", "Alexia Pacheco", "Gustavo López", "Vladimir Mandic", "Rita S. P Maciel", "Manoel Mendonça", "Davide Falessi", "Clemente Izurieta", "Carolyn Seaman", "Rodrigo Spínola"], "year": 2022, "keywords": "Requirements debt; Requirements documentation debt; Causes; Ef-fects; Technical debt prevention; Technical debt repayment", "abstract": "Requirements and requirements documentation debt (R2DD) indicate shortcuts taken in software development projects, resulting in requirements partially implemented and with outdated documentation, respec-tively. Knowing the causes and effects of R2DD can support software teams in defining actions to prevent the occurrence of these items and aid in the prioriti-zation for eliminating them, respectively. Besides, having information on how practitioners deal with R2DD items can support developing new strategies and artifacts for managing these items. However, little is known on the state of the practice of R2DD. [Aims:] To investigate the state of the practice of R2DD, re-vealing its causes, effects, and practices and practice avoidance reasons (PARs) considered for its prevention and repayment. [Method:] We analyzed quantita-tively and qualitatively a corpus of responses from a survey with software prac-titioners on R2DD and its elements (causes, effects, prevention, and repayment). [Results:] We identified 55 causes, 33 effects, 26 prevention practices, three PARs related to nonprevention, 18 repayment practices, and 16 PARs associated with nonrepayment of R2DD items. [Conclusion:] We organized those practices into a conceptual map. Software practitioners can use the map to start or improve their initiatives for dealing with R2DD items.", "url": "artigos/artigos_WER22/wer202208.html"}, {"title": "Requirements Engineering Processes in the Context of IoT and Requirements Validation Techniques", "authors": ["Lucas da Silva Souza", "Felipe Brito Ayres", "Pedro Henrique Teixeira Costa", "Edna Dias Canedo"], "year": 2022, "keywords": "Internet of Things; Non-Functional Requirements; Software System; Process; Techniques", "abstract": "The Internet of Things made possible an increase in the possibilities of automation and facilitation of peopleâs daily lives. From home automation to smart buildings, the rise in IoT's popularity brings a challenge to software development and requirements engineering. Developers and companies are not familiar with the requirements validation processes and techniques that exist in the context of an IoT system. Therefore, possible project failures and rework during software development are issues to be considered by development teams. This work aims at investigating the requirements engineering process and the requirements validation techniques in the IoT context described in the literature. Also, present a guide to support software development teams to have easy access to the processes and techniques proposed in the literature for this context. We conducted a survey of industry practitioners to investigate whether they use and know the processes and techniques identified in the literature. Our findings reveal that the technique most used by practitioners to perform requirements specification are stakeholders meeting and brainstorming and to validate requirements are prototypes and use cases.", "url": "artigos/artigos_WER22/wer202209.html"}, {"title": "Requirements: The Never-Ending Story", "authors": ["Julio Cesar Sampaio do Prado Leite"], "year": 2022, "keywords": "Requirements Engineering; Misunderstandings; Software Transparency; Education", "abstract": "A magic medallion is central in Michael Ende's novel, and it is depicted as two snakes biting each other, in a loop. Folk tale says that the design of the medallion changed for the Wolfgang Petersen's movie, depicting an even deeper image of infinity. The medallion turned out to be an icon for the story's fans. This vision paper will unleash a broad view of the realm of requirements and requirements engineering, comparing it to Percival's quest for the Holy Grail. Using literate and pop metaphors the paper posits that requirements engineering is an education process, which must be performed with transparency. Historical misunderstandings of \"requirements\" is reviewed, pitfalls to avoid are signaled and new trails to be built are proposed", "url": "artigos/artigos_WER22/wer202210.html"}, {"title": "Requisitos Não-Funcionais de Confiança: Um Catálogo para Robôs Socialmente Assistivos", "authors": ["Larissa Rodrigues da Costa", "Jaelson Castro", "Judith Kelner", "Maria Lencastre"], "year": 2022, "keywords": "Requisitos Não-Funcionais; Confiança; Robótica Socialmente Assistiva; Interação Humano-Robô; NFR Framework", "abstract": "Temos observado crescimento significativo no desenvol-vimento e utilização de robôs socialmente assistivos (Socially Assistive Robots  SARs) que interagem com humanos. Um dos aspectos críticos para a adoção desses robôs é a confiança (trust). Para a Engenharia de Requisitos, a confiança poderá ser considerada um requisito não-funcional a ser satisfeito. As fases de elicitação e especificação dos requisitos de confiança contribuirá diretamente para a qualidade dos SARs. Na literatura há uma escassez de trabalhos que abor-dam a confiança no contexto de SARs. [Objetivo]: Este trabalho propôs um ca-tálogo de Requisitos Não-Funcionais de Confiança para Robôs Socialmente As-sistivos - NFR4TRUST. [Método]: Foi realizado um levantamento bibliográfico, abrangendo o contexto de confiança em interação humano-robô. Em seguida, foi construída uma taxonomia de confiança para SARs que irá auxiliar a descoberta de requisitos, servindo de base para a elaboração do NFR4TRUST. A validação do catálogo incluiu o seu uso na definição de requisitos de confiança de um robô que auxilia na reabilitação de membros superiores, e a realização de entrevistas com especialistas das áreas de NFR Framework, interação-humano-robô, enge-nharia de requisitos e fisioterapia. [Resultados]: De acordo com os especialistas e engenheiros de requisitos consultados, o catálogo NFR4TRUST é um artefato útil, de fácil entendimento, apresentando uma boa abrangência em relação aos requisitos não-funcionais de confiança no domínio da SARs. [Conclusão]: O NFR4TRUST foi considerado útil e adequado para apoiar as etapas de elicitação e especificação em projetos de robôs socialmente assistivos, permitindo a identi-ficação de possíveis problemas sobre a perspectiva de confiança.", "url": "artigos/artigos_WER22/wer202211.html"}, {"title": "Um survey com especialistas como validação de elementos para composição de uma ontologia para Sistemas AAL (Ambient Assisted Living)", "authors": ["Timóteo Gomes", "Fernanda Alencar"], "year": 2022, "keywords": "Sistemas AAL; Ontologia; Compliance; Requisitos não funcionais", "abstract": "O Ambient Assisted Living (AAL) se constitui em uma abordagem tecnológica que surgiu para atender às demandas do público idoso e pessoas com deficiência. Por serem considerados sistemas complexos e multidisciplinares é necessário se ter como identificar e definir quais módulos precisam compor esses sistemas. Dentre os desafios encontrados no desenvolvimento de sistemas AAL está o alinhamento com os requisitos funcionais e/ou não funcionais e o cumpri-mento das restrições éticas, legais, sociais, médicas e técnicas que balizam esses tipos de sistemas. Diante disso, nesse trabalho é apresentado o resultado de um survey sobre o desenvolvimento de sistemas AAL, realizado com 28 especialistas (academia e indústria) sobre: tipos de sistemas AAL; ambientes; dispositivos; compliance; requisitos não-funcionais (qualidade do produto, qualidade de uso e requisitos éticos); e, stakeholders. A partir das contribuições recebidas e das evi-dências da literatura foram realizados ajustes em um modelo, de forma a ser pos-sível a proposição de uma ontologia para orientar o desenvolvimento de sistemas AAL e ampliando-se o conhecimento a esse respeito.", "url": "artigos/artigos_WER22/wer202212.html"}, {"title": "Uma taxonomia para requisitos de privacidade e sua aplicação no Open Banking Brasil", "authors": ["Sâmmara Éllen Renner Ferrão", "Edna Dias Canedo"], "year": 2022, "keywords": "Requisitos de Privacidad; Taxonomia; LGPD; Open Banking.", "abstract": "A preocupação com a privacidade de dados é vem se destacando ao longo dos anos em diversos países. No Brasil a Lei Geral de Proteção de Dados (LGPD) foi publicada em agosto de 2018, entrando em vigor em 2020 porém, algumas dificuldades ainda são enfrentadas pelos profissionais de TIC na adequação dos mecanismos tecnológicos, por parte das organizações. Assim, este trabalho propõe uma taxonomia de requisitos de privacidade baseada na LGPD e na ISO/IEC 29100 com o objetivo de apoiar as equipes de desenvolvimento de software no alcance da conformidade com os princípios da LGPD. A aplicação prática da taxonomia proposta foi realizada no processo de solicitação de consentimento e no termo e condições de consentimento do projeto Open Banking de três bancos no Brasil. A taxonomia de requisitos proposta é composta por 129 requisitos de privacidade divididos em 10 categorias e 5 contextos. A aplicação prática da taxonomia resultou em um percentual satisfatório de aderência aos requisitos de privacidade demonstrando a possibilidade de apoio as equipes de desenvolvimento de software na busca pela adequação à LGPD especificamente no âmbito dos requisitos de privacidade.", "url": "artigos/artigos_WER22/wer202213.html"}, {"title": "A catalog of quality criteria to guide the assessment of applications’ privacy policies", "authors": ["Augusto Terra", "Jéssyka Vilela", "Mariana Peixoto"], "year": 2022, "keywords": "Privacy; Privacy Policy; Personal Data; Catalog; Data protection; Quality Criteria; Snowballing", "abstract": "Context: The information about personal data processing must be described in the companies' privacy policies. Problem: privacy policies are long documents, full of jargon, and do not always comply with the current privacy law. Besides, the privacy policies should be consistent with requirements document and application behavior, hence, it is of paramount importance that stakeholders should be able to evaluate the quality of the privacy policies. Objective: This work proposes a catalog of criteria for assessing the quality of privacy policies. Method: the snowballing technique was performed to find relevant studies that evaluate privacy policies. Results: The proposed catalog, elaborated from the empirical results of 48 studies, has 29 different criteria grouped into five categories. Contributions: The developed catalog can help: (i) requirements engineers to check the consistency of the privacy policies content with the requirements document; (ii) writers to create more precise and complete documents regarding users' rights in accordance with the requirements document, (iii) analysts and developers to make them more straightforward which information must be properly documented about the practice of data collection; (iv) end-users to understand the content of the privacy policies.", "url": "artigos/artigos_WER22/wer202214.html"}, {"title": "Avaliação Experimental de um Catálogo de Padrões de Requisitos para Sistemas de Registro Eletrônico de Saúde", "authors": ["Mariana Crisostomo Martins", "Taciana Novo Kudo", "Renato F. Bulcão-Neto"], "year": 2022, "keywords": "Padrão de requisitos; S-RES; Experimentação; Estudo de caso; Survey; Métrica", "abstract": "Este artigo apresenta uma experimenta¸cão de um catálogo de padrões de requisitos (CPR) para Sistemas de Registro Eletrônico de Saúde (S-RES). A avalia¸cão do CPR inclui um estudo de caso e uma survey aplicados a duas turmas de gradua¸cão de disciplinas de Engenharia de Requisitos. Após elaborarem documentos de especifica¸cão de requisitos com e sem o auxílio do catálogo, os estudantes responderam a um questionário para identificar a utilidade e facilidade de uso do CPR para elicita¸cão e especifica¸cão de S-RES. Ao analisar a completude, o escopo e a consistência dos documentos elaborados pelos estudantes, constatou-se que o CPR para S-RES melhorou a qualidade das especifica¸cões. Além disso, há evidências de que o CPR para S-RES é útil, fácil de usar e tornou a elicita¸cão e a especifica¸cão mais rápidas.", "url": "artigos/artigos_WER22/wer202215.html"}, {"title": "Diretrizes para apresentação de políticas de privacidade voltadas à experiência do usuário", "authors": ["Egberto Santana", "Jéssyka Vilela", "Mariana Peixoto"], "year": 2022, "keywords": "Privacidade; Políticas de Privacidade; Experiência do Usuário; Usabilidade; Design Sprint; Heurísticas de Nielsen; LGPD.", "abstract": "Contexto: As empresas buscam o cumprimento e adequação de suas Políticas de Privacidade às novas Leis de Proteção de Dados. No entanto, as Políticas de Privacidade, geralmente, são apresentadas de forma longa e com um vocabulário muito formal, fazendo com que o usuário acabe perdendo o interesse em ler o documento. Objetivo: propor um Guia composto por diretrizes para melhorar a apresentação das interfaces de políticas de privacidade voltadas à experiência do usuário. Método: A avaliação heurística de Nielsen combinada com a técnica de Design Sprint do Google foram utilizadas. Resultado: Foi possível verificar que os usuários atingiram um bom nível de satisfação com as mudanças propostas pelo Guia, resultando em uma melhor interpretação e compreensão desta política apresentada. Conclusão: As melhorias na interface levam a uma melhor experiência do usuário.", "url": "artigos/artigos_WER22/wer202216.html"}, {"title": "Do Platforms Care About Your Child’s Data? A Proposal of Legal Requirements for Children’s Privacy and Protection", "authors": ["George Valença", "Maria Wanick Sarinho", "Vinícius Polito", "Fernando Lins"], "year": 2022, "keywords": "Privacy; Legal Requirements; Children’s rights", "abstract": "To promote children's data protection, the design of services and products matters, as well as continued enforcement of terms of use and privacy policies by tech companies. However, the child, their rights and Privacy by Design principles place the burden on platforms to develop age-appropriate and rights-oriented experience. To highlight the duties of Big Techs and guide them in implementing children's privacy and data protection, we present 19 legal requirements (LR) based on UNICEF's Manifesto and the standard Children's Right by Design. Besides, to illustrate how each LR can be implemented, we consider examples from Youtube Kids and TikTok platform ecosystems. Our goal is to pave the way for a shift towards children's protection and promotion by tech companies, reducing the detrimental use of their data.", "url": "artigos/artigos_WER22/wer202217.html"}, {"title": "Ensino de prevenção e gerenciamento de conflitos na Engenharia de Software baseado em Metodologias Ativas", "authors": ["Patricia Mergulhão", "Maria Lencastre", "Aline Barbosa"], "year": 2022, "keywords": "Metodologias ativas; Gerenciamento Conflito; Prevenção Conflito", "abstract": "Este artigo apresenta um componente curricular para a Engenharia de Software que propõe o ensino relacionado à prevenção e ao gerenciamento de conflitos, através do uso de Metodologias Ativas. Esta proposta é promissora para a formação, principalmente, de engenheiros de requisitos, que estão em constante interação com stakeholders e, por isso, mais sujeitos a problemas de comunicação e conflitos. O componente foi descrito através de um Canvas de Inovação Curricular, que orientou na definição dos elementos a serem incluídos e na sua articulação. O componente foi avaliado através de um estudo de caso que mostrou que este era promissor, dinâmico e propositivo.", "url": "artigos/artigos_WER22/wer202218.html"}, {"title": "Relato de experiência da linguagem de modelagem SysADL para documentação de sistemas embarcados com Arduino", "authors": ["Sara Guimarães", "Marcia Lucena", "Roberta Coelho"], "year": 2022, "keywords": "Sistemas embarcados; requisitos; Arduino; SysADL", "abstract": "O presente artigo discute como foi realizada a documentação de um sistema embarcado com a placa Arduino. Os sistemas embarcados são caracterizados por realizarem a automação de atividades, que muitas vezes se utilizam de elementos do tipo sensor e atuador (e.g., irrigação, monitoramento e exploração espacial). Diante da relevância desses sistemas, a utilização técnicas adequadas de documentação tornase premente. Neste artigo apresentamos um sistema embarcado utilizado em uma base de lançamento de foguete PET para automatizar o acionamento do lançamento e a inserção de combustível no foguete. Neste artigo apresentamos como este sistema foi modelado utilizando a visão estrutural, a visão comportamental e o diagrama de requisitos da SysADL, e discutimos sobre vantagens e desvantagens observadas com a modelagem adotada.", "url": "artigos/artigos_WER22/wer202219.html"}, {"title": "Requirements management improvements for an agile project: an experience report", "authors": ["Amanda Sousa", "Paulo Duarte", "Ismayle S. Santos", "Marina Reis Fernandes", "Mariana Salamoni Francisco", "Rossana M. C. Andrade"], "year": 2022, "keywords": "Requirement; Management; Traceability", "abstract": "Software requirements management is a process that involves several activities that generate artifacts that serve as a basis for project development. This process occurs continuously and is responsible for performing analysis, tracking, documentation, prioritization and change control so that all stakeholders agree on the requirements. However, these activities are not trivial and their form of execution varies according to the nature of each project. With this in mind, teams should be able to identify points for improvement, such as applying new practices, new technologies or tools and allocating resources to make the process more optimized and more productive. The present work presents our initial results towards improving a requirements engineering process within an agile team. Hence, this paper describes an experience report about identifying and applying good practices within a software development project. The difficulties and main lessons learned are also discussed.", "url": "artigos/artigos_WER22/wer202220.html"}, {"title": "ASP: An Aerospace Specification Process for Hardware Logic", "authors": ["Carlos Renato dos Santos", "Johnny Cardoso Marques"], "year": 2022, "keywords": "Aerospace; FPGA; VHDL; Requirements; life-cycle", "abstract": "This work intends to specify a process to develop aerospace devices that use VHDL (Very High-Speed Integrated Circuit (VHSIC) Hardware Description Language) to describe the digital hardware logic and assure all safety-critical features involved in the process were assessed. This work aims to a process that goes from the requirements to the logic implementation at the component described level. The research methodology contains 4 phases (Phases 1 to 4). We have already completed Phases 1 and 2. Currently, we are working on Phase 3. This work is being developed as part of a master's degree to be concluded by the end of 2023 inside of the Postgraduate Program in Space Sciences and Technologies of the Instituto Tecnológico de Aeronáutica.", "url": "artigos/artigos_WER22/wer202221.html"}, {"title": "Documentação de Requisitos de Sistemas Legados Uma proposta baseada na Engenharia de Requisitos Orientada a Objetivos", "authors": ["Renato G. Fritola", "Victor A. Santander"], "year": 2022, "keywords": "Legacy Systems; Requirements engineering; GORE Goal oriented requirements engineering; iStar; NFR Framework.", "abstract": "Sistemas legados estão presentes em muitas organizações e muitas vezes são responsáveis por gerenciar os dados principais e mais valiosos da organização. Devido à falta de documentação e código não estruturado, a manutenção desses sistemas normalmente é muito cara e proporciona um trabalho de baixa qualidade tornando-se um pesadelo para as equipes de desenvolvimento. Este trabalho aborda a questão da documentação inicial de requisitos de sistemas legados utilizando técnicas propostas pelo GORE, priorizando o contexto em que o uso de código fonte não é viável. Técnicas como i* (leia iStar), framework NFR, Kaos, entre outras, podem ser utilizadas para documentar requisitos funcionais e não funcionais destes sistemas. Essas técnicas têm a vantagem de focar nos objetivos e outras intenções que stakeholders possuem em ambientes organizacionais, neste caso, ambientes nos quais sistemas legados funcionam. Outro aspecto importante está relacionado ao processo a ser utilizado para gerar esses artefatos. Estudos iniciais apontam para o uso de entrevistas e questionários como alternativas viáveis para obter essas informações. O primeiro autor deste trabalho aplicou estas técnicas em um pequeno exemplo, visualizando diversas vantagens. Como continuação da proposta, uma revisão sistemática da literatura (RSL) está em andamento para investigar os trabalhos que contemplam estratégias e uso de técnicas para extração e documentação de requisitos de sistemas legados, com foco especial no uso de técnicas GORE. Os resultados desta RSL serão usados para apoiar e enriquecer a proposta a qual se pretende validar utilizando uma das abordagens recomendadas pela engenharia de software experimental.", "url": "artigos/artigos_WER22/wer202222.html"}, {"title": "Explorando a especificação de cenários de teste de segurança no desenvolvimento orientado por comportamento (Behavior Driven Development)", "authors": ["Maria Yêda Lima", "Carla Silva", "Renata Souza"], "year": 2022, "keywords": "Estudo exploratório; Pesquisa Qualitativa; Engenharia de Requisitos; Secure by Design · Desenvolvimento Orientado por Comportamento; Behavior Driven Development", "abstract": "Contexto: O aumento da coleta de dados pessoais tem levantado preocupações também crescentes sobre a segurança da informação em sistemas de software dos quais a sociedade está cada vez mais dependente. Neste cenário, desenvolver software seguro que esteja protegido de ameaças é uma preocupação que deve ser considerada na Engenharia de Requisitos. O desenvolvimento orientado por comportamento (Behavior Driven Development - BDD) é uma abordagem ágil de desenvolvimento de software que tem a característica de estimular a contínua interação entre o time de desenvolvimento e o cliente, facilitando a comunicação entre as partes, além de integrar a especificação de cenários de teste com a especificação dos requisitos do sistema. Objetivo: O objetivo geral desta pesquisa é investigar como a indústria de desenvolvimento de software vem realizando a especificação de cenários de teste em projetos que adotam o BDD e descrever um conjunto de cenários de teste de segurança que poderão ser usados por aqueles que desejam aprender sobre segurança de sistemas, bem como por engenheiros de software que desejam desenvolver sistemas mais seguros por projeto (secure by design). Metodologia: Esta pesquisa propõe inicialmente a realização de estudo da literatura para delimitar o problema de pesquisa a ser resolvido e analisar os trabalhos relacionados. Em seguida, um survey será conduzido para investigar as práticas que a indústria adota e as dificuldades que a indústria enfrenta em projetos que adotam BDD. Também realizaremos um estudo exploratório baseado em entrevista em empresas da indústria nacional que adotam o BDD, a fim de identificar boas práticas já adotadas e oportunidades de melhorias no processo de especificação de cenários de teste de segurança da informação. Com base nestes dados coletados, vamos definir cenários de teste de segurança que atendam as necessidades identificadas na literatura e na indústria. Por fim, esses cenários de teste de segurança serão avaliados considerando a sua utilidade e seu impacto por meio de um experimento controlado. Resultados: Com os resultados obtidos nesta pesquisa, pretendemos contribuir com a definição de artefatos de teste de segurança que auxiliem no desenvolvimento de software mais seguro.", "url": "artigos/artigos_WER22/wer202223.html"}, {"title": "Modelagem de Requisitos Iniciais de Segurança com Requirements4Safety", "authors": ["Moniky Ribeiro", "Jaelson Castro", "Ricardo Argenton"], "year": 2022, "keywords": "Sistemas Críticos de Segurança; IStar4Safety; GORE; STPA; UCM.", "abstract": "Contexto: Os requisitos de segurança de Sistemas Críticos de Segurança (SCSs) devem refletir as descobertas da fase de análise de segurança inicial. Portanto, é fundamental um alinhamento entre as práticas da Engenharia de Requisitos Orientada à Objetivos e as da Engenharia de Segurança. Observa-se o crescente interesse da comunidade de Engenharia de Segurança na adoção da técnica de análise de perigos STPA (System-Theoretic Process Analysis). Objetivo: Este trabalho tem por objetivo propor uma nova abordagem chamada Requirements4Safety para modelagem dos requisitos iniciais de segurança. Ela possibilitará alinhar os requisitos de segurança modelados na linguagem iStar4Safety, aos elementos correlatos identificados através do uso da técnica de análise de perigos STPA. Método: Serão estudadas as técnicas de modelagem iStar4Safety e STPA. Depois serão definidos passos para integrá-las, sendo estes definidos através do uso de uma notação adequada (ex. BPMN). Requirements4Safety será aplicada na definição dos requisitos de segurança de alguns sistemas críticos. Por último, espera-se que especialistas das áreas de requisitos e segurança avaliem a abordagem. Resultado: Espera-se que Requirements4Safety permita o alinhamento de técnicas conhecidas da comunidade de Engenharia de Requisitos (i.e., iStar4Safety) e Engenharia de Segurança (i.e., STPA). A abordagem será documentada e ilustrada. Também serão disponibilizados os resultados de surveys com a opinião de especialistas de Engenharia de Requisitos e de Segurança. Conclusão: Com o uso de Requirements4Safety, os requisitos de segurança dos SCs estarão alinhados aos elementos identificados durante a fase de análise preliminar de segurança. A certificação destes tipos de SCs será facilitada.", "url": "artigos/artigos_WER22/wer202224.html"}, {"title": "SAFE-Robot: Uma Abordagem para Sistematizar a Elaboração de Casos de Garantia de Segurança que Auxilie na Certificação de Sistemas Robóticos", "authors": ["Mozart de Melo Alves Júnior", "Maria Lencastre", "Jaelson Castro"], "year": 2022, "keywords": "Caso de Garantia de Segurança; Caso de Segurança; Certificação de Segurança; Robótica; Robôs Sociais.", "abstract": "Os sistemas robóticos estão presentes em nosso dia-dia, seja no trabalho colaborativo dentro das indústrias ou em casa auxiliando pessoas em diversas tarefas, acarretando um convívio intensivo com os seres humanos. Estas relações humanos-robôs precisam ser prudentes e planejadas, uma vez que são Sistemas Críticos (SC), onde a falha pode acarretar danos irreparáveis. Na maioria das vezes esses sistemas precisam ser certificados por órgãos reguladores que exigem evidências de segurança, o que não é um processo simples em função do grande volume de informações e artefatos que devem ser disponibilizados. Apesar da evolução constante das normas e dos processos de certificação, pesquisas científicas e de organizações internacionais relatam que existe uma grande dificuldade em descrever, de forma clara e rastreável essa documentação, por isso entidades regulatórias tem adotado os Casos de Garantia de Segurança (CGS) para auxiliar nesse processo. Objetivo: Propor uma abordagem que sistematize a elaboração de Casos de Garantia de Segurança, auxiliando o processo de certificação para sistemas robótico. Método: Aplicação de uma abordagem orientada para a melhoria evolutiva, dividida nas fases: informativa, analítica, proposicional e fase avaliativa. Conclusão: Desenvolver uma abordagem para sistematizar a elaboração de Casos de Garantia de Segurança, visando a construção de argumentos convincentes endereçando as evidências no auxilio da certificação de sistemas robóticos.", "url": "artigos/artigos_WER22/wer202225.html"}, {"title": "Safety - Security Alignment in Requirements Engineering Process for Autonomous Vehicles", "authors": ["Quelita Ribeiro", "Jaelson Castro"], "year": 2022, "keywords": "Autonomous Vehicle; Requirements Engineering; Safety; Security; STPA; Misuse Case.", "abstract": "Autonomous Vehicles (AVs) will transform the way we live and work. In order to cope with the complexity of AVs, we want to pro- vide an understandable process for organizations to analyze the areas of safety and security in requirements engineering for AVs. Initially, a bibliographic survey was carried out to verify the current state of the art. Based on this survey, we carried out a systematic literature review to find answers to our questions and better understand the requirements engineering context for AVs. From the review responses, a process will be built to unite safety and security analysis for AV. STPA, and Misuse Case techniques will be verified, and the advantages can be used in our process. Finally, we intend to evaluate and validate our re- search within the industry with requirements engineers in the automotive sector. This work is a step towards developing a body of knowledge in RE for AVs.", "url": "artigos/artigos_WER22/wer202226.html"}, {"title": "Towards an approach to conflict assessment in software teams", "authors": ["Aline Barbosa", "Maria Lencastre"], "year": 2022, "keywords": "Conflict; Conflict Management; Software engineering.", "abstract": "[Background] Conflicts are inherent in human relationships; people have different experiences, values, opinions, and ways of carrying out tasks, which can lead to disagreements. The composition of a software development team has a heterogeneity of individuals with different competencies, which impacts their interaction. Conflicts in the software development cycle are inevitable and can occur at any stage; if not well managed, they tend to generate adverse results and financial and time expenses. [Objective] In this thesis proposal, we aim to create an approach for evaluating the maturity of conflict management and prevention in software development environments; this occurs based on the analysis of a set of well-established metrics and extracted indicators. [Method] Initially, a Systematic Literature Review (SLR) was carried out to verify the state of the art on conflicts and their management in software development. After, a proposal is built to consider ways of identifying the team's level of maturity in terms of conflicts treatment; this evaluation includes an analysis of applied forms of conflict prevention and management and variables that point to high impacts on project success. Also, we want to analyse team members' symptoms that stand out at any given time, as they usually represent a thermometer of conflict problems. Finally, the approach will be validated in a work environment. [Expected results] An approach that supports the conflict assessment and management in software teams. [Conclusions] The proposed approach aims to help track a team's functioning during the software development life cycle, supporting team managers in a new way to guide the team appropriately.", "url": "artigos/artigos_WER22/wer202227.html"}, {"title": "rTiWIM: Uma Ferramenta para Elicitação e Validação de Requisitos de Software Utilizando Linguagem de Interface", "authors": ["João Victor R. Araújo", "Carla Bezerra", "Andréia Libório Sampaio"], "year": 2022, "keywords": "Elicitação de Requisitos; Validação de Requisitos; Linguagem de Interface", "abstract": "O processo de levantamento de requisitos é uma das etapas fundamentais no ciclo de vida de um produto de software. No contexto de desenvolvimento de software, há cada vez mais a necessidade de ferramentas que apoiem os stakeholders no processo de elicitação e validaçãoção dos requisitos do sistema. A participação do usuário final nesse processo consolida a comunicação entre as partes interessadas para novas descobertas e problem´aticas que o sistema possa apresentar. Dessa forma, este artigo propõe uma ferramenta de apoio aos stakeholders do sistema, denominada rTiWIM, que utilizará o modelo de comunicação TiWIM para elicitar e validar requisitos de software em sistemas web através da linguagem de interface. A ferramenta irá dispor das seguintes funcionalidades: (i) cadastro de usuários, (ii) validação de páginas, (iii) cadastro de páginas para validação e (iv) verificação das validações realizadas por usuários finais. Para validar a ferramenta, foi realizado um grupo focal com desenvolvedores e profissionais da área. Com base nos argumentos dos grupos, foi possível identificar melhorias e fortalecer a importância desta ferramenta dentro deste cenário.", "url": "artigos/artigos_WER22/wer202228.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2023)", "authors": ["Leandro Antonelli", "Marcia Lucena", "Roxana L.Q. Portugal"], "year": 2023, "keywords": "wer; Requirements Engineering", "abstract": "The twenty-sixth edition of the Requirements Engineering Workshop, held at PUC-RS in Porto Alegre, Brazil from August 15th to 17th, 2023, fostered vibrant discussions bridging academia and industry. Over three days, participants explored multifaceted topics including Usability, Transparency, Data Protection, Smart Cities, Safety Requirements, Modeling, and Knowledge Management Requirements. With 26 submissions and rigorous reviews, 11 full papers and 6 short papers were accepted. The event paid tribute to Professor Luiz Márcio Cysneiros and featured keynotes by Professors Ricardo Gaucitua and Juliana Saraiva. Engaging panel discussions centered on industry-academia synergy illuminated shared challenges and the potential for collaborative initiatives. Notably, a dedicated industry track was introduced, and Luciane Forte from Globo presented insights into Big Brother Brazil's voting platform requirements. The workshop's success was a result of international collaboration, paper contributors, organizers, and engaged participants, all committed to advancing the realm of Requirements Engineering.", "url": "artigos/artigos_WER23/wer202300.html"}, {"title": "Análise de conformidade da LGPD nas Instituições Públicas de Ensino Superior no Brasil sob a perspectiva dos profissionais de TIC", "authors": ["Keyla Silva", "Laura Sarkis"], "year": 2023, "keywords": "LGPD; Privacy Requirements; Requirements Engineering", "abstract": "Security techniques in software development need to be widespread, mainly because of their positive impact on risk mitigation. In August 2018, the General Law of Data Protection (LGPD) was sanctioned, which defines what is, or is not legal in data handling and guarantees individual rights. Several studies have sought to understand the LGPD compliance landscape. In addition, the research in this study aims to investigate the compliance of LGPD implementation in public higher education institutions in Brazil. Thus, it sought to identify whether ICT professionals perform the specification of privacy requirements, in addition to identifying the level of knowledge and compliance with the legislation from the perspective of these professionals. The survey presents the view of ICT professionals from 19 public institutions of higher education distributed in the five regions of Brazil. The results show that 70.6% of the organizations have somehow started to adapt to the LGPD; more than 70% said that their organization controls sensitive personal data; 20.6% of interviewed claimed to make use of the privacy approach in requirements specifications. Of these, nearly half only make in the end of the software development phase; more than 67% consider that there were impacts on software development; and 50% state that in the institutions there is no training on data security and that it is necessary to address this change of culture and have the support of senior management for the execution of action to adapt to the LGPD.", "url": "artigos/artigos_WER23/wer202301.html"}, {"title": "Avaliação de Conhecimento em Engenharia de Requisitos no Startup Gov.br", "authors": ["Ricardo Cordeiro Galvão SantAna van Erven", "Pollyanna C. O. Dias", "Demétrius de Almeida Jubé", "George Marsicano Corrêa", "Edna Dias Canedo"], "year": 2023, "keywords": "Engenharia de Requisitos; Startups de Governo; IMI; Transformação Digital", "abstract": "Em 2021, o Governo brasileiro deu início ao Programa Startup Gov.br, o qual possui como objetivos apoiar e promover a aceleração de projetos estratégicos que compõem a transformação digital do governo brasileiro. Em 2022, após um ano do Programa, foi realizado um estudo o qual, entre outras coisas, identificou que o conhecimento e práticas de engenharia de requisitos (ER) não estavam bem estabelecidas entre os profissionais membros das StartUps. Dada a importância e potenciais impactos que a ER pode exercer sob o sucesso de projetos, decidiu-se então, aprofundar o estudo sobre a ER nas StartUps. Neste sentido, o presente artigo possui como objetivo descobrir se os profissionais contratados para o Programa Startup Gov.br se sentem motivados e possuem os conhecimentos necessários em engenharia de requisitos. Para tanto, foi utilizado o questionário IMI- Intrinsic Motivation Inventory, assim como realizado um relacionamento entre habilidades e conhecimentos da disciplina de requisitos, presentes no Guia para o Desenvolvimento de Produtos e Soluções (GPS). Este guia foi criado para times digitais no âmbito do governo brasileiro. Além disso, buscou-se mapear o ambiente em que esses profissionais estão alocados e qual a motivação deles em aprender ferramentas e técnicas de Engenharia de Requisitos. Como resultado, apresenta-se um mapa do grau de conhecimento dos participantes do programa em técnicas e ferramentas de engenharia de requisitos. Identifica-se, também, os elementos que compõe a motivação dos participantes, o que foi apresentado com separação por papel de atuação. Para os pesquisadores, o resultado foi satisfatório do ponto de vista estatístico, bem como ajuda a gerar insights para a melhoria da ER no âmbito das startUps do governo brasileiro.", "url": "artigos/artigos_WER23/wer202302.html"}, {"title": "Evolving the USARP method to support usability requirements elicitation and specification", "authors": ["Anna Beatriz Marques", "Maria Victoria Fiori", "Bruna Ferreira"], "year": 2023, "keywords": "Usability requirements; USARP; Case study", "abstract": "USARP (USAbility Requirements with Personas and user stories) is a method for eliciting and specifying usability requirements using personas, user stories, and usability guidelines organized as cards. USARP suggests brainstorming sessions to discuss usability requirements oriented by its cards. We conducted an exploratory study in an academic environment to analyze the use of USARP in projects developed by undergraduate students acting as software engineers. We noted difficulties in selecting cards to use during the USARP adoption. Thus, this study proposes to evolve USARP to provide a more effective way to elicit and specify usability requirements. We reviewed the cards, removing redundant content and combining cards with similar content. Also, we proposed a checklist and a board to guide the selection of the cards according to users and system characteristics. Finally, the process suggested for adopting USARP was updated to reflect the use of the new artifacts. We expect these improvements could guide the customization of the brainstorming sessions to be more effective and efficient.", "url": "artigos/artigos_WER23/wer202303.html"}, {"title": "Improving the Requirement Elicitation Process using Empathy Maps and Personas: A Quasi-Experiment", "authors": ["Ezequiel Kahan", "Emilio Insfrán Pelozo", "Marcela Genero", "Alejandro Oliveros"], "year": 2023, "keywords": "", "abstract": "There is a growing interest in the use of Design Thinking (DT) to enrich re-quirements elicitation processes. This fact motivated us to explore the use of the Brainstorming technique, usually used alone for requirements elicitation, in combination with user-centered and empathy-oriented techniques taken from the DT process. Specifically, we carried out a quasi-experiment to com-pare the Effectiveness of Brainstorming sessions in terms of the number of ideas of requirements generated, and also the Identified Stakeholders, com-plementing the Brainstorming sessions with two of the most widely used DT techniques: Empathy Maps and Personas. Therefore, we consider three treatments: Personas + Brainstorming, Empathy Maps + Brainstorming, and Brainstorming alone (control group). The quasi-experiment was carried out with 74 students enrolled in the Bachelor of Computer Engineering course at the Universitat Politècnica de València in 2021. The results reveal a statisti-cally significant effect on Identified Stakeholders when using Empathy Maps. Descriptive analysis shows also an increase in Identified Stakeholders when using Personas, and in the Effectiveness of Brainstorming sessions when used together with Empathy Maps or Personas. There is also a variation in the type of ideas, with the number of functional ideas being higher, and that of non-functional ideas being lower when Empathy Maps are used. These re-sults seem to indicate that Brainstorming sessions are improved when com-plemented with Empathy Maps or personas techniques. However, we still do not have enough evidence to recommend either Personas or Empathy Maps. Therefore, further experimentations will be needed to obtain more conclu-sive results considering some improvements that are discussed in the paper.", "url": "artigos/artigos_WER23/wer202304.html"}, {"title": "Process of Transforming Requirements Elicited with MindMaps into iStar models", "authors": ["Gustavo Cesar Lopes Geraldino", "Victor Francisco Araya Santander"], "year": 2023, "keywords": "Requirements Engineering; iStar models; MindMaps", "abstract": "It is unlikely that the system will be better than the requirements identified in the design phase. So it is obvious that the quality of the software is closely related to the quality of the development process - from design to programming. The software requirements are a decisive factor for the software quality. The development of a computer system is not a task for a layman. Software development is a complex process composed of activities and steps that follow patterns and models developed by Software Engineering - SE. A requirements engineering - RE, a subfield there SE seeks a translation of customer needs through requirements elicitation. To have a greater chance of success for a successful software project, the activities da RE must not be neglected. This search aims to develop guidelines for building a strategy in the process of transforming requirements elicited using the MindMaps technique into iStar models. For the development of this search, a Systematic Literature Review - SLR was conducted to analyze the frequency of the use of MindMaps in the elicitation process and their transformation into more complex models. As a result of this research, templates and guidelines for the necessary routing for the process of transforming the requirements identified through the MindMaps into iStar models were created. The main contribution of this paper is to propose this routing in the process of converting the elicited requirements (MindMaps) into iStar models.", "url": "artigos/artigos_WER23/wer202305.html"}, {"title": "ReQSI-CI: Um Catálogo de Requisitos Não-Funcionais para Sistemas de Informação em Cidades Inteligentes sob a Perspectiva de Ecossistemas Digitais", "authors": ["Alexandre Barbosa", "Paulo Malcher", "Rodrigo Santos"], "year": 2023, "keywords": "Sistemas de Informação; Cidades Inteligentes; Requisitos Não-Funcionais; Ecossistemas Digitais", "abstract": "Iniciativas de cidades inteligentes (CI) vêm aumentando em todo mundo. Diante desse contexto, os sistemas de informação (SI) são vistos como ferramentas estratégicas para a solução de problemas a partir de uma visão sistêmica sobre pessoas, organizações e tecnologias. No entanto, vários SI têm sido usados para apoiar iniciativas de CI e não há uma diretriz específica ou padrão de requisitos que possa apoiar o desenvolvimento de SI. Este trabalho apresenta um catálogo de requisitos não-funcionais (RNF) de SI em CI sob a perspectiva de ecossistemas digitais (ED), chamado ReQSI-CI. A proposta de catálogo emergiu dos resultados de três estudos: (i) um estudo exploratório que identificou RNF por meio de oportunidades e barreiras na implantação de SI informais no domínio das CI; (ii) um mapeamento sistemático da literatura (MSL) que identificou SI formais, desafios e fatores de sucesso da implantação desses SI, que possibilitaram a identificação de RNF; e (iii) uma pesquisa de opinião que foi realizada com estudantes, pesquisadores e profissionais brasileiros interessados no tema, a fim de analisar as informações dos SI identificados no MSL e identificar novos RNF. Ao final, foi conduzida uma avaliação do catálogo por meio de um grupo focal com especialistas no assunto, resultando em uma nova versão do catálogo ReQSI-CI. Os resultados mostram que a proposta reúne elementos relevantes para CI, com destaque para características de ED. A contribuição deste trabalho é um catálogo com 46 RNF organizados em dimensões e domínios de CI.", "url": "artigos/artigos_WER23/wer202306.html"}, {"title": "Requirements4Safety – Construindo uma técnica para modelagem de Requisitos Iniciais de Segurança", "authors": ["Moniky Ribeiro", "Jaelson Castro", "Ricardo Ramos", "Maria Lencastre", "Abimael Santos"], "year": 2023, "keywords": "Sistemas Críticos de Segurança; iStar4Safety; STPA", "abstract": "Resumo. Os requisitos de segurança de Sistemas Críticos de Segurança de-vem refletir as descobertas da fase de análise de segurança inicial. Portanto, é fundamental um alinhamento entre as práticas da Engenharia de Requisitos Orientada a Objetivos e as da Engenharia de Segurança. Observa-se também o crescente interesse da comunidade de Engenharia de Segurança na adoção da técnica modernas de análise, tais como System-Theoretic Process Analysis- STPA. Este trabalho tem por objetivo apresentar uma proposta de pesquisa de uma nova abordagem para modelagem de requisitos iniciais de segurança chamada Requirements4Safety. Ela possibilitará alinhar os requisitos de segurança modelados na linguagem iStar4Safety, aos elementos correlatos identificados através do uso da técnica de análise de perigos STPA. Portanto, os requisitos de segurança estarão integrados aos elementos identificados durante a fase de análise preliminar de segurança, o que facilitará a certificação de sistemas críticos por órgãos de regulação. Requirements4Safety será aplicada na definição dos requisitos de segurança de alguns sistemas críticos, tais como um bomba de insulina. Entre as formas de avalição da proposta está a condução de surveys, envolvendo especialistas das áreas de requisitos e segurança.", "url": "artigos/artigos_WER23/wer202307.html"}, {"title": "Um Modelo de Conceitos Relacionados à Privacidade de Dados Pessoais", "authors": ["Arthur Vieira", "Mariana Peixoto", "Carla Silva"], "year": 2023, "keywords": "Engenharia de Software; Privacidade; Linguagens de Modelagem; Modelos Conceituais", "abstract": "Muitas informações disponíveis no dia a dia têm sido digitalizadas para tornar o seu acesso mais rápido e fácil. Esses dados muitas vezes apresentam informações pessoais, o que pode acarretar em problemas e preocupações com a privacidade. Porém, para tratar com eficiência esses problemas e preocupações no ambiente de desenvolvimento de software, os engenheiros de software precisam compreender melhor o conceito de privacidade. Dada a relevância do tópico nos últimos anos, especialmente após regulamentações de proteção de dados, o presente trabalho atualiza, por meio de uma Revisão Sistemática de Literatura, uma pesquisa prévia que define conceitos relacionados à privacidade na forma de um modelo conceitual. A atualização do modelo conceitual resulta em uma visão clara e atualizada dos conceitos relacionados à privacidade, tanto para profissionais da indústria como para acadêmicos da área.", "url": "artigos/artigos_WER23/wer202308.html"}, {"title": "Uma abordagem baseada no Catálogo de Requisitos Não Funcionais para conformidade à LGPD", "authors": ["Henrique Prado de Sá Sousa", "Eduardo Kinder Almentero", "Tadeu Moreira de Classe", "Rodrigo Juliao dos Santos", "Julio Cesar Leite"], "year": 2023, "keywords": "LGPD; RNF; Requisitos de Qualidade; Catálogo de Requisitos Não-Funcionais (RNFs); Requisitos legais", "abstract": "A Lei Geral de Proteção de Dados (LGPD) foi criada para garantir que direitos fundamentais, como a privacidade, fossem respeitados por organizações que rea-lizam tratamento de dados. O texto da Lei define uma série de restrições que de-vem ser consideradas por pessoas ou organizações que realizam o tratamento de dados, inclusive nos meios digitais. Quando o tratamento é realizado através de sistemas computacionais, estas restrições têm impacto no software que realiza o tratamento, uma vez que este é o responsável por implementar as ações relaciona-das ao tratamento dos dados. Em outras palavras, o software deve cumprir requi-sitos específicos para implementar as restrições estabelecidas pela Lei. Entretanto, a LGPD é alvo de muitas discussões e há uma série de dúvidas relacionadas a sua implementação. Para auxiliar o entendimento da Lei, e, consequentemente, sua implementação, apresentamos uma análise sob a ótica da engenharia de requisitos, orientado pela construção de catálogos de requisitos não funcionais, que são mencionados de forma recorrente no texto da Lei.", "url": "artigos/artigos_WER23/wer202309.html"}, {"title": "Using Self-assessment for Improving Maturity on Accessibility Requirements in Software Practice at ORG: A Case Study", "authors": ["Renata Vinadé", "Sabrina Marczak", "Daniela Cruzes", "Monica Iovan", "Julie Rasmussen", "Victoria Bondarchuk"], "year": 2023, "keywords": "Agile Software Development; Accessibility Requirements; WCAG Guidelines; Self-Assessment; Case Study", "abstract": "Technology has become ubiquitous, providing us with easy access to information, enhanced social connectivity, and expanded employment opportunities. However, nearly one billion people face significant challenges when using common software applications due to their disabilities. Consequently, it is crucial to prioritize accessibility requirements when developing inclusive software. Adhering to accessibility standards not only fulfills legal obligations but also enables software teams to identify the essential accessibility aspects that should be incorporated into software requirements. Agile teams have implemented various strategies, including self-assessment, to meet accessibility requirements. Nevertheless, there is a limited understanding of how agile software development teams effectively implement accessibility standards and strive to enhance accessibility requirements. This study presents a case study of how ORG software teams use self-assessments to facilitate the implementation of accessibility requirements. We evaluated 23 product self-assessments and it was revealed that some teams demonstrated significant progress in meeting the criteria, while others encountered challenges along the way. Multiple factors contribute to the non-compliance to accessibility standards such as insufficient time, knowledge, guidance, understanding, and resources. To overcome these challenges, planning carefully and considering all aspects is essential. By addressing these critical aspects, software teams can enhance their understanding, skills, and resources, ultimately improving the accessibility of their products and ensuring equal opportunities for all individuals.", "url": "artigos/artigos_WER23/wer202310.html"}, {"title": "Visual-PR: Uma abordagem visual e gamificada para o apoio à Priorização de Requisitos", "authors": ["Luiza Lira", "Maria Lencastre", "Joao Henrique Pimentel", "Jaelson Brelaz Castro", "Mônica Bandeira"], "year": 2023, "keywords": "Priorização; Requisitos; Gamificação; Visualização", "abstract": "This article aims to mitigate some barriers to adopting requirements prioritization, such as the complexity of the activity and the need for more engagement and interaction among its participants. The proposed process, called Visual-PR, integrates visual and gamified models and tools to support PR, ranging from early to late requirements. A case study demonstrated the process's use-fulness in supporting and motivating prioritization", "url": "artigos/artigos_WER23/wer202311.html"}, {"title": "Ambiguity resolution and legal compliance of requirements: an exploratory study in the literature", "authors": ["Dorgival Netto", "Carla Silva"], "year": 2023, "keywords": "Exploratory Study; Requirements Engineering; Legal Compliance; Ambiguity", "abstract": "[Background] Software requirements are usually specified in Natural Language, bringing challenges for Requirements Engineering (RE) as these specifications are inherently ambiguous. These challenges become bigger when dealing with software requirements that must comply with regulations, the so-called legal requirements. [Goal] This work investigates how ambiguity in legal requirements specification is addressed in works selected from the literature. [Method] We followed a snowballing technique with three backward and forward iterations. [Results] We systematically selected 24 papers and classified their proposals in approaches dealing with ambiguous requirements by identifying, reducing or avoiding ambiguity. Moreover, the protocol used to select the papers and the selected papers can be used as starting point to expand this studys results. [Conclusions] Our analysis in the selected papers revealed that a considerable amount of works deal with the identification of ambiguous requirements, in opposition to the number of works concerned in avoiding or reducing them.", "url": "artigos/artigos_WER23/wer202312.html"}, {"title": "An approach to extract a conceptual model from natural language specifications", "authors": ["Leandro Antonelli", "Juliana Delle Ville", "Matias Adorno", "Letizia Ballestero", "Santiago Cecconato", "Alejandro Fernandez", "Gregorio Maclen", "Giuliana Maltempo", "Juliana Mattei", "Luciana Tanevitch", "Diego Torres"], "year": 2023, "keywords": "", "abstract": "Requirements engineering is a critical phase in software development. Errors committed in the requirements, if not found and corrected early in the engineering process, become costly problems later on. Artifacts described in natural language are the most suitable for both parties that participate in the process: experts of the domain and the software development team. Nevertheless, natural language can have some issues because the diversity of participants writing and reading specification. Thus, it is necessary to guide and assist the production of these artifacts. Kernel sentences is a linguistic definition about small sentences (with only one verb) written in active voice. We argue that kernel sentences are adequate to use in the acquisition of knowledge. Then, conceptual model are a good technique to summarize a large and complex specification to provide an overview to the whole group of participants. This paper proposes an approach to acquire specification collaboratively checking the writing style to conform kernel sentences, and synthetizing a conceptual model to summarize the specification to help participants to have an overview of the knowledge gathered in order to provide a consistent and coherent model. The process proposed has two main activities: acquisition of the knowledge checking its style and synthesis of the conceptual model. This paper also describes a prototype that uses natural language processing and artificial intelligence tools to support the process. Finally, the paper shows the result of a preliminary evaluation with promising results about the applicability of the process.", "url": "artigos/artigos_WER23/wer202313.html"}, {"title": "Aplicação de Mineração na Elicitação de Citações em Scholar: o caso do WERpapers", "authors": ["Roxana Portugal", "Lyrene Silva", "Julio Cesar Leite", "Dennis Farfán Lovón", "Daniel Mosqueira Obando"], "year": 2023, "keywords": "Google Scholar; Scopus; H5; Digital Libraries", "abstract": "Este estudo investiga as limitações das métricas reportadas pelo Scopus e do H5 do Google Scholar, que são usadas pelas agências avaliadoras para qualificar eventos científicos como o WER. Por meio de uma mineração de citações em ambas as bases de dados, o estudo identifica inconsistências e imprecisões nessas métricas e discute possíveis maneiras de melhorar a avaliação. As descobertas deste estudo destacam a importância de uma avaliação precisa e justa de eventos científicos e sugerem a necessidade de aprimorar as métricas utilizadas.", "url": "artigos/artigos_WER23/wer202314.html"}, {"title": "Conformidade com a LGPD por meio de requisitos de negócio e requisitos de solução", "authors": ["Diego Menegazzi", "Carla Silva"], "year": 2023, "keywords": "Engenharia de Requisitos; Engenharia de Software; Lei Geral de Proteção de Dados; Proteção de Dados Pessoais", "abstract": "Em agosto de 2018, foi sancionada a Lei Geral de Proteção de Dados (LGPD), que entrou em vigor em setembro de 2020. Segundo a LGPD, as organizações públicas e privadas devem seguir regras para a coleta e o tratamento de informações pessoais, de modo que o não cumprimento dessas obrigações pode acarretar multas que chegam a R\\$ 50 milhões por infração. As organizações públicas e privadas vêm enfrentando dificuldades para conseguir alcançar essa conformidade. Esse problema pode estar associado à interpretação da Lei, muitas vezes ambígua, e pela falta de conhecimento jurídico dos analistas de sistemas. A extração de requisitos e a sua correta interpretação também são passíveis de erros. Esse problema é comum em pequenas e médias empresas que não possuem um setor ou apoio jurídico. Fornecer técnicas e ferramentas para profissionais de Tecnologia da Informação e Comunicação (TIC) que trabalham com privacidade de dados é fundamental para alcançar a conformidade com a LGPD. Assim, propomos um guia de 6 etapas para apoiar os profissionais de TIC nas atividades de conformidade legal por meio de requisitos de negócio e de solução com foco no artigo 6o da LGPD. O guia foi disponibilizado em um website onde há uma seção descrevendo os seus componentes: o modelo de mapeamento de dados, os requisitos de negócio, os requisitos de solução e o catálogo de controles de privacidade. Por fim, o website conta, ainda, com um vídeo de explicação de todos os componentes e as 6 etapas do guia, além de um exemplo ilustrado da aplicação do método.", "url": "artigos/artigos_WER23/wer202315.html"}, {"title": "O Uso de Inspeção para Aumentar a Transparência de Processos", "authors": ["Juliana Conceição", "Julio Leite", "Rita Pitangueira"], "year": 2023, "keywords": "Modelos BPMN; Transparência de Processos; V-V; Inspeção", "abstract": "A modelagem de processos estrutura o conhecimento organizacional de forma a sistematizar esse conhecimento. Descrever processos organizacionais é uma maneira de compartilhar o conhecimento de forma organizada. No entanto, a descrição de processos é uma atividade que precisa ser feita com cuidado, de forma a refletir efetivamente o conhecimento que se deseja compartilhar. Diferentes tipos de organizações têm utilizado a linguagem BPMN como maneira de estruturar seus processos, mas enfrentam diversos problemas para garantir sua qualidade. Uma maneira de garantir qualidade é através da revisão dos modelos. No entanto, apesar da disponibilização de ferramentas que ajudam na parte sintática de modelos BPMN, ainda é necessária uma revisão por humanos, não só pelos aspectos semânticos, mas também pragmáticos. A literatura reconhece a necessidade de estratégias que aumentem a qualidade dos processos, face aos aspectos não sintáticos e entende que o assunto é desafiador. Utilizando a premissa de que a transparência é fundamental para compartilhar com eficácia, o presente artigo trata o desafio de como utilizar a técnica de inspeção com um checklist orientado a transparência. Demonstra-se a estratégia usando um caso real no domínio da justiça.", "url": "artigos/artigos_WER23/wer202316.html"}, {"title": "Revisitando Processos de Construção de Requisitos: Uma Perspectiva de Transparência", "authors": ["Julio Cesar Leite"], "year": 2023, "keywords": "WERpapers; Transparência; Gestão de Processos de Requisitos", "abstract": "É conhecimento comum que problemas na gestão da construção de requisitos deterioram a qualidade do produto final: o software. Sabe-se, também, que quanto mais olhos estiverem atentos ao processo, maiores são as chances de sucesso. A meta do artigo é examinar o nível da transparência na gestão dos processos de requisitos segundo propostas de suas operacionalizações. A base de conhecimento utilizada inclui artigos publicados no WERpapers juntamente com relatos e sugestões encontradas na rede (literatura cinza), e, em particular, em sítios de fornecedores de tecnologia. Os resultados iniciais apontam a falta de cuidado com a qualidade de transparência, indicando que movimentos na direção de aumenta-la, trazem oportunidades de melhoraria para o processo de gerência. O presente trabalho pretende chamar a atenção para o processo gerencial da construção de requisitos, fornecendo uma base inicial para que outros estudos, com outras bases de conhecimento, sejam feitos no sentido de melhor compreendermos o papel da transparência na gestão dos requisitos.", "url": "artigos/artigos_WER23/wer202317.html"}, {"title": "A Requirements Specification Method: An Experience Report in Aerospace", "authors": ["Carlos Renato dos Santos", "Johnny Cardoso Marques"], "year": 2023, "keywords": "Requirements; Technical debt; Requirements Engineering; Standards; Requirements Engineering Tools", "abstract": "Context: Aerospace projects need well-written requirement documents. However, it is challenging to transform an abstract thought that has insufficiently detailed specifications into a requirement. Tracking the evolution of abstract thoughts and writing a requirements document during the product life cycle is complicated without a specific requirement tool; for the most part, the available requirement tools would be expensive. Objective: Apply a methodology in a real aerospace project to overcome the expensive requirements of engineering tools; this study relates a practical experience to creating a methodology to generate and track the requirements using Excel. However, due to the confidential information, some characteristics of the project must be omitted. Method: The method consists of taking the standard 29148 as a reference and using Excel formulas to semi-automate the requirements writing by raising flags to aid the requirements engineer by suggesting possible mistakes. Moreover, the hyperlink function is used to track and combine the requirement ID with the text document related to the requirement. Results: From unstructured requirements writing, where the linguistic construction used violates, for example, the ISO/IEC/IEEE-29148. A requirements document was created to track the aerospace project needs and to respect the characteristics of a well-written requirement. Conclusions: For the most part, this practical approach contributes to the implementation of requirements mentality without expending capital on expensive requirements engineering tools. Furthermore, it reduces technical requirements debt.", "url": "artigos/artigos_WER23/wer202318.html"}, {"title": "Graphical DSL Devoted to Ease the Application of Model-Driven Engineering in Petrochemical Industry Automation", "authors": ["Fábio Basso", "Jaqueline de Souza Moura", "Carlos Eduardo Xavier Correia", "Karina Casola", "Leandro Buss Becker"], "year": 2023, "keywords": "Petrochemical Industry; MDE; DSL; Components Library; Graphical Representation; Eclipse", "abstract": "Software design for the petrochemical automation industry should follow the best available practices, so that a high-level of quality is achieved, together with modern practices that cope with reusability and automatic models transformation. In a previous work, it was developed the M4PIA infrastructure, which allows using Model-Driven Engineering (MDE) to support the pre-configuration of petrochemical industrial plants. Initially, the adopted models were represented only in an EMF hierarchical tree. However, an evaluative study showed that understanding such models is very hard from the perspective of the stakeholders, resulting in significant losses in the process. With this motivation, a graphical Domain Specific Language (DSL) was developed aiming to increase M4PIA's models readability. It was also developed a diagram modeling tool and a component library in the Eclipse platform. To evaluate the semantic transparency of the elements proposed in our DSL, a quasi-experiment with domain experts was conducted. Precision between 75%-100%, F-measure between 86%-100% and recall between 88%-100% were obtained for each element.", "url": "artigos/artigos_WER23/wer202319.html"}, {"title": "Identifying Knowledge Gaps in Requirements Engineering: An Empirical Study with Professionals in the Brazilian Software Industry", "authors": ["João Epifânio", "Erica Esteves", "Marcia Lucena", "Gabriela Trindade"], "year": 2023, "keywords": "Requirements Documentation; Knowledge Gaps; Requirements Engineering; Industry", "abstract": "The rapid evolution of information technology in the software industry has led to challenges in Requirements Engineering, impacting the academic landscape. Recent studies identify risks to system quality and project success due to industry-specific processes. Professionals trained in academia face a disparity between market practices and academic teachings, resulting in significant knowledge gaps. To address this, a study engaged requirements engineers from Brazilian software development companies. Their experiences were gathered through a survey, focusing on requirements documentation problems and the challenges newcomers face. The study also identified specific knowledge areas that require reinforcement. The findings underscore the need to address significant knowledge gaps. It was concluded that industry practices in requirements engineering differ from documented literature, affecting professional training. Additionally, there is a demand for greater transparency within the industry, and professionals expressed a strong interest in bridging the gap and improving the current situation.", "url": "artigos/artigos_WER23/wer202320.html"}, {"title": "Um Modelo Híbrido de Gestão de Requisitos para Desenvolvimento e Aquisição de Softwares na Indústria Farmacêutica", "authors": ["Davi De França Carneiro", "Nelson Gutemberg Rocha Da Silva", "Iago Interaminense Gomes", "Mauricio Barros Ottoni"], "year": 2023, "keywords": "Engenharia de Requisitos; ERU; BPF; Scrum", "abstract": "As indústrias farmacêuticas estão sujeitas a regulamentações que pre-zam pelas boas práticas de fabricação (BPF). Nesse contexto, a área de tecnologia da informação deve viabilizar softwares capazes de atender às necessidades in-dustriais seguindo as diretrizes técnicas preconizadas pela engenharia de software e pela ANVISA (Agência Nacional de Vigilância Sanitária). O objetivo deste trabalho é, portanto, propor um modelo híbrido de gestão de requisitos, apli-cando-se o framework Scrum para gestão ágil de projetos, no processo de desen-volvimento e aquisição de softwares para a indústria farmacêutica, fundindo eta-pas da engenharia de requisitos  como elicitação, análise e negociação, docu-mentação, verificação e validação de requisitos  com a conformidade regulatória proposta na fase de conceito do ciclo de vida dos sistemas computadorizados da ANVISA, a fim de atender às boas práticas de fabricação. Diante desse cenário, a área de garantia da qualidade farmacêutica realiza qualificações que validam a conformidade do software com BPF, a partir da especificação dos requisitos do usuário (ERU). Por fim, um estudo de caso compara os resultados antes e após a aplicação do modelo proposto neste trabalho.", "url": "artigos/artigos_WER23/wer202321.html"}, {"title": "Verificação textual de requisitos legais no processo de aquisição de TIC: um estudo na administração pública federal", "authors": ["Raimundo Fagner Costa", "Carla Silva", "Rafael Mello"], "year": 2023, "keywords": "Conformidade legal; Aquisição de TIC; Processamento de Linguagem Natural", "abstract": "Existe uma legislação que norteia e regulamenta o processo de Aquisição de TIC na administração pública federal. Mesmo assim, ainda é comum a presença de inconformidades legais nos artefatos manipulados nesse processo. Esta pesquisa visa promover a verificação da conformidade legal dos itens informados nos documentos produzidos no processo de Aquisição TIC. Para este fim, foi necessário atualizar para a legislação atual um modelo de rastreabilidade proposto previamente e selecionar técnicas de Processamento de Linguagem Natural adequadas para calcular a similaridade textual entre os itens informados nos documentos e o que é requerido pela legislação. Assim, foi possível identificar inconformidades na documentação gerada no processo de Aquisição de TIC. A abordagem proposta foi implementada em uma ferramenta como prova de conceito e avaliada por dez potenciais stakeholders de diferentes instituições. A avaliação demonstrou os potenciais benefícios em automatizar a verificação da conformidade legal de documentos gerados no processo de Aquisição TIC._x000D_ _x000D_", "url": "artigos/artigos_WER23/wer202322.html"}, {"title": "Elaboração e avaliação de um Catálogo de Requisitos Não-Funcionais Críticos em um Contexto de Domínio de Aplicação de Diplomas Digitais", "authors": ["Vitor Luiz Caldeira Gilnek", "Victor A. Santander"], "year": 2023, "keywords": "Software Engineering; Non-Functional Requirements; NFR Framework; Requirements Engineering; Digital Security; Digital Diploma", "abstract": "Nos últimos anos, o Ministério da Educação do Brasil instituiu a implementação do Diploma Digital nas instituições de educação superior (IES), com o intuito de modernizar o processo de documentações acadêmicas e proporocionar maior segurança para registro e emissão de diplomas, evitando fraudes. Ao se tratar deste tipo de projeto de software, há a preocupação em definir, implementar e gerenciar requisitos não funcionais (RNFs) críticos para garantir a segurança e validade dos Diplomas Digitais, de acordo com as leis e padrões estabelecidos. O levantamento de um catálogo de RNFs críticos seria útil para auxiliar universidades interessadas a desenvolver seu próprio sistema, além de fornecer orientação para o desenvolvimento do software da UNIOESTE, reduzindo custos para as partes envolvidas. O objetivo principal desta pesquisa é elaborar e avaliar um catálogo de requisitos não funcionais críticos para o domínio do Diploma Digital, utilizando o NFR Framework.", "url": "artigos/artigos_WER23/wer202323.html"}, {"title": "Uma proposta de padrões de sintaxe de requisitos no idioma português", "authors": ["Rebeca Camurça Cunha", "Christopher Shneider Cerqueira"], "year": 2023, "keywords": "Padrões de Sintaxe; Modelos de Requisitos; Engenharia de Requisitos; MBSE", "abstract": "Requisitos permeiam todo o ciclo de vida de um sistema, desde a etapa de identificação das necessidades das partes interessadas, incluindo as atividades de verificação e validação, bem como operação, suporte, até o descarte. Para tal, deve-se observar o processo pelo qual estes requisitos são estabelecidos, isto é, as disciplinas que compõem a Engenharia de Requisitos, a fim de garantir que os requisitos sejam completos, coerentes e corretos, seja a declaração de requisito per se ou o documento contendo o conjunto de requisitos. Entretanto, observando práticas realizadas durante o desenvolvimento de um sistema, tem-se que programas problemáticos tendem a apresentar requisitos incertos, irrealistas ou instáveis. A organização de requisitos em uma estrutura adequada pode auxiliar nestes aspectos, além da redução da quantidade de requisitos, detecção de duplicidades e omissões, dentre outros. Este trabalho, portanto, pro-põe a utilização de padrões de sintaxe de requisitos em português, dentro do contexto da ferramenta de MBSE Capella, a fim de auxiliar no desenvolvimento de requisitos em diferentes níveis hierárquicos, tais como requisitos de usuário, e requisitos de sistema. Desta forma, serão identificados em literaturas consagradas de requisitos, atributos e características considerados necessários para atingir requisitos de qualidade, além de entender os requisitos-modelos em inglês propostos e assim viabilizar uma proposição de padrão de sintaxe em português contemplando tais considerações. Como resultado deste trabalho, identifica-se como oportuno a ampla divulgação do conhecimento na área de engenharia de requisitos na comunidade brasileira e a mitigação de problemas envolvendo requisitos de baixa qualidade, principalmente no que tange a questões de idioma.", "url": "artigos/artigos_WER23/wer202324.html"}, {"title": "Uso do Design Thinking na Elicitação de Requisitos em Ambientes de Trabalho Remoto e Distribuído", "authors": ["Márcia Hortência Fonseca Ribeiro Nardes Maciel", "Alexandre Lazaretti Zanatta"], "year": 2023, "keywords": "Elicitação; Requisitos; Software; Design Thinking", "abstract": "A técnica do Design Thinking pode ser utilizada para elicitação de requisitos, por meio de procedimentos sistematizados e bem estabelecidos. Empresas que necessitavam eliciar requisitos de clientes presencialmente, foram impedidas devido a políticas de distanciamento social com advento da pandemia do COVID-19. Neste trabalho, aplicou-se o Design Thinking tanto remoto quanto distribuído perpassando pelas três fases: Imersão, Ideação e Prototipação. Realizou-se um estudo de caso, durante 74 dias, com um grupo de sujeitos para elicitar requisitos para uma possível solução de um software web. Os resultados indicaram que, apesar de alguns integrantes jamais terem vivenciado atividades remotas e distribuídas, a experiência foi positiva. Um fator decisivo para a compreensão dos sujeitos foi a interação com o cliente, principalmente na fase da Imersão._x000D_", "url": "artigos/artigos_WER23/wer202325.html"}, {"title": "Preface: Proceedings of the Workshop on Requirements Engineering (WER2024)", "authors": ["Marcia Lucena", "Maria Lencastre", "Luciana Ballejos"], "year": 2024, "keywords": "wer; Requirements Engineering", "abstract": "The twenty-seventh edition of the Workshop on Requirements Engineering (WER 2024), hosted at Universidad de Belgrano in Buenos Aires, Argentina, from August 7th to 9th, 2024, brought together researchers and practitioners from across academia and industry. Over three vibrant days, discussions spanned key themes such as usability, transparency, data protection, natural language processing, sustainability, accessibility, technical debt, and security requirements. This year, 32 articles were presented as full papers. Following a thorough review by at least three committee members per submission. The event featured seven tracks: Research, Industry, Master's and Doctoral, Software Requirements Tools, Journal First, Tutorials, and a new Student Poster Track. Distinguished keynote speakers included Fabiano Dalplaz from Utrecht University, Alejandro Oliveros from the National University of Tres de Febrero, and Jorge Ceballos from the University of Belgrano, each offering unique insights into cutting-edge challenges in Requirements Engineering. Two hands-on tutorials were also delivered, covering Natural Language Processing and Design Thinking approaches to requirements elicitation. A strong industry presence was felt through dedicated sessions addressing real-world challenges, including AI in newsrooms and data privacy. WER 2024’s success was made possible by the commitment of a diverse international committee, contributing authors, track chairs, tutorial leaders, and enthusiastic participants. Special recognition goes to the organizing institutions — Universidad Nacional del Oeste, Universidad Abierta Interamericana, Universidad Nacional de La Plata, and Universidad de Belgrano — for their unwavering support and coordination.", "url": "artigos/artigos_WER24/wer202400.html"}, {"title": "A Canvas Metamodel to Bridging Agile Project Planning and Requirements Engineering", "authors": ["Ernesto F. Veiga", "Taciana N. Kudo", "Renato F. Bulcão-Neto"], "year": 2024, "keywords": "Canvas; Metamodel; Agile; Planning; Requirements elicitation; Reuse; Safety-critical; IoT", "abstract": "This paper addresses the lack of methodological support for canvas model construction, focusing on the link between project planning and the Requirements Engineering process. To tackle this problem, we present MM4Canvas, a metamodel that provides a solid foundation for creating canvas models, facilitating structuring, standardization, and promoting the reuse of models in different projects. We conducted a proof of concept by applying the MM4Canvas metamodel to instantiate a general-purpose canvas model for projects, which, in turn, was extended to address the domain of IoT-critical systems with safety and security requirements. The goal is to demonstrate the reuse and extensibility properties promoted by the MM4Canvas metamodel and its instances.", "url": "artigos/artigos_WER24/wer202401.html"}, {"title": "Alineación de glosarios específicos de dominio", "authors": ["Paola Grijalva-Arriaga", "Galo Cornejo-Gómez", "Leandro Antonelli", "Pablo Thomas"], "year": 2024, "keywords": "Alineación de Dominios. Requerimientos. Léxico Extendido del Lenguaje", "abstract": "Los glosarios son una parte importante de cualquier documento de requerimientos de software, ya que hace explícitos los términos técnicos en un dominio y proporciona definiciones, ayudando a mitigar la imprecisión y la ambigüedad. El Léxico Extendido del Lenguaje (LEL) es un glosario que describe el vocabulario del dominio caracterizando a cada expresión a través de dos atributos (a diferencia de un glosario tradicional que tiene una sola descripción). En la actualidad, es muy común la interoperación de los sistemas informáticos, en donde cierto sistema brinda servicios para que consuman otros sistemas. En este marco, es crucial comprender el lenguaje de ambos sistemas, para que la interacción sea efectiva. Este artículo propone un método de alineación de glosarios LEL del dominio. El método de alineación propuesto se basa en identificación de discrepancias y similitudes, para luego acordar el significado de los términos similares. Este articulo presenta una evaluación preliminar con resultados promisorios utilizando como caso de estudio un modelo de calidad para instituciones de educación superior.", "url": "artigos/artigos_WER24/wer202402.html"}, {"title": "An approach for Reverse Engineering from Web Applications into the Language of the Domain using the LEL Glossary", "authors": ["Angela Verónica Granizo Rodríguez", "Leandro Antonelli", "Sergio Firmenich", "Diego Firmenich"], "year": 2024, "keywords": "Reverse engineering; Software web applications; Domain language; LEL; Software requirements; Application domain; Software application", "abstract": "Requirement engineering plays a crucial role in the software lifecycle, since errors made in the requirements require significant effort to be corrected in later stages. The main source of requirements is people; however, it is common to analyze existing applications when developing new software. This is particularly the case in the process of reengineering. On the other hand, the language of the domain is essential to understanding the domain and thus comprehending the requirements. Language Extended Lexicon (LEL) is a structured glossary designed to capture this language. This paper proposes an approach for obtaining the language of an application domain from a web application using the LEL glossary. The process comprises three main activities: general analysis of the web application, domain language capture, and the verification of the generated domain language. Additionally, this paper describes a web browser extension tool designed to support the process. Finally, the paper presents the results of a preliminary evaluation with promising outcomes regarding the applicability of the approach.", "url": "artigos/artigos_WER24/wer202403.html"}, {"title": "Analyze of Verbs in Requirements with Natural Language Processing to Enhance Comprehension", "authors": ["Carlos Renato dos Santos", "Johnny Cardoso Marques"], "year": 2024, "keywords": "Requirements; Natural Language Processing; IEEE29148", "abstract": "Purpose: There can be some ambiguity when describing requirements using natural language. One of the critical parts of the requirement syntax is using verbs to express the action of the requirement. Therefore, it is essential to explore how verbs can be used in requirements to convey their intended meaning accurately. Problem: This study aims to investigate the action entity of ISO/IEC/IEEE-29148:2018 requirement syntax and establish a connection between the verbs used to express requirements. Methods: Using Spacy, a natural language processing library, to analyze 955 aerospace requirements from 2017-2022. Verbs are extracted and compared to the ISO/IEC/IEEE-29148:2018 action part of the requirement syntax. Results: The verbs used in a requirement express the desired action. In the requirements studied, it was observed that a particular verb was used more frequently than others. However, it is essential not to overuse a single verb to avoid confusion and ensure a better understanding of the requirement. Choosing the correct verb to describe the requirement can avoid misunderstandings in interpretation. Conclusion: This research aims to provide insight into the usage of verbs in requirements. However, additional research is necessary to determine how the verb functions with other grammatical elements within the requirements.", "url": "artigos/artigos_WER24/wer202404.html"}, {"title": "Avaliação de Acessibilidade em Aplicações Móveis: Uma Revisão Sistemática da Literatura", "authors": ["Gabriel Girardi da Costa", "Vitor Luiz Caldeira Gilnek", "Victor Francisco Araya Santander", "Marcos Alexandre dos Anjos"], "year": 2024, "keywords": "Validação; Aplicações móveis; Acessibilidade; Revisão Sistemática", "abstract": "Com a tecnologia em constante avanço, aplicações móveis tornaram-se parte do dia a dia das pessoas. Em razão da proliferação destas, é essencial que tais aplicativos garantam acesso equitativo a todos os usuários, evitando criar barreiras para aqueles com necessidades especiais. Torna-se necessário, portanto, que seja possível avaliar a acessibilidade de aplicações móveis. Este trabalho apresenta uma revisão sistemática da literatura na qual foram selecionadas e analisadas 49 fontes publicadas nos últimos 15 anos, com o intuito de identificar métodos, técnicas e ferramentas de avaliação de acessibilidade. Os resultados destacaram os métodos de avaliação com usuários e avaliação com ferramentas de testes automatizados. Além disso, o trabalho explora conceitos fundamentais sobre acessibilidade apontados nos trabalhos selecionados à luz das definições expressas no World Wide Web Consortium (W3C). A pesquisa também tem como fim, alertar desenvolvedores, pesquisadores e profissionais sobre a importância da acessibilidade em aplicativos móveis, incentivando a criação de aplicativos mais inclusivos e acessíveis.", "url": "artigos/artigos_WER24/wer202405.html"}, {"title": "Catálogo de Requisitos de Sustentabilidade: Um Estudo Preliminar", "authors": ["Abimael Santos", "Quelita Ribeiro", "Jaelson Castro", "Maria Lencastre"], "year": 2024, "keywords": "Sustentabilidade; Software; Engenharia de Requisitos", "abstract": "Contexto: Como engenheiros de software é essencial alinharmos os sistemas desenvolvidos na academia e na indústria às diretrizes de sustentabilidade e garantir a construção de softwares sustentáveis que tratem os potenciais efeitos a longo prazo ao invés do retorno imediato. Objetivos: Esse estudo tem como objetivo propor um catálogo de requisitos de sustentabilidade preliminar, chamado NFR4SUSTAIN, que aborda as dimensões de sustentabilidade econômica, social e técnica. Métodos: Para elaboração do estudo foi empregado um método de pesquisa de engenharia, no qual analisou-se soluções existentes na literatura e de forma exaustiva foi proposto melhorias e refinamentos até não ser mais possível encontrar novos insights. As etapas incluíram Levantamento de Informações, Desenvolvimento do Catálogo e a sua Avaliação. Resultados: Este catálogo ajudará os desenvolvedores de sistemas a incorporarem NFRs relacionados à sustentabilidade em seus projetos, bem como possibilitará que stakeholders selecionem sistemas adequados com base em requisitos de sustentabilidade.", "url": "artigos/artigos_WER24/wer202406.html"}, {"title": "Definición De Una Gramática Para El Léxico Extendido Del Lenguaje", "authors": ["Pablo Roldán Valdiviezo", "Leandro Antonelli"], "year": 2024, "keywords": "LEL; Requirements engineering; Grammar; EBNF", "abstract": "En la ingeniería de requerimientos es importante comprender el lenguaje del dominio de la aplicación, puesto que escribir requerimientos sin los términos adecuados puede llevar a confusiones. El Léxico Extendido del Lenguaje (LEL) es un lenguaje de representación que permite capturar dicho vocabulario. Sin embargo, la elaboración de un LEL enfrenta desafíos, para quienes son nuevos en el uso de este concepto. Dado que el lenguaje natural es por sí ambiguo y, además, el LEL puede usarse de diferentes maneras, los usuarios pueden utilizar distintos estilos de redacción que pueden afectar la comprensión del lenguaje. En este contexto, este artículo propone una gramática EBNF (Gramática Extendida de Backus-Naur), para ayudar a estandarizar la redacción del LEL. Esta gramática tiene por objetivo tratar la homonimia, sinonimia, jerarquías, tiempos verbales, frases nominales, atomicidad y conexiones claras entre distintos tipos de símbolos. La gramática EBNF propuesta se ajusta a los principios de circularidad y vocabulario mínimo. Finalmente, el artículo describe los resultados de una evaluación preliminar que muestra la aplicabilidad de la propuesta. Los participantes hallaron la gramática clara y directa, lo que sugiere su potencial como guía para quienes se inician en su uso.", "url": "artigos/artigos_WER24/wer202407.html"}, {"title": "Desenvolvimento Ágil e Documentação de Requisitos Rumo a Práticas Mais Efetivas: Uma Revisão Sistemática", "authors": ["Luana Souza", "Tiago Brito", "Marcia Lucena", "Apuena Gomes"], "year": 2024, "keywords": "Documentação de requisitos; Documentação ágil; Equipes ágeis; Metodologias Ágeis", "abstract": "A metodologia de desenvolvimento ágil - que tem sido adotada por muitas equipes - está conduzindo a uma transformação na forma de se trabalhar com os requisitos. Apesar do crescente interesse de diversos times na adoção das metodologias ágeis, pouco se discute na literatura como os documentos de requisitos devem ser trabalhados nesta metodologia, deixando essa decisão a cargo dos profissionais. Este artigo apresenta uma revisão sistemática com o objetivo de investigar as formas mais utilizadas para documentar requisitos em ambientes ágeis de desenvolvimento. Esta revisão buscou responder questões de pesquisas como: (i) Quais formas de documentar os requisitos estão sendo utilizadas pelas equipes que trabalham com metodologias ágeis; (ii) Quais os benefícios e limitações das principais formas de documentação de requisitos. A partir deste artigo será possível ter uma visão do estado atual do conhecimento para documentar os requisitos na metodologia ágil, como também identificar as principais formas de avaliar a eficácia desses documentos de requisitos.", "url": "artigos/artigos_WER24/wer202408.html"}, {"title": "Documentation Artifacts For Conversation-Related Requirements Specification in Chatbots", "authors": ["Larissa Pereira Gonçalves", "Geovana Ramos Sousa Silva", "Edna Dias Canedo"], "year": 2024, "keywords": "Chatbots conversational agents; specification conversational requirements; conversational integrated map", "abstract": "Context: Chatbots are complex applications due to their capacity to engage and maintain a conversation with humans. However, the conversational-related requirements of chatbots are hard to elicit, document, and test. Another challenge is the documentation since there are not so many directions on how to register and test subjective requirements. Methods: We followed systematic literature review (SLR) guidelines and identified 42 relevant papers that address the artifacts used by practitioners to document conversational-related requirements in literature. We also investigated what conversational requirements are addressed in requirements documentation. Results: The main results indicate that UML diagrams, prototypes, tables of requirements, conversational flows, and scenarios are present in most chatbot documentation. Except for UML diagrams, those artifacts are used to document standard requirements or conversational requirements. In those artifacts, context-dependent behavior, assertivity, error handling, and human-like attitude are the most approached conversational requirements in the studies. In sequence, based on our findings, we propose the conversational integrated map, a meta-model solution as documentation of conversational requirements.", "url": "artigos/artigos_WER24/wer202409.html"}, {"title": "Evaluación de modelos de procesamiento de lenguaje natural para medir similaridad entre escenarios escritos en español", "authors": ["Gabriela Pérez", "Catalina Mostaccio", "Leandro Antonelli"], "year": 2024, "keywords": "Ingeniería de Requerimientos; Escenarios; BERT; Similaridad Semántica; NLP; Sentence BERT", "abstract": "La ingeniería de requerimientos es una fase crítica en el desarrollo de software; busca comprender y documentar los requisitos del sistema desde etapas tempranas. Con frecuencia, la especificación de requerimientos es realizada de forma conjunta entre clientes y el equipo de desarrollo. Los clientes aportan conocimientos profundos en el lenguaje del dominio, mientras que los equipos de desarrollo utilizan términos más informáticos. A pesar de esto, la comprensión mutua es esencial. Uno de los artefactos más utilizados para este propósito son los escenarios. En entornos donde múltiples actores escriben escenarios, es común la duplicación. Es necesario contar con algún mecanismo que posibilite la detección de escenarios similares para evitar tal duplicación. En este trabajo se evalúan empíricamente varios modelos pre-entrenados de Procesamiento de Lenguaje Natural para analizar la similitud semántica entre escenarios en español, identificando palabras o expresiones con significados similares. Es importante destacar que el análisis se realiza en este lenguaje para brindar una contribución a la región. Finalmente, se presenta una herramienta que simplifica la creación de nuevos escenarios, mostrando la eventual existencia de similares. Permite operar con varios modelos y ofrece la posibilidad de seleccionar entre ellos para determinar de forma más precisa si existen escenarios similares al que se está definiendo.", "url": "artigos/artigos_WER24/wer202410.html"}, {"title": "Investigando o Processo de Documentação de Requisitos em Sistemas Enterprise Resource Planning (ERP)", "authors": ["Marco Antonio Damo", "Victor Francisco Araya Santander"], "year": 2024, "keywords": "Processo de documentação; Enterprise resource planning; Engenharia de requisitos", "abstract": "A engenharia de requisitos é essencial para a compreensão das responsabilidades de um sistema em desenvolvimento, especialmente quando se trata de Enterprise Resource Planning (ERP). Os ERP são sistemas integrados gerenciadores de recursos, processos e informações de uma organização em toda a sua extensão. Abrange as áreas de finanças, contabilidade, recursos humanos, produção, vendas e distribuição. Ao implementar um ERP, deve-se conhecer as necessidades específicas da organização e seus departamentos, os requisitos funcionais e não funcionais do sistema. Isso inclui a compreensão detalhada dos processos de negócios existentes, das políticas da empresa, das regulamentações aplicáveis e das expectativas dos usuários finais. O presente trabalho, por meio de uma revisão sistemática de literatura (RSL), busca identificar técnicas, práticas e desafios associados à documentação de requisitos para sistemas ERP. Questões de pesquisa são definidas, junto com demais elementos do planejamento da RSL. Em seguida, apresenta-se a execução da RSL concluindo com uma análise dos artigos selecionados.", "url": "artigos/artigos_WER24/wer202411.html"}, {"title": "Modelagem Conceitual de Dívida Técnica na Engenharia de Requisitos", "authors": ["José F. Guilhermino da Silva", "Maria Lencastre", "Jaelson Castro"], "year": 2024, "keywords": "Dívida técnica. Requisitos. Modelo conceitual", "abstract": "Contexto: Dívida técnica (DT) surge de vários fatores, como processos, decisões, ações, ou sua ausência, e pode ocorrer de forma intencional ou não intencional. Incorrer em DT pode proporcionar benefícios de curto prazo, como acelerar a entrega de produtos de software; no entanto, não gerenciar a DT pode levar a problemas financeiros e técnicos; também pode criar situações críticas que comprometam o futuro do software. Dívida Técnica em Requisitos (DTR) é um tipo de DT. Problema: Apesar da vasta literatura disponível, o conceito de DTR ainda precisa ser melhor compreendido. Objetivo: Nosso objetivo é melhorar a compreensão, disseminação e aplicação de DTR na academia e na indústria. Método: Desenvolvimento de um Modelo Conceitual para DTR baseado em pesquisa bibliográfica e modelos existentes. Resultados: O modelo proposto facilita a discussão e análise de DTR e ajuda a disseminar e aplicar seus conceitos e gestão do seu processo.", "url": "artigos/artigos_WER24/wer202412.html"}, {"title": "Modelos Visuales durante la Adquisición de Conocimiento: Un Mapeo Sistemático de la Literatura", "authors": ["Alberto Sebastián", "Graciela D.S. Hadad", "Leandro Antonelli", "Carlos Neil"], "year": 2024, "keywords": "Adquisición de conocimiento; Facilitación Gráfica; Mapas Conceptuales; Mapas Mentales", "abstract": "Existen dificultades en la comprensión del contexto de la aplicación por parte de los ingenieros de requisitos, así como también en la comunicación entre las partes durante la etapa de adquisición de conocimiento en el proceso de Ingeniería de Requisitos. Por lo cual, la calidad de los modelos derivados se ve afectada. Se propone entonces conocer la utilidad potencial de diversos modelos visuales como mapas mentales, mapas conceptuales y diagramas de facilitación gráfica según trabajos publicados vinculados a la adquisición de conocimiento, con aportes disciplinares de la Ingeniería de Requisitos, la Gestión del Conocimiento, la Educación y el Desarrollo Organizacional, mediante la técnica de un mapeo sistemático de la literatura. Existen trabajos previos relativos a estos modelos en la Ingeniería de Requisitos, pero se encuentran fuertemente vinculados a las herramientas y técnicas para su construcción, siendo la mayor cantidad de artículos publicados en los años 2014 y 2017. Como resultado, se ha obtenido que la disciplina de mayor aporte corresponde a la Ingeniería de Requisitos, a través del modelo visual mapa mental, mientras que no se ha detectado el uso de diagramas de facilitación gráfica. Por otro lado, el modelo de mapa conceptual tiene su máxima utilización en las disciplinas de Educación y Gestión del Conocimiento, con una menor utilización en la Ingeniería de Requisitos", "url": "artigos/artigos_WER24/wer202413.html"}, {"title": "Multi-Word Entity Extraction And Rich Relationship Identification To Derive Conceptual Models From Natural Language Specifications", "authors": ["Giuliana Maltempo", "Juliana Delle Ville", "Santiago Cecconato", "Federico Pellegrino", "Damiano Distante", "Leandro Antonelli"], "year": 2024, "keywords": "Requirements specification; Kernel sentences; Conceptual model; Natural language", "abstract": "Requirements engineering is a critical phase in software development. Errors in requirements specifications may become costly problems later on; therefore, such errors should be found and corrected early in the engineering process. Describing requirements in natural language is propitious for both the domain experts and the software development team. However, natural language may give rise to diverse interpretations as a consequence of the different backgrounds of the two participants involved. It is therefore necessary to provide guidance on the specification of unambiguous requirements. In previous work, we have advanced the notion of kernel sentences as an appropriate structure for the specification of knowledge. We have also discussed conceptual models as a useful technique to summarize specifications so that all participants have a concise overview of the domain. To achieve consistent and coherent specifications, we presented a two-step method: first compliance with kernel format is checked, and then a conceptual model is derived to summarize the knowledge gathered. This paper extends the conceptual model previously derived from kernel sentences by identifying multi-word entities and establishing various new relationships among entities. This is intended to help achieve better quality specifications. We also describe a prototype that uses natural language processing and artificial intelligence tools to support the method. Finally, we present the results of a preliminary evaluation of our method, which show a promising applicability.", "url": "artigos/artigos_WER24/wer202414.html"}, {"title": "Requirements Documentation Containing Natural Language: A Systematic Tertiary Literature Review", "authors": ["Larissa Pereira Gonçalves", "Edna Dias Canedo", "Daniel Alves da Silva", "Carlos Eduardo Lacerda Veiga", "Rafael Timóteo de Sousa Junior", "Fábio Lúcio Lopes de Mendonça"], "year": 2024, "keywords": "Requirements documentation; Specification; Software requirements; Natural language artifacts; Systematic Review", "abstract": "Context: Requirements documentation in natural language has diverse artifacts, but few studies address their suitability to types of requirements or ease of communication. Methods: We conducted a systematic tertiary literature review (STLR) and identified 22 relevant review papers that address natural language artifacts used by practitioners to document software requirements. We also investigated which types of requirements are addressed by artifacts and if there are guidelines for each. Results: A variety of artifacts used for this purpose were identified, of which the most referenced in the literature were diagrams, use cases, conceptual models, user stories, and prototypes. The analysis highlighted that artifacts are applied differently to functional and non-functional requirements. In general, diagrams, use cases, scenarios, and prototypes can be used for both types of requirements, depending on the content (usability, security, etc.). However, user stories and derived artifacts are more recommended for functional requirements and have limitations for non-functional requirements. Conclusion: Furthermore, the study explored different guidelines, structures, and formats used in documentation artifacts, reflecting the diversity in requirements documentation practices in software projects.", "url": "artigos/artigos_WER24/wer202415.html"}, {"title": "Requisitos de Segurança e Privacidade em Startups: Um Estudo Empírico em uma Aplicação de Governança de Dados", "authors": ["Ewerton David Brito de Jesus", "Jéssyka Vilela", "Carla Silva"], "year": 2024, "keywords": "Requisitos de segurança da informação; Requisitos de privacidade; Avaliação de riscos; Startups; LGPD; Estudo empírico.", "abstract": "Vários incidentes de vazamento de dados pessoais têm acontecido, trazendo impactos negativos tanto para o titular como para o controlador dos dados pessoais. Nesse contexto, leis de privacidade foram criadas para que dados pessoais sejam tratados de forma responsável. A segurança da informação, forte aliada à proteção de dados, muitas vezes é negligenciada por empresas de pequeno porte. Este trabalho apresenta a utilização de um modelo de avaliação de riscos de segurança da informação e privacidade em uma aplicação de governança de dados de uma startup de tecnologia de pequeno porte. Dos 14 riscos identificados, 13 estavam em nível alto de risco, principalmente devido à falta de recursos financeiros e profissionais especializados. Neste trabalho, 13 controles foram sugeridos para melhorar a segurança na startup e reflete as dificuldades enfrentadas por empresas de pequeno porte nesse cenário.", "url": "artigos/artigos_WER24/wer202416.html"}, {"title": "Requisitos de Transparência para Engajamento de Desenvolvedores em Portais de Ecossistemas de Software", "authors": ["Thiago de Moura Parracho", "Rodrigo Oliveira Zacarias", "Henrique Prado de Sá Sousa", "Rodrigo Pereira dos Santos"], "year": 2024, "keywords": "Engajamento; Transparência; Requisitos não funcionais; Ecossistemas de software; Experiência de desenvolvedor", "abstract": "Os portais de ecossistemas de software (ECOS) são interfaces Web que permitem a um desenvolvedor participar, consumir informações e se comunicar com outros atores, em um ecossistema de software. Melhorar o engajamento dos desenvolvedores é uma preocupação importante para manter um ECOS sustentável no mercado ao longo do tempo. A Experiência de Desenvolvedor (DX, do inglês Developer eXperience) é uma qualidade importante, uma vez que experiências negativas durante a interação com o ECOS pode resultar no desengajamento do desenvolvedor. Dificuldades enfrentadas durante a interação com um portal de ECOS dificultam o engajamento e podem fazer com que os desenvolvedores abandonem o portal e, consequentemente, o ecossistema. Este trabalho apresenta um conjunto de 13 requisitos não funcionais (RNF) de transparência para portais de ECOS que são capazes de contribuir para o engajamento. Esses requisitos foram definidos com base em fatores que afetam o engajamento dos desenvolvedores nos portais de ECOS, especificamente em ECOS de código aberto e híbrido. Para isso, foram realizados dois estudos de caso com desenvolvedores iniciantes e foram realizados uma pesquisa de opinião e um estudo de campo com desenvolvedores do mercado. Todos os RNF elicitados puderam ser mapeados às subcaracterísticas do RNF de transparência da informação, o que denota a importante contribuição desta qualidade tanto para incrementar o grau de satisfação na DX, como, consequentemente, para o engajamento", "url": "artigos/artigos_WER24/wer202417.html"}, {"title": "Unveiling Developer Perspectives: A Survey on Accessibility Practices and Requirements in Software Development", "authors": ["Renata Vinadé", "Sabrina Marczak"], "year": 2024, "keywords": "Software development; Accessibility requirements; Empirical research; Survey; Accessibility education", "abstract": "The World Health Organization has stated that disabilities are a natural part of the human experience and nearly everyone will experience temporary or permanent disabilities at some point in their lifetime. Approximately 1.3 billion individuals, which is roughly 16% of the global population, struggle with disabilities such as visual, auditory, physical, speech, cognitive, learning, and neurological impairments. The quality of software depends on non-functional characteristics such as availability, maintenance, performance, reliability, scalability, security, and usability. Non-functional requirements are crucial for the success of software projects. In this context, accessibility plays a critical role in emphasizing the importance of non-functional requirements in software development. We conducted a survey of software development professionals to identify their understanding, awareness, and level of adopted practices in accessibility. Our study revealed the need for comprehensive accessibility curricula, accessible training programs, and better collaboration between academia, industry, government agencies and advocacy groups. By leveraging collective expertise and resources, stakeholders can work together to advance accessibility initiatives and address common challenges to develop accessible software. Establishing partnerships to share best practices, develop guidelines, and support organizations striving to improve accessibility in their products and services will create a more inclusive digital landscape.", "url": "artigos/artigos_WER24/wer202418.html"}, {"title": "Using I* For An Early Analysis Of Interoperability Requirements", "authors": ["Roberto de Cerqueira Figueiredo", "Daniela Barreiro Claro", "Rita Suzana Pitangueira Maciel", "Julio Cesar Sampaio do Prado Leite"], "year": 2024, "keywords": "Pragmatic interoperability; Goal oriented requirement engineering; Intentional modeling", "abstract": "Interoperability is a desired quality when there are cooperating software components. Usually, interoperability is classified into three levels: syntactic, semantic, and pragmatic. The pragmatic level is challenging as it requires modeling contexts and intentions. Over the works we reviewed, some tackle intentions, others context, at different levels of abstraction. Our contribution lies in dealing with intentions and context based on distributed intentionality among the different cooperating components. Pragmatic interoperability depends on use, which varies depending on context and intention. As such, the notion of variability is key in dealing with this type of interoperability. This paper explores the early analysis of interoperability from the standpoint of a goal-based modeling strategy. Using a real case, we show how the models in i* allow for an early analysis of pragmatic interoperability, as modeled by intentions and contexts. A University campus surveillance case helped us to show how modeling helps in the derivation of pragmatic interoperability requirements.", "url": "artigos/artigos_WER24/wer202419.html"}, {"title": "Collab2US: a Tool for Collecting User Stories from Collaborative Boards", "authors": ["Pedro Lucas Dornelles", "Rafael Parizi"], "year": 2024, "keywords": "Software Development; Collaborative Work; User Stories", "abstract": "Software teams are increasingly adopting User-Centered Design (UCD) approaches to navigate complex problems, focusing on empathy, creativity, and iterative learning for a deep understanding of users’ needs. Despite UCD’s advantages, transitioning from conceptual prototypes to concrete requirements, such as detailed user stories, remains challenging. This paper introduces Collab2US, a tool designed to automate the conversion of UCD outcomes into structured user stories. Collab2US tackles the challenge of converting collaborative ideation outcomes into a structured product backlog of software requirements. It supports IT professionals’ workflow by integrating Miro for ideation and Trello for backlog organization, streamlining the process of turning collaborative ideas into user stories. An initial evaluation of Collab2US has shown it can aid software teams in turning team insights into user stories for product backlogs.", "url": "artigos/artigos_WER24/wer202420.html"}, {"title": "Una Herramienta Para Componer Escenarios A Través De Procesamiento Del Lenguaje Natural Y Derivar Casos De Prueba", "authors": ["Gregorio Maclen", "Diego Torres", "Leandro Antonelli"], "year": 2024, "keywords": "Escenarios; Casos de prueba; Procesamiento del lenguaje natural", "abstract": "El diseño de casos de prueba es una de las actividades más desafiantes en el contexto de la ingeniería de requerimientos, dado que implica la colaboración de diferentes individuos con variados conocimientos en el dominio y perspectivas, con el objetivo de desarrollar un producto que satisfaga las expectativas y necesidades de los clientes. El modelo de desarrollo en V propone abordar el diseño de casos de prueba a partir de los requerimientos. Aunque constituye un punto de partida valioso, no siempre resulta sencillo obtener una especificación de requerimientos ordenada y consistente, que describa de manera integral toda la funcionalidad del sistema de software. Los escenarios se presentan como un artefacto efectivo para la especificación de requerimientos. Consisten en descripciones en lenguaje natural que delinean una secuencia de pasos desde un contexto o punto de partida específico hasta un objetivo o meta determinados. Los escenarios son atómicos, lo que implica que diferentes expertos pueden describir distintos escenarios en función de su conocimiento y perspectiva. Sin embargo, para el diseño efectivo de los casos de prueba, resulta crucial organizar los escenarios en una estructura jerárquica que facilite la identificación sistemática de todos los casos que necesitan ser evaluados. Este artículo propone una herramienta que permite la edición de escenarios y utiliza diversas técnicas de procesamiento de lenguaje natural para organizarlos en un árbol. Este enfoque se fundamenta en la relación “un escenario se describe con otro escenario”, lo que posibilita la generación de un árbol exhaustivo que abarque toda la funcionalidad del sistema. Posteriormente, la herramienta facilita la poda de ramas no deseadas para limitar el árbol a la funcionalidad que sea de interés evaluar. Finalmente, a partir del árbol resultante, se obtienen los casos de prueba. Es importante señalar que las bases teóricas y metodológicas para la generación de casos de prueba han sido presentadas en publicaciones previas; sin embargo, este trabajo se centra en el desarrollo y aplicación de una herramienta que automatiza dicho proceso, contribuyendo así a la eficiencia y precisión de la fase de pruebas en el ciclo de desarrollo de software.", "url": "artigos/artigos_WER24/wer202421.html"}, {"title": "Unlock the Power of the USARP Method: The USARP Tool Contribution to Usability Requirements Elicitation and Specification", "authors": ["Erik B. Silva", "Mateus E. Andrade", "Ana M. Lima", "Anna B. Marques"], "year": 2024, "keywords": "Usability Requirements; USARP Tool; Web Platform", "abstract": "Usability is fundamental to the success of digital products. The USARP method (USability Requirements with Personas and user stories) emerged to assist in eliciting and specifying usability requirements. USARP suggests using personas, user stories, and brainstorming sessions to discuss usability guidelines in card format. Although its effectiveness in eliciting usability requirements, USARP must improve its application. Conducting the brainstorming sessions with USARP artifacts, registering decisions, and refining requirements based on them requires different support tools. This work proposes to fill this gap with the USARP Tool, a tool dedicated to eliciting and specifying usability requirements. The USARP Tool follows a client-server architecture and uses technologies such as JavaScript, React, Node.js, ​​", "url": "artigos/artigos_WER24/wer202422.html"}, {"title": "Do Entendimento à Aplicação: Requisitos de Privacidade e a Visão dos Usuários sobre a LGPD", "authors": ["Ruy Ovídio Perrelli de Melo", "Jéssyka Vilela", "Carla Silva"], "year": 2024, "keywords": "Privacidade; LGPD; Survey; Requisitos", "abstract": "Contexto: Casos recentes de vazamento de dados começaram a se tornar frequentes, despertando a preocupação dos usuários acerca dos seus dados pessoais. Diante disso, diversos países sancionaram leis de proteção de dados pessoais com o intuito de regulamentar como esses dados devem ser tratados pelas empresas, prevendo punições e sanções em caso de descumprimento. Problema: Diante desse cenário, surge a necessidade de compreender qual é a percepção e nível de conhecimento dos usuários sobre as leis de proteção de dados. Objetivo: Portanto, pretende-se investigar a percepção dos usuários sobre privacidade e seu nível de conhecimento sobre a Lei Geral de Proteção de Dados Pessoais (LGPD). Método: Um survey foi aplicado a usuários de sistemas e aplicativos. Resultados: Um panorama geral da percepção dos usuários, suas expectativas e conhecimentos acerca da LGPD foi obtido. Conclusão: Verificou-se a preocupação e insegurança dos usuários com os seus dados pessoais na Internet, reforçando a necessidade de criar uma cultura de privacidade.", "url": "artigos/artigos_WER24/wer202423.html"}, {"title": "Habilidades e Competências para um Profissional de Requisitos: uma Visão da Indústria", "authors": ["Cristiana De Paulo", "Jarbele C. S. Coutinho", "Dorgival Netto"], "year": 2024, "keywords": "Engenharia de Requisitos; Indústria de Software; Soft Skills; Hard Skills", "abstract": "Diante da necessidade de formar profissionais qualificados para as reais demandas da indústria de software, surge a necessidade de compreender as principais habilidades, competências e conhecimentos específicos que um profissional de Engenharia de Requisitos (ER) precisa conhecer para ingressar na indústria de software. Para identificar tais características, foi realizado um levantamento de dados através da rede social LinkedIn, para identificar responsabilidades e deveres, qualificações e diferenciais encontrados nas descrições de cargos de profissionais de ER. Para validar essas informações, foi realizada um survey com profissionais de ER. Os principais resultados apontam para uma lista de habilidades, competências e conhecimentos específicos esperados no perfil de um profissional de ER. Espera-se contribuir com informações relevantes para a formação acadêmica de futuros profissionais de ER e fornecer insights de formação específicos para profissionais da área.", "url": "artigos/artigos_WER24/wer202424.html"}, {"title": "Implementing Accuracy Quality for Responsible AI in Newsrooms", "authors": ["Roxana L.Q. Portugal", "Juliana Delle Ville", "Leandro Antonelli"], "year": 2024, "keywords": "Requirements engineering; Artificial Intelligence (AI); Natural Language Processing (NLP); Journalism; Non-Functional Requirements (NFRs)", "abstract": "This paper explores the intersection between software development and journalism, highlighting the fundamental importance of implementing non-functional requirements to achieve a balance between immediacy and accuracy. In software development, requirements encompass user needs and demand precise and continuous updates to meet time-to-market demands. In journalism, audience engagement drives the need for precise news coverage, especially with the growth of artificial intelligence (AI). Non-functional requirements (NFRs) have gained relevance, emphasizing the need for effective balance. This work investigates the integration of technologies such as Named Entity Recognition (NER) and topic modeling into news updating processes as means to enhance both efficiency and precision. Additionally, this strategy, beneficial in requirements management and applicable across domains, is explored. The article is structured to delve into the imperatives of news writing, the proposed strategy, potential applications, and directions for future research.", "url": "artigos/artigos_WER24/wer202425.html"}, {"title": "La ingeniería de requerimientos en el cumplimiento de la normativa de protección de datos personales", "authors": ["Ma. Carolina Sacoto", "Juan Pablo Carvallo"], "year": 2024, "keywords": "RGPD; privacidad desde el diseño; protección de datos desde el diseño; ingeniería de requerimientos", "abstract": "Este artículo examina el desafío del cumplimiento normativo en la protección de datos personales, enfocándose en su intersección con la ingeniería de requerimientos. Se introduce un enfoque que subraya la importancia de la \"protección de datos desde el diseño\" y propone un método sistemático para traducir las obligaciones legales en requerimientos no funcionales concretos, implementados a través de controles específicos. Este proceso resulta de gran valor para los ingenieros de software, ya que les facilita una comprensión más profunda de las obligaciones legales y les permite implementar las medidas adecuadas para su cumplimiento. Mediante esta metodología, se busca integrar controles eficaces desde las primeras fases del diseño de software, con el objetivo de minimizar los riesgos económicos y reputacionales para la organización y de proteger eficazmente los derechos de los titulares de los datos personales.", "url": "artigos/artigos_WER24/wer202426.html"}, {"title": "Migração da Infraestrutura de TI On-Premise para Multicloud: Desafios no Contexto da Administração Pública Federal no Brasil e da Indústria Farmacêutica", "authors": ["Davi de França Carneiro", "Nelson Gutemberg Rocha da Silva", "Mauricio Barros Ottoni", "Fabiano Alves da Silva"], "year": 2024, "keywords": "Governo Federal Brasileiro; Indústria Farmacêutica; Infraestrutura de TI; Migração para Nuvem", "abstract": "Em muitas organizações, a infraestrutura de TI é um ponto crítico e está sujeita a monitoramento contínuo no processo de gestão estratégica de riscos. Ela deve ser capaz de fornecer suporte a serviços e sistemas de forma segura, com alto desempenho e baixa latência. Assim, as abordagens tradicionais de infraestrutura de TI, conhecidas como on-premise, precisam ser otimizadas, aliadas ao suporte dos serviços em nuvem. No contexto da administração pública federal no Brasil e da indústria farmacêutica, essa combinação é ainda mais desafiadora, pois envolve orientações de órgãos reguladores – como a Agência Nacional de Vigilância Sanitária (ANVISA), que se preocupa em manter as Boas Práticas de Fabricação dos produtos farmacêuticos (BPF) – e regulamentações recentes ou de certo modo incipientes do Governo Federal Brasileiro, quando se trata do uso de serviços em nuvem. Este trabalho, portanto, propõe uma estratégia de migração da infraestrutura de TI on-premise para multicloud, passando pelas fases da Engenharia de Requisitos (elicitação, análise e negociação, documentação, verificação e validação), a fim de gerenciar os principais aspectos jurídicos, financeiros e técnicos, incluindo equipamentos de rede, servidores, aplicações e serviços de suporte na indústria pública farmacêutica.", "url": "artigos/artigos_WER24/wer202427.html"}, {"title": "Understanding Technical Debts of Requirements in an Industry Project: A Qualitative Study", "authors": ["Rhenara Oliveira", "Anna B. Marques", "Ismayle Santos", "Rossana Andrade"], "year": 2024, "keywords": "Requirements Engineering; Requirements Technical Debt; Qualitative Study", "abstract": "Technical Debt (TD) in software engineering refers to the additional cost generated by inadequate decisions or implementations in software projects. Requirements TD emerges when specific requirements are overlooked, poorly understood, or implemented inadequately, leading to disparities between the developed product and the original specifications. In this context, requirements engineering should worry about how to prevent requirements TD from occurring and how to deal with requirements TD. This paper presents a qualitative study investigating the causes of requirements TD and identifying actions that can mitigate or resolve them. This qualitative study occurs in a software project of a partnership between an IT company and the Computer Networks, Software Engineering, and Systems Group (GREat) of the Federal University of Ceará. The literature review helped identify types and causes of RTD, later correlated with responses from exploratory questions in project retrospective sessions. With the qualitative analysis conducted, significant challenges were detected, especially in the requirements elicitation phase, highlighting the need for more effective approaches. To deal with these issues, actions aimed at mitigating and resolving existing Requirements Technical Debts were identified and implemented.", "url": "artigos/artigos_WER24/wer202428.html"}, {"title": "Uso de Modelos Conversacionales Avanzados para Evaluar la Ambigüedad en Requerimientos de Software", "authors": ["Pedro E. Colla"], "year": 2024, "keywords": "IA; ChatGPT; Modelos conversacionales avanzados; Ambigüedad de los requerimientos", "abstract": "Este artículo propone evaluar preliminarmente mediante un experimento la aplicabilidad y ventajas de utilizar la tecnología de modelos conversacionales avanzados durante el ciclo de desarrollo de proyectos de software específicamente en la tarea de detectar y corregir ambigüedades en los requerimientos. La utilización de ésta tecnología tiene un enorme potencial para mejorar la calidad resultante del proyecto de software y la drástica reducción del esfuerzo de retrabajo con ventajas significativas en el costo, calidad y satisfacción del cliente.", "url": "artigos/artigos_WER24/wer202429.html"}, {"title": "A Requirements Engineering Process for Machine Learning Innovation Projects", "authors": ["Mariana Crisostomo Martins", "Taciana Novo Kudo", "Renato F. Bulcão-Neto"], "year": 2024, "keywords": "Requirements Engineering; Machine Learning; ISO/IEC 12207; Software Process; Design Thinking; Technology Transfer Model", "abstract": "Despite the increasing development of Machine Learning (ML) applications, Requirements Engineering (RE) activities face challenges in this new data-intensive paradigm, e.g., the high dependence on data availability and quality and the continuous adaptation to changing environments. In this context, we have identified a lack of an integrated view of the RE process of ML applications in the literature. This paper proposes an RE process tailored to ML application projects, covering requirements elicitation, analysis, specification, validation, and management. The process development methodology includes the ISO/IEC 12207 standard and Design Thinking. Our solution combines problem study and formulation supported by the state of the art in research. The solution proposal follows three evaluation formats: laboratory, static, and dynamic validation. We expect the process to improve RE practice and thus improve ML-based systems development with higher quality deliveries and easier maintenance.", "url": "artigos/artigos_WER24/wer202430.html"}, {"title": "Bart: Uma técnica de Elicitação de Requisitos para Sistemas Multiagentes", "authors": ["Willian Samuel Gerstberger", "Gilleanes Thorwald Araujo Guedes"], "year": 2024, "keywords": "engenharia de requisitos; elicitacao de requisitos; sistemas multiagentes", "abstract": "O primeiro passo na construção de um bom produto de software é entender as necessidades das partes interessadas, tornando assim a engenharia de requisitos uma das etapas que requer mais atenção no ciclo de desenvolvimento de qualquer software, incluindo os sistemas multiagentes. Este tipo de software é composto por entidades autônomas e proativas, as quais são chamadas de agentes e que podem colaborar entre si para atingir um objetivo. Entretanto, os sistemas multiagentes possuem alguns requisitos em particular que normalmente não são encontrados em outros tipos de softwares, o que faz com que os métodos de levantamento destes requisitos também possuam características distintas. Levando isto em consideração, este trabalho apresenta uma nova técnica de elicitação que, desde o seu início, foi pensada para auxiliar o levantamento de requisitos para sistemas multiagentes. Esta nova técnica se baseia nos resultados obtidos por meio de um estudo prévio que buscou entender quais eram as principais técnicas utilizadas para elicitação de sistemas multiagentes e, principalmente, como estas diferentes técnicas são aplicadas.", "url": "artigos/artigos_WER24/wer202431.html"}, {"title": "Proceso de Validación de Requerimientos Aplicando Técnicas de Procesamiento de Lenguaje Natural en un Entorno Colaborativo", "authors": ["Sonia Santana", "Leandro Antonelli", "Pablo Thomas"], "year": 2024, "keywords": "Validación de Requerimientos; Técnicas de Procesamiento de Lenguaje Natural; Entornos Colaborativos", "abstract": "Una de las fases más importantes en el desarrollo de un proyecto de software es la validación de los requerimientos. El principal objetivo de la validación de los requerimientos es confirmar que los mismos sean representaciones de las necesidades y expectativas de los usuarios y que sean completos, correctos y consistentes entre otras características. Hoy en día, los requerimientos se escriben con la participación de un gran número de personas que producen una cantidad variada de artefactos. En este contexto los entornos colaborativos y el procesamiento de lenguaje natural cobran importancia. En este trabajo se describe un proceso de validación de requerimientos utilizando técnicas de procesamiento de lenguaje natural un entorno colaborativo, donde las diferentes partes interesadas en un proyecto les permitirá validar requerimientos en menor tiempo y esfuerzo.", "url": "artigos/artigos_WER24/wer202432.html"}, {"title": "Preface: Proceedings of the 28th Workshop on Requirements Engineering (WER2025)", "authors": ["Marcela Ridao", "Márcia Lucena", "Rodrigo Santos"], "year": 2025, "keywords": "WER; Requirements Engineering", "abstract": "The twenty-eighth edition of the Workshop on Requirements Engineering (WER 2025), hosted at Federal University of Rio de Janeiro State in Rio de Janeiro, Brazil, from August 20th to 22th, 2025, brought together researchers and practitioners from across academia and industry. Over three vibrant days, discussions spanned key themes such as usability, transparency, data protection, natural language processing, sustainability, accessibility, technical debt, and security requirements. This year, 28 articles were presented as full papers. Following a thorough review by at least three committee members per submission. The event featured five tracks: Research, Industry, Master's and Doctoral, Software Requirements Tools, Tutorials. Distinguished keynote speakers included Marcos Kalinowski from PUC-Rio, offering unique insights into cutting-edge challenges in Requirements Engineering.", "url": "artigos/artigos_WER25/wer202500.html"}, {"title": "Tutorial: Gestión de los Requisitos: Aspectos Técnicos", "authors": ["Julio C.S.P. Leite", "Graciela Hadad", "Jorge H. Doorn"], "year": 2025, "keywords": "Gestión de Requisitos; Gestión de Configuración; Métricas", "abstract": "En todo proceso, su gestión es una actividad distinguible e interde\u0002pendiente de las demás. La gestión se ocupa de regular el proceso. Es muy im\u0002portante tener siempre presente que la gestión no solo debe actuar correctiva\u0002mente ante aquellos problemas internos derivados de dificultades en cumplir los planes, sino que también debe atender circunstancias externas que influyen en el proceso que está siendo gestionado. Esto ocurre porque usualmente el contexto evoluciona y en ocasiones esa evolución atenta contra el cumplimiento de los objetivos perseguidos. En ambos casos la gestión requiere disponer de métricas adecuadas que permitan controlar y tomar decisiones. Por otro lado, la gestión no solo establece las métricas a usar, sino también los métodos, técnicas y herra\u0002mientas a emplear en el proceso de requisitos con base en el contexto de aplica\u0002ción, y los objetivos, plazos y costos acordados, entre otros factores. En este tu\u0002torial, se presentan las actividades que hacen a la gestión del proceso de requisitos y sus productos, la configuración y los cambios, el uso de métricas y la selección de métodos, técnicas y herramientas que den soporte al proceso.", "url": "artigos/artigos_WER25/wer202500_1.html"}, {"title": "A Framework for Requirements Classification with Machine Learning Methods", "authors": ["João Azevedo", "João Araújo", "Alberto Sardinha", "Carina Alves"], "year": 2025, "keywords": "Requirements Classification; Machine Learning; Active Learning", "abstract": "Requirements Engineering (RE) is a critical phase in software development. Frequently, requirements are expressed in natural language and embedded in large documents. Classifying requirements is a time-consuming and error-prone activity. To address this issue, Machine Learning (ML) techniques can be leveraged to classify requirements. ML is a subfield of Artificial Intelligence that facilitates decision-making by developing automated models trained on data samples. This paper compares ML approaches to automatically classify requirements as functional (FR) and non-functional (NFR). Our study uses Supervised Machine Learning (SL) models alongside Active Learning (AL). SL models require large volumes of labeled data for effective training. However, in many cases, the datasets available for training are unlabeled, and the sheer size of these datasets makes manual labeling impractical. This poses a significant challenge for training supervised models. AL offers a solution to this challenge by strategically selecting specific xamples for user labeling, which are then used to train the model. By combining AL with SL, we aim to investigate whether Active Learning improves requirements classification. We propose a systematic approach to applying ML and AL to classify requirements datasets. By doing so, we aim to accelerate and automate the requirements classification process. Classifying requirements into distinct categories allows developers to concentrate more effectively on subsequent stages of the development process. We present a supporting process for our proposal.", "url": "artigos/artigos_WER25/wer202501.html"}, {"title": "Análisis comparativo de arquitecturas de NLP para detectar similitudes entre escenarios en español", "authors": ["Gabriela Pérez", "Catalina Mostaccio", "Leandro Antonelli"], "year": 2025, "keywords": "Requerimientos; NLP; LLM; Similaridad Semántica", "abstract": "La ingeniería de requerimientos es una fase crítica en el desarrollo de software, ya que permite identificar y definir los requerimientos del sistema. Involucra clientes y desarrolladores, quienes deben comunicarse de manera efectiva a pesar de manejar vocabulario diferente. Uno de los artefactos utilizado para este propósito es el escenario, ya que permite especificar el conocimiento de un dominio utilizando lenguaje natural. La especificación de requerimientos implica un trabajo colaborativo, por lo tanto, es esencial detectar tempranamente escenarios similares, con el fin de evitar la duplicación de esfuerzos. Una técnica comúnmente utilizada para identificar similitudes entre oraciones es el uso de LLMs para generar representaciones vectoriales que capturan el significado semántico de las frases en un espacio de alta dimensionalidad. Sin embargo, tienden a generar falsos positivos cuando dos oraciones emplean términos similares con significados distintos, debido a la proximidad superficial de sus embeddings en el espacio vectorial. En este trabajo, se analizan arquitecturas de modelos de procesamiento de lenguaje natural basadas en modelos encoder-decoder para detectar similitudes entre escenarios escritos en español. Para abordar las limitaciones de los encoders tradicionales, se analizan otras estrategias que combinan eficientemente arquitecturas de codificación y decodificación. Esta investigación busca determinar si estas aproximaciones pueden aumentar la precisión y reducir la tasa de falsos positivos en escenarios con terminología diversa.", "url": "artigos/artigos_WER25/wer202502.html"}, {"title": "Apoiando o reúso de requisitos de usabilidade na adoção do USARP: identificação de padrões emergentes", "authors": ["Larissa Santos Saraiva", "Patrícia Freitas Campos de Vasconcelos", "Anna Beatriz Marques"], "year": 2025, "keywords": "USARP; Padrões Emergentes; Requisitos de Usabilidade", "abstract": "A Engenharia de Requisitos ainda enfrenta desafios significativos na elicitação e especificação de requisitos de usabilidade, especialmente quando conduzida por Engenheiros de Software em formação. O Método USARP (USAbility Requirements with Personas and user stories) tem se mostrado promissor nesse contexto, ao incorporar a perspectiva do usuário desde as fases iniciais do desenvolvimento. Entretanto, o corpo de conhecimento da área carece de padrões formalizados voltados à usabilidade, dificultando a padronização e o reúso de requisitos. Diante dessa lacuna, este estudo propõe a análise de requisitos especificados com o uso do USARP, com o objetivo de identificar padrões emergentes. A investigação foi realizada com base em 24 projetos acadêmicos desenvolvidos por estudantes de Engenharia de Software, uma vez que o acesso a requisitos de projetos industriais é restrito por questões de confidencialidade. Como resultado, foram identificados 12 padrões recorrentes relacionados às funcionalidades: Cadastro, Busca, Exclusão, Login, Filtragem, Edição, Envio de Arquivos, Acompanhamento de Progresso, Geração de Relatórios, Gerenciamento, Personalização e Notificação. Esses padrões contribuem para a sistematização do método USARP, promovendo o reúso de requisitos e a melhoria da qualidade dos artefatos produzidos.", "url": "artigos/artigos_WER25/wer202503.html"}, {"title": "Application of the Extended Language Lexicon for Cyber-Physical Production Systems", "authors": ["Alejandro Oliveros", "Jorge Fossati"], "year": 2025, "keywords": "Cyber-Physical Production Systems (CPPS); Language Extended Lexicon (LEL); Capabilities elicitation.", "abstract": "This paper presents an approach for eliciting the capabilities of Cyber-Physical Production Systems (CPPS) through an extension of the Language Extended Lexicon (LEL), referred to as LEL-C. CPPS integrate hardware, software, and physical components—often in dynamic interaction with human and environmental factors—posing new challenges to requirements engineering. To address these, we adopt the capability-oriented perspective of e-CORE and propose leveraging LEL-C to systematically capture domain knowledge across digital and physical dimensions. The proposed extension incorporates additional attributes such as component type, system and physical location, interactions, data sources, and temporal constraints. We apply LEL-C to a wildfire detection and suppression system as a use case, showing how the method supports the structured identification of current system capabilities. It is planned to advance the validation of this prelimi-nary version of the LEL-C by developing a complete glossary for a CPSS. This will also provide improvements to the proposal. This foundational work enables a consistent strategy for capability elicitation in CPPS, con-tributing to the broader goal of aligning semantic models with both soft-ware and physical process properties.", "url": "artigos/artigos_WER25/wer202504.html"}, {"title": "Construindo um Catálogo de Metas-Flexíveis do Devido Processo Legal", "authors": ["Ulla Louise Didriksson", "Henrique Prado de Sá Sousa", "Julio Cesar Sampaio do Prado Leite"], "year": 2025, "keywords": "Catálogo de metas-flexíveis; Devido Processo Legal; Softgoal; Requisitos de qualidade; RNF.", "abstract": "A área do Direito está evoluindo substancialmente através da inclusão de softwares, especialmente os de Inteligência Artificial. Atualmente, os softwares estão sendo usados, por exemplo, para auxiliar a definição de sentenças judiciais e para apoiar o trabalho de advogados, em um mercado em franca expansão. No entanto, autoridades da área do Direito apontam a preocupação com diversos aspectos qualitativos, inerentes à legalidade, que não estão sendo observados com rigor suficiente na construção destes softwares. Trata-se de requisitos não funcionais, conhecidamente complexos de se implementar e comumente negligenciados. Neste artigo, abordamos o mapeamento de metas flexíveis a partir dos princípios legais presentes no Devido Processo Legal (DPL). Diversos elementos do DPL são qualitativos, e devem estar presentes durante um processo judicial, caso contrário, há o risco de se tornar inválido. Considerando a relevância do DPL e a necessidade de conhecimento específico do domínio do Direito para se estabelecer conhecimento para a especificação adequada de requisitos de software, neste artigo é proposto o Softgoal Interdependency Graph (SIG) para o DPL. O grafo foi construído a partir do conhecimento elicitado em fontes de informação com relevância reconhecida na área do Direito. Posteriormente foi enriquecido e validado a partir da visão de 7 especialistas que atuam em um Tribunal de Justiça do Rio de Janeiro.", "url": "artigos/artigos_WER25/wer202505.html"}, {"title": "Diseño de Casos de Pruebas a partir del Léxico Extendido del Lenguaje y la Especificación de Requerimientos", "authors": ["Julieta Screpnik", "María Alejandra Paz Menvielle", "Leandro Antonelli"], "year": 2025, "keywords": "Diseño de Casos de Pruebas; Léxico Extendido del Lenguaje; Especificación de Requerimientos de Software; Gherkin.", "abstract": "La prueba de software es una fase crítica en el ciclo de desarrollo del software, ya que consiste en un conjunto de actividades diseñadas para evaluar la calidad de los productos que se construyen. Además, los datos obtenidos durante esta etapa fortalecen la confianza en el producto final y aportan información valiosa para respaldar la toma de decisiones por parte de todos los interesados. En la actualidad, el incremento de la complejidad de los productos que solicitan los clientes exige la implementación de estrategias innovadoras, orientadas a identificar la mayor cantidad de defectos y disminuir el riesgo de fallas. En este artículo, se propone un método para el proceso de diseño de casos de pruebas en formato Gherkin, tomando como entrada la Especificación de Requerimientos de Software y el Léxico Extendido del Lenguaje.", "url": "artigos/artigos_WER25/wer202506.html"}, {"title": "Diseño y Aplicación de una Estrategia Didáctica en la Enseñanza de Ingeniería de Requerimientos", "authors": ["Jorge Ezequiel Moyano", "Ivan D'Uva", "Daniel Aguil Mallea"], "year": 2025, "keywords": "Estrategias Didácticas; Educación; Ingeniería de Software; Ingeniería de Requerimientos.", "abstract": "Los procesos de enseñanza y aprendizaje se caracterizan por reconocer el papel determinante del docente en identificar, planificar e instrumentar estrategias en la formación de sus estudiantes. La didáctica exige la utilización de estrategias y métodos centrados en el sujeto que aprende, en enfocar la enseñanza como un proceso de orientación del aprendizaje, donde los estudiantes no sólo se apropien de los conocimientos, sino que desarrollen diversas habilidades. La fase de Ingeniería de Requerimientos es crítica en el desarrollo de software, por lo que su enseñanza es fundamental. La formación académica debe generar habilidades y aptitudes determinadas como la abstracción, trabajo en equipo, toma de decisiones, comprensión del problema, etc., en donde se distinguen tres elementos: conceptual, procedimental e integrador. Para esto se necesitan técnicas que se incorporen en el proceso de enseñanza en el área de la ingeniería de requerimientos. La enseñanza de técnicas de ingeniería de requerimientos presenta desafíos como la dificultad de realizar prácticas reales. Metodología: para este caso de estudio planteamos la siguiente metodología: los estudiantes fueron divididos en grupos, algunos entrevistaron a un docente asistente de la cátedra mientras otros a un docente de otra carrera, quienes oficiaron de “clientes” a los efectos de obtener un documento de especificación de requerimientos. Resultados: el artículo presenta resultados parciales de nuevas estrategias didácticas para abordar la complejidad en la enseñanza de la ingeniería de requerimientos. La principal contribución radica en presentar nuevas estrategias que reflejen interacciones con los usuarios reales.", "url": "artigos/artigos_WER25/wer202507.html"}, {"title": "Engenharia de Requisitos na Formação Acadêmica no Brasil: Um Alinhamento com as Expectativas da Indústria de Software", "authors": ["Cristiana de Paulo", "Jarbele Coutinho", "Dorgival Netto"], "year": 2025, "keywords": "Engenharia de Requisitos; Indústria de Software; Formação Acadêmica.", "abstract": "A constante evolução da indústria de software aumenta a demanda por profissionais qualificados. Para atender às expectativas da indústria, a formação acadêmica deve se alinhar com as necessidades práticas do mercado. Na Engenharia de Requisitos (ER), tanto as habilidades técnicas quanto as comportamentais são atributos importantes na carreira de um profissional de requisitos. Portanto, é importante compreender os atributos, habilidades e competências esperadas pela indústria de software que estão sendo promovidas durante a formação acadêmica. Assim, o objetivo deste estudo é identificar e validar se os atributos exigidos pela indústria estão efetivamente sendo promovidos na academia. Uma revisão inicial da literatura foi realizada para identificar as principais habilidades e competências esperadas dos engenheiros de requisitos. Com base nessas descobertas, foi aplicada uma pesquisa com profissionais brasileiros envolvidos no ensino de ER para validar se esses atributos estão sendo discutidos e estimulados durante a formação acadêmica desses profissionais. Dessa forma, espera-se contribuir com indicadores que proporcionem um melhor alinhamento entre a formação acadêmica de profissionais de ER e as demandas atuais da indústria de software.", "url": "artigos/artigos_WER25/wer202508.html"}, {"title": "Exploring LLMs for User Story Extraction from Mockups", "authors": ["Diego Firmenich", "Leandro Antonelli", "Bruno Pazos", "Fabricio Lozada", "Leonardo Morales"], "year": 2025, "keywords": "User stories; high-fidelity mockups; language extended lexicon; requirements engineering", "abstract": "User stories are one of the most widely used artifacts in the software industry to define functional requirements. In parallel, the use of high-fidelity mockups facilitate end-user participation in defining their needs. In this work, we explore how combining these techniques with large language models (LLMs) enables agile and automated generation of user stories from mockups. To this end, we present a case study that analyzes the ability of LLMs to extract user stories from high-fidelity mockups, both with and without the inclusion of a glossary of the Language Extended Lexicon (LEL) in the prompts. Our results demonstrate that incorporating the LEL significantly enhances the accuracy and suitability of the generated user stories. This approach represents a step forward in the integration of AI into requirements engineering, with the potential to improve communication between users and developers.", "url": "artigos/artigos_WER25/wer202509.html"}, {"title": "Exploring LLMs on Supporting the Elicitation of Knowledge for NFR Catalogs: Insights from the Transparency Case", "authors": ["Roxana L. Q. Portugal", "Lyrene F. Silva", "Henrique S. P. Sousa", "Julio C. S. P. Leite"], "year": 2025, "keywords": "Large Language Models (LLMs); Non-Functional Requirements (NFR); Softgoals Interdependency Graph (SIG); Transparency; ChatGPT", "abstract": "The Softgoal Interdependency Graph (SIG) models non-functional requirements (NFRs) by representing softgoals and their interrelationships. However, building a SIG is challenging as it requires a deep understanding of qualitative concepts that vary across domains. The Transparency SIG (TSIG), which integrates over 30 related qualities, exemplifies this complexity. This study explores whether Large Language Models (LLMs), specifically ChatGPT-3.5 and ChatGPT-4o, can augment the knowledge of the TSIG. Through interactive dialogues, we analyzed the models’ ability to suggest relevant content and structure. Our findings show that, using the TSIG as the Gold Standard, the ChatGPT-generated models demonstrated the ability to approximate the expert knowledge represented in the TSIG, as evidenced by three authors achieving over 84% recall. Furthermore, since precision varied significantly—from 29.4% to 100%—this highlights differences in the amount of false positives. These elements require further qualitative evaluation to determine which of them may actually contribute to augmenting the knowledge on transparency, as modeled by the TSIG.", "url": "artigos/artigos_WER25/wer202510.html"}, {"title": "From Elicitation Interviews to Software Requirements: Evaluating LLM Performance in Requirement Generation", "authors": ["Camila Almeida", "Isaque Copque", "Alvaro Oliveira", "Murilo Arouca", "Adriano Barbosa", "Sávio Freire", "Manoel Mendonça", "Julio Cesar Leite"], "year": 2025, "keywords": "Requirements engineering; Large Language Models; Requirement generation.", "abstract": "Recent advancements in artificial intelligence (AI), particularly in large language models (LLMs), offer new possibilities for automating requirements generation from elicitation interviews. This study compares the performance of ChatGPT-4 and DeepSeek-V3 in generating software requirements based on transcribed stakeholder interviews. Using two case studies, the LLMs were tasked with identifying functional and non-functional requirements. The results indicate that ChatGPT-4 performed better in extracting precise requirements, particularly nonfunctional ones, while DeepSeek-V3 demonstrated advantages in efficiency. However, both models exhibited limitations in handling ambiguity and properly categorizing requirements. This study highlights the potential of LLMs in Requirements Engineering while emphasizing the need for improved prompt/dialogues techniques and human supervision. Future research should explore hybrid AI-human approaches and domain-specific fine-tuning to enhance requirement extraction accuracy.", "url": "artigos/artigos_WER25/wer202511.html"}, {"title": "Incorporating Cybersecurity Requirements in Agile Development Processes", "authors": ["Gabriella Castro Barbosa Costa Dalpra", "Victor Borges Loures de Paula", "Marcelo Augusto Silva Belisário", "Maria Júlia Marques Schettini", "José Eduardo Fernandes", "Tiago Pedrosa"], "year": 2025, "keywords": "Cybersecurity; Agile Methodologies. Security Requirements", "abstract": "The complexity and interconnectivity of modern software systems make cybersecurity a key concern. Each new device connected to a network increases security risks, and the rise of cyber threats and attack sophistication requires strong security measures from the start of development. Agile development methodologies are widely adopted for their ability to improve efficiency and flexibility in software development. However, these methodologies often lack clear guidance on how to incorporate security practices effectively. This gap can result in vulnerabilities being exploited by attackers, compromising the security of sensitive systems and data. Based on this fact, balancing security with agility is essential in today’s fast-paced digital landscape. Considering the application of cybersecurity requirements in agile development processes, since the beginning of the software development lifecycle, we propose the ASF Framework, developed using the Design Science Research approach. The framework evaluation focuses on its application to the OWASP ASVS cybersecurity standard and Scrum, using user stories with Acceptance Criteria and the Definition of Done to ensure clear and measurable development goals. This assessment was conducted in the context of a web platform that connects consumers and service providers, simplifying the process of offering and hiring services. The evaluation demonstrates the applicability of the ASF framework in a real-world scenario, and the results indicate that ASF effectively supported the identification of security requirements within an agile development context.", "url": "artigos/artigos_WER25/wer202512.html"}, {"title": "Non-functional requirements in 3D Mobile Applications and Virtual Reality Environments", "authors": ["Sebastián Dapoto", "Federico Cristina", "Pablo Thomas", "Patricia Pesado"], "year": 2025, "keywords": "Non-functional requirements; 3D mobile applications; virtual reality; graphics performance; Unity", "abstract": "Non-functional requirements (NFR) are characteristics that specify the quality criteria and constraints a system must meet. These requirements are essen-tial for the successful development of software, particularly in 3D mobile applica-tions, as they have a direct impact on user experience. Graphics performance is one of the most critical NFR in this type of application, as it affects both user ex-perience and the viability of these applications on devices with varying hardware capabilities. This paper examines the impact of NFR on 3D mobile applications, particularly focusing on the main variables influencing graphics performance, such as 3D modeling, texture usage, lighting, visual effects, and physical effects. Additionally, an experiment is presented on 3D mobile applications with and without virtual reality environments, where the impact of different features on the frames per second rate is evaluated. The results obtained help identify the main bottlenecks in one of the most critical non-functional requirements, contributing to optimizing performance and improving the overall quality of 3D mobile appli-cations and virtual reality environments.", "url": "artigos/artigos_WER25/wer202513.html"}, {"title": "PRIM-UI: un método para integrar patrones de interacción en la etapa de requerimientos", "authors": ["Jonathan Delgado Guerrero", "Leandro Antonelli", "Diego Firmenich"], "year": 2025, "keywords": "patrones de interacción; diseño de interfaces; enriquecimiento de interfaces; levantamiento de requisitos; usabilidad", "abstract": "La fase de requisitos es importante para el éxito de un proyecto de software, ya que un levantamiento bien definido evita costos altos por correcciones y asegura productos alineados con las expectativas del usuario. Sin embargo, el enfoque tradicional suele centrarse en requisitos funcionales y no funcionales, ignorando la interacción del usuario, lo que genera interfaces (UI) poco usables. Este trabajo propone un nuevo enfoque que incorpora patrones de interacción validados en la fase de requisitos para optimizar el diseño de UI. La metodología consta de tres etapas: 1) identificación sistemática de patrones de interacción relevantes para el dominio, 2) análisis contextual de requisitos y 3) mapeo de patrones a requisitos mediante validación heurística. Se evaluó mediante un caso de estudio en una aplicación web para actualización de datos con validación biométrica, con doce requisitos implementados por un equipo de cinco desarrolladores. Los resultados preliminares muestran que los patrones optimizaron la estructura de la UI y la retroalimentación, alineando requisitos con estándares de usabilidad. Los resultados sugieren que el enfoque no solo alinea el diseño con mejores prácticas, sino que también ofrece beneficios medibles en eficiencia y mantenibilidad. Futuros estudios podrían cuantificar su impacto con métricas como SUS y explorar su escalabilidad en sistemas complejos, integrar sistemáticamente las pautas de accesibilidad WCAG, y el uso de aprendizaje automático para recomendación adaptativa de patrones.", "url": "artigos/artigos_WER25/wer202514.html"}, {"title": "Puntos de Vista en el Uso de Mapas Mentales y Facilitación Gráfica en la Elicitación", "authors": ["Alberto Sebastián", "Graciela D.S. Hadad", "Leandro Antonelli"], "year": 2025, "keywords": "Mapas Mentales; Facilitación Gráfica; Elicitación; Comprensión del Problema.", "abstract": "La calidad de los modelos depende no sólo de las habilidades de los ingenieros de requisitos y del proceso de construcción, sino de la información adquirida. Muchos defectos en los modelos se originan en información deficiente de la elicitación, habitualmente de entrevistas. Esto revela dificultades en la comprensión del universo de discurso, del problema del usuario y de la funcionalidad general del software. Este trabajo propone mejorar esa comprensión utilizando técnicas visuales, como mapas mentales y facilitación gráfica. Se presentan los resultados de un análisis comparativo de las percepciones de estudiantes actuando como ingenieros junior de requisitos, a partir de encuestas realizadas en dos estudios de caso sobre el uso de estas técnicas durante la actividad de elicitación. Con ambas técnicas se construyeron diagramas individualmente, y luego se unificaron. Esto resultó ser clave para contrastar discrepancias e integrar diversos puntos de vista, así como base para construir un modelo conceptual. Los resultados indican que el nivel de comprensión alcanzado fue percibido como alto para ambas técnicas. Además, ambas facilitaron la interacción con el usuario. Se identificaron ciertas limitaciones, tales como la necesidad de adquirir experiencia en el uso de estas técnicas, y la importancia de realizar alguna reunión para discutir y validar el conocimiento adquirido mediante los diagramas.", "url": "artigos/artigos_WER25/wer202515.html"}, {"title": "Trayecto para Precisar Heurísticas en un Modelo Conceptual", "authors": ["Graciela D.S. Hadad", "Jorge H. Doorn", "María Celia Elizalde", "Marcela N. Ridao"], "year": 2025, "keywords": "Ingeniería de Requisitos; Modelado Conceptual; Glosario; Factores Cognitivos", "abstract": "Los ingenieros de requisitos deben adquirir información acerca del contexto don-de se desempeñará el futuro sistema de software y registrarla en modelos apro-piados. Estos modelos son utilizados durante la definición de los requisitos del sistema de software, pero también sirven de referencia para atender cualquier du-da que pueda surgir en etapas posteriores del desarrollo. Desafortunadamente, se ha comprobado que estos modelos dependen muy fuertemente de quien los cons-truya. Esto hace necesario que procedimientos y recomendaciones que acompa-ñan a los modelos consideren factores cognitivos, de manera que los resultados no sean tan dependientes de las personas. En tal sentido, se ha reformulado un proceso de construcción de un modelo en lenguaje natural con heurísticas que atienden dichos aspectos cognitivos y semánticos. Se presenta un experimento que utiliza este proceso modificado y se lo compara con experimentos antecesores donde se usó un proceso sin consideraciones lingüísticas-cognitivas y un proceso que atiende solo algunas cuestiones lingüísticas para construir el mismo modelo. Se pudieron evidenciar mejoras en la calidad del modelo cuando se utiliza un pro-ceso con heurísticas más precisas que atiende tanto aspectos semánticos y prag-máticos como cognitivos.", "url": "artigos/artigos_WER25/wer202516.html"}, {"title": "Uso de Large Language Models na Engenharia de Requisitos", "authors": ["Ytalo Silva", "Maria Gois", "Abimael Santos", "Jaelson Castro", "Maria Lencastre"], "year": 2025, "keywords": "Engenharia de Requisitos; Large Language Models; Revisão Sistemática da Literatura", "abstract": "Os Large Language Models (LLMs), que são amplamente adotados em domínios como processamento de linguagem natural e geração de código, emergem como ferramentas promissoras para otimizar a Engenharia de Re-quisitos (ER). Por meio de uma Revisão Sistemática da Literatura (RSL), este estudo visa analisar sistematicamente como os LLMs têm sido aplicados na ER, explorando suas contribuições, benefícios, desafios e implicações éticas. Seguindo o protocolo estabelecido, foram analisados 50 estudos de várias bases bibliográficas. Os resultados revelam que os LLMs são empregados em todas as fases da ER (elicitação, análise, documentação e validação), destacando-se em automação de tarefas repetitivas, refinamento de re-quisitos e melhoria da comunicação entre stakeholders. Benefícios incluem ganhos de eficiência (redução de tempo/esforço) e maior precisão na docu-mentação. Entretanto, desafios persistem, como inconsistências na saída dos modelos, dependência de intervenção humana, dificuldades em domí-nios especializados e riscos de vazamento de dados. Preocupações éticas, como transparência e privacidade, são pouco exploradas na literatura, apon-tando lacunas críticas. Conclui-se que os LLMs transformam a ER, mas exi-gem frameworks robustos de validação e políticas éticas para equilibrar inovação e responsabilidade.", "url": "artigos/artigos_WER25/wer202517.html"}, {"title": "Validación de método de alineación entre glosarios específicos de dominio.", "authors": ["Grijalva-Arriaga Paola", "Antonelli Leandro", "Cornejo Galo", "Thomas Pablo"], "year": 2025, "keywords": "Alineación de Dominios; Léxico Extendido del Lenguaje; Validación método.", "abstract": "La interoperabilidad entre sistemas de información es importante, ya que permite el intercambio de información, siendo uno de los pilares de la industria 4.0 [1]. Por ejemplo, los sistemas de información institucionales deben acoplarse para dar respuesta a los requerimientos de información de organismos gubernamentales o entes de control y calidad. Para lograrlo, es necesario comprender cada uno de los dominios y establecer las relaciones entre sus elementos. Una forma de hacerlo es definiendo el glosario de cada dominio y alinearlos. Existe un método que, basado en glosarios LEL determina los términos con similitud, diferentes y omitidos entre glosarios [2]. Este artículo tiene como objetivo validar la precisión y las limitaciones de este mé-todo, aplicando un caso de estudio. La ejecución del método se realizó con la participación de ingenieros de requerimientos y expertos en el área de estudio planteado. Se comprueban los resultados obtenidos, categorizándolos como alineación correcta o incorrecta. Se realizaron 1210 comparaciones de símbolos, hallando similitudes, diferencias y omisiones; por otro lado, se obtuvo también que 950 alineaciones fueron correctas y 39 alineaciones fueron clasificadas como incorrectas. El método de alineación evaluado obtuvo una precisión de 0.96, lo que demuestra que la mayoría de las alineaciones detectadas fueron correctas. La cobertura de 0.952 sugiere que el método fue capaz de identificar casi la totalidad de las alineaciones relevantes; estos resultados indican que el método es adecuado para realizar la alineación. Sin embargo, para ser utilizado con glosarios extensos, se sugiere automatizarlo aplicando técnicas de lenguaje natural.", "url": "artigos/artigos_WER25/wer202518.html"}, {"title": "Framing Cloud Migration of Legacy Systems as Technical Sustainability Requirements within a Proprietary Software Ecosystem", "authors": ["Claudio Coelho da Silva Junior", "Juliana Carvalho Silva do Outão", "Luiz Alexandre Martins da Costa", "Awdren de Lima Fontão", "Rodrigo Pereira dos Santos"], "year": 2025, "keywords": "Software Ecosystems · Software Asset · Cloud Migration · Sustainability · Legacy Systems · Requirements", "abstract": "The increasing complexity of software ecosystems (SECO) demands effective governance mechanisms to ensure long-term sustain\u0002ability, particularly within proprietary SECO (PSECO). As organiza\u0002tions modernize their technology platforms, cloud migration emerges as a key strategy to improve scalability, flexibility, and operational resilience. However, selecting an appropriate migration approach for legacy software assets requires a structured decision-making process that aligns with gov\u0002ernance principles, business continuity, and technical sustainability. This work investigates cloud migration strategies within a PSECO and pro\u0002poses a decision tree artifact to assist IT managers in valuating migra\u0002tion options. We analyze real-world constraints, stakeholder concerns, and governance requirements through a participative case study in a large international organization. Our findings revealed that migration de\u0002cisions are influenced not only by technical factors, such as architecture and performance, but also by business drivers, regulatory constraints, and organizational culture. The proposed guide provides a systematic approach to balancing modernization efforts with risk mitigation, help\u0002ing organizations avoid technical debt while adapting to evolving indus\u0002try demands. Using governance mechanisms in cloud migration strategies may support organizations in maintaining platform stability while foster\u0002ing continuous innovation. Future research should explore how emerging cloud technologies and governance frameworks further impact modern\u0002ization in the PSECO context.", "url": "artigos/artigos_WER25/wer202519.html"}, {"title": "appSCE: uma Ferramenta para Classificação da qualidade de evidências usadas em Casos de Garantia de Segurança", "authors": ["Mozart Alves-Júnior", "Sandeison Fernandes", "Jaelson Castro", "Alvaro Oliveira", "Aldo Nunes"], "year": 2025, "keywords": "Evidência; classificação de evidência; qualidade das evidên- cias; Caso de Garantia de Segurança; Caso de Segurança; Certificação de Segu- rança; viés cognitivo; viés de confirmação", "abstract": "Os Casos de Garantia de Segurança (CGS) tornaram-se elementos es- senciais e indispensáveis na certificação de segurança em diversos domínios de sistemas críticos. Esses processos de certificação são rigorosos e exigem argu- mentos sólidos, sustentados por um conjunto de evidências de alta qualidade que comprovem a segurança e a adequação do sistema ao seu ambiente de uso específico. No entanto, a avaliação dessas evidências frequentemente depende do julgamento humano, o que pode estar sujeito a vieses cognitivos, comprome- tendo a validade dos argumentos apresentados. Este trabalho apresenta o appS- CE (App for Safety Classification of Evidence), uma ferramenta de código aberto, acessível via web, que segue uma arquitetura cliente-servidor e utiliza tecnologias como TypeScript, React Native, Node.js e Firebase Firestore. O ap- pSCE apoia a abordagem Classify Evidence, que visa classificar a qualidade das evidências de segurança utilizadas na construção dos CGS. O objetivo do aplicativo é facilitar o controle e gerenciamento da classificação das evidências, tornando-as mais dinâmicas e acessíveis, e, desta, contribuir para uma comuni- cação mais eficaz e confiável entre os stakeholders envolvidos.", "url": "artigos/artigos_WER25/wer202520.html"}, {"title": "SafeSecRETS: A Project Planning Tool for Critical IoT Systems", "authors": ["Ernesto Fonseca Veiga", "Karlla Loane Santos Lima", "Taciana Novo Kudo", "Renato de Freitas Bulcão-Neto"], "year": 2025, "keywords": "Safety; Security; IoT; Planning; Canvas.", "abstract": "Assuring safety and security from the earliest stages of development in critical IoT systems requires a clear understanding of the system’s objectives, boundaries, and operational context. This paper presents SafeSecRETS, a software tool for agile project planning of critical IoT systems. Through a canvas-based approach, SafeSecRETS supports requirements engineers and stakeholders in project scope definition and system requirements elicitation. The tool features a collaborative pipeline with interconnected building blocks, fostering engagement among information, people, and decision-making. Moreover, it assists in identifying key elements of the critical IoT system, such as components, safety and security aspects, and potential risks, by preparing the requirements analysis and specification through methods based on STPA (Systems Theoretic Process Analysis). Built on a layered event-driven architecture, SafeSecRETS leverages modern, scalable technologies to provide a high-quality web application. We also demonstrate how the tool supports the planning of an automated insulin delivery system.", "url": "artigos/artigos_WER25/wer202521.html"}, {"title": "Stakeholder Virtual: Uma Ferramenta Baseada na IA Generativa para Apoiar Elicitação de Requisitos", "authors": ["Tiago Brito", "Márcia Lucena", "Isabel Nunes"], "year": 2025, "keywords": "Elicitação de Requisitos; Chatbot Inteligente; Inteligência Artificial Generativa; Ensino de Engenharia de Requisitos.", "abstract": "A elicitação de requisitos é um desafio na Engenharia de Requisitos, especialmente para estudantes que não têm acesso a stakeholders reais para entrevistas. Para mitigar essa limitação, este trabalho propõe um chatbot baseado em inteligência artificial generativa para simular entrevistas de elicitação. A ferramenta utiliza a técnica de Geração Aumentada por Recuperação (RAG) para fornecer respostas fundamentadas em documentos de requisitos, permitindo que alunos pratiquem entrevistas e recebam feedback automático. Atuando como mediador estruturado, o Stakeholder Virtual orienta os entrevistadores ao longo do processo e assegura que todas as perguntas essenciais sejam feitas. A solução visa aprimorar a formação prática dos estudantes, preparando-os para desafios reais no mercado. Como trabalhos futuros, pretende-se avaliar a ferramenta com alunos da disciplina e aprimorar sua adaptação a diferentes perfis de entrevistadores e stakeholders.", "url": "artigos/artigos_WER25/wer202522.html"}, {"title": "Tendify: Herramienta Innovadora para la Gestión de Requerimientos en Licitaciones de Desarrollo de Software", "authors": ["Jorge Hochstetter-Diez", "Belfor Acuña-Castillo", "Maximiliano Cortés-Leiva"], "year": 2025, "keywords": "licitaciones de software; ingeniería de requerimientos; in- teligencia artificial; autenticación; Cloudflare R2; WeasyPrint; Quill", "abstract": "Laslicitacionesparadesarrollodesoftwarerequierendelain- tegración de procesos de gestión de requerimientos, seguridad, manejo de documentos y asistencia inteligente. En este artículo presentamos Ten- dify, una plataforma web que integra un editor de texto enriquecido, autenticación robusta, conversión automática a formatos PDF y DOCX, gestión de imágenes mediante Cloudflare R2 y un asistente de Inteligen- cia Artificial para optimizar la redacción de requerimientos de licitaciones para desarrollo de software. Se describen la arquitectura del sistema, los módulos implementados y las innovaciones que la distinguen en el campo de la ingeniería de requerimientos. Este artículo enfatiza la aplicabilidad de la solución en la gestión de requerimientos.", "url": "artigos/artigos_WER25/wer202523.html"}, {"title": "Uso del procesamiento de lenguaje natural para derivar un modelo conceptual de Data Warehouses a partir del lenguaje del dominio", "authors": ["Carlos Antonio Carden", "Sandro Bimonte", "Stefano Rizzi", "Leandro Antonelli"], "year": 2025, "keywords": "NLP; DATAWAREHOUSE; LEL", "abstract": "Un Data Warehouse (almacén de datos) es un sistema de almacenamiento diseñado para recopilar, organizar y analizar grandes volúmenes de datos provenientes de diversas fuentes. Se utiliza en el análisis de negocios y la toma de decisiones, ya que permite consultar información histórica de manera eficiente. Un Data Warehouse ayuda a las empresas a gestionar, analizar y visualizar datos de manera eficiente, mejorando la toma de decisiones basada en información confiable y consolidada. Uno de los modelos para diseñar un Data Warehouse es el modelo multidimensional, que permite estructurar los datos de manera eficiente para análisis y reportes. Este modelo facilita la navegación y exploración de la información desde diferentes perspectivas, optimizando el rendimiento en consultas analíticas. Aunque constituye un punto de partida valioso, no siempre resulta sencillo obtener una especificación de requerimientos ordenada y consistente, que describa de manera integral toda la funcionalidad del modelo. Este artículo propone una herramienta que permite la derivación del modelo multidimensional utilizando diversas técnicas de procesamiento de lenguaje natural a partir del glosario del dominio LEL.", "url": "artigos/artigos_WER25/wer202524.html"}, {"title": "CATCOMPEDU - Elaboração de um Catálogo de Requisitos Não-Funcionais para o Desenvolvimento de Jogos Digitais para o ensino de Computação – Anos Iniciais", "authors": ["Alexssandro Morgenroth", "Victor Francisco Araya Santander"], "year": 2025, "keywords": "NFR-Framework; Catálogo de Requisitos Não-Funcionais; Jogos Digitais; Ensino de Computação; Anos Iniciais.", "abstract": "Como qualquer outro software, os jogos digitais devem ser desenvolvidos com base em modelos de sistemas. Assim, a aplicação de técnicas da Engenharia de Requisitos é fundamental para garantir a qualidade e a agilidade na construção desses produtos, cada vez mais demandados pelo mercado do entretenimento e âmbito educacional. Considerando a abordagem de desenvolvimento de Jogos Digitais, a perspectiva da Engenharia de Requisitos e o ensino de Computação plugada para estudantes de 6 a 10 anos, este projeto de pesquisa tem como objetivo o desenvolvimento e a avaliação de um catálogo de Requisitos Não-Funcionais para o desenvolvimento de Jogos Digitais Educacionais para o ensino de Computação nos Anos Iniciais do Ensino Fundamental. Como base teórica privilegiaram-se os pressupostos teóricos, legais e pedagógicos que sustentam a implementação da Computação na Educação Básica brasileira, para esta pesquisa, será enaltecida a etapa dos Anos Iniciais do Ensino Fundamental. Além disso, fazem parte da fundamentação, as definições e classificações, multidisciplinaridade e as arquiteturas do Desenvolvimento de Jogos Digitais. A estruturação do catálogo será baseada no NFR Framework.", "url": "artigos/artigos_WER25/wer202525.html"}, {"title": "Requisitos de Privacidade em Software: Uma Abordagem Baseada em Padrões para Conformidade com a LGPD", "authors": ["Marcio Veronez", "Roberto Pereira", "Victor Francisco Araya Santander"], "year": 2025, "keywords": "requirements engineering; data protection regulation; privacy; patterns", "abstract": "In recent decades, with the growth of new technologies, there has been an increase in the amount of personal data stored and also in unauthorized exposure, causing concern in society. To counteract this, governments have enacted laws that regulate the storage and use of data, such as the LGPD in Brazil. Software companies have faced challenges in operationalizing the principles of the LGPD due to limited technical knowledge about the law. This doctoral study proposes developing an approach for the elicitation and operationalization of LGPD requirements based on patterns. Its use can help the software industry to develop products that are compliant with the LGPD in a more efficient way.", "url": "artigos/artigos_WER25/wer202526.html"}, {"title": "Automating Testing with LabVIEW: A Requirements-Driven Approach", "authors": ["Carlos Renato dos Santos", "Adriano Costa Pinto", "Fábio Francisco de Carvalho Caballero", "Luciana Pereira Simões", "Alison de Oliveira Moraes"], "year": 2025, "keywords": "Requirements Engineering; Test Automation; LabVIEW; Verification and Validation; Traceability in Testing", "abstract": "Due to safety and performance requirements, lithium-ion cell testing is critical in aerospace applications. Manual testing methods are error-prone and inefficient, leading to inconsistent results and poor traceability. This paper presents a requirements-driven methodology for automating Li-ion charger testing using LabVIEW. The approach utilizes the IEC/ISO/IEEE 29148-2018 writing requirements syntax to assist the software design, improving maintainability and reducing technical debt. A case study illustrates the development of an automated system for capturing charging curves, linking each code section to specific requirements. The solution improved debugging, documentation, and test coverage while reducing misunderstandings of informal specifications. Although direct performance comparisons are limited, automation allowed operators to focus on parallel tasks, enhancing man-hour efficiency. Results show that requirements traceability improved code clarity and streamlined communication between stakeholders. This structured method can be applied to other graphical programming environments where test coverage, maintainability, and resource optimization are essential.", "url": "artigos/artigos_WER25/wer202527.html"}, {"title": "Utilizing LLMs for Early-Stage Qualities Elicitation: A Study on Responsible Fact-Checking in Journalism", "authors": ["Roxana L. Quintanilla Portugal", "Lyrene F. Silva", "Henrique P. Sousa", "Eduardo Almentero"], "year": 2025, "keywords": "Non-Functional Requirements; Large Language Models (LLMs); Responsible Fact-Checking; Elicitation", "abstract": "Requirements elicitation is the process through which engineers interact with information sources to acquire knowledge about a specific domain. In the early stages of software projects, it is uncommon for engineers to elicit non-functional requirements (NFRs) as first-class requirements, as this often demands time and articulation that stakeholders may not readily provide. Large Language Models (LLMs), such as ChatGPT, trained on massive textual datasets, offer a promising opportunity to support this process by generating coherent and context-relevant information about qualities that are key to a given domain problem. In this study, we explore the potential of ChatGPT as an information source for eliciting NFRs related to responsible fact-checking in journalism. Using a previously constructed reference model - developed by the first co-author during a series of Design Thinking sessions with journalism professionals - as a gold standard, three requirements engineering experts, none of whom were familiar with the domain, conducted individual chat sessions with ChatGPT and independently constructed Softgoal Interdependency Graphs (SIGs). Our findings go beyond a simple comparison with the gold standard. While some softgoals consistently emerged across sessions (e.g., trust, accuracy, transparency), participants also uncovered quality concerns such as integrity, dignity, and fairness - elements not explicitly included in the original model. These highlight risks that fact-checking practices must proactively mitigate and offer a broader understanding of relevant qualities in the domain. Additionally, the absence of certain softgoals from the LLM-generated models underscores the importance of human–AI collaboration to improve the completeness and contextual richness of SIGs.", "url": "artigos/artigos_WER25/wer202528.html"}, {"title": "Preface: Proceedings of the 29th Workshop on Requirements Engineering (WER2026)", "authors": ["Marcela Ridao", "Henrique Sousa", "Pablo Thomas"], "year": 2026, "keywords": "WER; Requirements Engineering", "abstract": "The twenty-nineth edition of the Workshop on Requirements Engineering (WER 2026), hosted at Universidad Tecnológica Nacional and Facultad Regional La Plata in La Plata, Argentina, from August 11th to 13th, 2026, brought together researchers and practitioners from across academia and industry. Over three vibrant days, discussions spanned key themes such as generative AI, transparency, data protection, natural language processing, sustainability, accessibility, technical debt, and security requirements. This year, 30 articles were presented as full papers. Following a thorough review by at least three committee members per submission. The event featured five tracks: Research, Industry, Master's and Doctoral, Software Requirements Tools, and Tutorial.", "url": "artigos/artigos_WER26/wer202600.html"}, {"title": "Requerimientos No Funcionales en Aplicaciones Móviles 3D con entornos de Realidad Aumentada", "authors": ["Sebastián Dapoto", "Federico Cristina", "Alex Leodan Arce", "Pablo Javier Thomas", "Patricia Pesado"], "year": 2026, "keywords": "Requerimientos No Funcionales; Aplicaciones Móviles 3D; Realidad Aumentada; Rendimiento gráfico; Unity", "abstract": "Los Requerimientos No Funcionales (RNF) son características que especifican los criterios de calidad y restricciones que un sistema debe cumplir. Estos requerimientos son esenciales en el desarrollo exitoso de software, particularmente en Aplicaciones Móviles 3D, ya que tienen un impacto directo en la experiencia del usuario. El rendimiento gráfico es uno de los RNF más críticos en este tipo de aplicaciones, dado que afecta tanto la experiencia del usuario como la viabilidad de estas aplicaciones en dispositivos con diferentes capacidades de hardware. Las aplicaciones con Realidad Aumentada superponen objetos virtuales 3D al mundo físico en tiempo real, utilizando sensores y capacidades gráficas del dispositivo. En este trabajo, se examina la incidencia de los RNF en las Aplicaciones Móviles 3D con Realidad Aumentada, particularmente enfocado en las principales variables que influyen en el rendimiento gráfico, tales como el modelado 3D, el uso de texturas, la iluminación, los efectos visuales y los efectos físicos. Se presenta una experimentación en la que se evalúa el impacto de las distintas características en la tasa de cuadros por segundo. Los resultados obtenidos permiten identificar los principales cuellos de botella en uno de los requerimientos no funcionales más críticos, lo que contribuye a optimizar el rendimiento y mejorar la calidad final de las Aplicaciones Móviles 3D con Realidad Aumentada.", "url": "artigos/artigos_WER26/wer202601.html"}, {"title": "Enriquecimiento Semántico del Lexico Extendido de Lenguaje (LEL) mediante Ontologías", "authors": ["Marc Marinho de Alcântara", "Leandro Antonelli", "Diego Torres"], "year": 2026, "keywords": "Léxico Extendido del Lenguaje (LEL); Vocabulario de Dominio; Elicitación; GAP Semántico; Ontologías; OWL; Web Semántica", "abstract": "La fase de elicitación en ingeniería de requisitos tiene como objetivo comprender el Universo de Discurso (UofD) y construir un vocabulario compartido entre los stakeholders y el equipo de desarrollo. El Léxico Extendido del Lenguaje (LEL) es una técnica ampliamente utilizada para este fin, ya que permite representar el conocimiento del dominio mediante lenguaje natural; sin embargo, la ambigüedad inherente a este tipo de lenguaje dificulta la verificación sistemática de la consistencia del léxico a medida que este evoluciona. Este trabajo propone un metamodelo del LEL formalizado en el Lenguaje de Ontologías Web (OWL), que explicita los elementos estructurales del léxico y sus relaciones como un modelo verificable. A diferencia de enfoques tradicionales, en los que el LEL se mantiene como un artefacto descriptivo, la propuesta permite incorporar restricciones formales que habilitan la detección automática de inconsistencias durante la elicitación. Asimismo, este trabajo define un proceso incremental de construcción del léxico guiado por dicho metamodelo, integrando la validación estructural como parte del flujo de trabajo del ingeniero de requisitos y promoviendo la coherencia y trazabilidad del conocimiento del dominio desde etapas tempranas. La propuesta se ilustra mediante su aplicación en un caso de estudio del dominio de una línea aérea, demostrando la viabilidad del enfoque mediante el uso de OWL y SPARQL como base tecnológica.", "url": "artigos/artigos_WER26/wer202602.html"}, {"title": "Guías para mejorar la calidad de especificaciones de requerimientos en lenguaje natural", "authors": ["Nicolás Simón Ruffolo", "Giuliana Maltempo", "Juliana Ailen Delle Ville", "Carlos Carden", "Elías Roa", "Enzo Giandon", "Gregorio Ponce", "Juan Escudero", "Juan Ignacio Glassman", "Martina Hübler", "Mauricio Rodríguez Ricon", "Sebastián Diaz", "Sofía Celano", "Carlos Nusch", "Gabriela Perez", "Leandro Antonelli"], "year": 2026, "keywords": "Calidad en Especificaciones; Procesamiento de Lenguaje Natural; Especificaciones Semiestructuradas", "abstract": "La calidad de los requerimientos impacta directamente en el desarrollo del software. Una especificación ambigua o incompleta puede generar un costo de retrabajo para corregir código incorrecto de entre 100 y 200 veces el esfuerzo invertido en especificar requerimientos. El lenguaje natural es el más utilizado para especificar requerimientos dado que los requerimientos es el medio de comunicación entre los usuarios y el equipo de desarrollo. Ahora bien, es común encontrar diferentes defectos en especificaciones de lenguaje natural tales como: ambigüedad, falta de precisión, redundancia, etc. La detección de estos defectos es muy útil, dado que permite reducir el retrabajo por errores. Este artículo tiene por objetivo presentar una serie de guías para revisar ciertos aspectos de oraciones escritas en lenguaje natural con el fin de mejorar la calidad de las mismas. Si bien las guías pueden ser consideradas como una lista de chequeo para el ingeniero de requerimientos, este artículo también muestra una herramienta que utiliza Inteligencia Artificial y que implementa servicios para que las revisiones puedan ser reutilizables por otra aplicaciones.", "url": "artigos/artigos_WER26/wer202603.html"}, {"title": "Detección Temprana de Escenarios Duplicados en Español mediante Enriquecimiento Semántico basado en LEL", "authors": ["Gabriela Perez", "Catalina Mostaccio", "Leandro Antonelli"], "year": 2026, "keywords": "Ingeniería de Requerimientos; Escenarios; LEL; Similaridad Semántica; NLP; Sentence BERT", "abstract": "La detección temprana de escenarios duplicados es un proble- ma relevante en ingeniería de requisitos, especialmente cuando distintos analistas describen una misma situación con vocabulario diferente. Los modelos de embeddings capturan regularidades lingüísticas generales, pero no conocimiento conceptual específico del dominio. En este traba- jo se propone una estrategia de enriquecimiento semántico que integra el Léxico Extendido del Lenguaje (LEL), ampliando cada escenario con definiciones del dominio antes de generar sus embeddings. La estrate- gia se evalúa sobre un dataset de 126 pares de escenarios agrícolas en español anotados por tres analistas. Los resultados muestran mejoras significativas en la correlación con las evaluaciones humanas, alcanzando un Spearman de 0.83 en la configuración título-objetivo, frente a 0.57 del baseline sin enriquecimiento. Los resultados sugieren que reutilizar artefactos propios del proceso de ingeniería de requisitos como fuente de conocimiento estructurado constituye una estrategia efectiva y de bajo costo de adopción, particularmente valiosa en etapas tempranas donde los escenarios contienen poca información y los modelos generales no dis- ponen de suficiente contenido textual para capturar el vocabulario del dominio.", "url": "artigos/artigos_WER26/wer202604.html"}, {"title": "Ambiguity in Requirements Engineering: A Systematic Mapping of AI-Based Approaches", "authors": ["Juan Ignacio Torres", "Leandro Antonelli", "Pablo Thomas"], "year": 2026, "keywords": "Ambiguity detection; Requirements Engineering; Artificial Intelligence; Systematic Mapping Study", "abstract": "Ambiguity in requirements engineering is a pervasive quality defect that can lead to misunderstandings, rework, and increased development costs. In recent years, Artificial Intelligence (AI) techniques have been increasingly explored to support the detection and analysis of ambiguity in natural language requirements. However, existing research is dispersed across different ambiguity types, AI techniques, and Requirements Engineering (RE) activities, making it difficult to obtain a consolidated view of the state of the art. This paper presents a Systematic Mapping Study (SMS) that examines AI-based approaches for addressing ambiguity in requirements engineering. Following established guidelines for systematic studies in software engineering, the literature was systematically identified, selected, and analyzed. The study provides a structured overview of existing approaches, identifies research trends and limitations, and highlights directions for future research in AI-supported requirements quality analysis.", "url": "artigos/artigos_WER26/wer202605.html"}, {"title": "Evaluating Generative Artificial Intelligence for Teaching User Stories", "authors": ["Claudia Marcos", "Guillermo Rodríguez", "Delfina Villarreal Garrido"], "year": 2026, "keywords": "Generative Artificial Intelligence; User Stories; Software Engineering Education; INVEST criteria; Pedagogical Assistance", "abstract": "Generative Artificial Intelligence (GAI) has demonstrated significant potential as a pedagogical assistant across various disciplines. In Software Engineering, User Stories (US) constitute a fundamental technique for requirement specification from the user's perspective, relying on the \"Three Cs\" framework (Card, Conversation, and Confirmation) to ensure functional and non-functional understanding. Nevertheless, teaching this technique in massive university environments poses a significant challenge due to the requirement for continuous feedback. This paper presents a study structured into four experiments with incremental context levels to evaluate GAI's capability to generate US aligned with specific pedagogical objectives. The methodology ranged from the exclusive provision of problem statements to the inclusion of detailed theoretical material and faculty-resolved examples. The results, evaluated through direct comparison with official solutions and compliance with the INVEST criteria, demonstrate that model precision significantly improves as domain-specific information is provided. The scenario integrating both theory and practice achieved the highest performance. However, persistent limitations were detected regarding the models' ability to adjust granularity and establish coherent relationships between stories. It is concluded that GAI is a valuable tool for fostering autonomous learning, although its use does not replace the supervision of a specialized instructor.", "url": "artigos/artigos_WER26/wer202606.html"}, {"title": "Toward a Framework for Explainability in Intelligent Systems: Preliminary Results", "authors": ["Lívia Mancine", "Renata Braga", "Renato Bulcão-Neto"], "year": 2026, "keywords": "Requirements; Explainability; Intelligent Systems; OpenUP", "abstract": "The widespread adoption of Intelligent Systems has highlighted the need for explainability as a key non-functional requirement to promote transparency, trust, and user acceptance. Despite its relevance, existing Requirements Engineering (RE) practices still provide limited support for systematically addressing explainability, especially in early development stages. This work aims to integrate explainability into RE through a systematic and process-oriented approach. The paper presents OpenUPExp, an extension of the Open Unified Process that introduces explicit roles, activities, and artifacts for explainability requirements. The framework structures explainability concerns across RE activities and supports their progressive refinement throughout development. An initial fragment of the framework was evaluated through an illustrative scenario analyzed by RE specialists to assess coherence and artifact clarity. The evaluation indicates that OpenUPExp provides useful guidance for incorporating explainability into RE, while also revealing aspects that require further refinement. The findings suggest the potential of the framework to support a more systematic treatment of explainability in Intelligent Systems.", "url": "artigos/artigos_WER26/wer202607.html"}, {"title": "A Requirements Engineering Perspective on Explainability Privacy Trade-offs in Decision Support Systems", "authors": ["Andressa Girotto Vargas", "Edna Dias Canedo"], "year": 2026, "keywords": "Requirements Engineering; Explainable Artificial Intelligence; Privacy-Preserving Systems; Non-Functional Requirements; Decision Support Systems", "abstract": "Context: The growing adoption of Artificial Intelligence (AI) in decision support systems operating on sensitive data has intensified demands for transparency, accountability, and privacy protection. In these contexts, explainability and privacy preservation often emerge as competing non-functional requirements. While explainable AI techniques aim to improve transparency and justification of automated decisions, privacy-preserving mechanisms restrict information disclosure to protect sensitive data, creating inherent tensions that remain insufficiently understood from a Requirements Engineering perspective. Goal: This study investigates how explainability and privacy requirements interact in AI-based decision support systems, focusing on identifying compatibility conditions, trade-offs, and stakeholder expectations. Method: We adopted a qualitative approach combining a structured literature analysis with an exploratory focus group involving eight stakeholders from technical, managerial, and governance roles. Results: The findings indicate that explainability and privacy-preserving techniques are compatible only under context-dependent conditions. Participants perceived global and aggregated explanations as more appropriate for privacy-constrained environments, whereas local explanations raised higher risks of information disclosure. Stakeholders also emphasized that explanations should be role-appropriate rather than maximally transparent. Conclusion: By conceptualizing explainability and privacy as competing non-functional requirements, this study provides a stakeholder-centered perspective that supports requirements elicitation, analysis, and negotiation in the design of trustworthy and privacy-preserving decision support systems.", "url": "artigos/artigos_WER26/wer202608.html"}, {"title": "Evaluación empírica del proceso ValReCo con propuesta de mejoras asistida por IA", "authors": ["Sonia Santana", "Leandro Antonelli", "Pablo Thomas", "Alejandro Fernandez"], "year": 2026, "keywords": "Validación de Requerimientos; Proceso Colaborativo; Procesamiento de Lenguaje Natural; Inteligencia Artificial", "abstract": "La validación de requerimientos es una actividad fundamental en la ingeniería de software, especialmente en contextos colaborativos donde intervienen múltiples stakeholders con perspectivas heterogéneas. En estos escenarios, la subjetividad del lenguaje natural, la gestión del consenso y la trazabilidad entre requerimientos representan desafíos significativos. Este trabajo presenta una contribución metodológica y empírica al campo de la ingeniería de requerimientos del proceso ValReCo, orientado a la validación colaborativa de requerimientos, mediante una adaptación de la System Usability Scale aplicada a un conjunto de stakeholders. A partir de este análisis, se propone mejoras asistidas por la inteligencia artificial, donde la IA desempeña un rol clave como facilitador de la colaboración y la trazabilidad, manteniendo el juicio experto humano como elemento central del proceso.", "url": "artigos/artigos_WER26/wer202609.html"}, {"title": "Uso de Abordagens da Engenharia de Requisitos Orientada a Objetivos na Indústria: Uma Revisão Sistemática da Literatura", "authors": ["Rafael Lima", "Victor Santander"], "year": 2026, "keywords": "Engenharia de requisitos orientada a objetivos (GORE); Revisão sistemática da literatura; Pequenas e médias empresas", "abstract": "Este artigo apresenta uma Revisão Sistemática da Literatura (RSL) cujo objetivo é identificar e analisar evidências sobre o uso de técnicas e métodos da Engenharia de Requisitos Orientada a Objetivos (GORE) no desenvolvimento de software, com atenção particular ao contexto de pequenas e médias empresas (PMEs). O trabalho foi conduzido seguindo diretrizes consolidadas para RSL na Engenharia de Software. A análise dos estudos selecionados permitiu identificar as principais técnicas da GORE empregadas, as atividades da Engenharia de Requisitos em que são aplicadas e os contextos organizacionais em que têm sido utilizadas, bem como as vantagens e limitações relatadas na literatura. Os resultados indicam que a GORE tem sido amplamente investigada e aplicada em diferentes contextos organizacionais, incluindo PMEs. Observa-se o uso recorrente de técnicas como i*, NFR Framework e KAOS, principalmente nas atividades de elicitação, análise e negociação de requisitos. Entre as principais vantagens relatadas destacam-se a melhoria da comunicação, o alinhamento entre objetivos organizacionais e requisitos de software e o apoio à tomada de decisão. Por outro lado, limitações como a complexidade das técnicas, a curva de aprendizado e o esforço necessário para manutenção dos modelos podem dificultar sua adoção contínua em ambientes industriais.", "url": "artigos/artigos_WER26/wer202610.html"}, {"title": "A Fuzzing-Based Framework for Automated Ethical Risk Detection in Large Language Models", "authors": ["João Lucas Vasconcelos", "Edna Dias Canedo"], "year": 2026, "keywords": "AI Ethics; Ethical Fuzzing; Large Language Models; Fairness Testing; Accountability; Transparency", "abstract": "Context: Ethical risks in Large Language Models (LLMs) are difficult to validate reproducibly because principles such as Fairness, Accountability, and Transparency (FAT) are often stated as abstract guidelines rather than measurable requirements. From a Requirements Engineering perspective, these principles can be treated as non-functional requirements, but current evaluation practices frequently rely on non-deterministic evaluators or LLM-as-a-judge approaches, limiting reproducibility. Goal: This paper proposes a systematic framework for the automated validation of ethical properties derived from FAT principles in LLMs. Method: We introduce an ethical fuzzing framework that operationalizes six of eleven FAT-derived ethical risks (R-F1, R-F2, R-F4, R-A2, R-T1, R-T2) as testing modules combining mutation-based, generation-based, differential, metamorphic, and adversarial techniques. The framework relies on deterministic oracles defined a priori, combining statistical metrics, semantic similarity via fixed SBERT embeddings, and structural verification, without depending on human or LLM-based judges. Results: The framework was evaluated on three commercial LLMs, GPT (gpt-5.2), Gemini (gemini-3-flash), and DeepSeek (deepseek-chat), comprising 8{,}880 cases and 14,160 API calls. Results show a global failure rate of 32.69% [31.72; 33.67], with the highest rates in counterfactual fairness (R-F1: 79.17%) and sensitivity to irrelevant attributes (R-T2: 70.00%). They also reveal a strong asymmetry in R-T1 between direct explanation (22.50-27.00%) and meta-explanation (0.00-1.50%), suggesting that LLM explanations may be more reliable in abstract descriptions than in concrete decision cases. Conclusion: The framework offers Requirements Engineering a mechanism to translate abstract ethical principles into measurable and auditable acceptance criteria, supporting evidence-based validation practices for AI-based systems.", "url": "artigos/artigos_WER26/wer202611.html"}, {"title": "Defining Requirements for Perishable Goods Management Systems (SAFE_GOOD)", "authors": ["Samuel Anjos Neto", "Jaelson Castro", "Maria Lencastre", "Over Causil"], "year": 2026, "keywords": "Requirements Engineering; Regulatory Compliance; Perishable Products; Inventory Management Systems; Logistics Systems", "abstract": "Abstract. Context: Logistics management of perishable products in Brazil requires aligning complex supply chain operations from production and stor-age to final delivery to consumers. In Brazil, the management of perishable inventories must be complied with regulations established by the National Health Surveillance Agency (ANVISA) and the Ministry of Agriculture and Livestock (MAPA). Hence, the supporting information systems are required not only to manage the relevant information but ensure that all regulatory requirements are fulfilled. Objective: Our goal is to propose the Perishable Goods Management Requirements Catalog (SAFE_GOOD) to guide the de-velopment or the selection of supporting management systems for logistics of perishable goods. Method: Regulatory standards issued by ANVISA and MAPA were collected and analyzed alongside a review of relevant literature. The identified regulatory and operational requirements were systematically extracted, and a Requirements Catalogue for the domain of perishable goods management was proposed. Finally, we will discuss how the catalog will be evaluated. Results: We proposed the SAFE_GOOD Requirements Catalog comprising 11 functional, and 5 non-functional requirements. The Func-tional Requirements description was based on the VOLERE template, while Non-Functional Requirement relied on an adapted version of the iNFR template. Some points for future improvement were also identified. Con-clusion: The SAFE_GOOD Requirements Catalog constitutes a reusable re-quirement engineering artifact that supports the development of manage-ment systems aligned with regulatory standards in the perishable products sector.", "url": "artigos/artigos_WER26/wer202612.html"}, {"title": "Requirements People Debt: Conceptualizing Human Factors in Requirements Engineering Debt", "authors": ["Larissa Pinheiro", "Sávio Freire", "Rita Suzana Pitangueira Maciel"], "year": 2026, "keywords": "Requirements Engineering; Requirement Debt; Conceptual Map", "abstract": "Context. Requirements debt (RD) refers to decisions regarding which requirements the development team should implement or how they should be implemented. While prior work has investigated RD from multiple perspectives, limited attention has been given to explicitly conceptualizing the role of human factors in its emergence. Goal. This work introduces Requirements People Debt (RPD), a human-centered perspective on RD that explains how human-related conditions lead to observable deficiencies in requirements artifacts and activities. Method. We cross-analyzed findings from two complementary empirical studies on desirable and undesirable attributes of requirements engineers. Results. We identified 12 causes of RPD, with difficulties in interpersonal relationships and lack of communication being the most frequently mentioned. We also found 55 preventive practices, the most notable being participation in training activities, maintaining frequent communication with stakeholders, and improving business understanding. Conclusion. We organized the findings on RPD into a conceptual map, which may support initiatives aimed at addressing RPD items in software projects and motivate future research in this area.", "url": "artigos/artigos_WER26/wer202613.html"}, {"title": "Goal-Oriented Requirements Engineering: An Updated Systematic Mapping Study (2021–2025)", "authors": ["Claudio Henrique Medaber Jambo", "Flavio Henrique Mendonca", "Paulo Roberto Silva dos Reis", "Tassio Ferenzini Martins Sirqueira", "Vera Maria Werneck"], "year": 2026, "keywords": "Goal-oriented Modeling; Requirements Engineering; Systematic Mapping Study", "abstract": "This paper presents a Systematic Mapping Study (SMS) on Goal-Oriented Requirements Engineering (GORE), covering research publications from 2021 to 2025.This paper presents a Systematic Mapping Study (SMS) on Goal-Oriented Requirements Engineering (GORE), covering research publications from 2021 to 2025. The study extends previous mapping efforts in the field, particularly the work of Delima et al. (2021), which analyzed the period from 2016 to 2020, allowing a comparison of recent research trends. Based on an analysis of 71 primary studies, the mapping examines publication venues, research contribution types, and application domains related to GORE. The results indicate a relatively stable publication volume during the analyzed period, with a balanced distribution between conference proceedings and journal articles. At the same time, the findings suggest changes in contributions, with more studies proposing new approaches than incremental improvements to existing methods. Another observed trend is the growing integration between GORE and artificial intelligence techniques, particularly from 2022 onwards. Some studies explore the use of Large Language Models (LLMs) to support activities such as requirements elicitation, analysis, and goal model generation. The mapping provides an updated overview of the research landscape, indicating that GORE research is progressively incorporating automated and AI-supported techniques, reflecting broader developments in software engineering research and practice.", "url": "artigos/artigos_WER26/wer202614.html"}, {"title": "Un Enfoque Híbrido LLM + OCL para la Detección de Inconsistencias en Escenarios", "authors": ["Gabriela Perez", "Catalina Mostaccio", "Leandro Antonelli"], "year": 2026, "keywords": "Ingeniería de Requerimientos; Escenarios; OCL; Validación formal; LLMs; Metamodelo", "abstract": "La especificación de requisitos mediante escenarios escritos en lenguaje natural es una práctica usada en ingeniería de requisitos. La forma narrativa de los escenarios dificulta su análisis sistemático, dado que los episodios suelen introducir actores y recursos de forma implícita y la consistencia entre la declaración estructural del escenario y su conte- nido narrativo raramente puede verificarse de manera automática. Este trabajo propone un enfoque híbrido que combina modelos de lenguaje de gran escala con invariantes formales expresadas en OCL para abordar este problema. Se define un metamodelo basado en los escenarios defini- dos por Leite, que formaliza los conceptos del dominio y las propiedades que toda especificación válida debe satisfacer. El proceso sigue un pipe- line de cuatro etapas que incluye la construcción del modelo mediante un esquema de dos pasadas con intersección semántica, la resolución de referencias entre escenarios y la evaluación de invariantes OCL. El enfo- que fue implementado en Python y validado sobre un corpus del dominio de huerta urbana, detectando inconsistencias concretas entre las decla- raciones estructurales de los escenarios y el contenido narrativo de sus episodios.", "url": "artigos/artigos_WER26/wer202615.html"}, {"title": "Use of LLMs in Requirements Engineering: An Exploratory Study in Industry", "authors": ["Fabio Levy Siqueira", "Caio Moussa Assumpção", "João Marcos de Mattos Barguil", "Julio Cesar Sampaio do Prado Leite"], "year": 2026, "keywords": "LLM; requirements engineer; chat", "abstract": "Large language models (LLMs) can support requirements engineering activities in different ways. Prior studies have investigated this potential through surveys and interviews with practitioners, focusing on how LLMs are reportedly used in RE tasks. However, these studies do not examine the actual prompts employed by software engineers in real-world contexts. To address this gap, this exploratory study analyzes a log of interactions between software engineers and LLMs during the execution of requirements engineering activities. These interactions are compared with the most frequently reported uses of LLMs in requirements engineering, as identified through queries to Gemini, ChatGPT, and Claude. Our motivation is to gain insights into how practitioners are using LLMs in their requirements engineering practice. The results indicate that software engineers issue a wide variety of requests to LLMs, many of which diverge from the commonly reported usage patterns. Furthermore, the identified queries span all requirements engineering activities, suggesting a broader and more heterogeneous use of LLMs.", "url": "artigos/artigos_WER26/wer202616.html"}, {"title": "Translating EU AI Act Transparency Requirements into Software Engineering Specifications", "authors": ["Eduardo Almentero", "Henrique de Sá Sousa", "Roxana Portugal", "Tadeu Classe", "Marcos Kalinowski"], "year": 2026, "keywords": "EU AI Act; NFR Framework; ISO/IEC 25059; Requirements Engineering; AI Transparency; Software Quality", "abstract": "The European Union Artificial Intelligence Act introduces strict obligations for high-risk AI systems, yet a significant translation gap remains between its legal mandates and the precise specifications that software engineering practice demands. Article 13 in particular, which governs transparency requirements, is written at a level of abstraction that resists direct technical implementation. This paper proposes a five-phase operationalization process that bridges this gap by integrating the Non-Functional Requirements Framework with the ISO/IEC 25059:2023 quality model. Starting from the legal text, the process extracts atomic obligations, maps them to standardized quality characteristics, and pro-duces measurable acceptance criteria organized in a bidirectional traceability matrix. Applied to a credit scoring AI system, the process yields nine traceable requirements across nine quality dimensions. The analysis shows that while Article 13 can be largely operationalized through this approach, some provisions remain technically indeterminate and require organizational governance mechanisms beyond what engineering specification alone can provide. The paper contributes a structured vocabulary and a concrete roadmap for translating AI regulation into verifiable software requirements.", "url": "artigos/artigos_WER26/wer202617.html"}, {"title": "Avaliação do Impacto da Engenharia de Prompt na Elicitação e Documentação de Requisitos com LLMs", "authors": ["Álvaro Soares dos Santos", "Lyrene Fernandes da Silva"], "year": 2026, "keywords": "Engenharia de Requisitos; Elicitação de Requisitos; Documentação de Requisitos; Large Language Models (LLMs); Engenharia de Prompt", "abstract": "A Engenharia de Requisitos é uma etapa fundamental no desenvolvimento de sistemas, responsável por identificar, compreender e documentar as necessidades dos stakeholders a partir da análise do contexto do sistema. Avanços recentes em Large Language Models (LLMs) têm impulsionado seu uso como ferramenta de apoio à Engenharia de Requisitos, embora ainda existam desafios relacionados à qualidade, consistência e confiabilidade dos resultados gerados. Este estudo avalia o impacto da Engenharia de Prompt nesse contexto, comparando diferentes abordagens de elicitação e escrita de requisitos. Para isso, foi definido um pipeline de prompts dividido em contextualização, elicitação (entrevista e seis chapéus do pensamento) e documentação (estruturada e não estruturada), cujos resultados foram avaliados com base em critérios de qualidade de requisitos. Os resultados indicam que prompts estruturados produzem requisitos mais consistentes e rastreáveis, enquanto prompts não estruturados apresentam maior flexibilidade e cobertura do domínio. Além disso, a técnica dos seis chapéus do pensamento apresentou melhores resultados nos critérios avaliados, enquanto entrevistas geraram informações mais focadas e alinhadas ao contexto do sistema. Conclui-se que a Engenharia de Prompt e as técnicas de elicitação utilizadas influenciam significativamente a qualidade dos artefatos gerados por LLMs.", "url": "artigos/artigos_WER26/wer202618.html"}, {"title": "Utilizando a Engenharia de Software Experimental para avaliar a implementação das Regras de Garantia de Consistência na ferramenta JGOOSE", "authors": ["Kauan Campos", "Rafael Lima", "Victor Santander"], "year": 2026, "keywords": "Engenharia de software experimental; Derivação semi-automática; Ferramenta CASE", "abstract": "A Engenharia de Requisitos de Software busca identificar, documentar e gerenciar requisitos ao longo do ciclo de vida de sistemas, sendo a consistência entre diferentes modelos um desafio recorrente na Engenharia de Software. Modelos como iStar e Casos de Uso da UML são amplamente utilizados, mas sua integração exige mecanismos que assegurem coerência entre artefatos ao longo da evolução do software. Este estudo tem como objetivo avaliar a implementação das Regras de Garantia de Consistência na ferramenta JGOOSE, verificando sua capacidade de manter a consistência semiautomática entre casos de uso e modelos iStar. A pesquisa foi conduzida sob princípios da Engenharia de Software Experimental, utilizando a estratégia de quase-experimento. O planejamento envolveu hipóteses formais, definição de variáveis e aplicação da abordagem GQM para estruturar métricas de avaliação. Os resultados indicam que, mesmo havendo oportunidades para ajustes futuros, as Regras de Garantia de Consistência foram aplicadas corretamente em diversos cenários, garantindo a derivação semi-automática consistente entre os modelos e contribuindo para a evolução da ferramenta.", "url": "artigos/artigos_WER26/wer202619.html"}, {"title": "Extensões BPMN para Conformidade com a LGPD e GDPR: Um Panorama do Estado da Arte", "authors": ["Geraldo Gabriel Crelier dos Santos", "Henrique Prado de Sá Sousa", "Eduardo Kinder Almentero", "Tadeu Classe"], "year": 2026, "keywords": "BPMN; Privacy; LGPD; GDPR; Requirements Engineering; Privacy-by-Design; Business Process Modeling", "abstract": "A entrada em vigor de regulamentações de proteção de dados, em destaque o GDPR (General Data Protection Regulation) na Europa e a LGPD (Lei Geral de Proteção de Dados) no Brasil, criou demanda por técnicas de modelagem capazes de representar requisitos de privacidade em modelos de processos de negócio para apoiar, por exemplo, a análise de aderência à Lei e o mapeamento de requisitos tecnológicos. Embora a BPMN seja o padrão de fato para modelagem de processos, ela não possui elementos que representem explicitamente conceitos vinculados à proteção de dados pessoais. Neste artigo apresentamos os resultados de um Mapeamento Sistemático da Literatura (MSL) que investiga como a BPMN tem sido adaptada para suportar a representação de conceitos legais vinculados à GDPR e à LGPD. Os resultados indicam o crescimento do tema a partir de 2018 e revelam contribuições em anotação visual, extensões ontológicas, verificação semiautomatizada e detecção de conflitos entre requisitos de privacidade. Apesar da GDPR ser alvo de maior número de estudos neste tema, destaca-se que foi encontrado apenas um estudo relacionado à LGPD, evidenciando uma lacuna significativa no contexto brasileiro.", "url": "artigos/artigos_WER26/wer202620.html"}, {"title": "Del Aula a la Práctica Profesional Temprana", "authors": ["Valeria Ortiz Quiroz", "Mercedes Soria", "Laura Tosselli", "María Laura Achetta"], "year": 2026, "keywords": "Educación en Ingeniería; Ingeniería de requerimientos; Elicitación de requerimientos; Aprendizaje Basado en Proyectos", "abstract": "La formación en Ingeniería de Requerimientos en los primeros años de las carreras de ingeniería presenta el desafío de promover la comprensión del dominio y la aplicación de conceptos teóricos en ausencia de experiencias profesionales directas. Este trabajo analiza una experiencia en la asignatura Análisis de Sistemas de Información del segundo año de Ingeniería en Sistemas de Información, orientada al desarrollo temprano de habilidades en elicitación, especificación y validación de requerimientos. La propuesta consistió en un Trabajo Práctico Integrador desarrollado bajo modalidad de Aprendizaje Basado en Proyectos, centrado en el análisis de un nuevo sistema de estacionamiento de la propia facultad, dominio organizacional auténtico y cercano al estudiantado. El proceso se estructuró en tres entregas con retroalimentación docente, donde las profesoras asumieron el rol de cliente institucional, promoviendo ciclos iterativos de revisión y validación de los modelos elaborados. Se adoptó un enfoque metodológico mixto que combinó el análisis de los entregables producidos por los equipos — evaluados mediante rúbricas sobre procesos, reglas de negocio y soluciones modeladas con BPMN y UML — con los resultados de una encuesta aplicada al finalizar la experiencia. El análisis de la primera iteración (elicitación) evidenció la identificación de procesos centrales y actores relevantes, así como dificultades iniciales en la delimitación del alcance y formalización de reglas operativas. Los resultados sugieren que la inmersión en contextos auténticos, complementada con retroalimentación sistemática, constituye una estrategia viable para introducir tempranamente prácticas de descubrimiento y análisis de requerimientos en la formación en ingeniería.", "url": "artigos/artigos_WER26/wer202621.html"}, {"title": "Modelagem Conceitual do Aprendizado Autodidata no Ambiente Online Orientado por Competências", "authors": ["Luísa Caetano Correia", "Henrique Prado de Sá Sousa", "Paulo Sérgio Medeiros", "Jobson Luiz Massollar da Silva", "Edgar Sarmiento Calisaya"], "year": 2026, "keywords": "Aprendizagem autodidata; Processo de aprendizagem; Aprendizado orientado por competências; Aprendizagem online; Modelagem conceitual", "abstract": "O aprendizado autodidata no ambiente virtual está sendo cada vez mais utilizado devido à evolução rápida das tecnologias, à popularização dos cursos online e à disponibilização de material técnico em redes sociais. No entanto, o processo de construção do conhecimento e aquisição de competências por pessoas autodidatas passa por dificuldades, por exemplo, na garantia de fontes confiáveis, ausência de encadeamento lógico de estudo e dificuldade de autoavaliação sobre o domínio do tema. Em busca de minimizar as dificuldades destes aprendizes, neste artigo buscamos entender conceitualmente as características de um processo de aprendizagem autodidata através do entendimento de diversos autores. Posteriormente, alinhamos essa teoria com a formalização da estrutura de conhecimento baseada na teoria de competências, a qual permite a projeção de múltiplos métodos para se alcançar o mesmo objetivo. Isso permitiria a proposição de construção de diferentes caminhos de aprendizagem de uma mesma competência, podendo alinhar-se ao determinado perfil do estudante. Consolidamos o conhecimento elicitado através de um mapeamento conceitual que servirá de base para a proposição futura de um método minimamente sistemático que mantenha as características de flexibilidade do aprendizado autodidata no ambiente virtual, reduzindo as barreiras que podem levar os estudantes a não alcançar seus objetivos iniciais.", "url": "artigos/artigos_WER26/wer202622.html"}, {"title": "Hacia un método para definir escenarios a partir de User Story Mapping", "authors": ["Andrea Alegretti", "Leandro Antonelli", "Marisa Panizzi"], "year": 2026, "keywords": "Especificación de Requisitos; User Story Mapping; Escenarios; Método Operacional; Trazabilidad", "abstract": "La especificación de requisitos en lenguaje natural continúa siendo una fuente de ambigüedades e inconsistencias que generan retrabajo en el desarrollo de softwa-re. En la Ingeniería de Requisitos, los escenarios proporcionan descripciones na-rrativas contextualizadas, mientras que el User Story Mapping (USM) ofrece una representación visual de la experiencia del usuario y facilita la priorización incre-mental. Este artículo presenta el proceso de investigación y los métodos aplicados en cada avance logrado. Primero, una encuesta exploratoria caracterizó el uso de estas técnicas en la industria del software de Argentina, identificando un alto inte-rés por combinarlas y una marcada carencia de soporte metodológico. Para el es-tado del arte, se desarrolló un mapeo sistemático de la literatura que evidenció una concentración en servicios en la nube y marcos ágiles, pero una carencia de guías operacionales validadas, con un 46% de trabajos limitados a propuestas teóricas. Basándose en estas evidencias, se diseñó la versión preliminar de un método para definir escenarios a partir de USM preservando la trazabilidad. Finalmente, se realizó una validación mediante un estudio de caso en una Pequeña y Mediana Empresa (PyME) de Argentina, demostrando una percepción favorable de facili-dad, utilidad e intención de uso, junto con hallazgos cualitativos sobre condicio-nes de adopción y puntos de mejora como el tratamiento de tareas ejecutadas por múltiples roles.", "url": "artigos/artigos_WER26/wer202623.html"}, {"title": "Explainability Requirements Engineering in AI-enabled Systems", "authors": ["Lívia Mancine", "Renata Braga", "Renato Bulcão-Neto"], "year": 2026, "keywords": "Requirements Engineering; Explainability; AI-enabled Systems; OpenUP; Design Science Research", "abstract": "Explainability is the ability to make the behavior and decisions of AI-enabled Systems understandable to stakeholders and has become essential for trust, transparency, and informed decision-making across application domains. However, Requirements Engineering (RE) still lacks systematic approaches for integrating explainability throughout the development lifecycle in a structured and stakeholder-oriented manner. This doctoral research proposes OpenUPExp, a process-oriented RE framework that extends the Open Unified Process by introducing roles, activities, and artifacts to support explainability by design as a non-functional requirement. The research follows the Design Science Research methodology and evaluates the framework through illustrative scenarios and real-world case studies involving AI-enabled Systems. The main contribution is OpenUPExp, a process-oriented RE approach for the systematic treatment of explainability from conception through elicitation, analysis, and specification. The framework aims to support stakeholder-centered explainability, improve the traceability and documentation of explainability requirements, and facilitate their alignment with different stakeholder needs and contexts.", "url": "artigos/artigos_WER26/wer202624.html"}, {"title": "Uma Abordagem para Elicitação de Requisitos em Ambientes Ágeis baseada na Integração entre Design Thinking e Engenharia de Requisitos", "authors": ["Maria Augusta Nascimento de Moura", "Fernanda Maria Ribeiro de Alencar"], "year": 2026, "keywords": "Engenharia de Requisitos; Design Thinking; Métodos Ágeis; Elicitação de Requisitos", "abstract": "No contexto do desenvolvimento de software, a Engenharia de Requisitos desempenha papel fundamental na compreensão e definição das necessidades dos stakeholders. Em ambientes ágeis, no entanto, essa atividade enfrenta desafios relacionados à compreensão do problema, à comunicação entre os envolvidos e à adaptação a mudanças, o que pode impactar diretamente a qualidade dos requisitos definidos. Como alter- nativa, o Design Thinking tem sido explorado como uma abordagem complementar, por promover uma perspectiva centrada no usuário e fa- vorecer a exploração do problema antes da definição da solução. Diante desse cenário, este trabalho tem como objetivo propor um guia prático que apoie a elicitação de requisitos por meio da integração entre Design Thinking e Engenharia de Requisitos em ambientes ágeis. Para isso, será conduzida uma Revisão Rápida da Literatura, com o intuito de iden- tificar práticas, contribuições e lacunas relacionadas a essa integração. Como resultado, espera-se contribuir para a definição de requisitos mais claros, consistentes e alinhados às necessidades dos stakeholders.", "url": "artigos/artigos_WER26/wer202625.html"}, {"title": "Proceso Visual de Conceptualización del Universo de Discurso", "authors": ["Alberto Sebastian", "Graciela Dora Susana Hadad", "Leandro Antonelli"], "year": 2026, "keywords": "Elicitación; Facilitación Gráfica; Mapas Conceptuales; Mapas Mentales; Modelado Conceptual", "abstract": "Las actividades de elicitación y modelado en el proceso de ingeniería de requisitos involucran la participación de diferentes personas, tales como usuarios, expertos e ingenieros de requisitos, y la construcción de varios modelos con distintas perspectivas. Dado los inconvenientes que surgen debido a la falta de comprensión del problema por parte de los ingenieros y la dificultad de comunicación entre las partes involucradas, construir un modelo Léxico Extendido del Lenguaje (LEL) mitiga esta situación al capturar el lenguaje del dominio. Sin embargo, varios estudios han detectado la persistencia de defectos en este modelo. Se propone entonces un proceso visual de conceptualización del problema, divido en dos fases. La primera tiene como objetivo comprender el problema dado por los usuarios a través de un artefacto gráfico basado en modelos visuales como los mapas conceptuales, mapas mentales o diagramas de facilitación gráfica. La segunda fase implica la construcción de un modelo LEL derivado a partir de esos modelos visuales, con el propósito describir el vocabulario del mundo real en el cual se encuentra inmerso el problema y la solución. De esta manera, se intenta mejorar la calidad del modelo LEL y, por ende, la calidad de los modelos que se generen a partir de él. Los primeros estudios de caso realizados dan indicios que la integración de modelos visuales y su validación con usuarios no solo facilitan la comprensión del dominio y la delimitación del problema, sino que colaboran en la comunicación y en la detección de inconsistencias en la información elicitada.", "url": "artigos/artigos_WER26/wer202626.html"}, {"title": "Métricas de Processo Observáveis em Repositórios Públicos: Um Catálogo Fundamentado na Literatura Scrum", "authors": ["Flávio Henrique Mendonça", "Tassio Ferenzini Martins Sirqueira", "Vera Maria Werneck"], "year": 2026, "keywords": "Métricas ágeis; Catálogo de métricas; Requisitos de qualidade; ISO/IEC 25010; Scrum; Projetos open source", "abstract": "A especificação e o monitoramento de requisitos de qualidade de processo em equipes ágeis constituem um desafio recorrente na Engenharia de Requisitos. Métricas de gestão podem atuar como instrumentos para avaliar atributos de qualidade associados ao desempenho de times de software, conectando requisitos a indicadores observáveis. A literatura, contudo, permanece fragmentada quanto à seleção e operacionalização dessas métricas em ambientes Scrum. Este artigo propõe um catálogo preliminar de métricas de gestão, derivado de um Mapeamento Sistemático da Literatura conduzido segundo o PRISMA e organizado conforme os atributos de qualidade da ISO/IEC 25010. Como estudo de aplicabilidade, o catálogo é instanciado com dados públicos de repositórios open source, com a análise de indicadores de fluxo, estabilidade e engajamento ao longo do ciclo de vida. Os resultados preliminares sugerem que o catálogo pode apoiar a identificação de padrões comportamentais em projetos em diferentes estágios de maturidade. O trabalho contribui com um artefato estruturado que organiza métricas dispersas e oferece uma referência para a avaliação de requisitos de qualidade de processo em contextos ágeis.", "url": "artigos/artigos_WER26/wer202627.html"}, {"title": "Using ChatGPT to Support Accessibility Requirements Specification: Experience from a Public Sector Platform", "authors": ["Anna Beatriz Marques", "Rhenara Oliveira", "Ramon Luna", "Amanda Sousa", "José Antônio Macêdo", "Rossana Andrade"], "year": 2026, "keywords": "Accessibility Requirements; Large Language Models; Requirements Engineering", "abstract": "Accessibility is a key quality requirement for digital systems, especially in the public sector, where inclusive access is essential. However, specifying accessibility requirements remains challenging in Requirements Engineering, as it requires specialized knowledge and careful interpretation of standards such as WCAG. Although Large Language Models (LLMs) have been explored for requirements-related tasks, there is limited empirical evidence of their use for accessibility requirements in real-world projects. This paper reports an industry experience using ChatGPT to support the specification of accessibility requirements for the Plataforma Antonieta de Barros, a public-sector digital platform designed to support data-driven decision-making in education. The goal is to investigate how an LLM can assist in generating requirements aligned with WCAG 2.2 and to evaluate their quality from practitioners’ perspectives. The findings suggest that ChatGPT can support the initial specification of clear, relevant accessibility requirements, but human validation and iterative refinement are essential to ensure quality and applicability. The experience also highlights the importance of structured prompts and multidisciplinary evaluation to transform AI-generated outputs into actionable requirements for real-world software projects.", "url": "artigos/artigos_WER26/wer202628.html"}, {"title": "From Workshop Transcripts to Requirements Models - A Heuristic and RAG-Based Approach for Reusing Elicitation Data", "authors": ["Roxana Portugal", "Julio C. S. P. Leite", "Lyrene F. Silva", "Edgar Sarmiento"], "year": 2026, "keywords": "Elicitation Data; Requirements Modeling; Interpretative Reasoning; Data Reuse; Qualitative Data; Semantic Analysis.", "abstract": "Elicitation activities such as workshops generate rich qualitative data; however their reuse in Requirements Engineering (RE) remains limited due to the lack of explicit structure and traceable interpretation. While modeling approaches such as i* and the NFR Framework define modeling constructs, they do not make explicit how model elements are derived from elicitation data. In this paper, we present an industrial case based on workshop transcripts and conduct an exploratory exercise of how RE engineers derive goals, tasks, and quality concerns from the same textual input. From a limited but representative sample, we identify recurring patterns in their interpretive reasoning and derive an initial set of heuristics that make this reasoning explicit. We further illustrate how these heuristics can be operationalized within a Retrieval-Augmented Generation (RAG) pipeline, enabling semantic and semi-automated processing grounded in RE engineers’ interpretations while preserving traceability. Our results suggest that, in this exploratory setting, making interpretative reasoning explicit supports the reuse of elicitation data through requirements models.", "url": "artigos/artigos_WER26/wer202629.html"}, {"title": "Construcción Incremental de LEL en Español Asistida por LLM con Trazabilidad e Integración Semántica", "authors": ["Gabriela Perez", "Joaquina Nogueira", "German Ruiz", "Leandro Antonelli"], "year": 2026, "keywords": "Ingeniería de Requerimientos; LEL; NLP; Modelos Generativos; Trazabilidad", "abstract": "La construcción del Léxico Extendido del Lenguaje (LEL) es una técnica utilizada en Ingeniería de Requisitos para capturar el vocabulario específico del dominio y establecer definiciones acordadas que faciliten la comprensión del sistema bajo estudio. Sin embargo, su adopción en proyectos reales se ve limitada por la naturaleza tediosa de la construcción manual, la ausencia de trazabilidad entre las definiciones y sus textos de origen, y la escasez de herramientas adecuadas para el español. Este trabajo presenta un método implementado con LEL-Constructor, una herramienta que aborda estas limitaciones combinando spaCy para la extracción de sintagmas candidatos, un modelo de lenguaje de gran escala (Gemma 3) para la generación y integración de definiciones, y búsqueda semántica sobre embeddings multilingües para detectar entradas redundantes, registrando automáticamente el texto de origen de cada decisión para garantizar trazabilidad. El método mantiene al analista de requisitos como responsable de todas las decisiones semánticas. Una evaluación preliminar con estudiantes de la Licenciatura en Sistemas sugiere que la asistencia automática reduce el esfuerzo inicial en la creación de definiciones sin reemplazar el juicio experto del analista ni su responsabilidad sobre el glosario producido. ********************************************** VIDEO -> https://youtu.be/_79ZimBIV04 **********************************************", "url": "artigos/artigos_WER26/wer202630.html"}];
